const NAME_DESCRIPTIONS_RICH = {

  "Adam": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adam pochodzi z języka <strong>hebrajskiego</strong>. Wywodzi się najprawdopodobniej od słowa <em>adamah</em>, oznaczającego „ziemię, rolę" — stąd znaczenie „zrodzony z ziemi" lub „rolnik". Możliwe też pochodzenie od słowa <em>adom</em> („czerwony", od koloru gliny). W językach ałtajskich <em>adam</em> oznacza „człowiek".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Adam to jedno z najstarszych imion chrześcijańskich — znane z Biblii jako imię pierwszego człowieka. W Polsce używane od wieków. Dziś należy do najczęstszych polskich imion męskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adaś, Adi, Adek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adam (ang., niem., franc., hiszp.), Ádám (węg.), Adão (port.), Ādam (arab.), Адам (ros., ukr.)</p></div>',

  "Anna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anna pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>hannāh</em> oznaczającego „łaska" lub „pełna łaski". Jest to jedno z najstarszych i najszerzej rozpowszechnionych imion na świecie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię Anna pojawia się już od <strong>1229 roku</strong>. Przez wieki należało do czołowych imion żeńskich — dziś nosi je ponad milion Polek, co czyni je <strong>najczęstszym imieniem żeńskim w Polsce</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ania, Anka, Anusia, Hania, Hanka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ann, Anne (ang.), Anne (franc.), Ana (hiszp.), Anna (ros.), Hanna (niem., skandynaw.)</p></div>',

  "Piotr": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Piotr pochodzi z języka <strong>greckiego</strong> — od słowa <em>petros</em> oznaczającego „skała" lub „kamień". Jest formą aramejskiego imienia Kefas, nadanego Szymonowi przez Jezusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozpowszechniło się w Europie dzięki kultowi świętego Piotra Apostoła — pierwszego papieża. W Polsce jest jednym z najstarszych i najpopularniejszych imion męskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Piotrek, Piotruś, Piotreczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Peter (ang., niem.), Pierre (franc.), Pedro (hiszp.), Pietro (wł.), Pyotr (ros.), Péter (węg.)</p></div>',

  "Krzysztof": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Krzysztof pochodzi z języka <strong>greckiego</strong> — od słów <em>Christos</em> (Chrystus) i <em>phero</em> (nieść), co oznacza dosłownie <strong>„niosący Chrystusa"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię pojawiło się w <strong>XIV wieku</strong>, początkowo wśród szlachty, wraz z przyjęciem chrześcijaństwa. Dziś jest jednym z najpopularniejszych imion męskich w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Krzysiek, Krzyś, Kris</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Christopher (ang.), Christoph (niem.), Christophe (franc.), Cristóbal (hiszp.), Cristoforo (wł.), Христофор (ros.)</p></div>',

  "Katarzyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Katarzyna pochodzi z języka <strong>greckiego</strong> — od słowa <em>katharos</em> oznaczającego „czysta", „nieskalana". Do Polski dotarło przez łacinę.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane jest od <strong>XII wieku</strong>. Od XV wieku przez wiele stuleci należało do trzech najpopularniejszych imion żeńskich. Dziś jest drugim najpopularniejszym imieniem żeńskim w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kasia, Kaśka, Katiusza, Kachna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Catherine, Katherine (ang.), Katharina (niem.), Catherine (franc.), Catalina (hiszp.), Ekaterina (ros.)</p></div>',

  "Małgorzata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Małgorzata pochodzi z łaciny — od słowa <em>margarita</em>, które z kolei wywodzi się z języka <strong>greckiego</strong> <em>margarites</em> oznaczającego <strong>„perła"</strong>. Polska forma powstała przez uproszczenie (r-r → ł-r).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Historyczne zapisy z Polski: <em>Margorzata</em> (1438), <em>Malgorzatha</em> (1468). Przez wieki jedno z czołowych imion żeńskich — dziś czwarte najpopularniejsze w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Małgosia, Gosia, Gośka, Greta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Margaret (ang.), Margarete (niem.), Marguerite (franc.), Margarita (hiszp.), Margherita (wł.), Маргарита (ros.)</p></div>',

  "Agnieszka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Agnieszka pochodzi z języka <strong>greckiego</strong> — od słowa <em>hagnē</em> oznaczającego „czysta", „dziewicza", „nieskalana". Możliwe też nawiązanie do łacińskiego <em>agnus</em> — „baranek". Do Polski dotarło wraz z chrześcijaństwem.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków, zaadaptowane z łacińskiej formy <em>Agnes</em>. Patronką jest święta Agnieszka Rzymska (†304), męczennica wczesnego chrześcijaństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aga, Agniecha, Jagna, Inka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Agnes (ang., niem.), Agnès (franc.), Inés (hiszp.), Ágnes (węg.), Агнесса (ros.)</p></div>',

  "Tomasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tomasz pochodzi z języka <strong>aramejskiego</strong> — od słowa <em>toma</em> oznaczającego <strong>„bliźniak"</strong>. Nosił je jeden z dwunastu apostołów Jezusa, znany jako „Tomasz Niedowiarek".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię trafiło do Polski wraz z chrześcijaństwem i przez wieki należało do najpopularniejszych. Dziś jest trzecim najpopularniejszym imieniem męskim w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tomek, Tomuś, Tomcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thomas (ang., niem.), Tomás (hiszp.), Tommaso (wł.), Tamás (węg.), Фома (ros.)</p></div>',

  "Andrzej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Andrzej pochodzi z języka <strong>greckiego</strong> — od rdzenia <em>andr-</em> oznaczającego „mężczyzna", „mężny", „odważny". Jest polską formą greckiego imienia Andreas.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków dzięki kultowi świętego Andrzeja Apostoła — brata Szymona Piotra. Historyczna forma <em>Jędrzej</em> była powszechna w XVII-XVIII wieku. Z imieniem związane są tradycyjne <strong>andrzejki</strong> — wróżby z 29 na 30 listopada.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jędrek, Jędruś, Andrzejek, Andy</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Andrew (ang.), Andreas (niem.), André (franc.), Andrés (hiszp.), Andrea (wł.), Андрей (ros.)</p></div>',

  "Paweł": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Paweł pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>paulus</em> oznaczającego <strong>„mały"</strong>, „skromny". Było to popularne imię w starożytnym Rzymie, znane szczególnie dzięki świętemu Pawłowi Apostołowi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię Paweł dokumentowane jest od <strong>XII wieku</strong> (łac. <em>Paulus</em>, 1155). Dało początek licznym polskim nazwom miejscowym i nazwiskom: Pawlak, Paszek, Pawłów.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Pawełek, Pawcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Paul (ang., niem., franc.), Pablo (hiszp.), Paolo (wł.), Pál (węg.), Павел (ros.)</p></div>',

  "Michał": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Michał pochodzi z języka <strong>hebrajskiego</strong> — od retorycznego pytania <em>Mikha-El</em>, co dosłownie znaczy <strong>„któż jest jak Bóg?"</strong>. Jest wyznaniem wiary — odpowiedź brzmi: nikt. Nosił je archanioł Michał — niebiański wódz i pogromca szatana.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od najwcześniejszego średniowiecza. <strong>Michał Anioł</strong> (1475–1564) — twórca Dawida, fresków Kaplicy Sykstyńskiej i kopuły bazyliki św. Piotra w Rzymie. <strong>Michał Ogiński</strong> — kompozytor słynnego Poloneza <em>Pożegnanie ojczyzny</em>. <strong>Michael Jackson</strong> — Król Popu, jedna z najważniejszych postaci muzyki XX w. Dziś Michał to jedno z najpopularniejszych imion w Polsce — nosi je blisko pół miliona Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Michałek, Michaś, Misiek, Misio, Michałeczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Michael (ang., niem.), Michel (franc.), Miguel (hiszp., port.), Michele (wł.), Mikhail (ros. Михаил), Mihail (rum.), Mikael (skandynaw.)</p></div>',

  "Ewa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ewa pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>hawwah</em> oznaczającego <strong>„życie"</strong> lub „dawczyni życia". Według Biblii Ewa była pierwszą kobietą — matką całej ludzkości.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najstarszych imion chrześcijańskich, znane z Księgi Rodzaju. W Polsce przez wieki należało do czołowych imion żeńskich — dziś nosi je blisko pół miliona Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewka, Ewcia, Ewusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eve (ang.), Eva (niem., hiszp., wł.), Ève (franc.), Eva (ros.), Éva (węg.)</p></div>',

  "Barbara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Barbara pochodzi z języka <strong>greckiego</strong> — od słowa <em>barbaros</em> oznaczającego „obcy", „cudzoziemiec". W starożytności Grecy tak nazywali wszystkich nie mówiących po grecku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię znane od wieków. Patronką jest <strong>święta Barbara z Nikomedii</strong> — legendarna męczennica z III/IV wieku, której wspomnienie obchodzone jest 4 grudnia. Z jej imieniem związane są liczne polskie przysłowia pogodowe.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Basia, Baśka, Basieńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Barbara (ang., niem., franc., hiszp.), Barbora (czes., słowac.), Warwara (ros., ukr.)</p></div>',

  "Jan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jan pochodzi z języka <strong>hebrajskiego</strong> — od imienia <em>Johanan</em> oznaczającego <strong>„Bóg jest łaskawy"</strong>. Do Polski dotarło przez grekę i łacinę.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najstarszych i najpopularniejszych imion w Polsce — dokumentowane od <strong>1012 roku</strong> (jako <em>Ioannes</em>), od <strong>1161 roku</strong> w formie Jan. Przez wieki należało do najczęstszych imion męskich w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Janek, Jasiek, Jaś, Jaszko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>John, Ian (ang.), Jean (franc.), Juan (hiszp.), Johannes (niem.), Giovanni (wł.), Иван (ros.)</p></div>',

  "Marcin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marcin pochodzi z języka <strong>łacińskiego</strong> — od imienia <em>Martinus</em>, które wywodzi się od imienia boga wojny <strong>Marsa</strong>. Oznacza dosłownie „należący do Marsa".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię poświadczone od <strong>1393 roku</strong> w księgach krakowskich. Popularność zawdzięcza kultowi świętego Marcina z Tours — jego święto (11 listopada) jest w Polsce tradycyjnie obchodzone rogalami świętomarcińskimi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marcinek, Martuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Martin (ang., niem., franc., hiszp.), Martino (wł.), Márton (węg.), Мартин (ros.)</p></div>',

  "Magdalena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Magdalena pochodzi od nazwy miejscowości <strong>Magdala</strong> nad Jeziorem Galilejskim w Izraelu, co po aramejsku oznaczało „wieża" lub „twierdza". Dosłownie znaczy <strong>„kobieta z Magdali"</strong>. Imię ściśle związane z postacią Marii Magdaleny z Nowego Testamentu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Maria Magdalena</strong> — pierwsza świadkini Zmartwychwstania Jezusa, zwana „apostołką apostołów". Imię trafiło do Polski wraz z chrześcijaństwem i od XIII w. stało się powszechne. <strong>Magdalena Abakanowicz</strong> (1930–2017) — polska rzeźbiarka o światowej sławie, twórczyni monumentalnych figur. <strong>Madeleine Albright</strong> (1937–2022) — pierwsza kobieta na stanowisku Sekretarza Stanu USA. Dziś nosi je ponad 430 tysięcy Polek — ósme najpopularniejsze imię żeńskie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Magda, Madzia, Lena, Magdusia, Magdunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Madeleine / Madeline (franc., ang.), Magdalena (niem., hiszp., port.), Maddalena (wł.), Magdaléna (czes.), Magdalina (ros. Магдалина)</p></div>',

  "Jakub": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jakub pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>Yaakov</em> (יַעֲקֹב), co oznacza „trzymający za piętę" lub „ten, który zastępuje". W Biblii Jakub był synem Izaaka i wnukiem Abrahama — praojciec dwunastu plemion Izraela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozpowszechniło się w Polsce dzięki dwóm apostołom noszącym to imię: Jakubowi Starszemu i Jakubowi Młodszemu. Dziś jest jednym z najpopularniejszych imion dla chłopców.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kuba, Kubek, Kubuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>James, Jacob (ang.), Jacques (franc.), Jaime (hiszp.), Giacomo (wł.), Jakob (niem.), Яков (ros.)</p></div>',

  "Elżbieta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Elżbieta pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>Eliszeba</em> (אלשבת) oznaczającego <strong>„Bóg moją przysięgą"</strong> lub „mój Bóg jest pełnią". W Biblii nosiła je matka Jana Chrzciciela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków. Noszone przez liczne królowe i cesarzowe — m.in. Elżbietę I i II królową Anglii. Dziś jest dziewiątym najpopularniejszym imieniem żeńskim w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elka, Elcia, Elunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elizabeth (ang.), Elisabeth (niem., franc.), Isabel (hiszp.), Elisabetta (wł.), Erzsébet (węg.), Елизавета (ros.)</p></div>',

  'Joanna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Joanna pochodzi z języka <strong>hebrajskiego</strong> — od imienia <em>Yohannah</em>, złożonego z <em>Yo</em> (skrót od Jahwe) i <em>hanan</em> (łaska). Oznacza <strong>„Bóg jest łaskawy"</strong> lub „obdarzona łaską Bożą". Do Polski dotarło przez łacińskie <em>Johanna</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię niezwykle ważne w historii. Joanna d&#39;Arc (ok. 1412–1431) — francuska bohaterka narodowa, patronka Francji, kanonizowana w 1920 r. W Polsce imię popularne od wieków, noszone przez wiele szlachcianek i królowych. Joanna Schopenhauer — matka słynnego filozofa Artura, sama będąca pisarką.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Asia, Joaśka, Joanka, Asiunia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Joan, Joanna (ang.), Jeanne (franc.), Juana (hiszp.), Giovanna (wł.), Johanna (niem.), Жанна (ros.)</p></div>',

  "Aleksandra": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aleksandra pochodzi z języka <strong>greckiego</strong> — od słów <em>alexein</em> (bronić, chronić) i <em>anēr</em> (mężczyzna), co oznacza <strong>„obrończyni ludzi"</strong>. Jest żeńską formą imienia Aleksander.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię weszło w użycie w <strong>XIV wieku</strong>. Popularność zyskało m.in. dzięki powieści Henryka Sienkiewicza <em>Potop</em>, gdzie jedna z bohaterek nosiła to imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ola, Oleńka, Sandra, Alesia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alexandra (ang., niem.), Alexandrine (franc.), Alejandra (hiszp.), Alessandra (wł.), Александра (ros.)</p></div>',

  'Krystyna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Krystyna pochodzi z języka <strong>greckiego</strong> — od słowa <em>Christos</em> (Chrystus, Namaszczony). Oznacza <strong>„chrześcijanka"</strong> lub „należąca do Chrystusa". Do Polski dotarło przez łacińskie <em>Christina</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez wiele świętych, m.in. świętą Krystynę z Bolseny (III w.) — męczennicę. W Polsce bardzo popularne w XX w., szczególnie w latach 1950–1970. Krystyna Janda (ur. 1952) — wybitna polska aktorka teatralna i filmowa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Krysia, Kryszka, Kryśka, Tina, Krycha</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Christina (ang., niem., hiszp.), Christine (franc.), Cristina (wł., hiszp.), Кристина (ros.)</p></div>',

  "Łukasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Łukasz pochodzi z języka <strong>greckiego</strong> — od słowa <em>Loukas</em>, nawiązującego do łacińskiego <em>lux</em> (światło) lub nazwy krainy Lukania we Włoszech. Oznacza „urodzony o świcie" lub „niosący światło".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce dzięki świętemu Łukaszowi Ewangeliście — autorowi trzeciej Ewangelii i Dziejów Apostolskich. Dziś nosi je blisko 380 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Łukaszek, Łukasz</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lucas, Luke (ang.), Lukas (niem.), Luc (franc.), Lucas (hiszp.), Luca (wł.), Lukáš (czes.)</p></div>',

  "Mateusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mateusz pochodzi z języka <strong>hebrajskiego</strong> — od słów <em>mattan</em> (dar) i <em>Yah</em> (Jahwe), co oznacza <strong>„dar Boga"</strong>. Nosił je Mateusz Apostoł i Ewangelista.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W dawnej Polsce imiona Mateusz i Maciej nie były rozróżniane aż do <strong>XVI wieku</strong>. W źródłach pojawia się jako <em>Mathaeus</em> i <em>Matyjasz</em>. Dziś nosi je ponad 370 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mateuszek, Matek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Matthew (ang.), Matthias (niem.), Mathieu (franc.), Mateo (hiszp.), Matteo (wł.), Матвей (ros.)</p></div>',

  "Monika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Etymologia imienia Monika jest niepewna. Prawdopodobnie pochodzi z języka <strong>greckiego</strong> — od słowa <em>monos</em> (jeden, jedyny) lub <em>monaché</em> (samotna, odosobniona). Możliwe też pochodzenie afrykańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię pojawia się już w <strong>XV wieku</strong> w formach Mońka i Muńka. Szerszą popularność zyskało w XIX wieku, a szczyt przypadał na lata 70. XX wieku. Patronką jest święta Monika — matka świętego Augustyna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Moniczka, Monia, Nika</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Monica (ang., wł., hiszp.), Monique (franc.), Mónika (węg.), Моника (ros.)</p></div>',

  "Grzegorz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Grzegorz pochodzi z języka <strong>greckiego</strong> — od słowa <em>gregoreo</em> oznaczającego <strong>„być czujnym"</strong>, „czuwać". Jest polską formą łacińskiego <em>Gregorius</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię bardzo popularne w historii chrześcijaństwa — nosił je aż <strong>16 papieży</strong>, w tym Grzegorz I Wielki (papież, doktor Kościoła). W Polsce używane od wieków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Grześ, Grześko, Grzesiek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gregory (ang.), Gregor (niem.), Grégoire (franc.), Gregorio (hiszp., wł.), Grigorij (ros.)</p></div>',

  "Marek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marek pochodzi z języka <strong>łacińskiego</strong> — wywodzi się od imienia boga wojny <strong>Marsa</strong> (<em>Mart-ico-s</em>), oznaczając „należący do Marsa". Należy do grupy starożytnych imion rzymskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce dokumentowane od <strong>XIII wieku</strong> w formach Marek, Marko, Markusz. Patronem jest <strong>święty Marek Ewangelista</strong> — autor drugiej Ewangelii, którego święto przypada 25 kwietnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maruś, Mareczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mark (ang.), Markus (niem.), Marc (franc.), Marcos (hiszp.), Marco (wł.), Марк (ros.)</p></div>',

  "Zofia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zofia pochodzi z języka <strong>greckiego</strong> — od słowa <em>sophía</em> (σοφία) oznaczającego <strong>„mądrość"</strong>. Jest jednym z najpiękniejszych semantycznie imion żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków, noszone przez liczne polskie księżniczki i królowe. W <strong>2022 roku</strong> było najczęściej nadawanym imieniem dla dziewczynek w Polsce. Dziś nosi je blisko 365 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zosia, Zośka, Sonia, Sosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sophie, Sophia (ang., franc.), Sofia (hiszp., wł.), Sofie (niem.), София (ros.)</p></div>',

  "Stanisław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Stanisław jest imię <strong>słowiańskie</strong> — złożone z członów <em>stani-</em> (stanąć, powstać) i <em>-sław</em> (sława), co oznacza <strong>„ten, który stanie się sławny"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najbardziej polskich imion — pod koniec XV wieku należało do najpopularniejszych w kraju. Patronem jest <strong>święty Stanisław ze Szczepanowa</strong> — biskup krakowski, patron Polski, męczennik (†1079).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Staś, Stasio, Stasiek, Staszek, Stach</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Stanislaus (łac., niem.), Stanislas (franc.), Estanislao (hiszp.), Szaniszló (węg.), Станислав (ros.)</p></div>',

  "Wojciech": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wojciech jest imieniem <strong>słowiańskim</strong> — złożonym z członów <em>woj-</em> (wojownik, żołnierz) i <em>-ciech</em> (radość, pociecha), co oznacza <strong>„wojownik przynoszący radość"</strong> lub „pociecha wojska".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od <strong>X wieku</strong>. Patronem jest <strong>święty Wojciech</strong> — czeski biskup, misjonarz i męczennik (†997), patron Polski. Jego imieniny obchodzone są 23 kwietnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wojtek, Wojtuś, Wojtas, Wojcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adalbert (łac., niem.), Vojtěch (czes.) — imię w swej polskiej formie nie ma bezpośrednich odpowiedników w językach zachodnich.</p></div>',

  "Maria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maria pochodzi od hebrajskiego <em>Miriam</em> o niepewnej etymologii. Proponowane znaczenia to „napawa radością", „ukochana przez Boga" (z egipskiego <em>meri-jam</em>) lub „orzeźwiająca" (od hebr. <em>rawah</em>). Imię nierozerwalnie związane z Maryją — matką Jezusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce przez wieki imię było „zarezerwowane" dla Matki Boskiej i rzadko nadawane dzieciom — zamiast niego używano form Marianna lub Maryna. Dopiero w XIX wieku upowszechniło się jako imię świeckie. Dziś jest jednym z najpopularniejszych imion żeńskich w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marysia, Maryśka, Maja, Mania</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mary (ang.), Marie (franc., niem.), María (hiszp.), Maria (wł.), Мария (ros.), Mária (węg.)</p></div>',

  "Natalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Natalia pochodzi z języka <strong>łacińskiego</strong> — od wyrażenia <em>dies natalis</em> oznaczającego „dzień narodzin". Dawniej nadawano je dzieciom urodzonym w Boże Narodzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków. W XXI wieku zyskało dużą popularność — dziś nosi je ponad 320 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Natka, Nata, Natasza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Natalie (ang.), Nathalie (franc.), Natalia (niem., hiszp., wł.), Наталья (ros.)</p></div>',

  'Julia': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Julia pochodzi z języka <strong>łacińskiego</strong> — od słynnego rodu <em>Iulius</em>, który wywodził swe pochodzenie od Julusa, syna Eneasza. Etymologia łączy się z greckim <em>ioulos</em> — <strong>„puszysty"</strong>, „miękkowłosy", co odnosi się do młodości i piękna.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię znane od czasów antycznych. Julia była imieniem wielu patrycjuszek rzymskich. W Polsce imię popularne szczególnie od końca XX w. — w 2010–2015 było jednym z najczęściej nadawanych imion dziewczynom. Julia Roberts (ur. 1967) — słynna amerykańska aktorka.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Julka, Julcia, Juleczka, Julusia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Julie (franc.), Julia (ang., niem., hiszp., wł.), Giulia (wł.), Юлия (ros.)</p></div>',

  "Teresa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Teresa pochodzi prawdopodobnie z języka <strong>greckiego</strong> — od nazwy wyspy <em>Thera</em> (dziś Santoryn) lub od słowa <em>therizo</em> (zbierać plony, żąć). Etymologia nie jest w pełni wyjaśniona.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię pojawiło się w <strong>XVII wieku</strong>. Patronkami są m.in. <strong>święta Teresa z Ávili</strong> — doktor Kościoła i mistyczka oraz <strong>święta Teresa z Kalkuty</strong> (Matka Teresa) — laureatka Pokojowej Nagrody Nobla.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tereska, Tesia, Resa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theresa (ang., niem.), Thérèse (franc.), Theresa (hiszp.), Тереза (ros.), Tereza (czes.)</p></div>',

  "Karolina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Karolina jest żeńską formą imienia Karol, które pochodzi ze <strong>starogermańskiego</strong> słowa <em>karl</em> oznaczającego „wolny mężczyzna", „mąż" lub „wojownik".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce od XVIII wieku, noszone przez liczne europejskie księżniczki i królowe. Dziś nosi je blisko 300 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Karo, Karolka, Lina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Caroline (ang., franc.), Carolina (hiszp., wł.), Karoline (niem.), Каролина (ros.)</p></div>',

  "Marta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marta pochodzi z języka <strong>aramejskiego</strong> — od słowa <em>marta</em> oznaczającego <strong>„pani domu"</strong>, „gospodarcza". W Biblii Marta była siostrą Marii i Łazarza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków dzięki tradycji chrześcijańskiej. Popularne szczególnie w XX i XXI wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Martusia, Marteczka, Martunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Martha (ang., niem.), Marthe (franc.), Marta (hiszp., wł.), Марта (ros.)</p></div>',

  "Danuta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Danuta pochodzi prawdopodobnie z języka <strong>litewskiego</strong> — od słowa <em>danutė</em>, łączącego znaczenia „niebo" i „córka". Możliwa jest też etymologia od łacińskiego <em>donata</em> — „darowana przez Boga". Imię typowo polskie, niemal nieznane poza Polską i Litwą.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>XIV wieku</strong>. Rozsławił je Henryk Sienkiewicz w powieści <em>Krzyżacy</em> (1900) — Danuta jest tu córką Kiejstuta, księżniczką litewską i żoną Zbyszka z Bogdańca. Po ekranizacji powieści imię zyskało ogromną popularność. <strong>Danuta Wałęsowa</strong> — żona Lecha Wałęsy, ikona epoki Solidarności. Szczyt popularności przypadł na lata 50.–70. XX w.; dziś nadawane rzadziej, ale cenione za swój piękny, słowiański charakter.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Danka, Danusia, Danuśka, Danutka, Danuchna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie i litewskie (Danutė), bez bezpośrednich odpowiedników zachodnioeuropejskich. Pokrewne z Donata (wł., hiszp.) lub Dana (ang.).</p></div>',

  "Mariusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mariusz pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu Mariuszów (<em>Marius</em>), wywodzącego się od imienia boga wojny <strong>Marsa</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię używane od <strong>XIII wieku</strong>. Dziś nosi je blisko 285 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mariuszek, Marian</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marius (ang., niem., franc.), Mario (hiszp., wł.), Máriusz (węg.), Марио (ros.)</p></div>',

  "Dariusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dariusz pochodzi z języka <strong>perskiego</strong> — od imienia <em>Dārayavahuš</em> złożonego z elementów oznaczających „posiadać" i „dobro", co razem daje znaczenie <strong>„posiadający dobro"</strong> lub „bogaty w dobra".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane z historii starożytnej dzięki trzem perskim królom Dariuszom. W Polsce w użyciu od co najmniej <strong>XVIII wieku</strong>, choć szeroką popularność zyskało dopiero w XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Darek, Daruś, Daro</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Darius (ang., niem.), Daire (franc.), Darío (hiszp.), Дарий (ros.)</p></div>',

  "Beata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Beata pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>beatus</em> oznaczającego <strong>„błogosławiona"</strong>, „szczęśliwa", „przynosząca szczęście". Jest żeńską formą imienia Beat.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków, szczyt popularności przypadał na lata 60.-80. XX wieku. Dziś nosi je blisko 280 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Beatka, Becia, Beaśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Beatrice, Beatrix (ang.), Beate (niem.), Béatrice (franc.), Beatriz (hiszp.), Беата (ros.)</p></div>',

  "Maciej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maciej pochodzi z języka <strong>hebrajskiego</strong> — jest polską formą aramejskiego <em>Matatjahu</em> (מַתִּתְיָהוּ), co oznacza <strong>„dar Boga"</strong> lub „Bóg jest łaskawy". Wywodzi się z elementów: <em>mattan</em> (dar) i <em>Yah</em> (Jahwe).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>1201 roku</strong>. Nosił je Maciej Apostoł — wybrany przez uczniów Jezusa na miejsce Judasza Iskarioty. Imię znane z polskiego folkloru i literatury ludowej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maciek, Maciuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Matthias (ang., niem.), Matías (hiszp.), Mattia (wł.), Матвей (ros.), Matěj (czes.)</p></div>',

  "Dorota": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dorota pochodzi z języka <strong>greckiego</strong> — złożone z elementów <em>doron</em> (dar) i <em>theos</em> (Bóg), co oznacza <strong>„dar Boży"</strong>. Jest żeńskim odpowiednikiem imienia Doroteusz — podobne znaczenie ma też imię Teodora.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>1385 roku</strong>. Dziś nosi je blisko 270 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dorotka, Dorcia, Dosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dorothy (ang.), Dorothée (franc.), Dorotea (hiszp., wł.), Dorottya (węg.), Дорота (ros.)</p></div>',

  "Rafał": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Rafał pochodzi z języka <strong>hebrajskiego</strong> — od słów <em>rofe</em> (uzdrowiciel) i <em>El</em> (Bóg), co oznacza <strong>„Bóg uzdrawia"</strong>. Nosił je archanioł Rafał — patron lekarzy i aptekarzy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię zyskało popularność w Polsce w końcu lat 30. XX wieku dzięki powieści Tadeusza Dołęgi-Mostowicza <em>Znachor</em> (1937), której bohater miał na imię Rafał Wilczur.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rafałek, Rafcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Raphael (ang., niem., franc.), Rafael (hiszp., port.), Raffaele (wł.), Рафаил (ros.)</p></div>',

  "Robert": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Robert pochodzi ze <strong>starogermańskiego</strong> — złożone z elementów <em>hrod</em> (sława, chwała) i <em>beraht</em> (jasny, błyszczący), co oznacza <strong>„sławny blaskiem"</strong> lub „jaśniejący chwałą".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię bardzo popularne w średniowiecznej Europie, noszone przez licznych królów — m.in. Roberta Bruce&#39;a króla Szkocji. W Polsce używane od wieków, szczyt popularności przypadał na lata 60.-80. XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Robek, Robi, Robertek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Robert (ang., niem., franc., hiszp.), Roberto (wł., hiszp.), Роберт (ros.)</p></div>',

  "Kamil": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kamil pochodzi z języka <strong>łacińskiego</strong> — od <em>Camillus</em>, co oznaczało „pomocnik kapłana" lub „szlachetnie urodzony chłopiec". Możliwe też pochodzenie etruskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków. Patronem jest <strong>święty Kamil de Lellis</strong> — włoski zakonnik, założyciel zakonu Kamilianów, patron chorych i personelu medycznego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kamilek, Kamilus</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Camille (franc.), Camilo (hiszp.), Camillo (wł.), Camil (rum.), Камилл (ros.)</p></div>',

  "Zbigniew": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zbigniew jest imieniem <strong>słowiańskim</strong> — złożonym z elementów <em>Zby-</em> (pozbyć się, uwolnić) i <em>-gniew</em> (gniew, złość), co oznacza <strong>„ten, kto pozbył się gniewu"</strong>. Pierwotna forma brzmiała <em>Zbygniew</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najstarszych polskich imion słowiańskich — pod koniec XV wieku nosiło je ok. 1000 osób w Polsce. Nosił je m.in. kardynał Zbigniew Oleśnicki (1389–1455).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zbyszek, Zbysio, Zbych</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach.</p></div>',

  "Szymon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Szymon pochodzi z języka <strong>hebrajskiego</strong> — od imienia <em>Shim\'on</em> (שמעון) oznaczającego <strong>„Bóg wysłuchał"</strong>. Nosił je jeden z dwunastu apostołów Jezusa — Szymon Piotr.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków dzięki tradycji chrześcijańskiej. Dziś przeżywa renesans — w 2017 roku było czwartym najczęściej nadawanym imieniem chłopcom w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Szymek, Szymonek, Szymuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Simon (ang., niem., franc.), Simón (hiszp.), Simone (wł.), Симон (ros.)</p></div>',

  "Dawid": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dawid pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>dawid</em> (דָּוִד) oznaczającego <strong>„ukochany"</strong> lub „przyjaciel". Nosił je jeden z największych królów Izraela — Dawid, autor Psalmów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków dzięki tradycji biblijnej. W XXI wieku zyskało dużą popularność — dziś nosi je blisko 240 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dawidek, Dawcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>David (ang., niem., franc., hiszp.), Davide (wł.), Давид (ros.)</p></div>',

  "Jolanta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jolanta pochodzi z języka <strong>greckiego</strong> — od <em>ion</em> (fiołek) i <em>anthos</em> (kwiat). Znaczenie: <strong>„kwiat fioletowy, fiołek"</strong>. Jest polską i środkowoeuropejską formą imienia Yolanda, popularnego w średniowiecznej Europie romańskiej i germańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię używane od <strong>XIII wieku</strong>, początkowo w formie Jolenta lub Iolanta. Patronką jest <strong>błogosławiona Jolanta</strong> (1244–1304) — córka króla Węgier Béli IV, żona Bolesława Pobożnego, księżna wielkopolska, tercjarka franciszkańska. <strong>Jolanta Kwaśniewska</strong> — pierwsza dama Polski w latach 1995–2005, znana z działalności charytatywnej. W XX w. imię cieszyło się dużą popularnością w Polsce, szczyt przypadł na lata 60.–70.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jola, Jolka, Jolantuś, Jolusia, Joleczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Yolanda (ang., hiszp., port.), Yolande (franc.), Iolanda / Iolanthe (wł.), Jolana (czes., słowac.), Иоланта (ros.)</p></div>',

  "Kacper": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kacper pochodzi z języka <strong>perskiego</strong> — od słowa <em>ganzabara</em> oznaczającego <strong>„strażnik skarbu"</strong>. Złożone z <em>ganzah</em> (skarb) i <em>barah</em> (nieść, strzec).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię tradycyjnie przypisywane jednemu z <strong>Trzech Króli</strong> (Mędrców ze Wschodu). W Polsce używane od <strong>połowy XIV wieku</strong>. Imieniny Kacpra obchodzone są 6 stycznia — w Święto Trzech Króli.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kacperek, Kacpruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Casper (ang., niem.), Gaspard (franc.), Gaspar (hiszp., port.), Jasper (niem., nid.)</p></div>',

  'Hanna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Hanna pochodzi z języka <strong>hebrajskiego</strong> — od imienia <em>Hannāh</em>, oznaczającego <strong>„łaska"</strong> lub „pełna łaski". Jest pierwotną, hebrajską formą imienia Anna. Do Polski dotarło przez Biblię i tradycję chrześcijańską.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię biblijne — Hanna była matką proroka Samuela, która długo modliła się o potomstwo. W Polsce forma Hanna i Anna funkcjonują równolegle od wieków. Hanna Suchocka (ur. 1946) — pierwsza kobieta premier Polski (1992–1993).</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Haneczka, Hanka, Haniczka, Hanusia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Hanna (niem., skandynaw., fin.), Hannah (ang.), Hanne (duń.), Ханна (ros.)</p></div>',

  "Zuzanna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zuzanna pochodzi z języka <strong>hebrajskiego</strong> — od <em>Shoshannah</em>, co oznacza <strong>„lilia"</strong> lub „lotos". Kwiat lilii w kulturze starożytnej symbolizował czystość, piękno i niewinność. Imię ma długą tradycję biblijną i chrześcijańską.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Zuzanna</strong> to cnotliwa niewiasta, fałszywie oskarżona przez starszych — ocalona przez mądrość młodego Daniela. W operze Mozarta <em>Wesele Figara</em> Zuzanna jest jedną z głównych bohaterek. <strong>Suzanne Vega</strong> — poetka i piosenkarka folkrockowa. W Polsce imię popularne od XVII w., dziś przeżywa renesans — Zuzia to jedno z najchętniej nadawanych imion dziewczęcych w XXI wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zuzia, Zuzka, Zuzanka, Zuzeczka, Zusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Susan / Susanna (ang.), Suzanne / Suzette (franc.), Susanna (wł.), Susana (hiszp., port.), Susanne (niem.), Сусанна (ros.)</p></div>',

  "Iwona": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Iwona pochodzi z języka <strong>germańskiego</strong> lub celtyckiego — jest żeńską formą imienia Iwo, wywodzącego się od germańskiego <em>iv</em> (cis). Możliwe też pochodzenie z celtyckiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię stosunkowo nowe w Polsce — upowszechniło się w <strong>XX wieku</strong>. Znane m.in. z dramatu Witolda Gombrowicza <em>Iwona, księżniczka Burgunda</em>. W latach 60.-80. otrzymało je ok. 180 tysięcy kobiet.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iwonka, Iwcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Yvonne (franc.), Yvonne (ang., niem.), Ivona (czes.)</p></div>',

  "Jacek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jacek wywodzi się od greckiego <em>Hyakinthos</em> — imienia mitologicznego młodzieńca, ulubieńca Apollina, od którego krwi wyrosł kwiat hiacynt. Oznacza dosłownie <strong>„hiacynt"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce znane od <strong>XII wieku</strong>. Patronem jest <strong>święty Jacek Odrowąż</strong> (1183–1257) — dominikanin, misjonarz, zwany „apostołem Północy". Imię rozkwitło szczególnie w XVII wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jacuś, Jaceczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jacinto (hiszp., port.), Giacinto (wł.), Jácint (węg.) — imię Jacek nie ma pełnego odpowiednika w językach zachodnich.</p></div>',

  "Halina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Halina pochodzi z języka <strong>greckiego</strong> — od słowa <em>galene</em> (γαλήνη) oznaczającego <strong>„spokój"</strong>, „cisza morska", „dobrobyt". Jest polską formą imienia Galina.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronką jest święta Halina z Koryntu — dziewica i męczennica (†258). Zdrobnienie <strong>Halka</strong> zyskało popularność dzięki operze Stanisława Moniuszki i zaczęło funkcjonować jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Halka, Haleczka, Halunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Galina (ros., ukr.), Helena (łac. forma podstawowa)</p></div>',

  'Paulina': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Paulina pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Paweł (Paulus), wywodzącego się od łacińskiego <em>paulus</em>, oznaczającego <strong>„mały"</strong>, skromny. Imię paradoksalnie noszone przez wiele wybitnych kobiet.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Polsce od wieków. Błogosławiona Paulina (1865–1942) — brazylijska zakonnica polskiego pochodzenia, założycielka zgromadzenia sióstr. Pierwsza Brazylijka wyniesiona na ołtarze. Paulina Młynarska, Paulina Krupińska — znane polskie dziennikarki.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Paula, Paulinka, Pola, Pauleczka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Pauline (franc., niem.), Paulina (ang., hiszp., wł.), Паулина (ros.)</p></div>',

  "Grażyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Grażyna pochodzi z języka <strong>litewskiego</strong> — od słowa <em>graži</em> oznaczającego <strong>„piękna"</strong>. Jest imieniem literackim — zostało wymyślone przez Adama Mickiewicza dla bohaterki jego poematu <em>Grażyna</em> (1823).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Choć wymyślone przez Mickiewicza, imię szybko przyjęło się w Polsce i stało się powszechnie używane. Szczyt popularności przypadał na lata 50.-70. XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Grażynka, Grażka, Grasia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach.</p></div>',

  "Jerzy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jerzy pochodzi z języka <strong>greckiego</strong> — od słów <em>ge</em> (ziemia) i <em>ergon</em> (praca), co oznacza <strong>„rolnik"</strong> lub „ten, kto uprawia ziemię". Jest polską formą greckiego Georgios.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Popularność imienia zawdzięczamy kultowi <strong>świętego Jerzego</strong> — legendarnego rycerza i męczennika, który pokonał smoka. Jego święto przypada 23 kwietnia. W Polsce imię używane od wieków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jurek, Jureczek, Jerzyk</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>George (ang.), Georg (niem.), Georges (franc.), Jorge (hiszp.), Giorgio (wł.), György (węg.), Юрий (ros.)</p></div>',

  "Jadwiga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jadwiga pochodzi ze <strong>starogermańskiego</strong> — złożone z elementów <em>hadu</em> i <em>wig</em>, oba oznaczające „walkę" lub „bitwę". Oznacza dosłownie <strong>„wojowniczka"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>1208 roku</strong>. Patronkami są <strong>święta Jadwiga Śląska</strong> (patronka Polski i Niemiec) oraz <strong>święta Jadwiga Królowa</strong> — pierwsza kobieta koronowana na króla Polski (†1399).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jadzia, Jaga, Jagoda, Iga, Jagienka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hedwig (niem.), Hedvika (czes.), Edvige (wł.)</p></div>',

  "Justyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Justyna pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>Iustus</em> (sprawiedliwy, prawy), wywodzącego się od <em>ius</em> (prawo, sprawiedliwość). Znaczenie: <strong>„sprawiedliwa, prawdziwa"</strong>. Imię o wyraźnym znaczeniu moralnym, popularne w chrześcijańskiej Europie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Justyna z Antiochii</strong> — chrześcijańska dziewica i męczennica, która swoją wiarą nawróciła maga Cypriana (III w.). <strong>Justyna Kowalczyk</strong> (ur. 1983) — polska biegaczka narciarska, czterokrotna mistrzyni olimpijska, jedna z największych sportsmenek w historii Polski. <strong>Justine Henin</strong> — belgijska tenisistka, siedmiokrotna triumfatorka turniejów Wielkiego Szlema. W Polsce imię popularne od lat 80. XX w., dziś nosi je blisko 200 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Justynka, Jusia, Just, Justka, Tynka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Justine (franc., ang.), Justina (hiszp., łac.), Giustina (wł.), Юстина (ros.), Justýna (czes.)</p></div>',

  "Wiktoria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wiktoria pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>victoria</em> oznaczającego <strong>„zwycięstwo"</strong>. W mitologii rzymskiej Wiktoria była boginią zwycięstwa i chwały.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię zyskało wielką popularność w XXI wieku — w 2009 roku było czwartym najczęściej nadawanym imieniem dziewczynkom. Noszone przez królową Wiktorię (1819–1901) — najdłużej panującą monarchinię Wielkiej Brytanii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wika, Wikta, Wikcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Victoria (ang., hiszp., wł.), Victoire (franc.), Viktoria (niem.), Виктория (ros.)</p></div>',

  "Bartosz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bartosz jest polską formą imienia <strong>Bartłomiej</strong>, które pochodzi z języka <strong>aramejskiego</strong> — od <em>bar-Talmaj</em>, co znaczy „syn Talmaja". Imię Talmaj wywodzi się z hebrajskiego i oznacza „bruzdy, rolnik". Bartłomiej był jednym z Dwunastu Apostołów Jezusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>1216 roku</strong>. <strong>Bartosz Głowacki</strong> (ok. 1758–1794) — chłopski bohater insurekcji kościuszkowskiej, kosynier spod Racławic, symbol walki ludu o wolność. <strong>Bartosz Kurek</strong> — siatkarz, kapitan mistrzostwa świata 2018. Po wiekach zapomnienia imię przeżyło wielki renesans pod koniec XX w. — dziś nosi je ponad 200 tysięcy Polaków, a Bartek jest jednym z ulubionych zdrobnień chłopięcych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bartek, Bartuś, Barto, Barteczek, Bartusiek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bartholomew (ang.), Bartholomäus (niem.), Barthélemy (franc.), Bartolomé (hiszp.), Bartolomeo (wł.), Варфоломей (ros.)</p></div>',

  "Artur": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Artur pochodzi z języka <strong>celtyckiego</strong> — od elementów <em>art</em> (niedźwiedź) i <em>ur</em> (młody, piękny), co oznacza <strong>„młody niedźwiedź"</strong> lub „szlachetny". Alternatywnie od celtyckiego <em>ard</em> — „wysoki", „szlachetny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławione przez legendarnego <strong>króla Artura</strong> — bohatera średniowiecznych romansów rycerskich o Okrągłym Stole. W Polsce używane od wieków, dziś nosi je blisko 200 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arek, Arturek, Artur</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arthur (ang., franc.), Arthur (niem.), Arturo (hiszp., wł.), Артур (ros.)</p></div>',

  "Maja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maja pochodzi z języka <strong>greckiego</strong> — od słowa <em>maia</em> oznaczającego <strong>„dobra matka, mamka, starszyzna"</strong>. W mitologii greckiej <strong>Maja</strong> była najstarszą i najpiękniejszą z siedmiu Plejad — córek Atlasa i nimfy Plejone. Była matką Hermesa, posłańca bogów. Jej imię związane jest też z miesiącem majem.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię obecne w Polsce od wieków, prawdziwy rozkwit przeżywa w XXI w. W 2017 r. zajmowało 5. miejsce wśród imion nadawanych dziewczynkom. Znane z kultowej bajki animowanej <em>Pszczółka Maja</em> (1975, na podstawie powieści Waldemara Bonselsa). <strong>Maya Angelou</strong> (1928–2014) — amerykańska poetka i aktywistka, autorka <em>I Know Why the Caged Bird Sings</em>. <strong>Maya Lin</strong> — architektka, projektantka Pomnika Weteranów Wietnamu w Waszyngtonie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Majka, Majeczka, Majusia, Majeczko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maya (ang., franc., hiszp., niem.), Maia (wł., port., łac.), Майя (ros.), Maja (niem., skandynaw., słow.)</p></div>',

  "Jarosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jarosław jest imieniem <strong>słowiańskim</strong> — złożonym z elementów <em>jary</em> (silny, krzepki, żywotny) i <em>-sław</em> (sława, chwała), co oznacza <strong>„ten o silnej sławie"</strong> lub „wsławiony siłą".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno ze starych polskich imion słowiańskich — znane od wieków. Nosił je m.in. <strong>Jarosław Mądry</strong> (978–1054) — wielki książę kijowski, jeden z najwybitniejszych władców Rusi. Pod koniec XV wieku nosiło je ok. 700 osób w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jarek, Jaruś, Jareczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jaroslav (czes., słowac.), Yaroslav (ukr.), Ярослав (ros.) — imię typowo słowiańskie.</p></div>',

  "Tadeusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tadeusz pochodzi z języka <strong>aramejskiego</strong> lub hebrajskiego — tradycyjnie interpretowane jako <strong>„odważny"</strong> lub „chwalebny wyznawca". Związane z imieniem apostoła Judy Tadeusza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce szczególnie popularny dzięki eposowi Adama Mickiewicza <em>Pan Tadeusz</em> (1834). Wybitni nosiciele to <strong>Tadeusz Kościuszko</strong> — bohater walk o niepodległość Polski i USA, oraz artysta awangardowy <strong>Tadeusz Kantor</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tadek, Tadzio, Tadzik, Tadeuszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thaddeus (ang.), Thaddäus (niem.), Taddeo (wł.), Tadeo (hiszp.), Tadeáš (czes.)</p></div>',

  "Sebastian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sebastian pochodzi z języka <strong>greckiego</strong> — od słowa <em>sebastos</em> oznaczającego <strong>„czcigodny"</strong>, „godny szacunku". Wywodzi się od nazwy miejscowej Sebastia (dzisiejsze Sivas w Turcji).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Popularność imienia zawdzięczamy kultowi <strong>świętego Sebastiana</strong> — oficera gwardii cesarskiej i męczennika (†ok. 288), patrona żołnierzy i sportowców. W Polsce szczyt popularności przypadł na lata 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sebek, Sebcio, Sebastianek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sebastian (ang., niem., hiszp.), Sébastien (franc.), Sebastiano (wł.), Себастьян (ros.)</p></div>',

  "Renata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Renata pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>renata</em> oznaczającego <strong>„odrodzona"</strong> (od <em>re-</em> znów + <em>natus</em> urodzony). Nawiązuje do chrześcijańskiej idei odrodzenia przez chrzest.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Do Polski imię dotarło w XVII wieku pod wpływem francuskim. Dziś nosi je blisko 186 tysięcy Polek. Znana nosicielka to słynna włoska sopranistka <strong>Renata Tebaldi</strong> (1922–2004).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rena, Renatka, Renia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Renée (franc.), Renata (wł., hiszp.), Renate (niem.), Рената (ros.)</p></div>',

  "Agata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Agata pochodzi z języka <strong>greckiego</strong> — od słowa <em>agathos</em> (ἀγαθός) oznaczającego <strong>„dobra"</strong>, „szlachetna". Rdzeń ten pojawia się m.in. w słowie „agat" — nazwie kamienia szlachetnego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię dokumentowane od <strong>XIII wieku</strong>. Patronką jest <strong>święta Agata z Sycylii</strong> — dziewica i męczennica (†ok. 251), patronka pielęgniarek i straży pożarnej. Imieniny 5 lutego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Agatka, Aga, Agateczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Agatha (ang., niem.), Agathe (franc.), Ágata (hiszp.), Agata (wł., ros.)</p></div>',

  "Damian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Damian pochodzi z języka <strong>greckiego</strong> — od słowa <em>daman</em> (δαμάω) oznaczającego <strong>„poskramiać"</strong>, „zwyciężać". Może też nawiązywać do bogini Damii czczonej w Epidaurze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Damian</strong> — lekarz i męczennik, brat Kosmy (patroni lekarzy i farmaceutów, †ok. 303). Belgijski <strong>ojciec Damian De Veuster</strong> (1840–1889) opiekował się trędowatymi na Hawajach, beatyfikowany w 1995 r.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Damianek, Damek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Damian (ang.), Damien (franc.), Damiano (wł.), Damián (hiszp.), Дамиан (ros.)</p></div>',

  "Sylwia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sylwia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>silva</em> oznaczającego <strong>„las"</strong>, „gaj". Nawiązuje do mitologicznej <strong>Rei Sylwii</strong> — matki Romulusa i Remusa, legendarnych założycieli Rzymu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane z mitologii i historii Rzymu. W Polsce popularność zyskało w XX wieku. Nosi je m.in. <strong>królowa Sylwia Szwecji</strong> (ur. 1943) oraz polska piosenkarka <strong>Sylwia Grzeszczak</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwcia, Sylweczka, Sylwa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sylvia (ang., niem.), Sylvie (franc.), Silvia (wł., hiszp.), Сильвия (ros.)</p></div>',

  "Sławomir": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sławomir jest imieniem <strong>słowiańskim</strong> — złożonym z elementów <em>sław-</em> (sława, chwała) i <em>-mir</em> (pokój, spokój), co oznacza <strong>„ten, kto zdobywa sławę pokojem"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane w Polsce od wieków. Największą popularność zyskało w latach 50.–60. XX w. Wybitnym przedstawicielem jest pisarz i dramaturg <strong>Sławomir Mrożek</strong>. Żeńską formą jest Sławomira.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sławek, Sław, Sławuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Slavomír (czes., słowac.), Slavomir (chorwac.) — imię typowo słowiańskie.</p></div>',

  "Patryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Patryk pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>patricius</em> oznaczającego <strong>„patrycjusz"</strong>, „szlachetnie urodzony". Jest polską formą imienia Patrycjusz.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Patryk</strong> (ok. 389–461) — apostoł Irlandii, jeden z jej patronów. Jego święto (17 marca) obchodzone jest na całym świecie jako Dzień Świętego Patryka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Patrycek, Patek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Patrick (ang., franc.), Patrik (szw., czes.), Patricio (hiszp.), Patrizio (wł.)</p></div>',

  "Urszula": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Urszula pochodzi z języka <strong>łacińskiego</strong> — jest zdrobnieniem od <em>ursa</em> (niedźwiedzica), co oznacza <strong>„mała niedźwiedzica"</strong>. Forma nawiązuje do konstelacji Małej Niedźwiedzicy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce dokumentowane od <strong>1367 roku</strong>. Patronkami są <strong>święta Urszula z Kolonii</strong> (†ok. 383) oraz <strong>Urszula Ledóchowska</strong> — polska zakonnica i działaczka charytatywna, kanonizowana w 2003 r.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ula, Ulka, Urszulka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ursula (ang., niem.), Ursule (franc.), Úrsula (hiszp.), Orsolya (węg.)</p></div>',

  "Antoni": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Antoni pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu Antoniuszów (<em>Antonius</em>). Znaczenie niepewne, może wywodzić się z greckiego <em>anthos</em> (<strong>„kwiat"</strong>) lub od etruskiego imienia własnego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Antoni Padewski</strong> (1195–1231) — franciszkanin, cudotwórca, patron Portugalii i osób szukających zagubionych przedmiotów. Jego imieniny obchodzone są 13 czerwca.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Antek, Anteczek, Toni</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anthony (ang.), Antoine (franc.), Anton (niem.), Antonio (wł., hiszp.), Антон (ros.)</p></div>',

  "Filip": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Filip pochodzi z języka <strong>greckiego</strong> — złożone z <em>philos</em> (przyjaciel) i <em>hippos</em> (koń), co oznacza <strong>„miłośnik koni"</strong>. Imię spopularyzował Filip II Macedoński — ojciec Aleksandra Wielkiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>Filip Apostoł</strong> — jeden z dwunastu uczniów Jezusa. W Polsce imię znane od wieków, dziś nosi je ponad 175 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Filipek, Filio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Philip (ang.), Philippe (franc.), Philipp (niem.), Felipe (hiszp.), Filippo (wł.), Филипп (ros.)</p></div>',

  "Roman": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Roman pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>Romanus</em> oznaczającego <strong>„Rzymianin"</strong>, „pochodzący z Rzymu". Nawiązuje do starożytnego Imperium Rzymskiego i jego kultury.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię znane od wieków. Wybitni nosiciele to reżyser <strong>Roman Polański</strong>, polityk <strong>Roman Dmowski</strong> oraz święty Roman — pustelnik z VII wieku. Żeńską formą jest Romana.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Romek, Romcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Roman (ang., niem., franc.), Romano (wł.), Román (hiszp.), Роман (ros., ukr.)</p></div>',

  "Mirosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mirosław jest imieniem <strong>słowiańskim</strong> — złożonym z elementów <em>miro-</em> (pokój) i <em>-sław</em> (sława, chwała), co oznacza <strong>„ten, kto wsławia pokój"</strong> lub „sławny pokojem".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno ze starych imion słowiańskich — relikt pogańskich imion używanych przez Słowian we wczesnym średniowieczu. W Polsce popularne szczególnie w połowie XX wieku. Żeńską formą jest Mirosława.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mirek, Mir, Mirko, Mirosz</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Miroslav (czes., słowac., chorwac.), Мирослав (ros.) — imię typowo słowiańskie.</p></div>',

  "Janusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Janusz jest polską formą imienia <strong>Jan</strong>, wywodzącego się z hebrajskiego <em>Johanan</em> — <strong>„Bóg jest łaskawy"</strong>. Pierwotnie zdrobnienie od Jana, z czasem usamodzielniło się jako odrębne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce dokumentowane od <strong>1145–1178 roku</strong>. Wybitnym nosicielem jest pedagog i pisarz <strong>Janusz Korczak</strong> — bohater, który zginął wraz ze swoimi wychowankami w Treblince w 1942 r.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Januszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię charakterystyczne dla języka polskiego. Pokrewne: Janus (łac.), Johannes (niem.), Jánuš (słowac.)</p></div>',

  "Daniel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Daniel pochodzi z języka <strong>hebrajskiego</strong> — złożone z <em>din</em> (sąd, sprawiedliwość) i <em>El</em> (Bóg). Znaczenie: <strong>„Bóg jest moim sędzią"</strong>. Jest imieniem jednego z czterech wielkich proroków biblijnych Starego Testamentu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Daniel</strong> to prorok porwany do niewoli babilońskiej — ocalał w lwiej jamie dzięki wierze i zasłynął z tłumaczenia snów króla Nabuchodonozora. W Polsce imię znane od wieków. <strong>Daniel Olbrychski</strong> — jeden z największych polskich aktorów, twarz kina Wajdy. <strong>Daniel Craig</strong> — aktor, piąty James Bond. <strong>Daniel Defoe</strong> — autor <em>Robinsona Crusoe</em>. Dziś w Polsce nosi je ponad 170 tysięcy Polaków — jedno z ulubionych imion końca XX i XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Danek, Danelek, Danio, Danielek, Danko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Daniel (ang., franc., niem., hiszp., port.), Daniele (wł.), Daniil (ros. Даниил), Dániel (węg.), Danel (bask.)</p></div>',

  "Patrycja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Patrycja pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>patricius</em> oznaczającego <strong>„patrycjuszka"</strong>, „szlachetnie urodzona". Jest żeńską formą imion Patrycjusz, Patrycy i Patryk.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronkami są święta Patrycja z Nikomedii (13 marca) i święta Patrycja z Neapolu (25 sierpnia). W Polsce dziś nosi je ponad 169 tysięcy kobiet.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Patka, Patrycyjka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Patricia (ang., niem., hiszp., franc.), Patrícia (port.), Патриция (ros.)</p></div>',

  "Oliwia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Oliwia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>oliva</em> oznaczającego <strong>„drzewo oliwne"</strong> lub „owoc oliwki". Symbol pokoju i płodności znany ze starożytności.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię mogło zostać stworzone przez <strong>Williama Szekspira</strong> dla bohaterki komedii <em>Wieczór Trzech Króli</em>. W Polsce popularność rosła od lat 80. XX w., od 2022 roku jest w pierwszej dziesiątce imion nadawanych dziewczynkom.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ola, Oliwka, Oliweczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Olivia (ang., wł., franc., niem., hiszp.) — imię popularne na całym świecie; od 2019 r. najczęściej nadawane w USA.</p></div>',

  "Karol": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Karol pochodzi z języka <strong>frankijskiego</strong> — od starogermańskiego <em>karl</em> oznaczającego <strong>„mężczyzna"</strong>, „mąż", „człowiek wolny". Spopularyzowane przez imię cesarza Karola Wielkiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Do Polski dotarło wraz z chrześcijaństwem. Najsłynniejszym polskim Karolem był <strong>Karol Wojtyła</strong> — papież Jan Paweł II. Zdrobnienie <em>Lolek</em> to potoczna forma imienia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lolek, Karolek, Karoleczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Charles (franc., ang.), Karl (niem.), Carlo (wł.), Carlos (hiszp.), Károly (węg.), Карл (ros.)</p></div>',

  "Emilia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emilia pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu <em>Aemilii</em>. Wywodzi się od słowa <em>aemulus</em> oznaczającego <strong>„rywalizująca"</strong>, „pilna", „gorliwa".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce szczególnie znana dzięki postaci <strong>Emilii Plater</strong> (1806–1831) — bohaterki powstania listopadowego, „polskiej Joanny d’Arc". W XXI wieku imię powróciło do łask — w 2017 r. zajmowało 14. miejsce wśród imion nadawanych dziewczynkom.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Emilka, Emi, Emileczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emily (ang.), Émilie (franc.), Emilie (niem., czes.), Emilia (hiszp., wł., ros.)</p></div>',

  "Przemysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Przemysław jest imieniem <strong>słowiańskim</strong> — złożonym z elementów <em>przemysł</em> (spryt, fortel) i <em>-sław</em> (sława), co oznacza <strong>„ten, kto zdobywa sławę sprytem"</strong> lub „sławny z przezorności".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Nosił je <strong>Przemysł II</strong> (1257–1296) — pierwszy od wieków król Polski po okresie rozbicia dzielnicowego, koronowany w 1295 r. Imię typowo polskie, używane od wczesnego średniowiecza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Przemek, Przemo, Przemeczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach. Sporadycznie używana forma Przemysl w języku czeskim.</p></div>',

  "Aleksander": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aleksander pochodzi z języka <strong>greckiego</strong> — złożone z <em>alexein</em> (bronić, chronić) i <em>aner/andros</em> (mężczyzna), co oznacza <strong>„obrońca ludzi"</strong> lub „ten, kto chroni mężów".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił <strong>Aleksander Wielki</strong> (356–323 p.n.e.) — macedoński król i zdobywca, jeden z największych wodzów w historii. W Polsce nosił je m.in. <strong>Aleksander Jagiellończyk</strong> — król Polski (1501–1506).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Olek, Aleksio, Aleks, Olo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alexander (ang., niem.), Alexandre (franc.), Alejandro (hiszp.), Alessandro (wł.), Александр (ros.)</p></div>',

  "Izabela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Izabela pochodzi ze średniowiecznej prowansalskiej formy imienia <strong>Elżbieta</strong>, wywodzącej się z hebrajskiego <em>eliszewa</em> — <strong>„Bóg jest moją przysięgą"</strong>. Może też nawiązywać do biblijnej Jezebel.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Pierwszą Polką o tym imieniu była <strong>Izabela Jagiellonka</strong> (1519–1559). Do Polski dotarło przez wpływy francuskie. Zdrobnienie Iza funkcjonuje jako samodzielne imię. Dziś nosi je ponad 159 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iza, Bella, Izabelka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Isabel (hiszp., port.), Isabelle (franc.), Isabella (wł., ang.), Elisabeth (niem.)</p></div>',

  "Helena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Helena pochodzi z języka <strong>greckiego</strong> — od słowa <em>helene</em> (ἑλένη), co może oznaczać <strong>„blask"</strong>, „pochodnia" lub nawiązywać do słowa „Hellas" (Grecja). Wywodzi się od imienia bogini księżyca Selene.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii greckiej <strong>Helena Trojańska</strong> — słynna z urody córka Zeusa, uprowadzenie której wywołało wojnę trojańską. W tradycji chrześcijańskiej patronką jest <strong>święta Helena</strong> — matka cesarza Konstantyna Wielkiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hela, Helcia, Helenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Helen (ang.), Hélène (franc.), Helene (niem.), Elena (hiszp., wł.), Елена (ros.)</p></div>',

  "Weronika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Weronika pochodzi z języka <strong>greckiego</strong> — złożone z <em>phero</em> (nieść) i <em>nike</em> (zwycięstwo), co oznacza <strong>„niosąca zwycięstwo"</strong>. Popularna etymologia ludowa łączy je z łacińskim <em>vera icon</em> — „prawdziwy obraz".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronką jest <strong>święta Weronika</strong> — kobieta, która według legendy otarła twarz Jezusa chustą podczas drogi na Krzyż. Na chuście miał pozostać cudowny wizerunek Chrystusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wera, Werka, Weronka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Veronica (ang., wł.), Véronique (franc.), Veronika (niem., czes.), Вероника (ros.)</p></div>',

  "Aneta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aneta pochodzi z języka <strong>hebrajskiego</strong> — jest zdrobnieniem od imienia Anna (<em>Anette</em>), wywodzącego się od <em>hannāh</em> oznaczającego <strong>„łaska, wdzięk"</strong>. Do Polski dotarło przez wpływ kultury i mody francuskiej w XIX i XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma Annette była modna w XVIII-wiecznej Francji — stąd trafiła do polskiej szlachty i mieszczaństwa. <strong>Aneta Kręglicka</strong> — Miss World 1989, pierwsza Polka z tym tytułem, symbol polskiej elegancji. <strong>Annette Bening</strong> — czterokrotnie nominowana do Oscara amerykańska aktorka. Dziś w Polsce imię nosi ok. 151 tysięcy kobiet; najbardziej popularne było w latach 70.–80. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anetka, Anka, Neta, Aneczka, Aneteczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Annette (franc., niem., duń.), Anette (norw., szw.), Annetta (ang., wł.), Anet (czes.), Аннет (ros.)</p></div>',

  "Henryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Henryk pochodzi ze <strong>starogermańskiego</strong> — złożone z <em>heim</em> (dom) i <em>ric</em> (władca, potęga), co oznacza <strong>„władca domu"</strong> lub „pan w swoim domu". Jest polską formą imienia Heinrich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Spopularyzowane przez dynastię frankijskich i niemieckich władców. W Polsce nosił je m.in. <strong>Henryk Walezy</strong> (król Polski 1573–1574), kompozytor <strong>Henryk Mikołaj Górecki</strong> i pisarz <strong>Henryk Sienkiewicz</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Henio, Heniu, Heneczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Henry (ang.), Henri (franc.), Heinrich (niem.), Enrique (hiszp.), Enrico (wł.), Генрих (ros.)</p></div>',

  "Adrian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adrian pochodzi z języka <strong>łacińskiego</strong> — od nazwy miasta <em>Hadria</em> (dzisiejsze Atri we Włoszech) lub Morza Adriatyckiego, co oznacza dosłownie <strong>„człowiek z Hadrii"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosił cesarz rzymski <strong>Hadrian</strong> (76–138) — budowniczy słynnego Muru Hadriana w Brytanii. W tradycji chrześcijańskiej znany jest papież Hadrian I. W Polsce popularne szczególnie od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adek, Adrianek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adrian (ang., niem., hiszp.), Adrien (franc.), Adriano (wł.), Адриан (ros.)</p></div>',

  "Ewelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ewelina wywodzi się z języka <strong>irlandzkiego</strong> — od celtyckiego <em>Éibhleann</em> oznaczającego <strong>„radość"</strong> lub „blask". Alternatywna etymologia wskazuje na starofrancuskie <em>aveline</em> (z łac. <em>avis</em> — ptak).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię upowszechniło się w XX wieku. Dziś nosi je ok. 148 tysięcy Polek. Imieniny obchodzone są 26 maja i 24 grudnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewelinka, Ewelka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eveline (franc., ang.), Evelina (wł.), Evelyn (ang.), Эвелина (ros.)</p></div>',

  "Martyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Martyna pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Marcin (<em>Martinus</em>), wywodzącego się od imienia boga wojny Marsa. Oznacza <strong>„należąca do Marsa"</strong> lub „bojowa".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronką jest <strong>święta Martyna z Rzymu</strong> (†226) — dziewica i męczennica, czczona 30 stycznia. W Polsce imię zyskało popularność w XX i XXI wieku. Dziś nosi je ok. 143 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Martynka, Martysia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Martina (ang., niem., wł., hiszp.), Martine (franc.), Мартина (ros.)</p></div>',

  "Mikołaj": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mikołaj pochodzi z języka <strong>greckiego</strong> — złożone z <em>nike</em> (zwycięstwo) i <em>laos</em> (lud, naród), co oznacza <strong>„zwycięstwo ludu"</strong>. Jest polską formą greckiego Nikolaos.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Mikołaj z Miry</strong> (IV w.) — biskup, patron dzieci, marynarzy i kupców. Jego postać zainspirowała tradycję Świętego Mikołaja przynoszącego prezenty 6 grudnia. Imię nosił też astronom <strong>Mikołaj Kopernik</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mikołajek, Miko, Nikola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicholas (ang.), Nicolas (franc.), Nikolaus (niem.), Nicolás (hiszp.), Nicola (wł.), Николай (ros.)</p></div>',

  "Franciszek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Franciszek pochodzi z włoskiego <em>Francesco</em> — oznacza <strong>„Francuz"</strong> lub „mały Francuz". Przydomek ten nadał swojemu synowi Janowi kupiec Piotr Bernardone po powrocie z Francji — i tak stał się imieniem własnym.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił <strong>święty Franciszek z Asyżu</strong> (1181–1226) — założyciel zakonu franciszkanów, patron ekologii i Włoch. Nosi je też papież <strong>Franciszek</strong> (Jorge Bergoglio, od 2013 r.).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Franek, Franuś, Franio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Francis (ang.), François (franc.), Franz (niem.), Francisco (hiszp.), Ferenc (węg.), František (czes.)</p></div>',

  "Klaudia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Klaudia pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu Klaudiuszów (<em>Claudius</em>). Etymologia nazwy rodu niepewna, możliwe nawiązanie do łacińskiego <em>claudus</em> (<strong>„kulawy"</strong>).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane w Polsce od XVI wieku, popularność zyskało w latach 70. XX w. Znana nosicielka to modelka <strong>Claudia Schiffer</strong> i aktorka <strong>Claudia Cardinale</strong>. Dziś nosi je ok. 139 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klaudka, Klaudia, Klaudzia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Claudia (ang., niem., wł., hiszp.), Claude (franc.), Клавдия (ros.)</p></div>',

  "Gabriela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gabriela pochodzi z języka <strong>hebrajskiego</strong> — jest żeńską formą imienia Gabriel, złożonego z <em>gebher</em> (mężczyzna, siła) i <em>El</em> (Bóg), co oznacza <strong>„Bóg jest moją siłą"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Gabriel to w Biblii archanioł — zwiastun. Imię żeńskie Gabriela znane w Polsce od wieków, szczyt popularności przypadał na lata 2010–2015. Dziś nosi je ponad 137 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gabrysia, Gabi, Gabryśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gabrielle (franc.), Gabriela (hiszp., port.), Gabrielle (ang.), Gabriella (wł.), Габриэла (ros.)</p></div>',

  "Dominik": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dominik pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>dominicus</em> oznaczającego <strong>„należący do Pana"</strong>, „Boży". Wywodzi się od <em>dominus</em> (Pan, władca).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Dominik Guzmán</strong> (1170–1221) — założyciel zakonu dominikanów, kaznodzieja i teolog. Jego święto obchodzone jest 8 sierpnia. Dziś imię nosi ok. 136 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Domek, Dominiczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dominic (ang.), Dominique (franc.), Domenico (wł.), Domingo (hiszp.), Domonkos (węg.)</p></div>',

  "Lena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Lena pochodzi z języka <strong>greckiego</strong> — jest zdrobnieniem od <strong>Helena</strong> lub <strong>Magdalena</strong>. Z greckiego <em>helene</em> (blask, pochodnia) lub od nazwy miejscowości Magdala.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce dokumentowane od <strong>1418 roku</strong>. Na początku XXI w. przeżyło wielki renesans — w 2013–2014 było <strong>najczęściej nadawanym imieniem żeńskim w Polsce</strong>. Dziś nosi je ok. 134 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lenka, Leneczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lena (ang., niem., franc., skandynaw.) — imię popularne w całej Europie.</p></div>',

  "Arkadiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Arkadiusz pochodzi z języka <strong>greckiego</strong> — od nazwy krainy <em>Arkadia</em> na Peloponezie, słynącej z pięknych pasterskich krajobrazów. Oznacza dosłownie <strong>„pochodzący z Arkadii"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosił cesarz wschodniorzymski <strong>Arkadiusz</strong> (377–408). W tradycji chrześcijańskiej znanych jest kilku świętych tego imienia. W Polsce popularne głównie w XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arek, Areczek, Arkadiuszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arcadius (łac.), Arcadio (hiszp., wł.), Arcadie (franc.), Аркадий (ros.)</p></div>',

  "Wiesław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wiesław jest imieniem <strong>słowiańskim</strong> — skrócona forma od <em>Wielisław</em> lub <em>Wielesław</em>, złożonego z <em>wiele-</em> (wielki, liczny) i <em>-sław</em> (sława), co oznacza <strong>„ten, kto pragnie sławy"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Stare polskie imię słowiańskie. Znane nosiciele to śpiewak operowy <strong>Wiesław Ochman</strong> i pisarz <strong>Wiesław Myśliwski</strong>. Ciekawostka: Władysław Gomułka używał „Wiesław" jako pseudonimu. Żeńską formą jest Wiesława.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wiesiek, Wiesio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach.</p></div>',

  "Amelia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amelia pochodzi ze <strong>starogermańskiego</strong> — od elementu <em>amal</em> oznaczającego <strong>„pracowita"</strong>, „niestrudzenie działająca". Związane z germańskim rodem Amalów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne wśród europejskich rodzin królewskich. W XXI wieku przeżyło ogromny renesans popularności w Polsce — dziś nosi je ponad 129 tysięcy Polek. Znana nosicielka to lotniczka <strong>Amelia Earhart</strong> — pierwsza kobieta, która przeleciała przez Atlantyk.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amelka, Amela, Amelcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amelia (ang., hiszp., wł.), Amélie (franc.), Амелия (ros.)</p></div>',

  "Marzena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marzena jest imieniem <strong>polskim</strong> — prawdopodobnie zdrobnieniem od <strong>Małgorzaty</strong> lub nawiązaniem do <strong>Marzanny</strong> — słowiańskiej bogini zimy i śmierci. Możliwe też związki z Martą lub Marią.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię typowo polskie, bez starożytnych korzeni. Popularność zyskało w XX wieku. Dziś nosi je ok. 129 tysięcy Polek. Znane nosicielki to aktorka <strong>Marzena Kipiel-Sztuka</strong> i dziennikarka <strong>Marzena Rogalska</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marzenia, Marzenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie. Wariant Marzenna używany rzadziej.</p></div>',

  "Bartłomiej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bartłomiej pochodzi z języka <strong>aramejskiego</strong> — od <em>bar-Talmaj</em>, co oznacza <strong>„syn Talmaja"</strong> (oracz, rolnik). Bartłomiej był jednym z dwunastu apostołów Jezusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię bardzo popularne w <strong>średniowieczu</strong>. Jego zdrobnieniem jest powszechne dziś imię Bartosz. Patron rzemieślników, garbarzy i rzeźników. Imieniny 24 sierpnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bartek, Bartosz, Bartuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bartholomew (ang.), Bartholomäus (niem.), Barthélemy (franc.), Bartolomé (hiszp.), Варфоломей (ros.)</p></div>',

  "Dominika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dominika pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Dominik, od <em>dominicus</em> oznaczającego <strong>„należąca do Pana"</strong>, „Boża". Pośrednio wywodzi się od <em>dies dominica</em> — dzień Pański (niedziela).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od wieków. Dziś nosi je ok. 123 tysięcy Polek. Imieniny obchodzone są 6 lipca.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Domi, Dominiczka, Nika</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dominique (franc.), Dominica (ang.), Doménica (hiszp.), Доминика (ros.)</p></div>',

  "Kinga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kinga pochodzi z języka <strong>węgierskiego</strong> — jest zdrobnieniem od <strong>Kunegunda</strong>, złożonego ze starogermańskiego <em>kuni</em> (ród, plemię) i <em>gund</em> (walka), co oznacza <strong>„walczącą z rodu"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronką jest <strong>święta Kinga</strong> (Kunegunda, 1224–1292) — polska księżna i zakonnica, patronka górników i żup solnych. Według legendy wrzuciła swój pierścionek do kopalni soli na Węgrzech — znaleziono go w Wieliczce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kingusia, Kineczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Kunigunde (niem.), Kunigunda (łac.), Kinga (węg.) — imię popularne głównie w Polsce i na Węgrzech.</p></div>',

  "Marian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marian pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu <em>Marii/Mariuszów</em>. Oznacza <strong>„należący do rodu Mariuszów"</strong>. W Polsce kojarzone też z imieniem Maria.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce znane od <strong>1332 roku</strong>. Szczyt popularności w latach 50. XX w. Wybitny nosiciel to <strong>Marian Rejewski</strong> — matematyk, który złamał szyfr Enigmy przed II wojną światową.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marek, Mario, Marianek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marion (franc., ang.), Marianus (łac.), Марьян (ros.) — w języku angielskim Marian używane bywa jako imię żeńskie.</p></div>',

  'Wiktor': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wiktor pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>victor</em>, oznaczającego <strong>„zwycięzca"</strong>. Wywodzi się z czasownika <em>vincere</em> — zwyciężać, pokonywać, triumfować. Imię niosące optymizm i obietnicę sukcesu, od starożytności nadawane z nadzieją na triumf nad przeciwnościami losu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię noszone przez trzech papieży — Wiktora I (189–199), Wiktora II i Wiktora III. Wiktor Hugo (1802–1885) — jeden z największych pisarzy romantyzmu, autor <em>Nędzników</em> i <em>Katedry Marii Panny w Paryżu</em>. Wiktor Zborowski i Wiktor Sadecki — znani polscy aktorzy teatralni i filmowi. W Polsce popularne przez cały XX wiek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Witek, Wituś, Wicek, Wiktuś, Wiktorek, Wiktorcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Victor (ang., franc., hiszp., port.), Viktor (niem., czes., słow., węg.), Vittore (wł.), Виктор (ros.)</p></div>',

  "Edyta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Edyta pochodzi ze <strong>staroangielskiego</strong> — od imienia <em>Eadgyð</em>, złożonego z <em>ead</em> (szczęście, majątek) i <em>gyð</em> (walka, bitwa). Znaczenie: <strong>„szczęśliwa wojowniczka"</strong>. Imię przeniknęło do Europy kontynentalnej w XIX w. jako elegancka forma angielska.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Edyta Stein</strong> (1891–1942) — filozofka żydowskiego pochodzenia, karmelitanka bosa, zamordowana w Auschwitz. Beatyfikowana przez Jana Pawła II (1987), ogłoszona patronką Europy (1999). <strong>Edith Piaf</strong> (1915–1963) — legenda francuskiego chanson, autorka <em>La Vie en Rose</em>. <strong>Edyta Górniak</strong> — polska piosenkarka, zdobywczyni 2. miejsca na Eurowizji 1994. W Polsce imię popularne od XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Edytka, Eda, Edzia, Edi, Edyteczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edith (ang., franc., niem., szw.), Edita (hiszp., wł., czes.), Editta (wł.), Эдита (ros.)</p></div>',

  "Kamila": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kamila pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Kamil. Wywodzi się od łacińskiego <em>camillus</em> — młodego pomocnika kapłana podczas obrzędów, co oznacza <strong>„służąca bogom"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii rzymskiej Kamilla to wojowniczka, córka króla Metabusa, opisana przez Wergiliusza w <em>Eneidzie</em>. Dziś imię nosi ok. 111 tysięcy Polek. Nosicielką jest też <strong>Kamila — królowa Wielkiej Brytanii</strong>, żona króla Karola III.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kama, Kamilka, Kamisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Camille (franc.), Camilla (ang., wł.), Camila (hiszp.), Камилла (ros.)</p></div>',

  "Leszek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leszek jest imieniem <strong>słowiańskim</strong> — wywodzi się od słowa <em>lest</em> oznaczającego <strong>„spryt"</strong>, „chytrość". Wbrew pozorom nie jest zdrobnieniem od Lecha — może być wręcz odwrotnie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane od <strong>XII wieku</strong> — Gall Anonim wymienił „Lestka" wśród przodków Mieszka I. Było dynastycznym imieniem władców Piastów. Dziś nosi je ok. 108 tysięcy Polaków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leszeczek, Lesio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach.</p></div>',

  "Alina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alina pochodzi z języka <strong>germańskiego</strong> — zdrobniała forma od <strong>Adelajdy</strong> lub Adeliny, oznaczających <strong>„szlachetna"</strong>. Może też nawiązywać do Haliny (gr. galene — spokój).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Ciekawostka: Alina to dawna pruska nazwa rzeki Łyny, gdzie słowo oznaczało „łanię" (samicę jelenia). Patronką jest <strong>święta Alina z Lasu</strong> — belgijska męczennica z VII wieku. Imieniny 16 czerwca i 16 grudnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alinka, Alineczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aline (franc.), Alina (wł., hiszp., ros.), Alena (czes.)</p></div>',

  "Radosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Radosław jest imieniem <strong>słowiańskim</strong> — złożonym z <em>rado-</em> (radość) i <em>-sław</em> (sława, chwała), co oznacza <strong>„ten, kto cieszy się sławą"</strong> lub „radosny i sławny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Stare polskie imię słowiańskie. Historyczny nosiciel to <strong>Jan Mazurkiewicz „Radosław"</strong> — legendarny dowódca Kedywu, używający tego pseudonimu w czasie powstania warszawskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Radek, Radeczek, Radosławek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Radoslav (czes., słowac., chorwac.), Радослав (ros., serb.) — imię typowo słowiańskie.</p></div>',

  "Waldemar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Waldemar pochodzi ze <strong>starogermańskiego</strong> — złożone z <em>wald</em> (rządzić, władca) i <em>meri</em> (sławny), co oznacza <strong>„sławny władca"</strong>. Alternatywnie wyprowadzane od słowiańskiego Władimira.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię dynastyczne — nosili je czterej królowie duńscy, m.in. <strong>Waldemar I Wielki</strong> (1131–1182). W Polsce znane od wieków. Wybitny nosiciel to premier <strong>Waldemar Pawlak</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Waldek, Waldeczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Waldemar (niem., skandynaw.), Vladimir (słow.), Vladimír (czes.), Вальдемар (ros.)</p></div>',

  "Igor": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Igor pochodzi z języka <strong>skandynawskiego</strong> — od staronordyckiego <em>Ingvar</em>, złożonego z <em>Ing</em> (imię bóstwa germańskiego) i <em>var</em> (stróż, pasterz), co oznacza <strong>„stróż Inga"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Do Polski dotarło przez Ruś Kijowską, gdzie imię było popularne wśród książąt waregskich. Patronem jest <strong>święty Igor</strong> — wielki książę kijowski z XII w. W Polsce szczyt popularności przypadł na lata 2010–2017.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Igorek, Iguś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Igor (ros., franc., hiszp.), Ihor (ukr.), Ingevar (skandynaw.)</p></div>',

  "Hubert": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hubert pochodzi ze <strong>starogermańskiego</strong> — złożone z <em>hugu</em> (umysł, rozum) i <em>beraht</em> (jasny, słynny), co oznacza <strong>„słynący z rozumu"</strong> lub „jaśniejący inteligencją".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>święty Hubert z Liège</strong> (ok. 656–727) — biskup, patron myśliwych, leśników i psów myśliwskich. Jego święto 3 listopada tradycyjnie otwiera sezon łowiecki. Znany nosiciel to tenisista <strong>Hubert Hurkacz</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hubertek, Hubercik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hubert (ang., franc., niem.), Umberto (wł.), Hobart (ang. arc.), Губерт (ros.)</p></div>',

  "Bogdan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bogdan jest imieniem <strong>słowiańskim</strong> — złożonym z <em>Bóg</em> i <em>dan</em> (dany), co oznacza <strong>„dany przez Boga"</strong>. Jest słowiańskim odpowiednikiem łacińskiego Adeodatus (Bożydar).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najstarszych polskich imion słowiańskich, używane od czasów pogańskich. Możliwe wpływy irańskie (scytyjskie) — elementy <em>-dan</em> spotykamy w imionach irańskich. Forma wschodnia to Bohdan (ukr., ros.).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bogdanek, Bogdaś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bohdan (ukr.), Богдан (ros., serb.), Bogdan (czes., chorwac.) — imię typowo słowiańskie.</p></div>',

  "Konrad": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Konrad pochodzi ze <strong>starogermańskiego</strong> — złożone z <em>kuoni</em> (śmiały, doświadczony) i <em>rad</em> (rada, doradca), co oznacza <strong>„śmiały doradca"</strong> lub „mądry i odważny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne wśród średniowiecznych władców europejskich. W Polsce nosił je m.in. <strong>Konrad Mazowiecki</strong> — książę, który w 1226 r. sprowadził Krzyżaków do Polski. W literaturze słynny jest <strong>Konrad</strong> z <em>Dziadów</em> Mickiewicza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Konradek, Konruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Conrad (ang.), Konrad (niem.), Conrado (hiszp.), Corrado (wł.), Конрад (ros.)</p></div>',

  "Daria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Daria pochodzi z języka <strong>perskiego</strong> — od słowa <em>daraya</em> oznaczającego <strong>„posiadać"</strong>, „ten, kto dzierży bogactwo". Jest żeńską formą imienia Dariusz.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronkami są <strong>święta Daria z Venafro</strong> (†303, 17 czerwca) i <strong>święta Daria z Rzymu</strong> (†283, 25 października) — obie męczennice. W Polsce imię popularne od końca XX wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Darka, Dareczka, Darysia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Daria (ang., wł., hiszp.), Darya (ros.), Darja (czes., słowac.), Дарья (ros.)</p></div>',

  "Wanda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wanda jest imieniem <strong>polskim</strong> — najprawdopodobniej wymyślonym przez kronikarza <strong>Wincentego Kadłubka</strong> w XII wieku. Możliwe etymologie: od słowiańskiego <em>węda</em> (wędka) lub od nazwy ludu Wendów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Wanda to legendarnapolska księżniczka — córka Kraka, założyciela Krakowa. Według legendy wolała się utopić w Wiśle, niż wyjść za mąż za germańskiego księcia. Imię upowszechniło się w XIX wieku dzięki romantycznej modzie na średniowiecze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wandzia, Wandeczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Wanda (ang., niem., franc.) — imię polskie znane na całym świecie.</p></div>',

  "Marianna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marianna jest połączeniem imion <strong>Maria</strong> i <strong>Anna</strong> — oznacza zatem <strong>„pełna łaski"</strong> (hebr. <em>hannāh</em>) i nawiązuje do Maryi, Matki Jezusa. Przez wieki zastępowało w Polsce samo imię Maria.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce przez wieki imię Maria było rzadkie (uznawane za zbyt święte), więc nadawano zamiast niego Mariannę. Wizerunek Marianny jako symbol Republiki Francuskiej pochodzi z rewolucji 1789 roku.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marysia, Marysia, Marylka, Mańka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marianne (franc., niem.), Mariana (hiszp., port.), Marion (ang.), Мариана (ros.)</p></div>',

  "Stanisława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Stanisława jest żeńską formą imienia <strong>Stanisław</strong> — słowiańskiego, złożonego z <em>stani-</em> (stanąć, powstać) i <em>-sław</em> (sława), co oznacza <strong>„ta, która stanie się sławna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma klasycznego polskiego imienia Stanisław. Dziś nosi je ok. 100 tysięcy Polek, choć imię należy już do starszego pokolenia. Patronką jest święta Stanisława — męczennica wczesnochrześcijańska.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Stasia, Staśka, Stanka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Stanislava (czes., słowac., chorwac.), Stanisława — imię typowo słowiańskie.</p></div>',

  "Wiesława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wiesława jest żeńską formą imienia <strong>Wiesław</strong> — słowiańskiego, od <em>Wielisław</em>, złożonego z <em>wiele-</em> (wielki) i <em>-sław</em> (sława), co oznacza <strong>„wielka sławą"</strong> lub „pragnąca sławy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Stare polskie imię słowiańskie. Dziś nosi je ok. 101 tysięcy Polek — imię należy do starszego pokolenia. Imieniny obchodzone są 22 maja i 7 czerwca.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wieśka, Wiesławka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez bezpośrednich odpowiedników w innych językach.</p></div>',

  "Alicja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alicja ma kilka możliwych etymologii — może wywodzić się ze starogermańskiego <em>Adalheidis</em> (szlachetna), z greckiego <em>aletheia</em> (<strong>„prawda"</strong>) lub z włoskiej formy imienia Aleksy. Wszystkie znaczenia łączy szlachetność i prawdziwość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię upowszechniło się dzięki powieści Lewisa Carrolla <em>Alicja w Krainie Czarów</em> (1865). W Polsce szczyt popularności przypadł na lata 50. XX w. Dziś nosi je ponad 253 tysiące Polek (23. miejsce).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ala, Alka, Alusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alice (ang., franc., niem.), Alicia (hiszp.), Alise (łot.), Аліса (ukr.)</p></div>',

  "Janina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Janina jest żeńską formą imienia <strong>Jan</strong>, wywodzącego się z hebrajskiego <em>Johanan</em> — <strong>„Bóg jest łaskawy"</strong>. Do Polski dotarło z języka czeskiego jako samoistne imię żeńskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce używane od średniowiecza (formy Janna, Jana). Dziś nosi je ponad 207 tysięcy Polek. Znana nosicielka to działaczka humanitarna <strong>Janina Ochojska</strong> — założycielka Polskiej Akcji Humanitarnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Janka, Janeczka, Jasia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jane (ang.), Juana (hiszp.), Gianna (wł.), Jana (czes.), Іванна (ukr.)</p></div>',

  "Irena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Irena pochodzi z języka <strong>greckiego</strong> — od słowa <em>eirene</em> (εἰρήνη) oznaczającego <strong>„pokój"</strong>. W mitologii Eirene była boginią pokoju, córką Zeusa i Temidy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Wybitne nosicielki to <strong>Irena Sendlerowa</strong> — polska działaczka, która uratowała ok. 2500 żydowskich dzieci z getta warszawskiego, oraz olimpijka <strong>Irena Szewińska</strong>. Dziś imię nosi ok. 203 tysięcy Polek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Irka, Irenka, Irusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Irene (ang., niem., wł., hiszp.), Irina (ros.), Iryna (ukr.), Eirene (gr.)</p></div>',

  "Bożena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bożena jest imieniem <strong>słowiańskim</strong> — wywodzi się od rdzenia <em>boż-</em> (Bóg), co oznacza <strong>„Boża"</strong>, „dana przez Boga". Jest słowiańskim odpowiednikiem łacińskiego Donata.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w historycznych dokumentach jako Bożana i Bożechna. W Polsce regularnie używane od XIX wieku. Dziś nosi je ok. 197 tysięcy Polek. Znana czeska pisarka to <strong>Božena Němcová</strong> — autorka <em>Babci</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bożka, Bożenka, Bozia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Božena (czes., słowac., chorwac.) — imię typowo słowiańskie.</p></div>',

  "Ryszard": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ryszard pochodzi ze <strong>starogermańskiego</strong> — złożone z <em>ric</em> (władca, potężny) i <em>hard</em> (twardy, dzielny), co oznacza <strong>„potężny i dzielny"</strong>. Jest polską formą imienia Ryszard.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił <strong>Ryszard Lwie Serce</strong> — król Anglii (1157–1199), bohater wypraw krzyżowych. W Polsce dokumentowane od XIII wieku. Szczyt popularności przypadał na lata 50. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rysiek, Ryszarek, Ryś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Richard (ang., franc., niem.), Ricardo (hiszp., port.), Richárd (węg.), Ричард (ros.)</p></div>',

  "Józef": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Józef pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yōsēp̄</em> (יוֹסֵף), co oznacza <strong>„niechaj Bóg przysporzy"</strong> lub „Bóg doda". Jest jednym z najważniejszych imion w tradycji biblijnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii Józef to syn Jakuba, sprzedany przez braci do Egiptu. W tradycji chrześcijańskiej patronem jest <strong>święty Józef z Nazaretu</strong> — opiekun Jezusa. Wybitny Polak to marszałek <strong>Józef Piłsudski</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Józek, Józio, Ziutek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Joseph (ang., franc.), Josef (niem.), José (hiszp.), Giuseppe (wł.), Иосиф (ros.)</p></div>',

  "Krystian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Krystian pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>Christianus</em> oznaczającego <strong>„chrześcijanin"</strong>, „wyznawca Chrystusa". Chrystus z kolei pochodzi od greckiego <em>christos</em> — namaszczony.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię noszą m.in. <strong>Hans Christian Andersen</strong> — duński bajkopisarz, i <strong>Christian Dior</strong> — legendarny projektant mody. W piłce nożnej znany jest <strong>Cristiano Ronaldo</strong>. W Polsce popularne szczególnie od lat 90.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Krystianek, Krystys</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Christian (ang., niem., skandynaw.), Cristiano (wł., port.), Cristián (hiszp.), Христиан (ros.)</p></div>',

  "Zdzisław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zdzisław to staropolskie imię dwuczłonowe, złożone z <em>Zdzie-</em> (od „czynić, dokonywać") i <em>-sław</em> („sława"). Znaczenie: <strong>„ten, kto dokonuje sławy"</strong>. Poświadczone w dokumentach już w 1198 roku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili m.in. <strong>Zdzisław Beksiński</strong> — malarz i fotograf, jeden z najwybitniejszych polskich artystów XX w., oraz <strong>Zdzisław Krzyszkowiak</strong> — olimpijczyk. Forma żeńska to Zdzisława.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zdziech, Zdziesz, Zdzieszko, Zdziś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zdislaus (łac.), Zdislav (niem.), Zdeněk (czes.), Zdenko (słow.), Zđislav (płd.-słow.)</p></div>',

  "Laura": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Laura pochodzi od łacińskiego słowa <em>laurus</em> — <strong>„wawrzyn, laur"</strong>. Wieniec laurowy był symbolem chwały i zwycięstwa w starożytnym Rzymie. Imię oznacza zatem „uwieńczona laurem".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła <strong>Laura de Noves</strong> — muza poety Francesco Petrarki, który poświęcił jej cykl sonetów <em>Canzoniere</em> (XIV w.). W Polsce popularne szczególnie od lat 90. XX w. Znana jest też <strong>Laura Pausini</strong> — włoska piosenkarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Laurka, Laurcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Laura (ang., niem., wł., hiszp.), Laure (franc.), Лора (ros.)</p></div>',

  "Lidia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Lidia pochodzi z języka <strong>greckiego</strong> — od słowa <em>Lydia</em> oznaczającego <strong>„mieszkankę Lidii"</strong>, krainy w zachodniej Anatolii (dzisiejsza Turcja), słynnej w starożytności z bogactwa króla Krezusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii Lidia z Tiatyry była pierwszą nawróconą na chrześcijaństwo w Europie (Dz 16). Imię nosi m.in. <strong>Lidia Skoblikowa</strong> — radziecka łyżwiarka, sześciokrotna mistrzyni olimpijska.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lidka, Lidzia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lydia (ang., niem.), Lydie (franc.), Lidia (wł., hiszp.), Lídia (węg.), Lidija (słow.)</p></div>',

  "Mariola": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mariola to zdrobnienie imienia <strong>Maria</strong>, które pochodzi z języka hebrajskiego — od <em>Miriam</em>, co tłumaczy się jako „ukochana przez Boga" lub „pani". Zakończenie <em>-ola</em> nadaje imieniu charakter pieszczotliwy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię upowszechniło się w Polsce po wydaniu powieści <strong>Tadeusza Dołęgi-Mostowicza <em>Znachor</em></strong> (1937), w której bohaterka nosiła imię Maria Jolanta, zwana Mariolą. Film i powieść uczyniły je modnym. Znana jest też <strong>Mariola Bojarska-Ferenc</strong> — gimnastyczka i dziennikarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marysia, Mariolka, Ola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Brak bezpośrednich odpowiedników — imię funkcjonuje głównie w Polsce i krajach frankofońskich</p></div>',

  "Oskar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Oskar ma dwa możliwe pochodzenia: <strong>germańskie</strong> — od <em>os</em> (bóg) + <em>gār</em> (włócznia), czyli „włócznia boga", lub <strong>staroirlandzkie</strong> — od <em>os</em> (jeleń) + <em>cara</em> (przyjaciel), czyli „przyjaciel jelenia".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili szwedzcy królowie Oskar I i Oskar II. Słynny <strong>Oscar Wilde</strong> — irlandzki pisarz, oraz <strong>Oskar Schindler</strong> — przemysłowiec, który uratował tysiące Żydów. Statuetka Akademii Filmowej (Oscar) nosi to imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oskarek, Osc</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Oscar (ang., hiszp.), Oskár (węg.), Oszkár (franc.), Ansgar (nordycki odpowiednik)</p></div>',

  "Nikola": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Nikola to forma imienia <strong>Mikołaj</strong>, które pochodzi z języka greckiego — od <em>nikolaos</em>: <em>nikē</em> (zwycięstwo) + <em>laos</em> (lud). Znaczenie: <strong>„zwycięski wśród ludu"</strong>. W Polsce używane zarówno jako imię żeńskie, jak i męskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosi <strong>Nikola Tesla</strong> — genialny serbski wynalazca i fizyk, pionier elektryczności. Wśród kobiet znana jest <strong>Nikola Weiss</strong> i liczne sportsmenki europejskie. Imię popularne zwłaszcza w krajach słowiańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nika, Niko, Nikolka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicola (wł.), Nicolas (franc., hiszp.), Nicholas (ang.), Nikolai (ros.), Nikolaus (niem.)</p></div>',

  "Milena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Milena to słowiańskie imię żeńskie, którego rdzeń <em>mil-</em> oznacza <strong>„miły, przyjemny"</strong>. Imię wywodzi się ze skróceń dłuższych imion dwuczłonowych jak Miłobora, Miłosława. Forma męska to Milan.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane nosicielki to <strong>Milena Jesenská</strong> — czeska dziennikarka i tłumaczka, korespondentka Franza Kafki, oraz <strong>Milla Jovovich</strong> — aktorka serbskiego pochodzenia. Popularne w całej Słowiańszczyźnie i we Francji jako Mylène.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mila, Milka, Milcia, Lena, Milenka, Milunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mylène (franc.), Milena (niem., wł.), Милена (ros., serb.), Milana (wariant słow.)</p></div>',

  "Lucyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Lucyna pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>lucina</em>, związanego z <em>lux</em> (światło). Znaczenie: <strong>„świetlista, niosąca światło"</strong>. W mitologii Lucyna była boginią porodu i światła.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Lucyny to <strong>Lucyna Ćwierczakiewiczowa</strong> (1829–1901) — autorka najpopularniejszych polskich książek kucharskich XIX w., oraz <strong>Lucyna Winnicka</strong> (1928–2013) — wybitna polska aktorka filmowa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Luśka, Lucynka, Lunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lucy, Lucia (ang., wł.), Lucinde (niem.), Lucie (franc.), Lucía (hiszp.)</p></div>',

  "Nikodem": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Nikodem pochodzi z języka <strong>greckiego</strong> — od <em>nikodem</em>: <em>nikē</em> (zwycięstwo) + <em>demos</em> (lud). Znaczenie: <strong>„ten, kto zdobywa zwycięstwo dla ludu"</strong>. Bliskie znaczeniowo imieniu Mikołaj.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Nikodem pojawia się w Ewangelii Jana jako faryzeusz, który nocą odwiedził Jezusa. W literaturze znany jest <strong>Nikodem Dyzma</strong> — sprytny karierowicz z powieści Dołęgi-Mostowicza. We współczesnej Polsce Nikodem jest jednym z modniejszych imion dla chłopców.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nikoś, Niko, Nikodemek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicodemus (ang., łac.), Nicodème (franc.), Nicodemo (wł., hiszp.), Никодим (ros.)</p></div>',

  "Maksymilian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maksymilian pochodzi z języka <strong>łacińskiego</strong> — od <em>Maximilianus</em>, złożonego z <em>maximus</em> (największy) i rodu Emiliuszów. Znaczenie: <strong>„największy z rodu Emiliuszów"</strong> lub po prostu „największy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Maksymilian Maria Kolbe</strong> — polski franciszkanin, oddał życie za współwięźnia w Auschwitz, jest patronem imienia. Imię nosili też cesarze Habsburgów. Skrót Max używany przez fizyka <strong>Maksa Plancka</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maks, Maksek, Maksiś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maximilian (ang., niem.), Maximilien (franc.), Maximiliano (hiszp.), Massimiliano (wł.)</p></div>',

  "Antonina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Antonina to żeńska forma imienia Antoni, które pochodzi od <strong>łacińskiego</strong> rodu Antoniuszów. Przyrostek <em>-ina</em> wskazuje na przynależność. Imię oznacza „należąca do rodu Antoniuszów" lub „bezcenna".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Najsłynniejszą Antoniną jest <strong>Maria Antonina</strong> — królowa Francji, żona Ludwika XVI, stracona podczas Rewolucji Francuskiej. W Polsce imię znane od 1637 roku. Nosi je m.in. Antonina Giryowska — polska pianistka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tosia, Antosia, Tonia, Nina, Tosiunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Antoinette (franc.), Antonina (niem., ros.), Antanina (litew.), Antonietta (wł.)</p></div>',

  "Edward": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Edward pochodzi ze <strong>staroangielskiego</strong> — od <em>ead</em> (dobrobyt, szczęście) + <em>weard</em> (strażnik, obrońca). Znaczenie: <strong>„strażnik dobrobytu"</strong> lub „opiekun szczęścia".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczni królowie Anglii (Edward I–VIII). Znani Edwardowie to <strong>Edward Jenner</strong> — twórca szczepionki przeciw ospie, <strong>Edward Hopper</strong> — malarz, i <strong>Edvard Munch</strong> — norweski ekspresjonista. W Polsce popularny <strong>Edward Stachura</strong> — poeta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Edek, Edzio, Edward</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edward (ang.), Eduardo (hiszp., port.), Eduard (niem.), Edoardo (wł.), Édouard (franc.)</p></div>',

  "Mieczysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mieczysław to staropolskie imię dwuczłonowe. Pierwszy człon <em>Miecz-</em> pochodzi od słowa „miecz", drugi <em>-sław</em> oznacza „sławę". Znaczenie: <strong>„ten, kto zdobywa sławę mieczem"</strong>. Poświadczone od XIII wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane osoby to <strong>Mieczysław Fogg</strong> — legendarny piosenkarz, <strong>Mieczysław Najdorf</strong> — arcymistrz szachowy, i <strong>Tony Halik</strong> (właśc. Mieczysław Halik) — podróżnik i dziennikarz. Forma żeńska to Mieczysława.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mietek, Miecio, Mieczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mečislav (czes., słow.), Miečislavas (litew.) — imię głównie polskie, bez szerszych odpowiedników</p></div>',

  "Leon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leon pochodzi z języka <strong>greckiego i łacińskiego</strong> — od słowa <em>leon</em> (λέων), oznaczającego <strong>„lwa"</strong>. Symbolizuje siłę, odwagę i królewskość. W Polsce poświadczone od 1265 roku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili <strong>13 papieży</strong> (Leon I Wielki do Leona XIII). Znani Leonowie to <strong>Lew Tołstoj</strong> — rosyjski pisarz, <strong>Lionel Messi</strong> — argentyński piłkarz, i <strong>Léon Gambetta</strong> — francuski polityk. W Polsce imię wraca do łask jako modne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leonek, Leoncio, Leoś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leon (ang., niem.), Léon (franc.), León (hiszp.), Leone (wł.), Лев (ros.), Leó (węg.)</p></div>',

  "Miłosz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Miłosz to <strong>słowiańskie</strong> imię wywodzące się z rdzenia <em>miło-</em>, oznaczającego <strong>„miły, kochany"</strong>. Powstało jako zdrobnienie dłuższych imion dwuczłonowych jak Miłobor, Miłogost czy Miłosław. Poświadczone już w 1136 roku w Bulli Gnieźnieńskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Czesław Miłosz</strong> — laureat Nagrody Nobla w dziedzinie literatury (1980), jest najsłynniejszym Miłoszem. Imię nosi też <strong>Miloš Forman</strong> — czeski reżyser filmowy. Współcześnie w Polsce bardzo modne imię dla chłopców.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Miłek, Miłoszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Miloš (czes., serb.), Милош (serb.), Milan (wariant), Miłosław (forma rozwinięta)</p></div>',

  "Mirosława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mirosława to staropolskie imię żeńskie, złożone z <em>Miro-</em> (pokój, spokój, dobro — od prasłowiańskiego <em>mirъ</em>) i <em>-sława</em> (sława). Znaczenie: <strong>„ta, która rozsławia pokój"</strong>. Poświadczone w Polsce od 1222 roku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma męska to Mirosław. Imię należy do grupy starych słowiańskich imion z członem <em>-mir</em>, jak Dobromira, Lubomira czy Sławomira. Dziś nieco rzadsze, ale wciąż obecne w polskim kalendarzu imion.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mirka, Mira, Mirusia, Mirosławka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Miroslava (czes., słow.), Mirka (fin., węg.), Мирослава (ros., ukr.)</p></div>',

  "Angelika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Angelika pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>angelicus</em> (anielski), które z kolei pochodzi z greckiego <em>angelos</em> (posłaniec). Znaczenie: <strong>„anielska, posłanniczka"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła seria powieści i filmów o <strong>Angélique</strong> — przygodowej bohaterce XVII-wiecznej Francji. Znana jest też tenisistka <strong>Angelique Kerber</strong> — trzykrotna mistrzyni Wielkiego Szlema, i aktorka <strong>Anjelica Huston</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ania, Anka, Angelka, Andżelika</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Angélique (franc.), Angélica (hiszp.), Angelica (ang., wł.), Angelika (niem.)</p></div>',

  "Władysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Władysław to staropolskie imię dwuczłonowe, złożone z <em>władać</em> (rządzić) i <em>-sław</em> (sława). Znaczenie: <strong>„ten, kto rządzi ze sławą"</strong> lub „sławny władca". Imię wywodzi się z tradycji słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili polscy królowie, m.in. <strong>Władysław II Jagiełło</strong> — zwycięzca spod Grunwaldu, i <strong>Władysław IV Waza</strong>. Znani Władysławowie to pisarz <strong>Władysław Reymont</strong> (Nobla 1924) i pianista <strong>Władysław Szpilman</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Władek, Władzio, Wład</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vladislav (czes., ros.), Ladislaus (łac., niem.), Ulászló (węg.), Ladislao (hiszp., wł.)</p></div>',

  "Olga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Olga pochodzi ze <strong>skandynawskiego</strong> Helga, wywodzącego się ze starogermańskiego <em>hails</em> — zdrowy, święty. Znaczenie: <strong>„święta, zdrowa, szczęśliwa"</strong>. Forma męska to Oleg.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Olga Kijowska</strong> (ok. 890–969) — władczyni Rusi Kijowskiej, pierwsza chrześcijańska władczyni Rusi, święta Kościołów wschodnich. Znana jest też <strong>Olga Tokarczuk</strong> — polska pisarka, laureatka Nagrody Nobla (2018), i <strong>Olga Kurylenko</strong> — aktorka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ola, Olcia, Olunia, Oleńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Helga (skandynaw.), Olga (ros., niem., franc., wł.), Ольга (ukr., ros.)</p></div>',

  "Michalina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Michalina to żeńska forma imienia Michał, które pochodzi z języka <strong>hebrajskiego</strong> — od pytania <em>Mi ka-El?</em> — <strong>„Któż jest jak Bóg?"</strong>. Imię wyraża uniżoność i chwałę Bożą.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię poświadczone w Polsce od 1744 roku. Znane Michaliny to <strong>Michelle Obama</strong> — pierwsza dama USA, <strong>Michelle Pfeiffer</strong> — aktorka, i <strong>Michelle Kwan</strong> — mistrzyni łyżwiarstwa figurowego. W Polsce modne szczególnie w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Misia, Michałka, Michalinka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Michelle (ang., franc.), Michaela (niem.), Miguela (hiszp.), Mihaela (rum.), Michaela (czes.)</p></div>',

  "Czesław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Czesław to staropolskie imię dwuczłonowe. Pierwszy człon pochodzi od prasłowiańskiego <em>čajati</em> (oczekiwać, spodziewać się), drugi <em>-sław</em> oznacza sławę. Znaczenie: <strong>„ten, kto oczekuje sławy"</strong> lub „czcigodny i sławny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Najsłynniejszy Czesław to <strong>Czesław Miłosz</strong> — poeta i eseista, laureat Nagrody Nobla (1980). Imię nosi też generał <strong>Czesław Kiszczak</strong> — minister spraw wewnętrznych PRL. Forma żeńska to Czesława.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Czech, Czach, Czaszek, Czeszko, Czesiek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Česlav (czes., serb.), Česlovas (litew.), Ceslaus (łac.) — imię głównie polskie</p></div>',

  'Ireneusz': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ireneusz pochodzi z języka <strong>greckiego</strong> — od słowa <em>eirēnē</em> (<em>εἰρήνη</em>), oznaczającego <strong>„pokój"</strong>. Jest rozbudowaną formą imienia Irena, wzbogaconą łacińskim sufiksem. Do Polski dotarło przez łacińskie <em>Irenaeus</em>. Imię symbolizuje harmonię, spokój ducha i pojednanie między ludźmi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Ireneusza z Lyonu (ok. 130–202) — biskupa, teologa i Ojca Kościoła, autora fundamentalnego dzieła <em>Adversus haereses</em> (Przeciw herezjom) skierowanego przeciwko gnozie. Ireneusz Iredyński (1939–1985) — wybitny polski dramaturg i poeta, autor sztuki <em>Żegnaj Judaszu</em>. W Polsce popularne w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Irek, Ireczek, Iruś, Ireneuszek, Ireczuś, Ireneuszko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Irenaeus (łac., ang.), Irénée (franc.), Ireneo (hiszp., wł.), Irinej (chorw., serb.), Ириней (ros.)</p></div>',

  "Bogusław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bogusław to staropolskie imię dwuczłonowe, złożone z <em>Bogu-</em> (Bóg lub fortuna, przeznaczenie) i <em>-sław</em> (sława). Znaczenie: <strong>„sławiący Boga"</strong> lub pierwotnie „ten, kto sławił przeznaczenie". Znane od XII wieku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię było wyjątkowo popularne wśród <strong>Gryfitów — dynastii książąt pomorskich</strong>: aż 14 władców Pomorza nosiło to imię, m.in. Bogusław X Wielki. We współczesnej Polsce znany jest <strong>Bogusław Linda</strong> — aktor filmowy.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bogusz, Boguta, Bogna, Bosław</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bohuslav (czes.), Boguslav (ang., niem.), Bogislav (niem., płd.-słow.), Boguslaus (łac.)</p></div>',

  "Maksym": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maksym pochodzi z języka <strong>łacińskiego</strong> — od przymiotnika <em>maximus</em>, oznaczającego <strong>„największy"</strong>. To skrócona forma imienia Maksymilian. Popularne w Polsce i na Ukrainie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię noszą liczni święci prawosławni i katoliccy. Wśród znanych Maksymów: <strong>Maksim Gorki</strong> — rosyjski pisarz, <strong>Maxime Vachier-Lagrave</strong> — arcymistrz szachowy, i <strong>Massimo Oddo</strong> — włoski piłkarz. W Polsce imię zyskuje na popularności.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maks, Maksek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maxim (ang., ros.), Massimo (wł.), Maxime (franc.), Máximo (hiszp.), Максим (ukr.)</p></div>',

  "Eugeniusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eugeniusz pochodzi z języka <strong>greckiego</strong> — od słów <em>eu</em> (dobrze) + <em>genos</em> (ród, pochodzenie). Znaczenie: <strong>„szlachetnie urodzony, dobrze urodzony"</strong>. Forma żeńska to Eugenia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili trzej papieże (Eugeniusz I, III, IV). Znani Eugeniusze to <strong>Eugène Ionesco</strong> — dramaturg, twórca teatru absurdu, <strong>Eugene Cernan</strong> — ostatni człowiek na Księżycu, i <strong>Jewgienij Pluszczenko</strong> — mistrz olimpijski w łyżwiarstwie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gienia, Gieniu, Eugenek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eugene (ang.), Eugène (franc.), Eugenio (hiszp., wł.), Eugen (niem.), Євген (ukr.)</p></div>',

  "Ilona": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ilona to <strong>węgierska</strong> forma imienia Helena, które pochodzi z języka greckiego — od <em>Helene</em>. Etymologia wskazuje na <em>helios</em> (słońce) lub <em>helene</em> (pochodnia). Znaczenie: <strong>„jasna, świetlista"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię zyskało popularność w Polsce w latach 60. XX w., kiedy stawało się modne imię z nową, egzotyczną formą. Znana jest <strong>Ilona Elek</strong> — węgierska mistrzyni olimpijska w szermierce (trzykrotna), i <strong>Ilona Ostrowska</strong> — polska aktorka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ilonka, Ilcia, Lona</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Helena (orig.), Hélène (franc.), Elena (wł., hiszp.), Helen (ang.), Jelena (serb., ros.)</p></div>',

  "Sandra": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sandra to skrócona forma imienia <strong>Aleksandra</strong>, które pochodzi z języka greckiego — od <em>alexandros</em>: <em>alexein</em> (bronić) + <em>aner</em> (człowiek). Znaczenie: <strong>„obrończyni ludzi"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane na świecie głównie dzięki <strong>Sandrze Bullock</strong> — amerykańskiej aktorce i laureatce Oscara. Znana jest też <strong>Sandra Oh</strong> — kanadyjska aktorka i <strong>Sandra Perković</strong> — chorwacka mistrzyni olimpijska w rzucie dyskiem. W Polsce modne w latach 80.–90.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sandzia, Sandrka, Ola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alexandra (ang., niem.), Aleksandra (ros.), Sandro (wł., forma męska), Sándor (węg., forma męska)</p></div>',

  "Witold": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Witold wywodzi się z języka <strong>litewskiego</strong> — od <em>Vytautas</em>: <em>vyti</em> (gonić, ścigać) + <em>tauta</em> (lud). Znaczenie: <strong>„ten, kto ściga lub rządzi ludem"</strong>. Możliwe też źródło germańskie: <em>witu</em> (las) + <em>waltan</em> (rządzić).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Witold Kiejstutowicz</strong> (ok. 1352–1430) — wielki książę litewski, jeden z najpotężniejszych władców Europy Środkowej. Znani Witoldowie to pisarz <strong>Witold Gombrowicz</strong> i kompozytor <strong>Witold Lutosławski</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Witek, Wituś, Wiciu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Witold (ang., niem.), Vitold (franc.), Vitoldo (wł.), Witoldus (łac.)</p></div>',

  "Kornelia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kornelia to żeńska forma imienia Kornel, które pochodzi od <strong>łacińskiego</strong> rodu Kornelii (<em>Cornelia gens</em>). Etymologia wskazuje na łacinę <em>cornu</em> (róg) lub etruskie pochodzenie. Imię oznacza „należąca do rodu Kornelii".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Kornelia</strong> (II w. p.n.e.) — matka Grakchów, słynna jako wzór cnoty i mądrości republikańskiego Rzymu, powiedziała o swoich synach: „oto moje klejnoty". W Polsce imię rzadsze, ale eleganckie i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Korcia, Kornel, Nela, Nelia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cornelia (ang., niem., wł.), Cornélie (franc.), Cornelia (hiszp.), Корнелия (ros.)</p></div>',

  "Pola": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Pola to <strong>zdrobnienie</strong> imion Apolonia lub Apollinaris, wywodzących się z greckiego <em>Apollon</em> — imienia boga słońca i sztuk pięknych. Możliwe też że imię nawiązuje do słowa „pole". Znaczenie: <strong>„córka Apollona"</strong> lub „polna".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła <strong>Pola Negri</strong> (właśc. Apolonia Chałupiec, 1897–1987) — pierwsza polska gwiazda Hollywood, symbol kina niemego. Dziś Pola to jedno z modniejszych imion dla dziewczynek w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Polcia, Polka, Polusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apolonia (pełna forma), Apolline (franc.), Apollonia (wł.), Polly (ang. wariant)</p></div>',

  "Alan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alan pochodzi z języka <strong>celtyckiego</strong> lub bretońskiego. Etymologia nie jest jednoznaczna: możliwe znaczenia to <strong>„harmonia, spokój"</strong> lub „skała", albo pochodzi od ludu Alanów — koczowniczego plemienia irańskiego. Forma żeńska to Alana.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Alanowie to <strong>Alan Turing</strong> — ojciec informatyki i twórca pierwszego komputera, <strong>Alan Shearer</strong> — angielski piłkarz, i <strong>Alan Rickman</strong> — aktor znany z roli Severusa Snape&#39;a. W Polsce popularne od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alanek, Al</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alan (ang., franc., niem.), Alain (franc.), Allen (ang. wariant), Алан (ros.)</p></div>',

  "Bogumiła": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bogumiła to staropolskie imię żeńskie, złożone z <em>Bogu-</em> (Bóg) i <em>-miła</em> (miła). Znaczenie: <strong>„miła Bogu"</strong> lub „Bogu oddana". Forma męska to Bogumił. Imię należy do starej warstwy słowiańskich imion chrześcijańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Bogumił</strong> — arcybiskup gnieźnieński z XII w., jest patronem imienia. Forma żeńska Bogumiła była popularna w Polsce w XX wieku. Znana jest <strong>Bogumiła Wander</strong> — polska aktorka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bogunia, Miłka, Bogusia, Basia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bohumila (czes.), Bogomila (płd.-słow.) — imię głównie polskie i słowiańskie</p></div>',

  "Ignacy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ignacy pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>ignis</em> (ogień) lub od rodu Egnatii. Znaczenie: <strong>„ognisty"</strong> lub „z rodu Egnatii". Możliwe też pochodzenie etruskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>Ignacy Loyola</strong> — założyciel zakonu jezuitów (XVI w.). Znani polscy Ignacowie to <strong>Ignacy Krasicki</strong> — poeta i satyryk, <strong>Ignacy Paderewski</strong> — pianista i premier Polski, oraz <strong>Ignacy Mościcki</strong> — prezydent II RP.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ignacek, Ignacuś, Ignasio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ignatius (ang., łac.), Ignatz (niem.), Ignacio (hiszp.), Ignazio (wł.), Игнатий (ros.)</p></div>',

  "Liliana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Liliana to imię żeńskie <strong>łacińskiego</strong> pochodzenia, wywodzące się od słowa <em>lilium</em> — <strong>lilia</strong>. Lilia symbolizuje czystość, niewinność i piękno. Forma z podwójnym <em>n</em> — Lilianna — to wariant tego samego imienia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Liliany to <strong>Liliana Cavani</strong> — włoska reżyserka filmowa, <strong>Liliana Komorowska</strong> — polska aktorka, i <strong>Liliana Urbańska</strong> — polska piosenkarka. Imię popularne w wielu krajach Europy i Ameryki Łacińskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lili, Lila, Lilka, Lilcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lillian, Lily (ang.), Lilian (niem., franc.), Liliana (hiszp., wł.), Лилиана (ros.)</p></div>',

  "Sylwester": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sylwester pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>silvestris</em>, oznaczającego <strong>„leśny, dziki, mieszkający w lesie"</strong>. Wywodzi się od <em>silva</em> (las). W Polsce poświadczone od 1220 roku.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Patronem jest <strong>papież Sylwester I</strong> (zm. 335), którego wspomnienie 31 grudnia nadało tę datę popularności jako „sylwester". Znany jest też aktor <strong>Sylvester Stallone</strong> i papież <strong>Sylwester II</strong> — pierwszy papież z Francji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwek, Sysz, Fester</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sylvester (ang.), Silvester (niem.), Silvestre (franc., hiszp.), Silvestro (wł.), Szilveszter (węg.)</p></div>',

  "Stefan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Stefan pochodzi z języka <strong>greckiego</strong> — od słowa <em>stephanos</em> (στέφανος), oznaczającego <strong>„wieniec, koronę"</strong>. Wieniec był symbolem zwycięstwa w antycznej Grecji. Pierwotna polska forma to Szczepan.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili 8 papieży oraz liczni królowie. Znani Stefanowie to <strong>Stefan Batory</strong> — król Polski, <strong>Stefan Banach</strong> — wybitny matematyk, <strong>Stefan Żeromski</strong> — pisarz, i <strong>Stephen Hawking</strong> — fizyk teoretyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Stefek, Stefuś, Szczepan (wariant)</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Stephen/Steven (ang.), Étienne (franc.), Esteban (hiszp.), Stefano (wł.), István (węg.), Степан (ros.)</p></div>',

  "Iga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Iga to <strong>zdrobnienie</strong> imienia Jadwiga, które pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hedwig</em>: <em>hadu</em> (walka) + <em>wig</em> (walka, bitwa). Znaczenie: <strong>„ta, która walczy"</strong>. Iga funkcjonuje dziś jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię zyskało ogromną popularność dzięki <strong>Idze Świątek</strong> — polskiej tenisistce, wielokrotnej mistrzyni Wielkiego Szlema i wieloletniej liderce rankingu WTA. Wcześniej znana była <strong>Iga Cembrzyńska</strong> — polska aktorka filmowa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Izia, Igusia, Igulka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hedwig (niem.), Hedwige (franc.), Edwige (wł.), Jadwiga (pełna forma pol.)</p></div>',

  "Łucja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Łucja to polska forma imienia Lucia, wywodząca się z języka <strong>łacińskiego</strong> — od słowa <em>lux</em> (światło). Znaczenie: <strong>„jasna, świetlista, córka światła"</strong>. Imię związane ze światłem i jasnością.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Łucja z Syrakuz</strong> (zm. 304) — męczennica chrześcijańska, patronka niewidomych i chorych na oczy. W Szwecji jej dzień (13 grudnia) obchodzony jest jako święto światła. Znana jest też <strong>Lucia di Lammermoor</strong> — bohaterka opery Donizettiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Łucka, Łusia, Łucynka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lucia (wł., hiszp.), Lucy (ang.), Lucie (franc.), Luzia (port.), Люция (ros.)</p></div>',

  "Nina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Nina ma kilka możliwych źródeł: może być zdrobnieniem imion z końcówką <em>-nina</em> (jak Antonina), może też pochodzić z języka <strong>asyryjskiego</strong> (<em>Nina</em> — bogini wód) lub z języka <strong>gruzińskiego</strong> (patron Gruzji). Znaczenie: <strong>„królowa, pani"</strong> lub „posłanniczka".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Nina</strong> — apostołka Gruzji z IV w., jest patronką imienia. Znane Niny to <strong>Nina Simone</strong> — legendarna amerykańska artystka soul i jazz, i <strong>Nina Ricci</strong> — projektantka mody i twórczyni słynnego domu mody.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ninka, Nineczka, Niusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nina (ang., franc., niem., ros., wł.), Нина (ros., ukr.)</p></div>',

  "Marcelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Marcelina to żeńska forma imienia Marcelin, wywodzącego się od <strong>łacińskiego</strong> <em>Marcellus</em> — zdrobnienia od <em>Marcus</em>. Marcus pochodzi od imienia boga wojny Marsa. Znaczenie: <strong>„mała Marcja, wojownicza"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Marcelina</strong> — siostra świętego Ambrożego z Mediolanu (IV w.). W Polsce znana jest <strong>Marcelina Kulikowska</strong> — polska poetka i publicystka. Imię Marcelina zyskuje na popularności we współczesnej Polsce jako imię eleganckie i klasyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marcela, Marcelka, Celina, Lina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marceline (franc.), Marcelina (hiszp., wł.), Marcelline (ang.), Марцелина (ros.)</p></div>',

  "Marlena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Marlena to imię złożone z <strong>Maria</strong> (hebr. „łaska Boża") i <strong>Magdalena</strong> (hebr. „z Magdali"). Powstało jako zrost obu imion. Znaczenie: <strong>„łaskawa kobieta z Magdali"</strong>. Popularne szczególnie w Niemczech i Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła <strong>Marlene Dietrich</strong> (właśc. Marie Magdalene Dietrich, 1901–1992) — legendarna niemiecka aktorka i piosenkarka. W Polsce znana jest <strong>Marlena Dietrich</strong> i polska aktorka <strong>Marlena Milwiw-Baron</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marlenka, Marcia, Lenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marlene (niem., ang., franc.), Marlena (hiszp., wł.) — imię znane przede wszystkim w Europie Zachodniej</p></div>',

  "Cezary": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Cezary pochodzi z języka <strong>łacińskiego</strong> — od rodowego nazwiska <em>Caesar</em>. Etymologia niepewna: możliwe znaczenia to <strong>„urodzone przez cesarskie cięcie"</strong> (od łac. <em>caedere</em> — ciąć) lub związane z etruskim pochodzeniem rodu Juliuszów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię wywodzi się od <strong>Juliusza Cezara</strong> — dyktatora Rzymu. Słynny Cezary to <strong>Cezary Pazura</strong> — popularny polski aktor komediowy. Imię nosił też <strong>Cesare Borgia</strong> — renesansowy książę i kardynał, syn papieża Aleksandra VI.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cezarek, Czarek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Caesar (ang., łac.), César (franc., hiszp.), Cesare (wł.), Cäsar (niem.), Цезарь (ros.)</p></div>',

  "Gabriel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gabriel pochodzi z języka <strong>hebrajskiego</strong> — od <em>Gavriel</em>: <em>gever</em> (mąż, siła) + <em>El</em> (Bóg). Znaczenie: <strong>„mąż Boży"</strong> lub „Bóg jest moją siłą". To imię jednego z trzech archaniołów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Archanioł Gabriel</strong> zwiastował Marii Pannie narodziny Jezusa. Znani Gabrielowie to <strong>Gabriel Narutowicz</strong> — pierwszy prezydent II RP (zamordowany w 1922), <strong>Gabriel García Márquez</strong> — kolumbijski noblista, i <strong>Gabriel Fahrenheit</strong> — twórca skali temperatury.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gabryś, Gabrysio, Gabi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gabriel (ang., franc., hiszp., niem.), Gábor (węg.), Gabriele (wł.), Гавриил (ros.)</p></div>',

  "Zygmunt": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zygmunt pochodzi ze <strong>starowysokonieimeckiego</strong> — od <em>Sigismund</em>: <em>sigi</em> (zwycięstwo) + <em>mund</em> (ochrona, ręka). Znaczenie: <strong>„zwycięski obrońca"</strong> lub „chroniący zwycięstwo".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili polscy królowie z dynastii Jagiellonów i Wazów: <strong>Zygmunt I Stary, Zygmunt II August</strong> i <strong>Zygmunt III Waza</strong>. Znani Zygmunty to <strong>Zygmunt Freud</strong> — twórca psychoanalizy, i <strong>Zygmunt Krasiński</strong> — polski poeta romantyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zygmuś, Zygmuntek, Zyga</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sigismund (ang., niem., łac.), Sigmund (ang.), Sigismondo (wł.), Segismundo (hiszp.), Жигмонд (węg.)</p></div>',

  "Anita": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Anita to <strong>zdrobnienie</strong> imienia Ana/Anna, które pochodzi z języka hebrajskiego — od <em>hannāh</em>: <strong>„łaska, pełna łaski"</strong>. Forma Anita popularna jest szczególnie w krajach hispanojęzycznych i w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Anity to <strong>Anita Ekberg</strong> — szwedzka aktorka, symbol elegancji w filmie Felliniego <em>Słodkie życie</em>, <strong>Anita Baker</strong> — amerykańska piosenkarka R&B, i <strong>Anita Włodarczyk</strong> — polska mistrzyni olimpijska w rzucie młotem.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anitka, Ania, Anka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anita (ang., hiszp., niem., franc., wł.), Anna (forma pełna), Анита (ros.)</p></div>',

  "Bogusława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bogusława to żeńska forma imienia Bogusław — staropolskiego imienia złożonego z <em>Bogu-</em> (Bóg lub fortuna) i <em>-sław</em> (sława). Znaczenie: <strong>„sławiąca Boga"</strong>. Imię z dawnej warstwy słowiańskich imion chrześcijańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia popularnego w Polsce od XII w. Bogusławowie/Bogusławy były szczególnie popularne na Pomorzu — w dynastii Gryfitów. Dziś imię rzadziej nadawane, ale wciąż obecne w polskim kalendarzu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bogusia, Bogna, Sława</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bohuslava (czes.), Bogomila (płd.-słow.) — imię głównie polskie i słowiańskie</p></div>',

  "Sabina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sabina pochodzi z języka <strong>łacińskiego</strong> — od nazwy starożytnego ludu italskiego <em>Sabini</em> (Sabinowie), zamieszkującego środkową Italię. Znaczenie: <strong>„Sabinka, kobieta z ludu Sabinów"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Sabina</strong> (zm. ok. 126) — chrześcijańska męczennica, patronka imienia. Znana jest też <strong>Poppea Sabina</strong> — żona cesarza Nerona, i <strong>Vibia Sabina</strong> — żona cesarza Hadriana. Wśród współczesnych znana jest polska łyżwiarka <strong>Sabina Wojtala</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sabinka, Sabcia, Binka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sabine (niem., franc.), Sabina (ang., wł., hiszp.), Сабина (ros.)</p></div>',

  "Jagoda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Jagoda to polskie imię żeńskie, które nawiązuje do słowa <strong>jagoda</strong> — czyli leśny owoc. Wywodzi się jako zdrobnienie imion Jadwiga lub Agata. Imię dosłownie kojarzy się z naturą i słodyczą.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce już w średniowieczu — zapis z 1423 roku notuje je jako imię męskie (Thomas Jagoda). Dziś funkcjonuje wyłącznie jako imię żeńskie. 2 lipca obchodzi się ludowe święto Matki Bożej Jagodnej, skojarzono z tym imieniem.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jagódka, Jagusia, Jaga</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Brak bezpośrednich odpowiedników — imię typowo polskie; powiązane z Jadwigą: Hedwig (niem.), Edwige (wł.)</p></div>',

  "Julian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Julian pochodzi z języka <strong>łacińskiego</strong> — od <em>Iulianus</em>, wywodzącego się od rodu Juliuszów (<em>Iulius</em>). Etymologia wskazuje na łacińskie <em>Iulus</em> (młody, puszysty) lub na grecki odpowiednik. Znaczenie: <strong>„z rodu Juliuszów"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosił <strong>Julian Apostata</strong> — ostatni pogański cesarz Rzymu. Znani Julianie to <strong>Julian Tuwim</strong> — wybitny polski poeta i satyryk, i <strong>Julian Schwinger</strong> — fizyk, laureat Nagrody Nobla. W serialu <em>Wiedźmin</em> Jaskier to przydomek Juliana Alfreda Pannacottiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Julek, Julo, Jul</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Julian (ang., niem.), Julien (franc.), Giuliano (wł.), Julián (hiszp.), Gyula (węg.)</p></div>',

  "Tymon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tymon pochodzi z języka <strong>greckiego</strong> — od słowa <em>timon</em> (τίμων), oznaczającego <strong>„szanujący, ceniący"</strong>, lub od <em>timao</em> (czcić, cenić). Imię wyraża cześć i szacunek.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane z dramatu Szekspira <strong><em>Tymon Ateńczyk</em></strong> — o szlachcicu, który stał się mizantropem po rozczarowaniu ludźmi. W Polsce Tymon to imię znane m.in. dzięki <strong>Tymonowi Tymańskiemu</strong> — muzykowi i artyście. Imię wróciło do mody w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tymuś, Tymek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Timon (ang., niem., franc.), Timone (wł.), Тимон (ros.) — forma Tymoteusz to pokrewne imię greckie</p></div>',

  "Genowefa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Genowefa pochodzi z języka <strong>celtyckiego</strong> — od <em>geno</em> (ród, potomek) + <em>wefa/veva</em> (kobieta). Znaczenie: <strong>„szlachetna kobieta"</strong> lub „córka nieba". Przez łacinę Genoveva trafiło do języków europejskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Genowefa z Paryża</strong> (ok. 422–512) — patronka Paryża, która modlitwą miała odwrócić najazd Attyli. Jej relikwie czczone są w kościele św. Genowefy (Panteon). W Polsce imię znane od średniowiecza, popularne w XIX–XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Genia, Genka, Wefka, Genosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Genevieve (ang., franc.), Genoveva (niem., hiszp.), Genoveffa (wł.), Женевьева (ros.)</p></div>',

  'Henryka': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Henryka pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Henryk, złożonego z <em>heim</em> (dom, ojczyzna) i <em>ric</em> (władca, władza). Oznacza <strong>„władczyni domu"</strong> lub „pani rodu i ojczyzny". Do Polski dotarło w średniowieczu przez łacińskie <em>Henricus</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce szczególnie w XIX i pierwszej połowie XX w. Henryka Krzywonos (ur. 1953) — polska działaczka „Solidarności", motornicza tramwaju i uczestniczka historycznego strajku sierpniowego 1980 r. w Gdańsku. Henrietta Temple — tytułowa bohaterka powieści Beniamina Disraelego z 1836 r.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Henia, Henka, Heńka, Henrisia, Henryczka, Henrietta, Heniuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Henriette (franc.), Henrietta (ang., niem., węg.), Enriqueta (hiszp.), Enrichetta (wł.), Генриетта (ros.)</p></div>',

  "Tymoteusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tymoteusz pochodzi z języka <strong>greckiego</strong> — od <em>Timotheos</em>: <em>timao</em> (czcić, szanować) + <em>theos</em> (Bóg). Znaczenie: <strong>„czczący Boga"</strong> lub „oddający cześć Bogu".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Tymoteusz</strong> — uczeń i towarzysz świętego Pawła, adresat dwóch listów apostolskich (1 i 2 Tm), jest patronem imienia. Znany jest też kolarz <strong>Fabian Cancellara</strong> (Tymoteusz to imię jego syna). W Polsce imię modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tymek, Tymuś, Timek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Timothy (ang.), Timothée (franc.), Timoteo (wł., hiszp.), Тимофей (ros.), Timotheus (łac.)</p></div>',

  "Regina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Regina pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>regina</em>, oznaczającego <strong>„królową"</strong>. Wywodzi się od <em>rex/regis</em> (król). Imię symbolizuje dostojeństwo i królewskość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Regina</strong> — chrześcijańska męczennica z III w. Znane Reginy to <strong>Regina Spektor</strong> — rosyjsko-amerykańska piosenkarka, i <strong>Regina Hall</strong> — aktorka. W Polsce używane od XIV w., popularne szczególnie w XX w. Imieniny: 7 września.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Reginka, Rega, Regusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Regina (ang., niem., wł.), Reine (franc.), Reina (hiszp.), Régina (franc.), Регина (ros.)</p></div>',

  "Zenon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zenon pochodzi z języka <strong>greckiego</strong> — od <em>Zenodoros</em> lub bezpośrednio od imienia boga Zeusa (<em>Zen-</em>). Znaczenie: <strong>„dar Zeusa"</strong> lub „należący do Zeusa".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Zenon z Elei</strong> (V w. p.n.e.) — grecki filozof, autor słynnych paradoksów (np. paradoks Achillesa i żółwia). W Polsce znany jest <strong>Zenon Martyniuk</strong> — wokalista disco-polo, lider zespołu Akcent. Imię nosił też papież <strong>Zeno</strong> z IV w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zenek, Zeneczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zeno (wł.), Zénon (franc.), Zenón (hiszp.), Zenon (ang.), Зенон (ros.)</p></div>',

  "Diana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Diana pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>diviana</em> (boska, świetlista), związanego z <em>deus</em> (bóg) i <em>dies</em> (dzień). Znaczenie: <strong>„boska, niebiańska"</strong>. Diana to rzymska bogini łowów i Księżyca.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła <strong>Diana, księżna Walii</strong> (1961–1997) — „Księżna Serc", żona księcia Karola. Znane są też <strong>Diana Ross</strong> — legenda muzyki soul/pop, i <strong>Diana Krall</strong> — kanadyjska jazzwoman. W Polsce imię popularne od lat 80.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dianeczka, Disia, Di</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Diana (ang., niem., wł., hiszp.), Diane (franc.), Диана (ros.)</p></div>',

  "Sara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sara pochodzi z języka <strong>hebrajskiego</strong> — od <em>śārāh</em> (שָׂרָה), oznaczającego <strong>„księżniczkę, panią"</strong>. To pierwotna forma imienia żony Abrahama, zmieniona przez Boga z Saraj na Sara.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Sara</strong> jest żoną Abrahama i matką Izaaka — pramatką narodu izraelskiego. Znane Sary to <strong>Sarah Bernhardt</strong> — legendarna francuska aktorka teatralna, i <strong>Sarah Jessica Parker</strong> — aktorka, gwiazda serialu <em>Seks w wielkim mieście</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sarusia, Sarinka, Sarenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sarah (ang., franc., niem.), Sara (wł., hiszp., skandynaw.), Сара (ros.), שָׂרָה (hebr.)</p></div>',

  "Fabian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Fabian pochodzi z języka <strong>łacińskiego</strong> — od rodu Fabiuszów (<em>Fabius</em>), którego nazwa wywodzi się od słowa <em>faba</em> (bób). Znaczenie: <strong>„z rodu Fabiuszów"</strong> lub „ten, który uprawia bób".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Fabian</strong> — papież i męczennik, zginął w 250 r. n.e. podczas prześladowań cesarza Decjusza, jest patronem imienia. Słynny kolarz szosowy <strong>Fabian Cancellara</strong> — szwajcarski mistrz Tour de France. W Polsce wariant Pabian jest rzadszy.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fabianek, Fabek, Fabus</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Fabian (ang., niem.), Fabien (franc.), Fabiano (wł.), Fabián (hiszp.), Фабиан (ros.)</p></div>',

  "Adrianna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Adrianna to żeńska forma imienia Adrian, wywodzącego się z języka <strong>łacińskiego</strong> — od nazwy miasta <em>Hadria</em> (Adria) w północnej Italii, skąd pochodzi też nazwa Morza Adriatyckiego. Znaczenie: <strong>„z Adrii"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znana jest <strong>Adriana Lima</strong> — brazylijska supermodelka, wieloletnia aniołek Victoria&#39;s Secret. W Polsce znana jest <strong>Adrianna Rusowicz</strong> — piosenkarka. Imię zyskało popularność w Polsce w latach 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adrianka, Ada, Adusia, Dusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adriana (wł., hiszp.), Adrienne (franc.), Adriana (ang.), Jadranka (chorwac.), Адриана (ros.)</p></div>',

  "Błażej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Błażej pochodzi z języka <strong>łacińskiego</strong> — od <em>blaesus</em>, oznaczającego <strong>„jąkający się, sepleniący"</strong>. Etymologia wskazuje na cechę wymowy, która stała się imieniem rodu, a następnie świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Błażej</strong> — biskup Sebasty w Armenii, męczennik z IV w., patron chorych na gardło i świec (tradycja poświęcania świec w jego dzień, 3 lutego). Znany jest też <strong>Blaise Pascal</strong> — francuski matematyk, fizyk i filozof. W Polsce imię popularne od średniowiecza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Błażek, Błaźko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Blaise (ang., franc.), Blas (hiszp.), Biagio (wł.), Balázs (węg.), Blasius (łac.)</p></div>',

  "Klara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Klara pochodzi z języka <strong>łacińskiego</strong> — od przymiotnika <em>clarus</em>, oznaczającego <strong>„jasny, sławny, wyraźny"</strong>. Imię wyraża jasność i chwałę.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Klara z Asyżu</strong> (1194–1253) — założycielka zakonu klarysek, przyjaciółka i naśladowczyni św. Franciszka, jest patronką imienia. <strong>Clara Barton</strong> — założycielka Czerwonego Krzyża. W Polsce imię znane od XIII w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klarcia, Klarunia, Klarusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Clara (ang., niem., wł., hiszp.), Claire (franc.), Klára (węg., czes.), Клара (ros.)</p></div>',

  "Roksana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Roksana pochodzi z języka <strong>perskiego</strong> — od <em>Roshanak</em>, oznaczającego <strong>„świetlista, jutrzenka"</strong> lub „blask świtu". Do Europy trafiło przez historię Aleksandra Macedońskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Roksana</strong> (IV w. p.n.e.) — baktriańska księżniczka, żona Aleksandra Wielkiego. W muzyce popularnym imieniem jest utwór <em>Roxanne</em> zespołu The Police (1978). W Polsce znana jest <strong>Roksana Węgiel</strong> — młoda piosenkarka, zwyciężczyni Eurowizji Junior.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Roksi, Roksanka, Roksa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Roxana, Roxanne (ang.), Rossana (wł.), Роксана (ros.), Roxane (franc.)</p></div>',

  "Róża": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Róża pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>rosa</em>, oznaczającego kwiat <strong>róży</strong>. Róża od wieków symbolizuje miłość, piękno i doskonałość. Jest jednym z najbardziej rozpowszechnionych imion kwiatowych na świecie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Róże to <strong>Rosa Parks</strong> — afroamerykańska działaczka praw obywatelskich, która odmówiła ustąpienia miejsca białemu w autobusie (1955), <strong>Róża Luksemburg</strong> — polska działaczka lewicowa, i <strong>Róża Czacka</strong> — polska zakonnica, błogosławiona.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Różyczka, Różusia, Rozia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rose (ang., franc.), Rosa (niem., wł., hiszp.), Rózsa (węg.), Роза (ros.)</p></div>',

  "Żaneta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Żaneta to polska adaptacja francuskiego imienia <strong>Jeannette</strong> — zdrobnienia od Jeanne (Jan). Wywodzi się z hebrajskiego <em>Johanan</em>: <strong>„Bóg jest łaskawy"</strong>. Forma Janette lub Żaneta wniosła do polszczyzny galicyjski akcent.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce w latach 80.–90. XX w. Znana jest <strong>Janette MacDonald</strong> — amerykańska aktorka i piosenkarka z ery kina dźwiękowego, i <strong>Jeanette Lee</strong> — mistrzyni bilardu. W Polsce imię kojarzy się z popkulturą lat 80.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Żanetka, Żanka, Neta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jeannette (franc.), Janet, Janette (ang.), Jeanette (niem., skandynaw.)</p></div>',

  'Cecylia': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Cecylia pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu <em>Caecilius</em>, wywodzącego się od łacińskiego <em>caecus</em> (<strong>„ślepy"</strong>). Paradoksalnie imię to nosi patronka muzyki i muzyków — jakby wskazując, że prawdziwa muzyka odczuwana jest sercem, a nie jedynie uszami ciała.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Cecylii — rzymskiej patrycjuszki i dziewicy, męczennicy z II lub III w., <strong>patronki muzyki, muzyków, śpiewaków i organistów</strong>. Według legendy śpiewała Bogu w sercu podczas własnego ślubu. W Polsce noszone od średniowiecza. Cecilia Bartoli (ur. 1966) — jedna z najwybitniejszych mezzosopranistek na świecie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Celka, Cela, Cecylka, Ceśka, Cecyleczka, Cilka, Celusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cecilia (ang., hiszp., wł.), Cécile (franc.), Cäcilie (niem.), Цецилия (ros.)</p></div>',

  "Felicja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Felicja pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>felix</em> (szczęśliwy, pomyślny). Znaczenie: <strong>„szczęśliwa"</strong>. Forma męska to Feliks. Imię wyraża radość i pomyślność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Felicyta</strong> — chrześcijańska męczennica z II w., jedna z pierwszych afrykańskich świętych. Imię nosił też humorystyczny kot filmowy <strong>Felix the Cat</strong> — jedna z najstarszych postaci animowanych w historii. Forma polska Felicja była modna w XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fela, Felcia, Felusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Felicia (ang., wł.), Félicie (franc.), Felicia (hiszp.), Феличия (ros.)</p></div>',

  "Wanda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wanda jest pochodzenia <strong>słowiańskiego lub germańskiego</strong>. Możliwe znaczenie nawiązuje do Wandalów (germańskiego ludu) lub do słowa <em>wand</em> (młoda gałąź). Znaczenie tradycyjne: <strong>„córka Wandalów"</strong> lub „słowiańska pani".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Legendarna <strong>Wanda</strong> — córka Kraka, władca Krakowa, która wolała śmierć niż małżeństwo z germańskim rycerzem. Znane Wandy to <strong>Wanda Rutkiewicz</strong> — polska himalaistka, pierwsza Europejka na Mount Everest (1978), i pianistka <strong>Wanda Landowska</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wandzia, Wandeczka, Wandusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Wanda (ang., niem., franc., wł.), Вандa (ros.) — imię znane przede wszystkim w krajach słowiańskich</p></div>',

  "Elżbieta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Elżbieta to polska forma imienia Elisabeth, które pochodzi z języka <strong>hebrajskiego</strong> — od <em>Elisheba</em>: <em>El</em> (Bóg) + <em>sheba</em> (przysięga lub pełnia). Znaczenie: <strong>„Bóg jest moją przysięgą"</strong> lub „Bogu poświęcona".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili dwaj matkowie biblijne — żona Zachariasza i matka Jana Chrzciciela. Liczne królowe nosiły to imię: <strong>Elżbieta I</strong> i <strong>Elżbieta II</strong> — królowe Anglii. W Polsce znana jest <strong>Elżbieta Barszczewska</strong> — aktorka, i <strong>Elżbieta Czyżewska</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elka, Elusia, Betka, Besia, Elżunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elizabeth (ang.), Elisabeth (niem., franc.), Elisabetta (wł.), Isabel (hiszp.), Erzsébet (węg.), Елизавета (ros.)</p></div>',

  "Karolina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Karolina to żeńska forma imienia Karol, które pochodzi ze <strong>starogermańskiego</strong> — od <em>Karl</em> (wolny człowiek, mężczyzna). Znaczenie: <strong>„wolna kobieta"</strong>. Do Polski trafiło przez łacińską formę <em>Carolina</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularyzowały europejskie księżniczki i królowe, m.in. <strong>Karolina Monakijska</strong> — córka Grace Kelly. Znana jest też <strong>Carolina Herrera</strong> — wenezuelska projektantka mody i <strong>Karolina Kurkova</strong> — czeska supermodelka. W Polsce popularny szczyt lat 90.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Karo, Karolcia, Lina, Karola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Carolina (ang., wł., hiszp.), Caroline (franc., niem., ang.), Карина (ros.)</p></div>',

  "Radosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Radosław to staropolskie imię dwuczłonowe — złożone z <em>Rado-</em> (rado, radość) i <em>-sław</em> (sława). Znaczenie: <strong>„ten, kto rozsławia radość"</strong> lub „sławny z radości". Imię typowo słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Radosławowie to <strong>Radosław Sikorski</strong> — polski polityk i dyplomata, minister spraw zagranicznych, i <strong>Radosław Majdan</strong> — były piłkarz i bramkarz reprezentacji Polski. Forma żeńska to Radosława. Zdrobnienie Radek jest bardzo popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Radek, Radeczek, Rado</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Radoslav (czes., serb., bułg.), Radoslava (forma żeńska), Радослав (ros.)</p></div>',

  "Damian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Damian pochodzi z języka <strong>greckiego</strong> — od <em>damazein</em> (ujarzmić, poskromić) lub od imienia boga Damiosa. Znaczenie: <strong>„ten, który poskramia"</strong> lub „nieugięty".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święci Kosma i Damian</strong> — bracia i lekarze, patroni medyków i aptekarzy (zm. ok. 303). Znani Damianie to <strong>Damian Lillard</strong> — ameryk. koszykarz NBA, i <strong>Damián Damiani</strong> — włoski reżyser. W Polsce imię popularne od lat 80. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Damianek, Damek, Damo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Damian (ang., niem.), Damien (franc.), Damiano (wł.), Damián (hiszp.), Дамиан (ros.)</p></div>',

  "Tadeusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tadeusz pochodzi z języka <strong>aramejskiego lub hebrajskiego</strong> — od <em>Taddai</em>, co tłumaczy się jako <strong>„odważny serce"</strong> lub „ten, który chwali". Możliwe też połączenie z imieniem Teodot.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Tadeusz</strong> — apostoł Jezusa. W literaturze polskiej imię rozsławił epos Adama Mickiewicza <strong><em>Pan Tadeusz</em></strong> (1834). Znani Tadeuszowie to <strong>Tadeusz Kościuszko</strong> — generał i bohater, i <strong>Tadeusz Różewicz</strong> — wybitny poeta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tadek, Taduś, Tadzio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thaddeus (ang., łac.), Thaddée (franc.), Taddeo (wł.), Tadeo (hiszp.), Фаддей (ros.)</p></div>',

  "Przemysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Przemysław to staropolskie imię dwuczłonowe — złożone z <em>Przemysł</em> (pomysłowość, przebiegłość, kunszt) i <em>-sław</em> (sława). Znaczenie: <strong>„sławny ze swej przebiegłości"</strong> lub „zmyślny i sławny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Przemysł II</strong> (1257–1296) — książę Wielkopolski, który jako pierwszy po rozbiciu dzielnicowym zjednoczył ziemie polskie i koronował się na króla Polski. Znani Przemysławowie to piłkarz <strong>Przemysław Frankowski</strong> i dziennikarz <strong>Przemysław Babiarz</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Przemek, Przemo, Przemuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Přemysl (czes.) — imię głównie polskie bez szerszych odpowiedników</p></div>',

  "Wiesław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wiesław to staropolskie imię dwuczłonowe — złożone z <em>Wie-</em> (wieść, wiedzieć) i <em>-sław</em> (sława). Znaczenie: <strong>„ten, kto rozsławia wiedzę"</strong> lub „sławny z mądrości". Forma żeńska to Wiesława.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Wiesławowie to <strong>Wiesław Myśliwski</strong> — wybitny polski pisarz, dwukrotny laureat Nike, i <strong>Wiesław Gołas</strong> — popularny polski aktor komediowy. Imię typowo polskie, bez odpowiedników w językach niesłowiańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wiesiek, Wiesio, Wietek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vjeslav (czes.), Vieslav (ang. transkrypcja) — imię typowo polskie i słowiańskie</p></div>',

  "Natalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Natalia pochodzi z języka <strong>łacińskiego</strong> — od wyrażenia <em>dies natalis Domini</em> (dzień narodzin Pana), nawiązującego do Bożego Narodzenia. Znaczenie: <strong>„urodzona w Boże Narodzenie"</strong> lub „dar Bożego Narodzenia".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Natalje to <strong>Natalia Gontcharova</strong> — rosyjska artystka awangardowa, i <strong>Natasza Rostowa</strong> — bohaterka powieści Tołstoja <em>Wojna i pokój</em>. W Polsce imię popularne od lat 80. XX w., dziś jedno z częstszych imion dla dziewczynek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nata, Natka, Natalka, Natasza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Natalie (ang., franc., niem.), Natalia (wł., hiszp., ros.), Nathalie (franc.), Наталья (ros.)</p></div>',

  "Waleria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Waleria to żeńska forma imienia Walerian, które pochodzi z języka <strong>łacińskiego</strong> — od rodu Waleriuszów (<em>Valerius</em>), od <em>valere</em> — być silnym, zdrowym. Znaczenie: <strong>„silna, zdrowa, dzielna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Waleria</strong> — patronka imienia. Znana jest też <strong>Valeria Messalina</strong> — żona cesarza Klaudiusza. We współczesnej popkulturze popularna jest rosyjska piosenkarka <strong>Valeria</strong>. W Polsce imię dawnej świetności powoli wraca do użycia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wala, Walka, Walerka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Valeria (ang., wł., hiszp.), Valérie (franc.), Valerie (niem., ang.), Валерия (ros.)</p></div>',

  "Alicja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Alicja to polska forma imienia Alice, które pochodzi ze <strong>starofrancuskiego</strong> <em>Aalis</em> — skrótu od germańskiego <em>Adalheidis</em>: <em>adal</em> (szlachetny) + <em>heid</em> (rodzaj, stan). Znaczenie: <strong>„szlachetna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił Lewis Carroll powieścią <strong><em>Alicja w Krainie Czarów</em></strong> (1865). Znane Alicje to <strong>Alice Walker</strong> — noblistka, autorka <em>Purpurowego koloru</em>, i <strong>Alicia Keys</strong> — wielokrotna zwyciężczyni Grammy. W Polsce imię znane od XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ala, Alka, Alcia, Alisz</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alice (ang., franc., wł.), Alicia (hiszp.), Aliz (węg.), Алиса (ros.)</p></div>',

  "Klaudia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Klaudia to żeńska forma imienia Klaudiusz, które pochodzi z języka <strong>łacińskiego</strong> — od rodu Klaudiuszów (<em>Claudia gens</em>), wywodzącego się od łacińskiego <em>claudus</em> — <strong>„kulawy"</strong>. Imię oznacza „z rodu Klaudiuszów".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosi znana supermodelka <strong>Claudia Schiffer</strong> — niemiecka modelka, jedna z twarzy lat 90. Znana jest też <strong>Claudia Cardinale</strong> — włoska aktorka filmowa. W Polsce imię popularne szczególnie od lat 80. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klauda, Klaudka, Klauś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Claudia (ang., niem., wł., hiszp.), Claude (franc., forma neutralna), Клавдия (ros.)</p></div>',

  "Patryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Patryk pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>patricius</em>, oznaczającego <strong>„szlachcic, senator, patricy"</strong>. W Rzymie patrycjusze tworzyli warstwę rządzącą. Imię symbolizuje szlachetność i wysokie urodzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Patryk</strong> (ok. 387–461) — apostoł Irlandii, patron tego kraju. 17 marca obchodzi się jego dzień jako irlandzkie święto narodowe (St. Patrick&#39;s Day). Znani Patrykowie to <strong>Patrick Stewart</strong> — aktor, i <strong>Patrick Mahomes</strong> — gwiazdor NFL.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Patrycek, Patryczek, Patrik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Patrick (ang., franc., niem.), Patrizio (wł.), Patricio (hiszp.), Patricius (łac.), Patrik (czes.)</p></div>',

  "Walentyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Walentyna to żeńska forma imienia Walenty, które pochodzi z języka <strong>łacińskiego</strong> — od <em>valens</em> (silny, zdrowy). Znaczenie: <strong>„silna, zdrowa, dzielna"</strong>. Forma żeńska Valentina jest popularna w Europie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Walentyna Tierieszkowa</strong> (ur. 1937) — pierwsza kobieta w kosmosie, radziecka kosmonautka (1963). Patronem dnia 14 lutego jest <strong>święty Walenty</strong> — patron zakochanych. Walentynki (14 lutego) wzięły od niego nazwę.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Walka, Walcia, Walentynka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Valentina (ang., wł., hiszp., ros.), Valentine (franc.), Валентина (ros., ukr.)</p></div>',

  "Sylwia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sylwia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>silva</em> (las). Znaczenie: <strong>„leśna, córka lasu"</strong>. Forma żeńska imienia Sylwester. W mitologii Rea Silwia była matką Romulusa i Remusa — założycieli Rzymu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Silvia Reina</strong> — królowa Szwecji, żona króla Karola XVI Gustawa. Znana jest też <strong>Sylvia Plath</strong> — amerykańska poetka i autorka <em>Szklanego klosza</em>. W Polsce imię popularne szczególnie w latach 80.–90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwia, Sylweczka, Sylwa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Silvia (wł., hiszp.), Sylvie (franc.), Sylvia (ang., niem.), Сильвия (ros.)</p></div>',

  "Benedykt": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Benedykt pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>benedictus</em>, oznaczającego <strong>„błogosławiony"</strong>. Wywodzi się od <em>bene</em> (dobrze) + <em>dicere</em> (mówić, błogosławić). Imię to wyraża Boże błogosławieństwo.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Benedykt z Nursji</strong> (480–547) — ojciec zachodniego monastycyzmu, założyciel benedyktynów, patron Europy. Imię nosił też <strong>papież Benedykt XVI</strong> (Joseph Ratzinger) — emerytowany papież. Znany jest też <strong>Benedict Cumberbatch</strong> — aktor.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benik, Benio, Benedek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedict (ang.), Benoît (franc.), Benedetto (wł.), Benito (hiszp.), Benedikt (niem.), Бенедикт (ros.)</p></div>',

  "Norbert": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Norbert pochodzi ze <strong>starowysokoniemieckiego</strong> — złożone z <em>nord</em> (północ) + <em>beraht</em> (jasny, błyszczący). Znaczenie: <strong>„jasny z północy"</strong> lub „blask północy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Norbert z Xanten</strong> (1080–1134) — założyciel zakonu norbertanów (premonstratensów), arcybiskup Magdeburga, jest patronem imienia. W Polsce imię znane od XII w. Znany jest też <strong>Norbert Wiener</strong> — twórca cybernetyki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Norber, Norber, Norbi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Norbert (ang., franc., niem.), Norberto (wł., hiszp.), Норберт (ros.)</p></div>',

  "Monika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Monika pochodzi prawdopodobnie z języka <strong>berberyjskiego lub punickiego</strong> (afrykańskiego), gdzie oznaczało <strong>„jedyna, samotna"</strong>. Inne etymologie wskazują na grecki <em>monos</em> (jeden) lub łacińskie <em>monere</em> (doradzać).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Monika</strong> (332–387) — matka świętego Augustyna, której modlitwy przyczyniły się do nawrócenia syna, jest patronką imienia. Znane Moniki to <strong>Monica Bellucci</strong> — włoska aktorka, i <strong>Monika Richardson</strong> — polska dziennikarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Monia, Moniczka, Monisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Monica (ang., wł.), Monique (franc.), Mónica (hiszp.), Monika (niem., skandynaw.), Моника (ros.)</p></div>',

  "Emilia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emilia pochodzi z języka <strong>łacińskiego</strong> — od rodu Emiliuszów (<em>Aemilia gens</em>), wywodzącego się od łacińskiego <em>aemulus</em> — <strong>„rywalizujący, starający się dorównać"</strong>. Imię oznacza staranie i ambicję.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Emilie to <strong>Émile Zola</strong> — francuski pisarz (forma męska), i <strong>Emily Dickinson</strong> — wybitna poetka americańska. W literaturze polskiej słynna jest <strong>Emilia Plater</strong> — bohaterka powstania listopadowego 1831. Dziś jedno z najpopularniejszych imion w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Emilka, Emi, Milka, Mila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emily (ang.), Émilie (franc.), Emilia (niem., wł., hiszp.), Эмилия (ros.)</p></div>',

  "Wincenty": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wincenty pochodzi z języka <strong>łacińskiego</strong> — od czasownika <em>vincere</em> (zwyciężać). Imię oznacza <strong>„zwycięski, zwyciężający"</strong>. Weszło do Polski przez łacińską formę kościelną <em>Vincentius</em>, popularną dzięki kultowi świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Wincenty à Paulo</strong> (1581–1660) — francuski kapłan, założyciel zgromadzenia wincentynów i sióstr miłosierdzia, patron dzieł miłosierdzia. <strong>Wincenty Kadłubek</strong> (ok. 1150–1223) — kronikarz, biskup krakowski, błogosławiony. <strong>Wincenty Witos</strong> (1874–1945) — trzykrotny premier Rzeczypospolitej, przywódca ruchu ludowego, symbol chłopskiego patriotyzmu. Imię znane w Polsce od wieków, szczyt popularności przypadł na XIX i pierwszą połowę XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Witek, Winuś, Winek, Wicio, Wincentek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vincent (ang., franc.), Vincenzo (wł.), Vicente (hiszp., port.), Vinzenz (niem.), Vinko (chorw.), Vikentiy (ros. Викентий)</p></div>',

  "Dominika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Dominika to żeńska forma imienia Dominik, które pochodzi z języka <strong>łacińskiego</strong> — od <em>dominicus</em> (pański, należący do Pana). Wywodzi się od <em>dominus</em> (pan, władca). Znaczenie: <strong>„Pańska, należąca do Boga"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma męska Dominik upamiętnia <strong>Świętego Dominika Guzmána</strong> — założyciela zakonu dominikanów (XIII w.). Wśród znanych Dominik: <strong>Dominique Strauss-Kahn</strong> — ekonomista, i piosenkarka <strong>Dominique</strong> (Sœur Sourire). W Polsce imię modne od lat 80.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Domisia, Domi, Dominiczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dominique (franc.), Domenica (wł.), Dominica (ang.), Доминика (ros.)</p></div>',

  "Amelia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amelia pochodzi ze <strong>starogermańskiego</strong> — od <em>Amal</em>, nazwy dynastii Ostrogotów, lub od <em>amal</em> (praca, trud). Znaczenie: <strong>„pracowita, wytrwała"</strong>. Nie należy mylić z imieniem Emilia — oba są różnego pochodzenia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Amelia Earhart</strong> (1897–1937) — pierwsza kobieta, która przeleciała Atlantyk samotnie. Imię popularne wśród europejskich arystokratek. W Polsce Amelia to jedno z najmodniejszych imion XXI w. Znana jest też postać <strong>Amelie</strong> z kultowego francuskiego filmu (2001).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amelka, Amela, Mela, Ame</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amelia (ang., wł., hiszp.), Amélie (franc.), Amalie (niem., skandynaw.), Амелия (ros.)</p></div>',

  "Zbigniew": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zbigniew to staropolskie imię dwuczłonowe — złożone z <em>Zbi-</em> (od <em>zbić, odpędzić</em>) i <em>-gniew</em> (gniew, oburzenie). Znaczenie: <strong>„ten, kto odpędza gniew"</strong> lub „uśmierzający gniew".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosił <strong>Zbigniew Oleśnicki</strong> — kardynał i kanclerz Polski w XV w. Znani Zbigniewowie to <strong>Zbigniew Brzezinski</strong> — doradca prezydenta USA ds. bezpieczeństwa, <strong>Zbigniew Boniek</strong> — najsłynniejszy polski piłkarz, i <strong>Zbigniew Herbert</strong> — poeta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zbyszek, Zbysio, Zbychu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zbigniew (ang., niem. — bez zmian), Zbignev (czes.) — imię typowo polskie bez odpowiedników</p></div>',

  'Florian': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Florian pochodzi z języka <strong>łacińskiego</strong> — od <em>florianus</em>, wywodzącego się z <em>flos, floris</em> (<strong>„kwiat"</strong>). Oznacza „kwitnący", „rozkwitający jak kwiat wiosną". Imię związane z rozkwitem natury i nowym życiem, pełne świeżości i radosnego optymizmu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Floriana (ok. 250–304) — oficera legii rzymskiej w Noricum (dziś Austria), <strong>patrona Polski, Austrii, strażaków i kominiarzy</strong>. Poniósł śmierć męczeńską przez utopienie w rzece Enns. W Polsce <strong>4 maja</strong> — dzień świętego Floriana — jest Dniem Strażaka. Kościół Świętego Floriana w Krakowie to jedna z najstarszych świątyń miasta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Florek, Florianek, Floreczek, Florko, Flo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Florian (niem., franc., ang., pol.), Floriano (wł., hiszp., port.), Флориан (ros.)</p></div>',

  "Henryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Henryk pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Heimrich</em>: <em>heim</em> (dom) + <em>ric</em> (władca, bogaty). Znaczenie: <strong>„władca domu"</strong> lub „bogaty pan". Do Polski trafiło przez kontakty z dynastią Piastów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczne europejskie rody królewskie. Znani Henrykowie to <strong>Henryk VIII</strong> — król Anglii, <strong>Henryk Sienkiewicz</strong> — noblista i autor <em>Quo vadis</em>, <strong>Henryk Ibsen</strong> — norweski dramaturg. W Polsce też <strong>Henryk IV Probus</strong> — książę śląski.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Heniek, Heniu, Henio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Henry (ang.), Henri (franc.), Heinrich (niem.), Enrico (wł.), Enrique (hiszp.), Henrik (skandynaw.)</p></div>',

  "Helena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Helena pochodzi z języka <strong>greckiego</strong> — od <em>Helene</em>, związanego z <em>helios</em> (słońce) lub <em>helene</em> (pochodnia, blask). Znaczenie: <strong>„jasna, świetlista"</strong>. Helena to jedno z najstarszych imion Europy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Helena Trojańska</strong> — mityczna grecka piękność, która stała się przyczyną wojny trojańskiej. <strong>Święta Helena</strong> — matka cesarza Konstantyna, odkrywczyni Krzyża Świętego. W Polsce znana jest <strong>Helena Modrzejewska</strong> — wielka aktorka XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hela, Helenka, Halka, Hania</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Helen (ang.), Hélène (franc.), Elena (wł., hiszp., ros.), Eleni (gr.), Ilona (węg.)</p></div>',

  "Konstancja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Konstancja pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>constantia</em>, oznaczającego <strong>„stałość, wytrwałość, niezłomność"</strong>. Wywodzi się od <em>constans</em> (stały, wytrwały). Forma męska to Konstanty.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczne córki cesarskie w Bizancjum. <strong>Konstancja Sforza</strong> — włoska arystokratka renesansowa. W Polsce znana jest <strong>Konstancja Habsburżanka</strong> — żona Zygmunta III Wazy. Imię wraca do mody w XXI w. jako eleganckie i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kosia, Konka, Stancja</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Constance (ang., franc.), Konstanze (niem.), Costanza (wł.), Constanza (hiszp.), Константина (ros.)</p></div>',

  "Bronisław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bronisław to staropolskie imię dwuczłonowe — złożone z <em>Broni-</em> (bronić) i <em>-sław</em> (sława). Znaczenie: <strong>„ten, kto broni sławy"</strong> lub „sławny obrońca". Forma żeńska to Bronisława.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Bronisławowie to <strong>Bronisław Malinowski</strong> — polski antropolog, jeden z ojców etnografii, i <strong>Bronisław Komorowski</strong> — prezydent RP w latach 2010–2015. Błogosławiona <strong>Bronisława</strong> — siostra błogosławionego Czesława. Imię typowo polskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bronek, Bronio, Broniś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bronislav (czes., ros.), Bronislovas (litew.) — imię głównie polskie i słowiańskie</p></div>',

  "Ambroży": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ambroży pochodzi z języka <strong>greckiego</strong> — od <em>ambrosios</em>, oznaczającego <strong>„nieśmiertelny, boski"</strong>. Wywodzi się od <em>ambrosia</em> — boskiego pokarmu olimpijczyków. Imię wyraża nieśmiertelność i boskość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Ambroży z Mediolanu</strong> (340–397) — jeden z czterech wielkich doktorów Kościoła zachodniego, arcybiskup Mediolanu i nauczyciel świętego Augustyna. Wynalazł jeden ze stylów śpiewu kościelnego (chorał ambrozjański). Patron Mediolanu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ambrek, Ambro</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ambrose (ang.), Ambroise (franc.), Ambrogio (wł.), Ambrosio (hiszp.), Ambrosius (łac.), Амвросий (ros.)</p></div>',

  "Franciszek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Franciszek pochodzi z języka <strong>łacińskiego/germańskiego</strong> — od <em>Franciscus</em>, czyli <strong>„Francuz, z ludu Franków"</strong>. Frankowie byli germańskim ludem, który dał nazwę Francji. Imię symbolizuje przynależność do zachodu Europy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Franciszek z Asyżu</strong> (1181–1226) — założyciel franciszkanów, patron ekologii i zwierząt, jeden z najpopularniejszych świętych. Imię nosił też <strong>papież Franciszek</strong> — pierwszy papież z Ameryki i z zakonu jezuitów. <strong>Franz Kafka</strong> — czeski pisarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Franek, Franio, Franuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Francis (ang.), François (franc.), Francesco (wł.), Francisco (hiszp.), Franz (niem.), Франческо (ros.)</p></div>',

  "Franciszka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Franciszka to żeńska forma imienia Franciszek, wywodzącego się z łaciny/germańskiego — od <em>Franciscus</em>: <strong>„Francuzka, z ludu Franków"</strong>. Imię upamiętnia związek z zachodnim chrześcijaństwem i tradycją franciszkańską.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Franciszka Cabrini</strong> (1850–1917) — pierwsza Amerykanka kanonizowana, założycielka Misjonarek Najświętszego Serca. Znana jest też <strong>Franciszka Cegielska</strong> — polska polityczka. Imię popularne wśród kobiet w polskich tradycjach katolickich XIX–XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Frania, Franka, Franeczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Frances (ang.), Françoise (franc.), Francesca (wł.), Francisca (hiszp.), Franziska (niem.)</p></div>',

  "Celina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Celina pochodzi z języka <strong>łacińskiego</strong> — może wywodzić się od <em>caelum</em> (niebo) lub być skróconą formą imienia Marcellina. Znaczenie: <strong>„niebiańska"</strong> lub „z rodu Celiniuszów".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znana jest <strong>Céline Dion</strong> — kanadyjska piosenkarka, jedna z najlepiej sprzedających się artystek w historii muzyki. Imię nosi też <strong>Celina Śmigas-Dion</strong>. W Polsce imię Celina było popularne w XIX i pierwszej połowie XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Celka, Celineczka, Lina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Céline (franc.), Celina (ang., hiszp., wł.), Celíne (niem.) — imię znane głównie w Europie Zachodniej</p></div>',

  "Natasza": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Natasza to zdrobnienie imienia <strong>Natalia</strong> lub Natasha — imion łacińskiego pochodzenia, wywodzących się od <em>dies natalis Domini</em> (dzień narodzin Pana). Znaczenie: <strong>„urodzona w Boże Narodzenie"</strong>. W Polsce funkcjonuje jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła <strong>Natasza Rostowa</strong> — ukochana bohaterka powieści Lwa Tołstoja <em>Wojna i pokój</em>. Znana jest też <strong>Natasha Bedingfield</strong> — brytyjska piosenkarka i <strong>Natascha McElhone</strong> — aktorka. W Polsce Natasza jako samodzielne imię pojawiła się w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nata, Natka, Tasza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Natasha (ang.), Natacha (franc.), Natascha (niem.), Наташа (ros., forma zdrobniała)</p></div>',

  "Seweryn": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Seweryn pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>severus</em>, oznaczającego <strong>„surowy, poważny, wymagający"</strong>. Wywodzi się z rzymskiego rodu Seweriuszów. Forma żeńska to Seweryna.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Seweryn z Noricum</strong> (V w.) — apostoł Austrii, patron Bawarii i Austrii. Cesarz <strong>Septymiusz Sewer</strong> (146–211) nosił pokrewne imię. W Polsce znany jest kompozytor i pianista <strong>Seweryn Krajewski</strong> — założyciel zespołu Czerwone Gitary.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sewek, Sewuś, Sewerin</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Severin (ang., franc., niem.), Severino (wł., hiszp.), Северин (ros.)</p></div>',

  "Oktawia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Oktawia to żeńska forma imienia Oktawiusz, które pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>octavus</em> (ósmy). Znaczenie: <strong>„ósma"</strong> — imię nadawane ósmemu dziecku w rodzinie lub urodzonym w ósmym miesiącu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oktawia</strong> — siostra cesarza Oktawiana Augusta i żona Marka Antoniusza (I w. p.n.e.), znana ze swej piękności i szlachetności. Imię Augusta (Octavian August) pochodzi od Oktawiusza. W Polsce imię rzadkie, ale wyjątkowo eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oktawka, Tawia, Awia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Octavia (ang., wł., hiszp.), Octavie (franc.), Октавия (ros.)</p></div>',

  "Melania": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Melania pochodzi z języka <strong>greckiego</strong> — od <em>melas/melanos</em>, oznaczającego <strong>„czarny, ciemny"</strong>. Mogło oznaczać kogoś o ciemnej karnacji lub ciemnych włosach. Forma łacińska to Melania.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Melania Młodsza</strong> (383–439) — rzymska arystokratka, która rozdała cały majątek biednym i założyła klasztor w Jerozolimie. W XXI w. imię rozsławiła <strong>Melania Trump</strong> — słoweńska modelka i pierwsza dama USA. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mela, Melanusia, Melanka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Melanie (ang., niem.), Mélanielle (franc.), Melania (wł., hiszp.), Мелания (ros.)</p></div>',

  "Izabela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Izabela to iberyjska forma imienia <strong>Elżbieta</strong>, które pochodzi z hebrajskiego <em>Elisheba</em>: <em>El</em> (Bóg) + <em>sheba</em> (przysięga). Znaczenie: <strong>„Bogu poświęcona"</strong>. Forma Isabel/Isabella dotarła do Polski przez dwory królewskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Izabela Kastylijska</strong> (1451–1504) — królowa Kastylii, która sfinansowała ekspedycję Krzysztofa Kolumba. W Polsce znana jest <strong>Izabela Czartoryska</strong> — założycielka Puławskiego muzeum, i <strong>Izabela Łęcka</strong> — bohaterka <em>Lalki</em> Prusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iza, Izka, Bela, Isia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Isabella (ang., wł.), Isabelle (franc.), Isabel (hiszp., port.), Изабелла (ros.)</p></div>',

  "Leszek": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leszek to staropolskie imię, wywodzące się jako zdrobnienie od imion z członem <em>Lesz-/Leszcz-</em>, związanych ze słowem <em>las</em>. Możliwe też że imię wywodzi się od <strong>leszy</strong> — leśnego ducha słowiańskiego. Znaczenie: <strong>„leśny, z lasu"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili polscy książęta piastowscy: <strong>Leszek Biały</strong> (1186–1227) — książę krakowski i senioralnalny władca Polski. Znani współcześnie Leszkowie to <strong>Leszek Balcerowicz</strong> — ekonomista i autor reform transformacji ustrojowej w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leszuś, Lesik, Leszczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie bez bezpośrednich odpowiedników w innych językach</p></div>',

  "Weronika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Weronika pochodzi z języka <strong>greckiego lub łacińskiego</strong> — możliwa etymologia to greckie <em>phero nike</em> (nosząca zwycięstwo) lub łacińskie <em>vera icon</em> (prawdziwy obraz). Znaczenie: <strong>„niosąca zwycięstwo"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Według tradycji <strong>Weronika</strong> — kobieta, która podczas drogi krzyżowej otarła twarz Jezusa, a na chuście pozostał odcisk Jego oblicza (Święta Chusta). Znana jest też <strong>Weronika Lake</strong> — hollywoodzka aktorka lat 40., i polska poetka <strong>Weronika Murek</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Werka, Weronka, Wera, Ronka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Veronica (ang., wł.), Véronique (franc.), Veronika (niem.), Вероника (ros.)</p></div>',

  "Leopold": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leopold pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Liutpold</em>: <em>liut</em> (lud) + <em>bald</em> (śmiały, odważny). Znaczenie: <strong>„odważny wśród ludu"</strong>. Do Polski trafiło przez kontakty z dynastią Habsburgów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Leopold Mandić</strong> — chorwacki kapłan, patron spowiedników. Imię nosili belgijscy królowie Leopold I–III. <strong>Leopold von Sacher-Masoch</strong> — austriacki pisarz, od którego imienia pochodzi słowo masochizm. <strong>Leopold Staff</strong> — polski poeta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lolek, Leo, Leopoldek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leopold (ang., franc., niem., wł.), Leopoldo (hiszp.), Леопольд (ros.)</p></div>',

  "Aureliusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aureliusz pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>aureus</em>, oznaczającego <strong>„złoty"</strong>. Wywodzi się od <em>aurum</em> (złoto). Imię symbolizuje złotość, doskonałość i wartość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Marek Aureliusz</strong> (121–180) — cesarz Rzymu i filozof stoicki, autor <em>Rozmyślań</em>. Uważany za wzór władcy-filozofa. W Polsce Aureliusz to imię rzadkie, ale eleganckie. Forma żeńska to Aurelia. W Ameryce Łacińskiej forma Aurelio jest popularna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aurel, Aurelek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aurelius (ang., łac.), Aurélius (franc.), Aurelio (wł., hiszp.), Аврелий (ros.)</p></div>',

  "Bożydar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bożydar to staropolskie imię dwuczłonowe — złożone z <em>Boży-</em> (Boży, należący do Boga) i <em>-dar</em> (dar). Znaczenie: <strong>„dar Boży"</strong>. Jest słowiańskim odpowiednikiem łacińskiego Deodatus lub hebrajskiego Natanael.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w Polsce od XIV w. jako forma wcześniejszego Bogodara. Bożydar — jak wiele staropolskich imion dwuczłonowych — przeżywa renesans w XXI w. Forma żeńska to Bożydara. Imię typowo polskie i słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bożek, Dar, Bodar</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Božidar (czes., serb., chorwac.), Bozydar (ang. transkrypcja) — imię typowo słowiańskie</p></div>',

  "Juliusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Juliusz pochodzi z języka <strong>łacińskiego</strong> — od rodu Juliuszów (<em>Iulius gens</em>), najszlachetniejszego rodu Rzymu, który uważał się za potomków bogini Wenus. Etymologia słowa <em>Iulius</em> jest niepewna — możliwe związki z greckim <em>Iulos</em> (puszysty).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Juliusz Cezar</strong> (100–44 p.n.e.) — dyktator Rzymu. W Polsce wybitni Juliusze to <strong>Juliusz Słowacki</strong> — jeden z trzech polskich wieszczów romantycznych, autor <em>Kordiana</em> i <em>Balladyny</em>, i <strong>Juliusz Kossak</strong> — malarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Julek, Julo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Julius (ang., niem.), Jules (franc.), Giulio (wł.), Julio (hiszp.), Юлий (ros.)</p></div>',

  "Balbina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Balbina pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>balbus</em>, oznaczającego <strong>„jąkający się, sepleniący"</strong>. Etymologicznie bliskie imieniu Błażej. Imię nadawane w tradycji chrześcijańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Balbina</strong> — chrześcijańska męczennica z III w., córka Kwiryna. Imię znane w Polsce od średniowiecza. Jest to jedno z rzadszych imion w polskim kalendarzu imienin — Balbiny obchodzą imieniny 31 marca.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Balba, Balbinka, Bala</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Balbina (wł., hiszp.), Balbine (franc.), Balbína (czes.) — imię znane głównie w krajach katolickich</p></div>',

  'Feliks': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Feliks pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>felix</em>, oznaczającego <strong>„szczęśliwy"</strong>, pomyślny, błogosławiony. Wywodzi się prawdopodobnie z <em>ferre</em> — przynosić, nosić. Imię pełne optymizmu, związane z dobrą fortuną i radością życia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię czterech papieży i wielu świętych. Feliks Dzierżyński (1877–1926) — urodzony w Polsce rewolucjonista, założyciel sowieckiej tajnej policji Czeka. Feliks Nowowiejski (1877–1946) — kompozytor, twórca melodii do <em>Roty</em>. Feliks Stamm (1901–1976) — legendarny trener polskich bokserów olimpijskich. W Polsce popularne przez wieki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Felek, Felicianek, Feluś, Feleczek, Felicek, Felunek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Felix (ang., niem., hiszp., port.), Félix (franc.), Felice (wł.), Феликс (ros.)</p></div>',

  "Wacław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wacław to forma polsko-czeskiego imienia, wywodzącego się z czeskiego <em>Václav</em> — złożonego z <em>více</em> (więcej) + <em>sław</em> (sława). Znaczenie: <strong>„bardziej sławny"</strong> lub „ten, kto ma więcej chwały".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Wacław</strong> (907–935) — książę Czech, patron Czech i Pragi, jeden z najważniejszych świętych Europy Środkowej. Jego kult był silny też w Polsce. Znany jest też <strong>Václav Havel</strong> — czeski dramaturg i prezydent Czechosłowacji/Czech.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wacek, Wacio, Watuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Václav (czes.), Wenceslas (ang., franc.), Venceslao (wł., hiszp.), Вацлав (ros.)</p></div>',

  "Narcyz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Narcyz pochodzi z języka <strong>greckiego</strong> — od <em>Narkissos</em>, związanego z <em>narke</em> (otępienie, odurzenie — od zapachu narcyza). Znaczenie: <strong>„odurzający"</strong>. Imię nosi kwiat narcyz i termin psychologiczny narcyzm.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii <strong>Narcyz</strong> — piękny młodzieniec, który zakochał się we własnym odbiciu w wodzie. Od jego imienia pochodzi pojęcie <em>narcyzmu</em>. W tradycji chrześcijańskiej: Święty Narcyz — biskup Jerozolimy (II w.). W Polsce imię rzadkie, ale znane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Narcyzek, Narczyś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Narcissus (łac.), Narciso (wł., hiszp.), Narcisse (franc.), Нарцисс (ros.)</p></div>',

  "Lila": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Lila to imię o kilku możliwych źródłach: może być zdrobnieniem imion <strong>Elżbieta, Emilia, Liliana</strong> lub nawiązywać do arabskiego <em>layla</em> (noc). Może też pochodzi od angielskiego <em>lilac</em> (bez, kolor lila). Znaczenie: <strong>„liliowa, nocna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w wielu kulturach: w literaturze arabskiej <strong>Layla</strong> to symboliczne imię ukochanej. W Polsce Lila to jedno z modnych, krótkich imion dla dziewczynek w XXI w. Znana jest <strong>Lila Grace Moss</strong> — córka supermodelki Kate Moss.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lilka, Lisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lila (ang., franc., niem.), Layla (arab.), Lilah (hebr., ang.), Лила (ros.)</p></div>',

  "Klemens": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Klemens pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>clemens</em>, oznaczającego <strong>„łagodny, miłosierny, wyrozumiały"</strong>. Imię wyraża dobroć i miłosierdzie. Forma żeńska to Klementyna.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczni papieże — aż 14 (od Klemensa I do XIV). <strong>Klemens I</strong> — trzeci następca świętego Piotra, patron marynarzy i kowali. <strong>Klemens Maria Hofbauer</strong> — polski redemptorysta, patron Wiednia. W Polsce znany jest poeta <strong>Klemens Janicki</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klemek, Klemuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Clement (ang.), Clément (franc.), Clemente (wł., hiszp.), Clemens (niem.), Климент (ros.)</p></div>',

  "Kazimiera": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kazimiera to żeńska forma imienia Kazimierz — staropolskiego imienia dwuczłonowego, złożonego z <em>Kazi-</em> (niszczyć, nakazywać) + <em>-mierz</em> (sławę lub pokój). Znaczenie: <strong>„ten, kto nakazuje pokój"</strong> lub „sławę wymuszający".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili polscy królowie: <strong>Kazimierz Wielki</strong> (1310–1370) — król, który zastał Polskę drewnianą, a zostawił murowaną. Znane Kazimiery to <strong>Kazimiera Iłłakowiczówna</strong> — polska poetka. Imię popularne w Polsce szczególnie w XIX i pierwszej połowie XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kazia, Kazka, Kazimiórka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Kasimira (ang.), Casimire (franc.), Casimira (hiszp., wł.), Казимира (ros.)</p></div>',

  "Gertruda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Gertruda pochodzi ze <strong>starowysokoniemieckiego</strong> — złożone z <em>ger</em> (włócznia) i <em>trud</em> (siła, moc). Znaczenie: <strong>„silna włócznią"</strong>. Imię typowo germańskie, znane w Polsce od XIII w. dzięki kontaktom z Zachodem i dynastiom królewskim.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Gertruda Wielka</strong> (1256–1302) — mistyczka, benedyktynka z Helfty, autorka <em>Posłannictwa Bożej miłości</em>. <strong>Gertruda z Nivelles</strong> — patronka podróżników i chorych. <strong>Gertruda Stein</strong> (1874–1946) — pisarka i mecenas paryskiej awangardy (Picasso, Hemingway, Matisse). <strong>Gertruda</strong> — matka Hamleta u Szekspira. W Polsce imię popularne w średniowieczu; dziś rzadkie, o historycznym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gerda, Trudzia, Gerta, Trudy, Gertrudka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gertrude (ang., franc.), Gertrud (niem., skandynaw.), Gertrudes (port.), Гертруда (ros.)</p></div>',

  "Benedikta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Benedikta (Benedicta) to żeńska forma imienia Benedykt, wywodzącego się z języka <strong>łacińskiego</strong> — od <em>benedictus</em> (błogosławiony). Znaczenie: <strong>„błogosławiona"</strong>. To elegancka, historyczna forma imienia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w kręgach benedyktyńskich i wśród europejskich arystokratek. <strong>Benedikta Eleonora</strong> — żona Fryderyka V Palatyna. W Polsce forma Benedykta lub Benedikta jest rzadka, ale znana jako imię historyczne. Zdrobnienie Benka lub Necia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benka, Necia, Benia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedicta (ang., łac.), Bénédicte (franc.), Benedetta (wł.), Benedicta (hiszp.), Benedikta (niem.)</p></div>',


  "Władimir": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Władimir (Włodzimierz) pochodzi ze <strong>starosłowiańskiego</strong> — złożone z <em>vladeti</em> (rządzić) + <em>mir</em> (pokój lub świat). Znaczenie: <strong>„władca świata"</strong> lub „rządzący pokojem". Jest starszą formą polskiego imienia Włodzimierz.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Włodzimierz Wielki</strong> (ok. 958–1015) — wielki książę Kijowa, który ochrzcił Ruś w 988 r. W Polsce Włodzimierz nosił m.in. kompozytor <strong>Włodzimierz Korcz</strong>. Forma Władimir jest typowo rosyjska i nosił ją m.in. <strong>Włodzimierz Lenin</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Włodek, Włodzio, Wołodia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vladimir (ang., franc.), Vladimiro (wł.), Vladimír (czes.), Владимир (ros.)</p></div>',

  "Dorota": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dorota pochodzi z języka <strong>greckiego</strong> — od <em>Dorothea</em>: <em>doron</em> (dar) + <em>theos</em> (Bóg). Znaczenie: <strong>„dar Boży"</strong>. Jest odwróconą formą imienia Teodora (Ten, kto daje Bóg).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Dorota z Cezarei</strong> — chrześcijańska męczennica z IV w., patronka ogrodników i nowożeńców. Słynna jest też <strong>Dorothy</strong> — bohaterka powieści <em>Czarnoksiężnik z Oz</em>. W Polsce znana jest <strong>Dorota Masłowska</strong> — pisarka i dramaturg.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dorotka, Dora, Dosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dorothy (ang.), Dorothée (franc.), Dorota (wł., hiszp. — rzadziej), Дорота (ros.)</p></div>',

  "Renata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Renata pochodzi z języka <strong>łacińskiego</strong> — od <em>renatus</em> (odrodzony), od <em>re-</em> (ponownie) + <em>nasci</em> (rodzić się). Znaczenie: <strong>„odrodzona"</strong> — w kontekście chrześcijańskim odrodzenie przez chrzest.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce w XX w. Znane Renaty to <strong>Renata Tebaldi</strong> — włoska sopranistka operowa, rywalka Marii Callas, i <strong>Renata Przemyk</strong> — polska piosenkarka bluesowa. W Polsce imię szczyt popularności osiągnęło w latach 60.–70.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rena, Renatka, Renusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Renée (franc.), Renata (ang., wł., hiszp., niem.), Рената (ros.)</p></div>',

  "Barnaba": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Barnaba pochodzi z języka <strong>aramejskiego</strong> — od <em>bar naba</em>, co tłumaczy się jako <strong>„syn proroka"</strong> lub „syn pociechy". Grecka forma to Barnabas. Imię biblijne, rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Barnaba</strong> — towarzysz apostoła Pawła, jeden z pierwszych misjonarzy chrześcijańskich na Cyprze. Wspomnienie 11 czerwca. Imię to nosi też <strong>Barnabas Collins</strong> — fikcyjna postać z serialu <em>Dark Shadows</em>. W Polsce imię rzadkie, znane jako imię historyczno-biblijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Barnabeusz, Barnaś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Barnabas (ang., łac.), Barnabé (franc.), Barnaba (wł.), Barnabás (węg.), Варнава (ros.)</p></div>',

  "Rozalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rozalia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>rosa</em> (róża) lub od <em>rosalia</em> — święta ku czci przodków, podczas których zdobiono groby różami. Znaczenie: <strong>„różana"</strong> lub „ofiarująca róże".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Rozalia</strong> (ok. 1130–1160) — sycylijska pustelnica i patronka Palermo. W czasie zarazy 1625 r. modlitwy do niej miały zakończyć epidemię dżumy na Sycylii. W Polsce imię popularne wśród kobiet w XIX w., dziś rzadsze, ale historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rózia, Rozalka, Roza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rosalie (ang., franc.), Rosalia (wł., hiszp.), Rosalia (niem.), Розалия (ros.)</p></div>',

  "Dobrosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Dobrosław to staropolskie imię dwuczłonowe — złożone z <em>Dobro-</em> (dobry, dobroć) i <em>-sław</em> (sława). Znaczenie: <strong>„sławny z dobroci"</strong> lub „ten, kto rozsławia dobro". Imię z dawnej tradycji słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rzadkie w Polsce, należy do archaicznej warstwy słowiańskich imion dwuczłonowych. Obok Dobrosławy (formy żeńskiej) znane są pokrewne imiona: Dobromił, Dobromir, Dobromira. Forma Dobrosław przeżywa dziś mały renesans jako imię historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dobrek, Dobroś, Sławek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dobroslav (czes., serb., bułg.), Dobroslava (forma żeńska) — imię typowo słowiańskie</p></div>',

  "Wirginia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wirginia pochodzi z języka <strong>łacińskiego</strong> — od rodu Virginiuszów (<em>Virginius</em>), wywodzącego się od <em>virgo</em> (dziewica, panna). Znaczenie: <strong>„dziewicza, czysta"</strong>. Imię symbolizuje czystość i niewinność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znana jest <strong>Virginia Woolf</strong> — angielska pisarka i eseistka, jedna z najważniejszych autorek modernizmu (<em>Pani Dalloway</em>, <em>Własny pokój</em>). Stany Virginia i West Virginia w USA wzięły nazwę od królowej Elżbiety I — Dziewiczej Królowej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wirka, Wirgineczka, Ginnia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Virginia (ang., wł., hiszp.), Virginie (franc.), Вирджиния (ros.)</p></div>',

  "Cyryl": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Cyryl pochodzi z języka <strong>greckiego</strong> — od <em>Kyrillos</em>, wywodzącego się od <em>Kyrios</em> (pan, władca). Znaczenie: <strong>„pan, władca"</strong>. Imię związane z kulturą słowiańską przez swojego najsławniejszego nosiciela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Cyryl</strong> (826–869) — wraz z bratem Metodym stworzył alfabet słowiański (głagolicę), od którego cyrylica wzięła nazwę. Apostołowie Słowian, patroni Europy. Cyrylica (ros., ukr., bułg., serb.) do dziś nosi imię świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cyrek, Cyruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cyril (ang., franc.), Cyrillus (łac.), Kirill (ros.), Кирилл (ros.), Kyrillos (gr.)</p></div>',

  "Metody": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Metody pochodzi z języka <strong>greckiego</strong> — od <em>methodos</em> (droga, metoda, sposób postępowania). Znaczenie: <strong>„podążający drogą"</strong> lub „metodyczny". Imię biblijno-historyczne, rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Metody</strong> (815–885) — brat Cyryla, apostoł Słowian, razem z Cyrylem stworzył piśmiennictwo słowiańskie i przetłumaczył Biblię na język staro-cerkiewno-słowiański. Obaj patronują Europie. W Polsce imię bardzo rzadkie, ale historycznie ważne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Metodek, Meto</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Methodius (ang., łac.), Méthode (franc.), Metodio (wł., hiszp.), Мефодий (ros.)</p></div>',

  "Halina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Halina to polska forma imienia <strong>Helena</strong>, która pochodzi z języka greckiego — od <em>Helene</em>, związanego z <em>helios</em> (słońce) lub <em>helene</em> (pochodnia). Znaczenie: <strong>„jasna, świetlista"</strong>. Forma Halina jest typowo polska.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Haliny to <strong>Halina Poświatowska</strong> — polska poetka, autorka lirycznych wierszy miłosnych, i <strong>Halina Kowalska</strong> — polska aktorka. Imię było bardzo popularne w Polsce w pierwszej połowie XX w. Dziś rzadziej nadawane nowym pokoleniom.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Halka, Halunia, Haleczka, Hala</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Helena (forma pełna), Helen (ang.), Hélène (franc.), Elena (wł., hiszp.), Halina (niem., czes.)</p></div>',

  "Ninaida": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ninaida (Naida) to imię o korzeniach <strong>greckich lub słowiańskich</strong> — możliwe połączenie z imieniem Nina lub z greckim <em>naias</em> (nimfa wodna). Znaczenie: <strong>„nimfa, wodna panna"</strong>. Imię rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rzadkie, obecne w polskim kalendarzu imienin. Związane z wodną symboliką — najaidy były nimfami rzek i źródeł w mitologii greckiej. W Polsce funkcjonuje jako imię egzotyczne i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Naidunia, Naidka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Naiad, Naida (ang.), Naïade (franc.), Naiade (wł.) — forma mitologiczna</p></div>',

  "Marta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marta pochodzi z języka <strong>aramejskiego</strong> — od słowa <em>marta</em>, oznaczającego <strong>„pani, władczyni"</strong>. To żeński odpowiednik aramejskiego <em>mar</em> (pan). Imię biblijne, znane w całej tradycji chrześcijańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Ewangelii <strong>Marta z Betanii</strong> — siostra Marii i Łazarza, gościła Jezusa w swoim domu, patronka gospodyń domowych i kucharzy. Znane Marty to <strong>Martha Graham</strong> — pionierka tańca nowoczesnego, i <strong>Marta Kubiszyn</strong> — polska dziennikarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Martunia, Martusia, Martka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Martha (ang., niem.), Marthe (franc.), Marta (wł., hiszp.), Марта (ros.)</p></div>',

  "Łukasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Łukasz pochodzi z języka <strong>łacińskiego lub greckiego</strong> — od <em>Lucas/Lukas</em>, wywodzącego się od <em>lux</em> (światło) lub od nazwy krainy Lukania. Znaczenie: <strong>„świetlisty"</strong> lub „z Lukanii".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Łukasz Ewangelista</strong> — autor trzeciej Ewangelii i Dziejów Apostolskich, lekarz, patron malarzy i lekarzy. Jego symbolem jest wół. Znani Łukaszowie to <strong>Lucas van Leyden</strong> — malarz, i reżyser <strong>George Lucas</strong> — twórca Gwiezdnych Wojen.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Łukasik, Łuczek, Łuku</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Luke, Lucas (ang.), Luc (franc.), Luca (wł.), Lucas (hiszp., niem.), Лука (ros.)</p></div>',

  "Wanda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wanda jest pochodzenia <strong>słowiańskiego</strong> — możliwe związki z prasłowiańskim <em>vęda</em> (wiedza) lub z germańskim ludem Wandalów. Znaczenie: <strong>„córka Wandalów"</strong> lub „słowiańska pani". Imię z polskiej legendy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Legendarna <strong>Wanda</strong> — córka Kraka, która wolała śmierć niż małżeństwo z germańskim rycerzem Rytygerem. Jej grób to Kopiec Wandy pod Krakowem. <strong>Wanda Rutkiewicz</strong> — pierwsza Europejka na Mount Everest (1978). <strong>Wanda Landowska</strong> — pianistka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wandzia, Wandeczka, Wandunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Wanda (ang., niem., franc., wł.) — imię znane przede wszystkim w krajach słowiańskich i przez polską legendę</p></div>',

  "Modest": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Modest pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>modestus</em>, oznaczającego <strong>„skromny, umiarkowany, powściągliwy"</strong>. Wywodzi się od <em>modus</em> (miara, sposób). Imię wyrażające cnotę skromności.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Modest</strong> — wychowawca świętego Wita, męczennik z IV w. W muzyce znany jest rosyjski kompozytor <strong>Modest Musorgski</strong> — autor <em>Obrazków z wystawy</em> i opery <em>Borys Godunow</em>. W Polsce imię rzadkie, ale historycznie znane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Modek, Modeś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Modestus (łac.), Modeste (franc.), Modesto (wł., hiszp.), Модест (ros.)</p></div>',

  "Sylwana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sylwana to żeńska forma imienia Sylwan, wywodząca się z języka <strong>łacińskiego</strong> — od <em>silva</em> (las). Znaczenie: <strong>„leśna, córka lasu"</strong>. Spokrewnione z imionami Sylwia i Sylwester.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nawiązuje do Sylwanusa — rzymskiego boga lasów i pasterzy. W Polsce Sylwana to imię rzadkie, ale znane. Forma Silvana jest popularna we Włoszech. Znana jest włoska aktorka <strong>Silvana Mangano</strong> — gwiazda lat 50.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwanka, Sylwa, Wana</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Silvana (wł.), Sylvaine (franc.), Silvana (hiszp.), Сильвана (ros.)</p></div>',


  "Wiktoria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wiktoria to żeńska forma imienia Wiktor, wywodząca się z języka <strong>łacińskiego</strong> — od słowa <em>victoria</em> (zwycięstwo). Znaczenie: <strong>„zwycięska"</strong>. Victoria była też rzymską boginią zwycięstwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Królowa Wiktoria</strong> (1819–1901) — najdłużej panująca monarchini Wielkiej Brytanii, dała nazwę epoce wiktoriańskiej. W Polsce znana jest <strong>Wiktoria Wiedeńska</strong> (1683) — zwycięstwo Jana III Sobieskiego nad Turkami. Imię jedno z najpopularniejszych w Polsce XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wika, Wikcia, Wisia, Toria</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Victoria (ang., hiszp., wł.), Victoire (franc.), Viktoria (niem.), Виктория (ros.)</p></div>',

  "Eryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eryk pochodzi ze <strong>staronordyjskiego</strong> — od <em>Eiríkr</em>: <em>ei</em> (zawsze, wieczny) + <em>ríkr</em> (władca, potężny). Znaczenie: <strong>„wieczny władca"</strong> lub „zawsze potężny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Eryk Rudy</strong> — wikingski odkrywca Grenlandii (X w.), ojciec Leifa Erikssona. Imię nosili liczni skandynawscy królowie. <strong>Erik Satie</strong> — francuski kompozytor awangardowy. W Polsce imię popularne szczególnie od lat 80. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Eryczek, Eryś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eric (ang., franc.), Erik (skandynaw., niem.), Erico (wł.), Érico (hiszp.), Эрик (ros.)</p></div>',

  'Eleonora': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eleonora pochodzi prawdopodobnie z języka <strong>starofrancuskiego</strong> lub <strong>prowansalskiego</strong> — od <em>Aliénor</em>. Etymologia niepewna: część badaczy wiąże je z arabskim <em>al-nūr</em> (<strong>„światło"</strong>), inni z greckim <em>helene</em> (jasność) lub łacińskim <em>aelianus</em>. Imię o wielowiekowej królewskiej tradycji w Europie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Eleonora Akwitańska (ok. 1122–1204) — jedna z najpotężniejszych kobiet średniowiecza, królowa Francji i Anglii. Eleanor Roosevelt (1884–1962) — pierwsza dama USA, współautorka Powszechnej Deklaracji Praw Człowieka ONZ (1948). Eleonora Duse (1858–1924) — wybitna włoska aktorka, rywalka Sary Bernhardt.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elka, Nora, Lora, Eleonorka, Neli, Elenka, Lorka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eleanor (ang.), Éléonore (franc.), Eleonora (wł., hiszp., port.), Eleonore (niem.), Элеонора (ros.)</p></div>',

  "Remigiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Remigiusz pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>remigium</em> (wiosłowanie, wiosłarstwo), wywodzącego się od <em>remus</em> (wiosło). Znaczenie: <strong>„wioślarz"</strong>. Imię rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Remigiusz</strong> (437–533) — arcybiskup Reims, który ochrzcił Chlodwiga — króla Franków w 496 r., co zapoczątkowało chrystianizację Galii. Jest patronem Francji. W Polsce imię znane, choć rzadko nadawane współcześnie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Remek, Remiguś, Remi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Remigius (łac.), Rémi (franc.), Remigio (wł., hiszp.), Ремигий (ros.)</p></div>',

  "Tekla": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tekla pochodzi z języka <strong>greckiego</strong> — od <em>Thekla</em>: <em>theos</em> (Bóg) + <em>kleos</em> (chwała). Znaczenie: <strong>„chwała Boża"</strong>. Imię biblijno-chrześcijańskie, historyczne w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Tekla z Ikonium</strong> — uczennica apostoła Pawła, uważana za pierwszą kobietę-męczennicę. W Polsce imię Tekla było popularne w XIX w. Nosił je m.in. ojciec Teofil Lenartowicz — poeta, który pisał o Tekli jako o pięknej Polce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Teklunia, Teklusia, Tecia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thecla (ang., łac.), Thècle (franc.), Tecla (wł., hiszp.), Фёкла (ros.)</p></div>',

  "Zofia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zofia pochodzi z języka <strong>greckiego</strong> — od słowa <em>sophia</em> (σοφία), oznaczającego <strong>„mądrość"</strong>. To jedno z fundamentalnych pojęć filozofii greckiej. Imię symbolizuje mądrość i wiedzę.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Hagia Sophia w Stambule — jeden z największych kościołów świata, nosi imię Mądrości Bożej. W Polsce wybitne Zofie to <strong>Zofia Kossak-Szczucka</strong> — pisarka i współzałożycielka Żegoty, i <strong>Zofia Nałkowska</strong> — pisarka. Imię bardzo popularne przez wieki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zosia, Zosieńka, Zochna, Zocha</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sophia (ang., niem., gr.), Sophie (franc., ang.), Sofía (hiszp.), Sofia (wł.), София (ros.)</p></div>',

  "Roch": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Roch pochodzi z języka <strong>germańskiego</strong> — od <em>hroch</em> lub <em>hrok</em>, możliwe znaczenie <strong>„kruk"</strong> lub nawiązanie do siły i odwagi. Inne źródła wskazują na starofrancuskie <em>roc</em> (skała).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Roch</strong> (ok. 1295–1327) — pielgrzym z Montpellier, który opiekował się chorymi na dżumę we Włoszech. Patron chorych na zaraźliwe choroby i epidemie. W Polsce kult świętego Rocha był silny w czasach zarazy. Imię popularne na polskiej wsi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rochek, Rochu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rocco (wł.), Roque (hiszp., port.), Roch (franc.), Рох (ros., serb.)</p></div>',

  "Hieronim": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hieronim pochodzi z języka <strong>greckiego</strong> — od <em>Hieronymos</em>: <em>hieros</em> (święty) + <em>onoma</em> (imię). Znaczenie: <strong>„noszący święte imię"</strong>. Imię wyrażające duchową godność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Hieronim ze Strydonu</strong> (347–420) — doktor Kościoła, który przetłumaczył Biblię na język łaciński (Wulgata). Patron bibliotekarzy, uczonych i tłumaczy. Znany jest też <strong>Hieronim Bosch</strong> — niderlandzki malarz fantastycznych wizji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hiero, Hieronimek, Jeronimo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jerome (ang.), Jérôme (franc.), Girolamo (wł.), Jerónimo (hiszp.), Иероним (ros.)</p></div>',

  "Kacper": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kacper pochodzi prawdopodobnie z języka <strong>perskiego</strong> — od <em>Gaspar/Kaspar</em>, co tłumaczy się jako <strong>„strażnik skarbca"</strong> lub „pan skarbu". Imię jedno z trzech Króli Mędrców.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Tradycja chrześcijańska przypisuje imię Kacper jednemu z Trzech Króli (Magów) — obok Melchiora i Baltazara — którzy przynieśli dary Jezusowi. Ich relikwie czczone są w Kolonii. W Polsce imię bardzo popularne w XXI w. Znany jest też <strong>Caspar David Friedrich</strong> — malarz romantyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kaśka (żart.), Kacperek, Kacpuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Caspar, Jasper (ang.), Gaspard (franc.), Gaspare (wł.), Gaspar (hiszp.), Каспар (ros.)</p></div>',

  'Melchior': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Melchior pochodzi prawdopodobnie z języka <strong>hebrajskiego</strong> lub <strong>perskiego</strong> — od <em>melekh</em> (król) i <em>or</em> (światło). Oznacza <strong>„król światła"</strong>. Tradycja chrześcijańska przypisuje to imię jednemu z Trzech Króli, którzy przybyli oddać hołd narodzonemu Jezusowi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Według tradycji Melchior był starym, siwym królem z Europy, który przyniósł <strong>złoto</strong> — symbol królewskiej godności Chrystusa. Inicjał M wchodzi w skrót <strong>K+M+B</strong> (Kacper, Melchior, Baltazar) pisany kredą na drzwiach w Święto Trzech Króli (6 stycznia). Melchior Wańkowicz (1892–1974) — wybitny polski pisarz i reporter.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Melchiorek, Melek, Melcio, Melchioruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Melchior (ang., franc., niem., hiszp., pol.), Melchiorre (wł.), Мельхиор (ros.)</p></div>',

  "Baltazar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Baltazar pochodzi z języka <strong>aramejskiego lub babilońskiego</strong> — od <em>Bel-šarra-uṣur</em>: <em>Bel</em> (bóg) + <em>sharra</em> (król) + <em>uṣur</em> (chroń). Znaczenie: <strong>„Bel, chroń króla"</strong>. Imię jednego z Trzech Króli.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Tradycja chrześcijańska wymienia Baltazara jako jednego z Trzech Króli Mędrców. Biblijny <strong>Baltazar</strong> — ostatni król Babilonu, na uczcie widział tajemniczy napis na ścianie (<em>Mane, Tekel, Fares</em>). <strong>Balthazar Getty</strong> — aktor. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Baltazarek, Baltek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Balthasar (ang., niem., franc.), Baldassare (wł.), Baltasar (hiszp.), Валтасар (ros.)</p></div>',

  "Czesława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Czesława to żeńska forma imienia Czesław — staropolskiego imienia dwuczłonowego. Wywodzi się od prasłowiańskiego <em>čajati</em> (oczekiwać) i <em>-sława</em> (sława). Znaczenie: <strong>„oczekująca sławy"</strong> lub „czcigodna i sławna".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Błogosławiona <strong>Czesława</strong> — dominikanka z Wrocławia, siostra błogosławionego Jacka Odrowąża (XIII w.). Imię popularne w Polsce w pierwszej połowie XX w., dziś rzadziej nadawane. Jego żeńska forma wpisuje się w tradycję polskich imion dwuczłonowych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Czesia, Czesieńka, Czeska</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Česlava (czes., słow.), Чеслава (ros.) — imię typowo słowiańskie</p></div>',

  "Bernard": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bernard pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Bernhard</em>: <em>bern</em> (niedźwiedź) + <em>hard</em> (twardy, dzielny). Znaczenie: <strong>„dzielny jak niedźwiedź"</strong> lub „mocny niedźwiedź".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Bernard z Clairvaux</strong> (1090–1153) — doktor Kościoła, reformator monastycyzmu, inicjator II wyprawy krzyżowej. Rasa psa bernardyn wzięła od niego nazwę. <strong>Bernard Shaw</strong> — irlandzki dramaturg, noblista. W Polsce znany jest <strong>Bernard Prus</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bernek, Bernardek, Berny</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bernard (ang., franc.), Bernardo (wł., hiszp.), Bernhard (niem.), Бернард (ros.)</p></div>',

  "Bartłomiej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bartłomiej pochodzi z języka <strong>aramejskiego</strong> — od <em>Bar Talmaj</em> (syn Talmaja). Talmai to imię hebrajskie oznaczające <strong>„bogatego w bruzdy"</strong>. Pełna forma to Bar-Tholmai — „syn Tolmaja".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Bartłomiej Apostoł</strong> — jeden z dwunastu apostołów Jezusa, głosił Ewangelię w Armenii, gdzie poniósł śmierć męczeńską przez obdarcie ze skóry. Jego atrybut to nóż. <strong>Bartholomäus Vischer</strong> — złotnik. W Polsce imię znane od wieków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bartek, Bartuś, Bartu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bartholomew (ang.), Barthélemy (franc.), Bartolomeo (wł.), Bartolomé (hiszp.), Bartholomäus (niem.)</p></div>',

  "Serafin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Serafin pochodzi z języka <strong>hebrajskiego</strong> — od <em>saraph</em> (serafin), oznaczającego <strong>„ognisty"</strong> lub „palący". Serafiny to najwyższa klasa aniołów w tradycji żydowskiej i chrześcijańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Serafin z Sarowa</strong> (1759–1833) — rosyjski mnich prawosławny, jeden z najbardziej czczonych świętych Kościoła wschodniego. Znany jest też <strong>Serafin Kaszuba</strong> — polski misjonarz. Imię rzadkie w Polsce, ale znane w tradycji religijnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Serafinek, Serafek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Seraphim (ang.), Séraphin (franc.), Serafino (wł.), Serafín (hiszp.), Серафим (ros.)</p></div>',

  "Grzegorz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Grzegorz pochodzi z języka <strong>greckiego</strong> — od <em>Gregorios</em>, wywodzącego się od <em>gregorein</em> (czuwać, być czujnym). Znaczenie: <strong>„czujny, czuwający"</strong>. Imię symbolizuje duchową czujność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczni papieże — aż 16 (od Grzegorza I do XVI). <strong>Grzegorz I Wielki</strong> — doktor Kościoła, reformator liturgii (chorał gregoriański). W Polsce wybitny Grzegorz to <strong>Grzegorz Ciechowski</strong> — lider Republiki. <strong>Gregory Peck</strong> — aktor.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Grzesiek, Grześ, Grzesio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gregory (ang.), Grégoire (franc.), Gregorio (wł., hiszp.), Gregor (niem.), Григорий (ros.)</p></div>',

  "Klaudiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Klaudiusz pochodzi z języka <strong>łacińskiego</strong> — od słynnego rodu Klaudiuszów (<em>Claudia gens</em>), wywodzącego się od łacińskiego <em>claudus</em> — <strong>„kulawy"</strong>. Imię oznacza przynależność do rodu cesarskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Klaudiusz</strong> (10 p.n.e. – 54 n.e.) — cesarz Rzymu, uczony i historyk, znany z powieści Roberta Gravesa <em>Ja, Klaudiusz</em>. <strong>Claude Monet</strong> — francuski malarz impresjonizmu. W Polsce imię rzadkie, ale eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klaud, Klauś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Claudius (ang., łac., niem.), Claude (franc.), Claudio (wł., hiszp.), Клавдий (ros.)</p></div>',

  "Wacława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wacława to żeńska forma imienia Wacław — wywodzącego się z czeskiego <em>Václav</em>: <em>více</em> (więcej) + <em>sław</em> (sława). Znaczenie: <strong>„bardziej sławna"</strong>. Forma żeńska popularnego imienia piastowskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię żeńskie powiązane z kultem świętego Wacława — patrona Czech, czczonego też w Polsce. Wacława była popularna w Polsce w pierwszej połowie XX w. Imię typowo słowiańskie, bez szerszych odpowiedników poza krajami słowiańskimi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wacia, Wacka, Wacusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Václava (czes.), Вацлава (ros.) — imię typowo słowiańskie</p></div>',

  "Ksawery": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ksawery pochodzi z języka <strong>baskijskiego</strong> — od nazwy zamku <em>Javier</em> w Nawarze, wywodzącej się od baskijskiego <em>etxe berri</em> (nowy dom). Znaczenie: <strong>„z nowego domu"</strong>. Imię rozsławił jezuicki misjonarz, którego pełne imię brzmiało Francisco de Javier.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Franciszek Ksawery</strong> (1506–1552) — jezuita, jeden z pierwszych towarzyszy Ignacego Loyoli, misjonarz Indii, Japonii i Chin. Ochrzcił setki tysięcy ludzi, zwany „Apostołem Azji". <strong>Ksawery Pruszyński</strong> (1907–1950) — polski dziennikarz i pisarz, reporter wojenny. W Polsce imię popularne w XIX w. wśród szlachty; dziś przeżywa renesans jako imię eleganckie i oryginalne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ksawerek, Ksawek, Wery, Ksawuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Xavier (ang., franc., hiszp., port.), Saverio (wł.), Javier (hiszp.), Xaver (niem.), Ксаверий (ros.)</p></div>',

  "Anzelm": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anzelm pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Anshelm</em>: <em>ans</em> (bóg, bóstwo) + <em>helm</em> (hełm, ochrona). Znaczenie: <strong>„pod ochroną boga"</strong> lub „boski hełm".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Anzelm z Canterbury</strong> (1033–1109) — doktor Kościoła, arcybiskup Canterbury, twórca dowodu ontologicznego na istnienie Boga. Jeden z największych filozofów średniowiecza. W Polsce imię rzadkie, znane głównie w środowiskach kościelnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anzelek, Anzelmuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anselm (ang., niem.), Anselme (franc.), Anselmo (wł., hiszp.), Ансельм (ros.)</p></div>',

  "Eustachy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eustachy pochodzi z języka <strong>greckiego</strong> — od <em>Eustachios</em>: <em>eu</em> (dobrze) + <em>stachys</em> (kłos zboża). Znaczenie: <strong>„bogaty w kłosy"</strong> lub „dobry plon". Imię symbolizuje obfitość i dostatek.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Eustachy</strong> — legendarny rzymski żołnierz, który nawrócił się po ujrzeniu jelenia z krzyżem między rogami (podobna historia co święty Hubert). Patron myśliwych. W Polsce imię Eustachy nosił m.in. <strong>Eustachy Tyszkiewicz</strong> — archeolog.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Stach, Stacho, Eustachek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eustace (ang.), Eustache (franc.), Eustachio (wł.), Eustaquio (hiszp.), Евстафий (ros.)</p></div>',

  "Marianna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Marianna to imię złożone z <strong>Maria</strong> (hebr. „łaska Boża") i <strong>Anna</strong> (hebr. „łaskawa"). Zrost tych dwóch imion tworzy <strong>„podwójnie łaskawą"</strong>. Popularne w całej Europie jako imię maryjne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Marianne</strong> — symbol Francji i Republiki Francuskiej, wyobrażona na pocztówkach i monetach z frygijską czapką. Znane Marianny to <strong>Marianne Faithfull</strong> — brytyjska piosenkarka, i <strong>Marian Anderson</strong> — pierwsza afroamerykańska solistka Metropolitan Opera. W Polsce bardzo popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marysia, Marianeczka, Marynia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marianne (franc., niem.), Marianna (ang., wł., hiszp.), Мариана (ros.)</p></div>',

  "Przemysława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Przemysława to żeńska forma imienia Przemysław — staropolskiego imienia dwuczłonowego, złożonego z <em>Przemysł</em> (pomysłowość) i <em>-sława</em> (sława). Znaczenie: <strong>„sławna ze swej przebiegłości"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię żeńskie powiązane z tradycją Piastów i władców Wielkopolski — od księcia Przemysła II (1257–1296), który zjednoczył Polskę. Przemysława to imię rzadkie, dziś egzotyczne, ale o bogatej historycznej tradycji słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Przemka, Przemusia, Mysia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Přemysla (czes.) — imię typowo polskie i słowiańskie</p></div>',

  "Ildefons": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ildefons pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hildifuns</em>: <em>hild</em> (bitwa) + <em>funs</em> (gotowy). Znaczenie: <strong>„gotowy do bitwy"</strong> lub „bojowy". Do Hiszpanii trafiło przez Wizygotów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Ildefons z Toledo</strong> (607–667) — arcybiskup Toledo, teolog i pisarz, znany z kultu maryjnego. W Polsce imię rzadkie, używane głównie przez tradycję katolicką. <strong>Ildefons Gałęzowski</strong> — XIX-wieczny polski lekarz okulistyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ilek, Ildefoncio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ildefonso (wł., hiszp.), Ildefonse (franc.), Ildephonsus (łac.), Ильдефонс (ros.)</p></div>',

  "Konrad": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Konrad pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Kuonrat</em>: <em>kuon</em> (odważny, śmiały) + <em>rat</em> (rada, mądrość). Znaczenie: <strong>„odważny doradca"</strong> lub „śmiały w radzie".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Konrad Mazowiecki</strong> — książę Polski, który w 1226 r. sprowadził Krzyżaków do Prus, co miało epokowe konsekwencje. <strong>Joseph Conrad</strong> (właśc. Józef Korzeniowski) — polski pisarz piszący po angielsku. <strong>Konrad Adenauer</strong> — pierwszy kanclerz RFN.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Konradek, Konradzik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Conrad (ang.), Konrad (niem., czes.), Corrado (wł.), Конрад (ros.)</p></div>',

  "Ludwik": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ludwik pochodzi ze <strong>starogermańskiego</strong> — od <em>Hlodwig</em>: <em>hlod</em> (sławny) + <em>wig</em> (wojownik, bitwa). Znaczenie: <strong>„sławny wojownik"</strong>. Do Polski trafiło przez kontakty z dynastią Karolingów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili liczni europejscy królowie — 18 królów Francji, od Ludwika I do Ludwika XVIII. <strong>Ludwig van Beethoven</strong> — kompozytor. <strong>Louis Pasteur</strong> — odkrywca pasteryzacji. W Polsce: <strong>Ludwik Waryński</strong> — działacz. Forma żeńska to Ludwika lub Luiza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ludo, Ludek, Luduś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Louis (franc., ang.), Ludwig (niem.), Luigi (wł.), Luis (hiszp.), Людвиг (ros.)</p></div>',

  "Gerarda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Gerarda to żeńska forma imienia Gerard, które pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Gerhard</em>: <em>ger</em> (włócznia) + <em>hard</em> (twardy, dzielny). Znaczenie: <strong>„dzielna włócznia"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Gerard z Csanádu</strong> — wenecki mnich, misjonarz Węgier, męczennik z XI w. — patron formy męskiej. Gerarda to rzadka forma żeńska, używana w Polsce tradycyjnie. Imię eleganckie i historyczne, bez szerszego użycia poza krajami katolickimi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gera, Gerardka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gerarda (wł., hiszp.), Gérarde (franc.), Gerarda (ang.) — forma rzadka</p></div>',

  "Teodor": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Teodor pochodzi z języka <strong>greckiego</strong> — od <em>Theodoros</em>: <em>theos</em> (Bóg) + <em>doron</em> (dar). Znaczenie: <strong>„dar Boży"</strong>. Jest odwróconą formą imienia Dorota.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Teodorowie to <strong>Teodor Roosevelt</strong> — 26. prezydent USA, od którego imienia pochodzi pluszowy miś (<em>teddy bear</em>), i <strong>Fiodor Dostojewski</strong> (Teodor — ros. Fiodor) — wielki rosyjski pisarz. W Polsce imię nosił <strong>Teodor Axentowicz</strong> — malarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tedor, Tedek, Felek (przez ros. formę)</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theodore (ang.), Théodore (franc.), Teodoro (wł., hiszp.), Theodor (niem.), Фёдор (ros.)</p></div>',

  "Kandyda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kandyda pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>candidus</em>, oznaczającego <strong>„biały, lśniący, czysty"</strong>. Imię symbolizuje czystość i niewinność. Stąd pochodzi też słowo <em>kandydat</em> (w Rzymie kandydaci na urzędy nosili białe togi).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Kandyda</strong> — chrześcijańska męczennica. <strong>Candide</strong> — bohater filozoficznej powiastki Woltera (1759), symbol naiwnego optymizmu. Imię rzadkie w Polsce, ale znane w tradycji katolickiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kandydka, Kandzia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Candida (ang., wł., hiszp.), Candide (franc.), Кандида (ros.)</p></div>',

  "Bazyli": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bazyli pochodzi z języka <strong>greckiego</strong> — od <em>Basileios</em>, wywodzącego się od <em>basileus</em> (król). Znaczenie: <strong>„królewski, majestatyczny"</strong>. Stąd też pochodzi słowo <em>bazylika</em> (budowla królewska).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Bazyli Wielki</strong> (330–379) — arcybiskup Cezarei, doktor Kościoła wschodniego, organizator życia monastycznego na Wschodzie. Mnisi bazylianie nazwani są od niego. Znany jest też <strong>Wasyl Kandyński</strong> — malarz abstrakcjonizmu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bazylек, Bazyluś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Basil (ang.), Basile (franc.), Basilio (wł., hiszp.), Wasyl (ukr.), Василий (ros.)</p></div>',

  'Bertold': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bertold pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>beraht</em> (jasny, błyszczący, sławny) i <em>wald</em> (władza, panowanie). Oznacza <strong>„jasny władca"</strong> lub „ten, który słynie z mądrości i rządzenia". Imię niegdyś popularne wśród germańskiej szlachty i duchowieństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Bertolt Brecht (1898–1956) — wybitny niemiecki dramaturg i poeta, twórca teatru epicznego, autor <em>Opery za trzy grosze</em>, <em>Matki Courage</em> i <em>Życia Galileusza</em>. Brecht celowo zmienił pisownię swego imienia (Bertolt zamiast Berthold). Bertold Schwarz — XIV-wieczny mnich, któremu przypisuje się wynalezienie prochu strzelniczego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bertek, Bertoldek, Berto, Bertoldeczek, Bertuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Berthold (niem.), Bertoldo (wł.), Bertolde (franc.), Бертольд (ros.)</p></div>',

  "Albina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Albina to żeńska forma imienia Albin, które pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>albus</em> (biały). Znaczenie: <strong>„biała, jasna"</strong>. Imię symbolizuje czystość i jasność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Albina</strong> — chrześcijańska męczennica z III w. W Polsce imię Albina było popularne w XIX i pierwszej połowie XX w. Forma żeńska rzadsza od Albina, ale znana. Albin nosił też <strong>Albín Polášek</strong> — czeski rzeźbiarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alba, Albinka, Bineczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Albina (ang., wł., hiszp.), Albine (franc.), Альбина (ros.)</p></div>',

  "Amand": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amand (Amanda) pochodzi z języka <strong>łacińskiego</strong> — od <em>amandus</em> (godzien miłości), od <em>amare</em> (kochać). Znaczenie: <strong>„ten, kogo należy kochać"</strong>. Forma żeńska Amanda jest popularniejsza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Amand</strong> (ok. 584–675) — apostoł Belgii i Holandii, misjonarz frankijski. Forma żeńska <strong>Amanda</strong> to jedno z popularnych imion angielskich. W Polsce Amand jest imieniem rzadkim, funkcjonującym głównie w tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amantek, Mando</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amand (franc.), Amando (wł., hiszp.), Amanda (forma żeńska), Аманд (ros.)</p></div>',


  "Przemka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Przemka to potoczna forma imienia <strong>Przemysław lub Przemysława</strong>, staropolskiego imienia dwuczłonowego. Złożone z <em>Przemysł</em> (pomysłowość) i <em>-sław</em> (sława). Znaczenie: <strong>„sławna ze swej przebiegłości"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Przemka jako samodzielne imię jest rzadkie w Polsce — najczęściej to zdrobnienie lub przydomek. Wywodzi się z tradycji piastowskiej związanej z księciem Przemysłem II (1257–1296) — pierwszym królem zjednoczonej Polski po rozbiciu dzielnicowym.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Przemeczka, Mysia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Přemyslava (czes.) — imię typowo słowiańskie</p></div>',

  "Katarzyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Katarzyna pochodzi z języka <strong>greckiego</strong> — od <em>Katharos</em> (czysty, niepokalany). Znaczenie: <strong>„czysta, nieskalana"</strong>. Przez łacińską formę <em>Catharina</em> trafiło do Polski.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Katarzyna Aleksandryjska</strong> — patronka uczonych, filozofów i młodych kobiet. <strong>Katarzyna Wielka</strong> — caryca Rosji. W Polsce wybitna jest <strong>Katarzyna Kobro</strong> — rzeźbiarka awangardowa. Jedno z najpopularniejszych imion żeńskich w historii Polski.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kasia, Katarzynka, Kasieńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Katherine, Catherine (ang.), Catherine (franc.), Caterina (wł.), Catalina (hiszp.), Екатерина (ros.)</p></div>',

  "Patrycja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Patrycja to żeńska forma imienia Patryk, wywodząca się z języka <strong>łacińskiego</strong> — od <em>patricius</em> (szlachcic, patrycjusz). Znaczenie: <strong>„szlachetna, z wyższej warstwy"</strong>. Imię symbolizuje arystokratyczne urodzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Patrycje to <strong>Patricia Highsmith</strong> — amerykańska pisarka kryminalna, autorka <em>Utalentowanego pana Ripleya</em>, i <strong>Patricia Kaas</strong> — francuska piosenkarka chanson. W Polsce imię popularne szczególnie od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Patka, Patryczka, Pati</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Patricia (ang., wł., hiszp.), Patrice (franc.), Патриция (ros.)</p></div>',

  "Józefina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Józefina to żeńska forma imienia Józef, wywodząca się z języka <strong>hebrajskiego</strong> — od <em>Yōsēp̄</em> (יוֹסֵף): „niechaj Bóg przysporzy". Znaczenie: <strong>„Bóg doda"</strong> lub „Boże wzmocnienie".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Józefina de Beauharnais</strong> (1763–1814) — pierwsza żona Napoleona Bonaparte, cesarzowa Francji. Znana jest też <strong>Josephine Baker</strong> — afroamerykańska piosenkarka i tancerka, symbol Paryża lat 20. W Polsce imię popularne w XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Józia, Jozia, Jósia, Pepa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Josephine (ang., franc.), Giuseppina (wł.), Josefina (hiszp.), Жозефина (ros.)</p></div>',

  "Zygmunta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zygmunta to żeńska forma imienia Zygmunt, które pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Sigismund</em>: <em>sigi</em> (zwycięstwo) + <em>mund</em> (ochrona). Znaczenie: <strong>„zwycięska obrończyni"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia popularnego wśród polskich królów z dynastii Jagiellonów i Wazów. Imię rzadkie w Polsce, stosowane jako żeński odpowiednik królewskiego Zygmunta. Wpisuje się w tradycję polskich imion nawiązujących do historii dynastycznej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zyga, Zygmunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sigismunda (ang., wł.), Sigismonde (franc.), Sigismunda (hiszp.) — forma bardzo rzadka</p></div>',

  "Jadwiga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jadwiga pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hedwig</em>: <em>hadu</em> (walka) + <em>wig</em> (walka, bitwa). Znaczenie: <strong>„ta, która walczy"</strong>. Do Polski trafiło w XIII w. przez dynastię Piastów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Jadwiga Śląska</strong> (1174–1243) — patronka Polski i Śląska. <strong>Jadwiga Andegaweńska</strong> (1374–1399) — pierwsza kobieta-król Polski (rex Poloniae), żona Jagiełły, kanonizowana przez Jana Pawła II w 1997 r. Jedna z najważniejszych postaci w historii Polski.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jadzia, Jadwisia, Hadzka, Iga</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hedwig (niem.), Hedwige (franc.), Edwige (wł.), Hedvig (szwedz.), Hedvig (węg.)</p></div>',

  "Łucja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Łucja to polska forma imienia Lucia, wywodząca się z języka <strong>łacińskiego</strong> — od słowa <em>lux</em> (światło). Znaczenie: <strong>„jasna, świetlista, córka światła"</strong>. Imię związane z jasnością i dniem.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Łucja z Syrakuz</strong> (zm. 304) — chrześcijańska męczennica, patronka niewidomych i chorych na oczy. W Szwecji jej dzień (13 grudnia) obchodzony jest jako wielkie święto światła (Luciadagen). W Polsce imię znane od średniowiecza, imieniny 13 grudnia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Łucka, Łusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lucia (wł., hiszp.), Lucy (ang.), Lucie (franc.), Luzia (port.), Люция (ros.)</p></div>',

  "Cyprian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Cyprian pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od nazwy wyspy <em>Kypros</em> (Cypr), słynącej z kultu Afrodyty. Znaczenie: <strong>„mieszkaniec Cypru"</strong>. Imię przywiezione przez misjonarzy chrześcijańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Cyprian z Kartaginy</strong> (ok. 200–258) — jeden z pierwszych ojców Kościoła afrykańskiego, biskup i męczennik. W Polsce znany jest <strong>Cyprian Kamil Norwid</strong> — wielki poeta romantyczny, czwarty wieszcz, o którym powiedziano, że „był za wcześnie".</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cypek, Cypris</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cyprian (ang.), Cyprien (franc.), Cipriano (wł., hiszp.), Ципрiан (ukr.)</p></div>',

  "Benigna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Benigna pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>benignus</em> (dobrotliwy, łaskawy, życzliwy). Znaczenie: <strong>„dobrotliwa, łaskawa"</strong>. Imię wyrażające dobroć serca.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Benigna</strong> — chrześcijańska męczennica z III w. Imię rzadkie w Polsce, używane głównie w tradycji kościelnej. W Niemczech Benigna była popularna jako imię klasztorne. Dziś należy do imion historycznych i egzotycznych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benia, Bengusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benigna (wł., hiszp.), Bénigne (franc.), Бенигна (ros.) — imię katolickie</p></div>',

  "Joachim": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Joachim pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yehoyakim</em>: <em>Yeho</em> (Bóg) + <em>yakim</em> (ustanowi, wzmocni). Znaczenie: <strong>„Bóg ustanowi"</strong> lub „Bóg dźwiga".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Joachim</strong> — ojciec Najświętszej Marii Panny, dziadek Jezusa (wg tradycji apokryficznej). Patron ojców i dziadków. Znani Joachimowie to <strong>Joachim von Ribbentrop</strong> — polityk, i <strong>Jochen Schell</strong> — kierowca. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Joachimek, Joach</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Joachim (ang., niem., franc.), Gioacchino (wł.), Joaquín (hiszp.), Иоаким (ros.)</p></div>',

  "Brunon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Brunon pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>brun</em>, oznaczającego <strong>„brązowy, brunatny"</strong>, możliwe też związki z <em>brunnen</em> (źródło). Imię nawiązuje do koloru lub siły przyrody.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Brunon z Kwerfurtu</strong> (974–1009) — misjonarz i męczennik, autor żywota Wojciecha, zginął głosząc Ewangelię Prusom. <strong>Brunon z Kolonii</strong> — założyciel kartuzjanów. W Polsce imię rzadkie. <strong>Bruno Schulz</strong> — wybitny polski pisarz i rysownik z Drohobycza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bruneczek, Bruno</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bruno (ang., wł., franc., hiszp., niem.), Бруно (ros.)</p></div>',

  "Honorata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Honorata to żeńska forma imienia Honorat, wywodząca się z języka <strong>łacińskiego</strong> — od słowa <em>honoratus</em> (zaszczycony, uhonorowany). Znaczenie: <strong>„uhonorowana, zaszczycona"</strong>. Imię wyrażające godność i szacunek.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Błogosławiony Honorat Koźmiński</strong> (1829–1916) — polski kapucyn, założyciel licznych zgromadzeń zakonnych. Imię Honorata było popularne w Polsce w XIX w. Forma żeńska rzadsza od Honoraty we Włoszech i Francji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Honka, Honoratka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Honorata (wł., hiszp.), Honorée (franc.), Honorata (ang.) — imię katolickie</p></div>',

  "Celestyn": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Celestyn pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>caelestis</em> (niebiański, boski), wywodzącego się od <em>caelum</em> (niebo). Znaczenie: <strong>„niebiański, boski"</strong>. Forma żeńska to Celestyna.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili pięciu papieży, m.in. <strong>papież Celestyn V</strong> (1215–1296) — jedyny papież, który dobrowolnie zrzekł się tiary, uwieczniony przez Dantego w <em>Boskiej Komedii</em>. W Polsce imię rzadkie. Planeta Ceres i nazwa <em>celestyna</em> (minerał) nawiązują do podobnych korzeni.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Celestynek, Celest</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Celestine (ang., franc.), Celestino (wł., hiszp.), Celestinus (łac.), Целестин (ros.)</p></div>',

  "Aniela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aniela pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>angelus</em> (anioł, posłaniec), wywodzącego się od greckiego <em>angelos</em>. Znaczenie: <strong>„anielska, posłanniczka"</strong>. Polska forma imienia Angela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Błogosławiona Aniela Salawa</strong> (1881–1922) — polska służąca i mistyczka krakowska, beatyfikowana przez Jana Pawła II. Imię Aniela było bardzo popularne w Polsce w XIX i pierwszej połowie XX w. Znana jest też <strong>Angela Merkel</strong> — kanclerz Niemiec.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ania, Anielka, Anielcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Angela (ang., niem., wł.), Angèle (franc.), Ángela (hiszp.), Ангела (ros.)</p></div>',

  "Sławomir": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sławomir to staropolskie imię dwuczłonowe — złożone z <em>Sław-</em> (sława) i <em>-mir</em> (pokój, świat). Znaczenie: <strong>„sławny z pokoju"</strong> lub „ten, kto rozsławia pokój". Forma żeńska to Sławomira.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Sławomirowie to <strong>Sławomir Mrożek</strong> — wybitny polski dramaturg i rysownik satyryczny, autor <em>Tanga</em> i <em>Emigrantów</em>, i <strong>Sławomir Rawicz</strong> — autor <em>Długiego marszu</em>. Imię typowo polskie, popularne w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sławek, Sławko, Sławuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Slavomír (czes., słow.), Slavomir (ang. transkrypcja), Славомир (ros.) — imię typowo słowiańskie</p></div>',

  "Jowita": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jowita pochodzi z języka <strong>łacińskiego</strong> — od <em>Iovita</em> (Jowiszowa), wywodzącego się od Jowisza (<em>Iuppiter/Iovis</em>) — naczelnego boga rzymskiego. Znaczenie: <strong>„należąca do Jowisza"</strong> lub „córka nieba".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Jowita</strong> — chrześcijańska męczennica z II w. Imię rzadkie w Polsce, ale obecne w kalendarzu imienin. Jowita Budnik — polska aktorka teatralna i filmowa. Imię egzotyczne i wyróżniające się w Polsce, gdzie rzadko nadawane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jowisia, Jowitka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jovita (wł., hiszp.), Jovite (franc.), Иовита (ros.)</p></div>',

  "Leokadia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leokadia pochodzi z języka <strong>greckiego</strong> — od nazwy wyspy <em>Leukas</em> (dziś Lefkada w Grecji), wywodzącej się od <em>leukos</em> (biały). Znaczenie: <strong>„biała, jasna"</strong> lub „z wyspy Leukas".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Leokadia z Toledo</strong> — chrześcijańska męczennica z III w., patronka Toledo. Jej kult był niegdyś silny w Polsce, szczególnie w Poznaniu. Imię popularne w Polsce w XIX i pierwszej połowie XX w. <strong>Leokadia Pancewicz-Leska</strong> — polska śpiewaczka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leosia, Leoka, Kadia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leocadia (wł., hiszp.), Léocadie (franc.), Леокадия (ros.)</p></div>',

  "Tobiasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Tobiasz pochodzi z języka <strong>hebrajskiego</strong> — od <em>Tobiyah</em>: <em>tov</em> (dobry) + <em>yah</em> (Bóg). Znaczenie: <strong>„Bóg jest dobry"</strong>. Imię biblijne, znane z Księgi Tobiasza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Tobiasz</strong> — syn Tobita, którego podróż z archaniołem Rafałem stała się tematem wielu dzieł sztuki. Scena „Tobiasz i Anioł" to jeden z ulubionych motywów malarstwa renesansowego. W Polsce imię popularne w kręgach katolickich, w XXI w. wróciło do mody.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tobias, Tobek, Tobiaszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Tobias (ang., niem.), Tobie (franc.), Tobia (wł.), Tobías (hiszp.), Товий (ros.)</p></div>',

  "Alojzy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alojzy pochodzi z prowansalskiego <em>Aloys</em> — formy imienia Ludwik (<em>Ludwig</em>), wywodzącego się ze starogermańskiego: <em>hlod</em> (sław.) + <em>wig</em> (wojownik). Znaczenie: <strong>„sławny wojownik"</strong>. Forma polska pochodzi z łacińskiego Aloysium.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Alojzy Gonzaga</strong> (1568–1591) — włoski jezuita, patron młodzieży i studentów. Jako syn arystokraty wyrzekł się tytułów i poświęcił opiece nad chorymi. W Polsce imię nadawane tradycyjnie, popularne w XIX w. <strong>Alojzy Feliks</strong> — polski artysta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alojzek, Alojsik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aloysius (ang., łac.), Alois (niem.), Luigi (wł. forma), Алоизий (ros.)</p></div>',

  "Longin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Longin pochodzi z języka <strong>łacińskiego</strong> — od rodu Longinuszów (<em>Longinus</em>), wywodzącego się od <em>longus</em> (długi). Znaczenie: <strong>„długi, wysoki"</strong>. Imię historyczne i biblijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Longin</strong> — według tradycji żołnierz rzymski, który przebił bok Jezusa włócznią podczas ukrzyżowania (<em>włócznia Longina</em>). Relikwia ta jest czczona do dziś. Imię rzadkie w Polsce, obecne w kalendarzu imienin. Popularyzowane przez tradycję chrześcijańską.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lonek, Longin</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Longinus (łac.), Longin (franc.), Longino (wł., hiszp.), Лонгин (ros.)</p></div>',

  "Rozyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rozyna to zdrobnienie imienia <strong>Rozalia lub Róża</strong>, wywodzących się z łacińskiego <em>rosa</em> (róża). Znaczenie: <strong>„różyczka, mała róża"</strong>. W Polsce funkcjonuje jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię Rozyna znane jest z opery <strong>Rosina</strong> — bohaterki <em>Cyrulika sewilskiego</em> Rossiniego (1816), naiwnej dziewczyny uwikłanej w romans z hrabią Almavivą. W Polsce imię rzadkie, o romantycznym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Roza, Rozychna, Rozusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rosina (wł.), Rosine (franc.), Rosina (hiszp.), Розина (ros.)</p></div>',

  "Symeon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Symeon pochodzi z języka <strong>hebrajskiego</strong> — od <em>Shimon</em>, wywodzącego się od <em>shama</em> (słyszeć). Znaczenie: <strong>„wysłuchany przez Boga"</strong> lub „Bóg wysłuchał". Forma grecka to Simon/Szymon.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Symeon Sprawiedliwy</strong> — starzec, który w Świątyni Jerozolimskiej wziął na ręce niemowlę Jezusa i wypowiedział hymn <em>Nunc dimittis</em>. <strong>Symeon I Wielki</strong> — car Bułgarii, złoty wiek literatury bułgarskiej. Forma Szymon używana powszechnie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Symek, Symon</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Simeon (ang., franc.), Simeone (wł.), Simeón (hiszp.), Симеон (ros.), Szymon (pol.)</p></div>',

  "Apolonia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Apolonia pochodzi z języka <strong>greckiego</strong> — od boga <em>Apollon</em> (Apollo), boga słońca, muzyki i sztuk pięknych. Znaczenie: <strong>„córka Apollona"</strong> lub „należąca do Apollona".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Apolonia</strong> — chrześcijańska męczennica z Aleksandrii (III w.), patronka dentystów i chorych na ból zębów (torturowano ją wybijając zęby). Apolonia = pełna forma imienia <strong>Pola Negri</strong> (właśc. Apolonia Chałupiec) — pierwszej polskiej gwiazdy Hollywood.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Pola, Apolka, Apollka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apollonia (ang., wł.), Apollonie (franc.), Apolonia (hiszp.), Аполлония (ros.)</p></div>',

  "Ewald": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ewald pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Egiwald</em> lub <em>Ewalt</em>: <em>ew</em> (wieczny, prawy) + <em>wald</em> (rządca, władca). Znaczenie: <strong>„wieczny rządca"</strong> lub „prawy władca".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święci Ewald Biały i Ewald Czarny</strong> — dwaj bracia i misjonarze fryzyjscy, którzy ponieśli śmierć męczeńską w Westfalii ok. 695 r. Ich relikwie czczono w Kolonii. W Polsce imię rzadkie, używane w tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewaldek, Ewal</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ewald (niem., ang., franc.), Ewaldo (wł.), Эвальд (ros.)</p></div>',

  "Walburga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Walburga pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Walburg</em>: <em>wald</em> (władca, las) + <em>burg</em> (zamek, twierdza). Znaczenie: <strong>„pani zamku"</strong> lub „władczyni twierdzy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Walburga</strong> (ok. 710–779) — angielska mniszka, misjonarka Niemiec, opatka Heidenheim. Jej wspomnienie 1 maja zbiegło się ze starym germańskim świętem Walpurgis Nacht (Noc Walpurgii) — nocą czarownic. W Polsce imię bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Walga, Walburka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Walpurga (niem.), Walburge (franc.), Валбурга (ros.) — imię typowo germańskie</p></div>',

  "Kazimierz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kazimierz to staropolskie imię dwuczłonowe — złożone z <em>Kazi-</em> (niszczyć, nakazywać) i <em>-mierz</em> (pokój, sława). Znaczenie: <strong>„ogłaszający pokój"</strong> lub „niszczący spokój wrogów". Imię dynastyczne polskich Piastów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Kazimierz Jagiellończyk</strong> (1458–1484) — królewicz polski i litewski, patron Polski i Litwy, imieniny 4 marca. <strong>Kazimierz Wielki</strong> — król, reformator i budowniczy. <strong>Kazimierz Dolny</strong> i <strong>Kazimierz</strong> — dzielnica Krakowa noszą to imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kazik, Kazio, Kazimierzek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Casimir (ang., franc.), Casimiro (wł., hiszp.), Казимир (ros.), Kazimieras (litew.)</p></div>',

  "Augustyn": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Augustyn pochodzi z języka <strong>łacińskiego</strong> — od <em>Augustus</em> (majestatyczny, godny czci), wywodzącego się od <em>augere</em> (powiększać, czcić). Znaczenie: <strong>„majestatyczny, czcigodny"</strong>. Imię cesarskie i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Augustyn z Hippony</strong> (354–430) — jeden z największych ojców i doktorów Kościoła, autor <em>Wyznań</em> i <em>O Państwie Bożym</em>. Założyciel zakonu augustianów. <strong>Augustyn z Canterbury</strong> — apostoł Anglii. W Polsce imię rzadkie, ale eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gucio, Gutek, Augustek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Augustine (ang.), Augustin (franc., hiszp.), Agostino (wł.), Augustinus (łac.), Августин (ros.)</p></div>',

  "Wiesława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wiesława to żeńska forma imienia Wiesław — staropolskiego imienia dwuczłonowego, złożonego z <em>Wie-</em> (wieść, wiedzieć) i <em>-sława</em> (sława). Znaczenie: <strong>„sławna z mądrości"</strong> lub „ta, która niesie sławną wiedzę".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znana Wiesława to <strong>Wisława Szymborska</strong> (właściwie Wiesława) — polska poetka, laureatka Nagrody Nobla (1996), jedna z najważniejszych poetek XX w. Jej lapidarne, ironiczne wiersze tłumaczone są na dziesiątki języków. Imię popularne w Polsce w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wiesia, Wieśka, Wiesieńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vjeslava (czes.), Вислава (ros.) — imię typowo polskie i słowiańskie</p></div>',

  "Benedikta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Benedikta (Benedicta) to żeńska forma imienia Benedykt — z języka <strong>łacińskiego</strong> <em>benedictus</em> (błogosławiony). Znaczenie: <strong>„błogosławiona"</strong>. Imię wywodzone z tradycji benedyktyńskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia Benedykt — patrona Europy. <strong>Bénédicte de Bourbon</strong> — księżniczka belgijska. W Polsce Benedikta lub Benedykta to imię rzadkie, używane historycznie w klasztorach benedyktyńskich. Zdrobnienie Benka lub Benia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benka, Benia, Necia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedicta (ang., łac.), Bénédicte (franc.), Benedetta (wł.), Benedicta (hiszp.)</p></div>',

  "Lucjan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Lucjan pochodzi z języka <strong>łacińskiego</strong> — od rodu Lucjanów (<em>Lucianus</em>), wywodzącego się od imienia Lucius, związanego z <em>lux</em> (światło). Znaczenie: <strong>„syn Lucjusza, świetlisty"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Lukian z Samosat</strong> (ok. 120–180) — grecki pisarz satyryczny, autor <em>Prawdziwej historii</em> — pierwszej powieści science fiction w historii. <strong>Lucjan Rydel</strong> — polski dramaturg, bohater <em>Wesela</em> Wyspiańskiego. W Polsce imię popularne w XIX i XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lucjanek, Lucek, Lucjan</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lucian (ang.), Lucien (franc.), Luciano (wł., hiszp.), Лукиан (ros.)</p></div>',

  "Oliwia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Oliwia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>oliva</em> (oliwka, drzewo oliwne). Znaczenie: <strong>„oliwna, symbol pokoju"</strong>. Gałązka oliwna od antyku symbolizuje pokój i pojednanie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła Szekspirowska <strong>Olivia</strong> — bohaterka komedii <em>Wieczór Trzech Króli</em>. Znana jest też <strong>Olivia Newton-John</strong> — australijska piosenkarka i aktorka (<em>Grease</em>). W Polsce Oliwia to jedno z najpopularniejszych imion żeńskich XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ola, Oliwka, Liwia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Olivia (ang., wł., hiszp.), Olive (franc.), Olivie (franc.), Оливия (ros.)</p></div>',

  "Oliwier": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Oliwier to polska forma imienia Oliver, wywodząca się z <strong>łacińskiego</strong> <em>oliva</em> (oliwka) lub ze staronordyjskiego <em>Áleifr</em> (dziedzic przodków). Znaczenie: <strong>„drzewo oliwne"</strong> lub „dziedzic".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W literaturze <strong>Oliwier</strong> to rycerz Karola Wielkiego, przyjaciel Rolanda w <em>Pieśni o Rolandzie</em>. <strong>Oliver Twist</strong> — tytułowy bohater powieści Dickensa. <strong>Oliver Hardy</strong> — komik duetu Flip i Flap. W Polsce imię zyskało popularność w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Olek, Oliwierek, Oli</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Oliver (ang., niem., skandynaw.), Olivier (franc.), Oliviero (wł.), Olivero (hiszp.), Оливер (ros.)</p></div>',

  "Maksymiliana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Maksymiliana to żeńska forma imienia Maksymilian, wywodząca się z języka <strong>łacińskiego</strong> — od <em>Maximilianus</em>: <em>maximus</em> (największy). Znaczenie: <strong>„największa"</strong>. Rzadka i elegancka forma żeńska.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska popularnego imienia Maksymilian — patronem jest <strong>święty Maksymilian Maria Kolbe</strong> — polski franciszkanin, który oddał życie za współwięźnia w Auschwitz. Maksymiliana to imię rzadkie w Polsce, wyjątkowe i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maksia, Maksymilka, Mila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maximiliana (łac., niem.), Maximilienne (franc.), Massimiliana (wł.) — forma bardzo rzadka</p></div>',

  "Arkadiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Arkadiusz pochodzi z języka <strong>greckiego</strong> — od nazwy krainy <em>Arkadia</em> na Peloponezie, słynącej z sielankowej przyrody i szczęśliwego życia pasterzy. Znaczenie: <strong>„mieszkaniec Arkadii"</strong> lub „szczęśliwy pasterz".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W literaturze Arkadia to symbol raju na ziemi — niewinnego, szczęśliwego życia. Łaciński napis <em>Et in Arcadia ego</em> (nawet w Arkadii jestem — mówi Śmierć) jest motywem malarstwa barokowego. W Polsce popularne zdrobnienie Arek jest powszechnie znane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arek, Areczek, Arkuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arcadius (ang., łac.), Arcade (franc.), Arcadio (wł., hiszp.), Аркадий (ros.)</p></div>',

  "Mateusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mateusz pochodzi z języka <strong>hebrajskiego</strong> — od <em>Mattithyahu</em>: <em>mattan</em> (dar) + <em>Yah</em> (Bóg). Znaczenie: <strong>„dar Jahwe"</strong> lub „Boży dar". To samo znaczenie co imię Natanael.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Mateusz Ewangelista</strong> — apostoł Jezusa, były celnik, autor pierwszej Ewangelii. Patron bankierów, celników i księgowych. Symbolem jest człowiek lub anioł. <strong>Matt Damon</strong> i <strong>Matthew McConaughey</strong> — sławni Mateuszowie. W Polsce jedno z modniejszych imion XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mateuszek, Mati, Teo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Matthew (ang.), Matthieu (franc.), Matteo (wł.), Mateo (hiszp.), Matthäus (niem.), Матфей (ros.)</p></div>',

  "Izydor": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Izydor pochodzi z języka <strong>greckiego</strong> — od <em>Isidoros</em>: <em>Isis</em> (egipska bogini) + <em>doron</em> (dar). Znaczenie: <strong>„dar Izydy"</strong>. Egipska bogini Izyda — matka bogów — była czczona w hellenistycznym świecie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Izydor Oracz</strong> (1070–1130) — patron rolników i Madrytu, patron Hiszpanii. <strong>Izydor z Sewilli</strong> — doktor Kościoła, encyklopedysta średniowiecza, uznawany za patrona internetu. W Polsce imię znane od wieków, Izydory obchodzą imieniny 4 kwietnia i 15 maja.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Izek, Izydorek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Isidore (ang., franc.), Isidoro (wł., hiszp.), Isidor (niem.), Исидор (ros.)</p></div>',

  "Elwira": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Elwira pochodzi ze <strong>starowysokoniemieckiego lub arabskiego</strong> — prawdopodobnie z arabskiego <em>al-Wira</em> (biała, blada) lub z germańskiego <em>Alwira</em>: <em>al</em> (wszystko) + <em>wer</em> (prawdziwy). Znaczenie: <strong>„prawdziwie biała"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Hiszpanii i Ameryce Łacińskiej. Znana jest operowa <strong>Elvira</strong> — bohaterka opery Donizettiego <em>Purytanie</em> i <em>Don Giovanniego</em> Mozarta. W Polsce imię Elwira było popularne szczególnie w latach 50.–70. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elwirka, Wirka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elvira (ang., wł., hiszp.), Elwire (franc.), Эльвира (ros.)</p></div>',

  "Sybilla": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sybilla pochodzi z języka <strong>greckiego</strong> — od <em>Sibylla</em>, co oznaczało <strong>„wróżbitkę, prorokinię"</strong>. Sybille były w starożytności kapłankami przepowiadającymi przyszłość, m.in. słynna Sybilla Kumańska.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Sybille przepowiadały losy Rzymu i sprzedały Tarquiniuszowi <em>Księgi Sybillińskie</em>. W Biblii <em>Dies Irae</em> wspomina <em>teste David cum Sibylla</em>. <strong>Sibylle Szaggars</strong> — niemiecka artystka. W Polsce imię rzadkie, literackie i eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sybilka, Syba</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sybil (ang.), Sibylle (franc., niem.), Sibilla (wł.), Sibila (hiszp.), Сивилла (ros.)</p></div>',

  "Sylweriusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Sylweriusz pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>silva</em> (las). Znaczenie: <strong>„leśny, z lasu"</strong>. Spokrewnione z imionami Sylwia i Sylwester. To rzadka forma wywodząca się z tradycji papieskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Sylweriusz</strong> (zm. 537) — papież z VI w., syn papieża Hormizdy, zesłany na wygnanie przez cesarzową Teodorę. Jest patronem imienia. W Polsce imię bardzo rzadkie, obecne w kalendarzu imienin. Znane przez tradycję kościelną.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwek, Sylwuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Silverius (ang., łac.), Silverio (wł., hiszp.), Silvère (franc.), Сильверий (ros.)</p></div>',

  "Marian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marian pochodzi z języka <strong>łacińskiego</strong> — od rodu Mariuszów (<em>Marianus</em>), wywodzącego się od imienia Marius, związanego z bogiem Marsem lub imieniem Maria. Znaczenie: <strong>„z rodu Mariuszów"</strong> lub „poświęcony Marii".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Marianie to <strong>Marian Anderson</strong> — pierwsza afroamerykańska solistka Metropolitan Opera, i <strong>Marian Rejewski</strong> — matematyk, który złamał kod Enigmy przed wojną. W Polsce imię było bardzo popularne w XX w. Forma żeńska to Mariana lub Marianna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marek, Maniek, Maryś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marian (ang., rum.), Mariano (wł., hiszp.), Марьян (ros.)</p></div>',

  "Kornelia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kornelia to żeńska forma imienia Kornel, które pochodzi od <strong>łacińskiego</strong> rodu Kornelii (<em>Cornelia gens</em>). Etymologia wskazuje na łacinę <em>cornu</em> (róg) lub etruskie pochodzenie. Imię oznacza <strong>„z rodu Kornelii"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Kornelia</strong> (II w. p.n.e.) — matka Grakchów, wzór cnoty i mądrości, która powiedziała o swoich synach: „oto moje klejnoty". <strong>Cornelia Parker</strong> — brytyjska artystka konceptualna. W Polsce imię rzadkie, ale eleganckie i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nela, Korcia, Nelia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cornelia (ang., niem., wł.), Cornélie (franc.), Cornelia (hiszp.), Корнелия (ros.)</p></div>',

  "Wawrzyniec": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wawrzyniec to polska forma imienia Laurentius, wywodząca się z języka <strong>łacińskiego</strong> — od nazwy miasta <em>Laurentum</em> lub od <em>laurus</em> (wawrzyn, laur). Znaczenie: <strong>„uwieńczony laurem"</strong> lub „z Laurentum".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Wawrzyniec</strong> — diakon i męczennik z III w., który podczas męczeństwa na ruszcie miał powiedzieć: „Obróćcie mnie, jestem już dopieczony z tej strony". Patron kucharzy i piekarzy. Imię nosili papieże i malarze — <strong>Lorenzo de&#39; Medici</strong> to włoska wersja.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wawrzek, Wawrzon, Lolek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lawrence (ang.), Laurent (franc.), Lorenzo (wł.), Lorenzo (hiszp.), Laurenz (niem.), Лаврентий (ros.)</p></div>',

  "Oktawian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Oktawian pochodzi z języka <strong>łacińskiego</strong> — od <em>Octavianus</em>, wywodzącego się od <em>octavus</em> (ósmy). Znaczenie: <strong>„ósmy"</strong> — imię nadawane ósmy dziecku lub jako imię dynastyczne. Najsłynniejszy nosiciel przyjął przydomek Augustus.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oktawian August</strong> (63 p.n.e. – 14 n.e.) — pierwszy cesarz Rzymu, bratanek Juliusza Cezara. Za jego panowania narodził się Jezus. W Polsce imię rzadkie, używane jako imię historyczne i nawiązanie do starożytności. Forma żeńska to Oktawia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oktawek, Oktan</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Octavian (ang., rum.), Octavien (franc.), Ottaviano (wł.), Octaviano (hiszp.), Октавиан (ros.)</p></div>',

  "Miriam": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Miriam to <strong>hebrajska</strong> forma imienia Maria — najstarsza jej postać. Etymologia niepewna: możliwe znaczenia to <strong>„kochana przez Boga"</strong>, „gorzka morze" lub „pani". To imię, od którego pochodzi Maria i wszystkie jej formy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Miriam</strong> — siostra Mojżesza i Aarona, prorokini, która zaśpiewała pieśń dziękczynną po przejściu przez Morze Czerwone. To najstarsza udokumentowana forma imienia Maria. W Polsce Miriam to imię rzadkie, o biblijnym i poetyckim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Miri, Mirka, Mirusieńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Miriam (ang., franc., niem., wł.), Míriam (hiszp.), Мириам (ros.), מִרְיָם (hebr.)</p></div>',

  "Judyta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Judyta pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yehudit</em>, żeńskiej formy od <em>Yehudah</em> (Juda). Znaczenie: <strong>„z pokolenia Judy"</strong> lub „Żydówka". Imię biblijne, znane z Księgi Judyty.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Judyta</strong> — odważna wdowa z Betulii, która uratowała miasto, odcinając głowę asyryjskiemu wodzowi Holofernesowi. Scena ta jest ulubionym tematem barokowego malarstwa (Artemisia Gentileschi). W Polsce imię rzadkie, biblijne i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Judytka, Jutka, Judy</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Judith (ang., niem.), Judith (franc.), Giuditta (wł.), Judit (hiszp., węg.), Иудифь (ros.)</p></div>',

  "Witosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Witosław to staropolskie imię dwuczłonowe — złożone z <em>Wito-</em> (od <em>wit</em>: pan, władca lub las) i <em>-sław</em> (sława). Znaczenie: <strong>„sławny władca"</strong> lub „sławny z lasu". Imię z dawnej tradycji słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rzadkie w Polsce, należy do warstwy archaicznych imion słowiańskich. Obok Witosława znane są pokrewne imiona Witosława (forma żeńska) i Witold. Imię przeżywa mały renesans w XXI w. jako imię historyczne i oryginalne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Witek, Wituś, Sławek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vitoslav (czes., serb.) — imię typowo słowiańskie bez szerszych odpowiedników</p></div>',

  "Rufin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Rufin pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>rufus</em>, oznaczającego <strong>„rudowłosy, rudy"</strong>. Wywodzi się od <em>ruber</em> (czerwony). Imię nadawane pierwotnie dzieciom o rudych włosach.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Rufin z Asyżu</strong> — jeden z pierwszych towarzyszy świętego Franciszka, kuzyn Klary z Asyżu. <strong>Rufinus z Akwilei</strong> — tłumacz dzieł greckich na łacinę (IV w.). W Polsce imię rzadkie, obecne w kalendarzu imienin w tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rufinek, Rufo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rufinus (łac.), Rufin (franc.), Rufino (wł., hiszp.), Руфин (ros.)</p></div>',

  "Wilhelmina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wilhelmina to żeńska forma imienia Wilhelm, wywodząca się ze <strong>starowysokoniemieckiego</strong> — od <em>Willehelm</em>: <em>willo</em> (wola) + <em>helm</em> (hełm, ochrona). Znaczenie: <strong>„chroniąca swą wolą"</strong> lub „dzielna obrończyni".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Wilhelmina</strong> (1880–1962) — królowa Holandii przez 58 lat, znana ze sprzeciwu wobec nazistowskiej okupacji. Imię popularne wśród europejskich arystokratek. W Polsce rzadkie, ale eleganckie i historyczne. Zdrobnienie Mina lub Wilma.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mina, Wilma, Wilhelminka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Wilhelmina (ang., hol.), Wilhelmine (niem., franc.), Guglielmina (wł.), Guillermina (hiszp.), Вильгельмина (ros.)</p></div>',

  "Chryzostom": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Chryzostom pochodzi z języka <strong>greckiego</strong> — od <em>chrysostomos</em>: <em>chrysos</em> (złoto) + <em>stoma</em> (usta). Znaczenie: <strong>„złotousty"</strong>. Przydomek nadany sławnemu mówcy, który stał się imieniem własnym.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Jan Chryzostom</strong> (347–407) — arcybiskup Konstantynopola, doktor Kościoła, jeden z największych mówców chrześcijaństwa. Jego przydomek <em>Złotousty</em> oddaje niezwykły talent kaznodziejski. W Polsce imię rzadkie, znane przez tradycję kościelną i literaturę.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Chrysek, Krzysztomek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Chrysostom (ang.), Chrysostome (franc.), Crisostomo (wł., hiszp.), Хризостом (ros.)</p></div>',

  "Nadzieja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Nadzieja to <strong>słowiańskie</strong> imię żeńskie, wywodzące się bezpośrednio od słowa <em>nadzieja</em> — <strong>„oczekiwanie czegoś dobrego, wiara w przyszłość"</strong>. Jest słowiańskim odpowiednikiem łacińskiego imienia Spes (Nadzieja).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Nadzieja (Nadeżda) to imię popularne w krajach słowiańskich. Rosyjska <strong>Надежда Крупская</strong> — żona Lenina i działaczka. Bułgarska wersja to Nadeżda. W Polsce Nadzieja to imię rzadkie, ale o pięknym brzmieniu i głębokim znaczeniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nadzia, Nadziuszka, Nada</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nadezhda (ros., bułg.), Nadia (franc., ang.), Надія (ukr.), Nadzieja (pol.) — imię typowo słowiańskie</p></div>',

  "Marceli": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Marceli pochodzi z języka <strong>łacińskiego</strong> — od <em>Marcellus</em>, zdrobnienia od <em>Marcus</em> (imię boga Marsa). Znaczenie: <strong>„mały Marek"</strong> lub „należący do Marsa". Imię z tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili papieże: <strong>Marceli I</strong> (zm. 304) i <strong>Marceli II</strong> (1555) — najkrócej panujący papież nowożytny (22 dni). W Polsce znany jest <strong>Marceli Nowotko</strong> — działacz. <strong>Marcel Proust</strong> — autor <em>W poszukiwaniu straconego czasu</em>. Forma żeńska to Marcelina.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marcelek, Marcel, Marcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marcel (franc., ang., niem.), Marcello (wł.), Marcelo (hiszp.), Марсель (ros.)</p></div>',

  "Erwin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Erwin pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Herewin</em> lub <em>Erwin</em>: <em>heri</em> (wojsko) + <em>wini</em> (przyjaciel). Znaczenie: <strong>„przyjaciel wojska"</strong> lub „przyjaciel żołnierzy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znani Erwinowie to <strong>Erwin Rommel</strong> — niemiecki feldmarszałek z II wojny, znany jako „Lis Pustyni", i <strong>Erwin Schrödinger</strong> — austriacki fizyk, noblista, twórca słynnego eksperymentu myślowego z kotem. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Erwinek, Ero</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Erwin (ang., niem., franc.), Ervino (wł.), Эрвин (ros.)</p></div>',

  "Bogdan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bogdan to staropolskie imię dwuczłonowe — złożone z <em>Bog-</em> (Bóg) i <em>-dan</em> (dany). Znaczenie: <strong>„dany przez Boga"</strong> lub „Boży dar". Jest słowiańskim odpowiednikiem łacińskiego Deodatus lub hebrajskiego Natanael.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne we wszystkich krajach słowiańskich. W Polsce znani Bogdanowie to <strong>Bogdan Łazuka</strong> — aktor i piosenkarz, i <strong>Bogdan Wojcieszek</strong> — reżyser. Forma żeńska to Bogdana. Imię nosili też hospodarowie wołoscy i mołdawscy.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bogdanek, Bogduś, Bogda</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bogdan (ang., franc.), Bogdano (wł.), Богдан (ros., ukr., serb.) — imię typowo słowiańskie</p></div>',

  "Julianna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Julianna to żeńska forma imienia Julian, wywodząca się z języka <strong>łacińskiego</strong> — od rodu Juliuszów (<em>Iulius</em>). Znaczenie: <strong>„z rodu Juliuszów"</strong>. Imię eleganckie, historyczne i biblijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Julianna z Norwich</strong> (ok. 1342–1416) — angielska mistyczka, autorka <em>Objawień Boskiej Miłości</em> — najstarszej zachowanej książki napisanej przez kobietę po angielsku. <strong>Juliana</strong> — królowa Holandii (1948–1980). W Polsce imię modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Julia, Julka, Julcia, Julisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Julianne (ang.), Julienne (franc.), Giuliana (wł.), Juliana (hiszp., niem.), Юлиана (ros.)</p></div>',

  "Cyryla": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Cyryla to żeńska forma imienia Cyryl, które pochodzi z języka <strong>greckiego</strong> — od <em>Kyrillos</em>, wywodzącego się od <em>Kyrios</em> (pan, władca). Znaczenie: <strong>„pani, władczyni"</strong>. Imię rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia Cyryl — apostoła Słowian, twórcy cyrylicy. Cyryla to imię rzadkie, używane w kręgach katolickich jako wyraz czci dla świętego Cyryla. Jego wspomnienie (razem z Metodym) obchodzi się 14 lutego — tego samego dnia co Walentynki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cyrylka, Cyra</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cyrilla (ang., łac.), Cyrille (franc., forma neutralna), Кирилла (ros.) — forma rzadka</p></div>',

  "Leokadiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leokadiusz to męska forma imienia Leokadia, wywodząca się z języka <strong>greckiego</strong> — od nazwy wyspy <em>Leukas</em> (<em>leukos</em> — biały). Znaczenie: <strong>„biały, jasny"</strong> lub „z wyspy Leukas". Imię bardzo rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Męska forma imienia Leokadia — świętej z Toledo. Imię obecne w kalendarzu kościelnym, używane sporadycznie. W Polsce Leokadiusz to imię wyjątkowo rzadkie, dziś prawie nienadawane, ale poświadczone historycznie w dokumentach metrykalnych XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leo, Leokad</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leocadius (łac.), Léocade (franc.), Leocadio (wł., hiszp.)</p></div>',

  "Wanda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wanda to imię <strong>słowiańskie</strong>, możliwie powiązane z Wandalami lub ze słowem <em>wand</em> (gałąź, latorośl). Znaczenie tradycyjne: <strong>„córka Wandalów"</strong>. Imię polskiej legendy — córki Kraka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Legendarna <strong>Wanda</strong> — córka króla Kraka, wolała śmierć niż małżeństwo z obcym rycerzem. Jej kurhan wznosi się pod Krakowem. Znane Wandy to <strong>Wanda Rutkiewicz</strong> — himalaistka, i <strong>Wanda Landowska</strong> — klawesynistka. Jedno z najbardziej polskich imion.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wandzia, Wandunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Wanda (ang., niem., franc., wł.) — imię znane przez polską legendę i historię</p></div>',

  "Longina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Longina to żeńska forma imienia Longin, wywodząca się z języka <strong>łacińskiego</strong> — od rodu Longinuszów (<em>Longinus</em>), od <em>longus</em> (długi, wysoki). Znaczenie: <strong>„wysoka, długa"</strong>. Imię historyczne i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia Longin — żołnierza, który wg tradycji przebił bok Jezusa włócznią. Longina to imię rzadkie w Polsce, używane historycznie w XIX w. Obchodzi imieniny 15 marca. Imię dziś prawie niespotykane, ale poświadczone w dawnych metrykach.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lonka, Lona</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Longina (wł., hiszp.), Longine (franc.), Лонгина (ros.) — forma rzadka</p></div>',

  "Serafina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Serafina to żeńska forma imienia Serafin, wywodząca się z języka <strong>hebrajskiego</strong> — od <em>saraph</em> (serafin, ognisty). Znaczenie: <strong>„ognista, anielska"</strong>. Serafiny to najwyższy rząd aniołów, otaczający tron Boży.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Serafina</strong> — włoska mistyczka z XIII w. z San Gimignano, znana z cierpliwości w chorobie. <strong>Seraphina</strong> — córka Jennifer Garner i Bena Afflecka. W Polsce Serafina to imię rzadkie, o duchowym i poetyckim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sera, Serafinka, Fina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Seraphina (ang.), Séraphine (franc.), Serafina (wł., hiszp.), Серафина (ros.)</p></div>',

  "Mikołaj": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Mikołaj pochodzi z języka <strong>greckiego</strong> — od <em>Nikolaos</em>: <em>nikē</em> (zwycięstwo) + <em>laos</em> (lud). Znaczenie: <strong>„zwycięski wśród ludu"</strong>. Jedno z najszerzej rozpowszechnionych imion w historii chrześcijaństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Mikołaj z Miry</strong> (IV w.) — patron dzieci, żeglarzy i kupców. Jego holenderska forma Sinterklaas dała angielskie Santa Claus. <strong>Mikołaj Kopernik</strong> — astronom, twórca heliocentryzmu. <strong>Niccolò Machiavelli</strong> — włoski myśliciel polityczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mikoś, Mikołajek, Mikuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicholas (ang.), Nicolas (franc., hiszp.), Nicola (wł.), Nikolaus (niem.), Николай (ros.)</p></div>',

  "Benedikta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Benedikta to żeńska forma imienia Benedykt z języka <strong>łacińskiego</strong> — od <em>benedictus</em> (błogosławiony), od <em>bene dicere</em> (dobrze mówić, błogosławić). Znaczenie: <strong>„błogosławiona"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia patrona Europy — <strong>świętego Benedykta z Nursji</strong>. <strong>Bénédicte de Bourbon</strong> — belgijska księżniczka. W Polsce rzadka, stosowana jako imię zakonne lub historyczne. Zdrobnienie Benka lub Benia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benka, Benia, Necia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedicta (ang., łac.), Bénédicte (franc.), Benedetta (wł.), Benedicta (hiszp.)</p></div>',

  "Inga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Inga pochodzi ze <strong>staronordyjskiego</strong> — wywodzi się od imienia boga <em>Ing</em> lub <em>Yngvi</em> (starogermańskie bóstwo płodności i urodzaju). Znaczenie: <strong>„należąca do Inga"</strong> lub „córka Yngviego". Imię skandynawskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w krajach skandynawskich. <strong>Inga Swenson</strong> — szwedzka aktorka. W Polsce Inga to imię rzadkie, kojarzące się z nordycką elegancją. Funkcjonuje też jako zdrobnienie imion z <em>-inga</em>, jak Ingrid. Znana jest <strong>Ingrid Bergman</strong>, która używała skrótu Inga.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ingusia, Inka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Inga (skandynaw., niem.), Inge (duń., norwes.), Инга (ros.) — imię typowo nordyckie</p></div>',

  "Achilles": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Achilles pochodzi z języka <strong>greckiego</strong> — etymologia niepewna; możliwe połączenie z <em>achos</em> (ból, smutek) + <em>laos</em> (lud). Znaczenie: <strong>„przynoszący ból ludowi"</strong> lub „leczący ból". Imię mitologicznego herosa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Achilles</strong> — największy grecki bohater Iliady, niemal nieśmiertelny za wyjątkiem pięty (stąd „pięta Achillesa"). W tradycji chrześcijańskiej Achilles to imię noszone przez rzadkich świętych. W Polsce imię wyjątkowo rzadkie, używane literacko i historycznie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Achillesek, Achil</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Achilles (ang., łac.), Achille (franc., wł.), Aquiles (hiszp.), Ахилл (ros.)</p></div>',

  'Donata': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Donata pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>donatus</em>, oznaczającego <strong>„dany przez Boga"</strong>, „podarowany z nieba". Jest żeńską formą imienia Donat. Wywodzi się z <em>donare</em> — dawać, obdarowywać. Każda Donata jest postrzegana jako wyjątkowy dar.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię kilku świętych kobiet wczesnochrześcijańskich — m.in. świętej Donaty, męczennicy z Afryki Północnej z IV w. W Polsce rzadkie, lecz cenione za piękne znaczenie i elegancję brzmienia. Pełne imię rzeźbiarza Donatella to Donato di Niccolò di Betto Bardi (ok. 1386–1466).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Donatka, Donisia, Dona, Donatusia, Donateczka, Doni</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Donata (ang., wł., pol.), Donate (franc.), Donatella (zdrobn. wł.), Доната (ros.)</p></div>',

  "Hipolit": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hipolit pochodzi z języka <strong>greckiego</strong> — od <em>Hippolytos</em>: <em>hippos</em> (koń) + <em>lyein</em> (uwolnić). Znaczenie: <strong>„ten, który uwalnia konie"</strong> lub „pogromca koni". Imię mitologiczne i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii <strong>Hipolit</strong> — syn Tezeusza, czczący Artemidę, zginął stratowany przez własne konie (temat tragedii Eurypidesa i Racine&#39;a). <strong>Święty Hipolit</strong> — ojciec Kościoła z III w., autor wielu pism teologicznych. W Polsce imię rzadkie, historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hipoś, Hipek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hippolyte (franc.), Hippolytus (łac., ang.), Ippolito (wł.), Hipólito (hiszp.), Ипполит (ros.)</p></div>',

  'Leonarda': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leonarda pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Leonard, złożonego z <em>leo</em> (lew) i <em>hard</em> (twardy, silny, dzielny). Oznacza <strong>„silna jak lwica"</strong> lub „odważna niczym lew". Imię łączy królewską zwierzęcą symbolikę z kobiecą siłą.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeński odpowiednik genialnego Leonarda da Vinci (1452–1519) — florenckiego artysty, wynalazcy i myśliciela renesansu, twórcy <em>Mona Lizy</em> i <em>Ostatniej Wieczerzy</em>. Święty Leonard z Noblat (VI w.) — patron więźniów i kobiet w ciąży. W Polsce imię rzadkie, lecz eleganckie i dobrze zapamiętywane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leonardka, Lena, Narda, Leona, Leonardzia, Nardka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leonarda (wł., hiszp., port.), Léonarde (franc.), Леонарда (ros.)</p></div>',

  "Maksymilia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Maksymilia to skrócona żeńska forma imienia Maksymilian, wywodząca się z języka <strong>łacińskiego</strong> — od <em>maximus</em> (największy). Znaczenie: <strong>„największa"</strong>. Forma rzadsza od Maksymiliany.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię żeńskie powiązane z patronem — <strong>świętym Maksymilianem Marią Kolbe</strong> (1894–1941) — polskim franciszkaninem, który w Auschwitz ofiarował życie za współwięźnia. Beatyfikowany 1971, kanonizowany 1982. Imię rzadkie w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maksia, Mila, Ilia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maximiliane (niem.), Maximilianne (franc.) — forma bardzo rzadka</p></div>',

  "Irydion": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Irydion to imię <strong>greckie</strong> — od <em>iris</em> (tęcza) lub od pierwiastka chemicznego <em>iryd</em> (iridium, nazwany od tęczy z powodu kolorowych soli). Znaczenie: <strong>„tęczowy"</strong>. Imię literackie i rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Irydion</strong> — tytułowy bohater dramatu <strong>Zygmunta Krasińskiego</strong> (1836) — poematu dramatycznego o Grekiem walczącym z Rzym w imię zemsty za ojczyznę. To jedno z najważniejszych dzieł polskiego romantyzmu. Imię w Polsce znane wyłącznie przez ten dramat.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Irys, Iry</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Iridion (łac.) — imię literackie bez odpowiedników w innych językach</p></div>',

  "Klementyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Klementyna to żeńska forma imienia Klemens, wywodząca się z języka <strong>łacińskiego</strong> — od słowa <em>clemens</em> (łagodny, miłosierny). Znaczenie: <strong>„łagodna, miłosierna"</strong>. Imię wyraża dobroć i wyrozumiałość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Klementyny to <strong>Clementine Churchill</strong> — żona Winstona Churchilla, i <strong>Clementine Hunter</strong> — afroamerykańska malarka naiwna. W Polsce Klementyna była popularna w XIX w. <strong>Klementyna Hoffmanowa</strong> — pierwsza polska autorka zarabiająca wyłącznie pisarstwem. Gatunek mandarynki też nazywa się klementynka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Klemcia, Klemka, Klema</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Clementine (ang., franc.), Clementina (wł., hiszp.), Клементина (ros.)</p></div>',

  "Kornel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kornel pochodzi od <strong>łacińskiego</strong> rodu Kornelii (<em>Cornelia gens</em>). Etymologia wskazuje na łacińskie <em>cornu</em> (róg) lub etruskie korzenie. Znaczenie: <strong>„z rodu Kornelii"</strong>. Forma żeńska to Kornelia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Kornel Makuszyński</strong> (1884–1953) — wielki polski pisarz dla dzieci, autor <em>Koziołka Matołka</em> i <em>Szatana z siódmej klasy</em>. <strong>Kornel Ujejski</strong> — polski poeta romantyczny. Imię znane w Polsce, popularne szczególnie w XIX–XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kornelek, Korneluś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cornelius (ang., łac.), Corneille (franc.), Cornelio (wł., hiszp.), Kornelius (niem.), Корнелий (ros.)</p></div>',

  "Wiesława": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Wiesława to żeńska forma imienia Wiesław — złożonego z <em>wie-</em> (wiedzieć, wieść) i <em>-sława</em> (sława). Znaczenie: <strong>„sławna z wiedzy"</strong>. Imię typowo polskie i słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Najsławniejsza Wiesława to <strong>Wisława Szymborska</strong> (właściwie Wiesława Maria, 1923–2012) — polska poetka, laureatka Nagrody Nobla w dziedzinie literatury (1996). Jej wiersze tłumaczono na ponad 40 języków. Jeden z największych autorytetów polskiej kultury XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wiesia, Wieśka, Wiesia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vjeslava (czes.), Вислава (ros.) — imię typowo polskie i słowiańskie</p></div>',

  "Urszula": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Urszula pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>ursa</em> (niedźwiedzica), zdrobnienie <em>ursula</em>. Znaczenie: <strong>„mała niedźwiedzica"</strong>. Imię symbolizuje siłę i dzikość natury.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Urszula</strong> — legendarna chrześcijańska księżniczka, która z 11 000 dziewic poniosła śmierć za wiarę w Kolonii (IV w.). Zakon urszulanek wzięł od niej nazwę. <strong>Ursula von der Leyen</strong> — przewodnicząca Komisji Europejskiej. W Polsce Urszula Dudziak — jazzowa wokalistka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ula, Ulka, Urszulka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ursula (ang., niem., wł.), Ursule (franc.), Úrsula (hiszp.), Урсула (ros.)</p></div>',

  "Fryderyk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Fryderyk pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Fridurih</em>: <em>frid</em> (pokój) + <em>rih</em> (władca, bogaty). Znaczenie: <strong>„pokojowy władca"</strong> lub „bogaty w pokój".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Fryderyk Wielki</strong> (1712–1786) — król Prus, jeden z najwybitniejszych władców-reformatorów Europy. <strong>Fryderyk Chopin</strong> (1810–1849) — najsłynniejszy polski kompozytor i pianista, symbol polskiej muzyki. Imię nosili też cesarze niemieccy.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Frydek, Fredek, Fredi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Frederick (ang.), Frédéric (franc.), Friedrich (niem.), Federico (wł., hiszp.), Фредерик (ros.)</p></div>',

  "Benedykta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Benedykta to polska żeńska forma imienia Benedykt, wywodząca się z języka <strong>łacińskiego</strong> — od <em>benedictus</em> (błogosławiony, pochwalony). Znaczenie: <strong>„błogosławiona"</strong>. Imię z tradycji benedyktyńskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia patrona Europy — <strong>świętego Benedykta z Nursji</strong>. Benedykta Bayer — mistyczka. W Polsce imię rzadkie, używane historycznie jako imię zakonne i chrzcielne. Stanowi elegancką alternatywę dla popularniejszych form żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benka, Benia, Necia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedicta (ang., łac.), Bénédicte (franc.), Benedetta (wł.), Benedicta (hiszp.)</p></div>',

  "Leonia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leonia to żeńska forma imienia Leon, wywodząca się z języka <strong>greckiego i łacińskiego</strong> — od <em>leon</em> (lew). Znaczenie: <strong>„lwica, odważna jak lew"</strong>. Imię symbolizuje odwagę i królewskość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię Leonia popularne w Polsce w XIX w. <strong>Błogosławiona Leonia Nastał</strong> — polska urszulanka, beatyfikowana przez Jana Pawła II w 2000 r. Imię dziś rzadsze, ale wraca do mody jako elegancka alternatywa dla Leonory. Znana jest też <strong>Léonie Villard</strong> — francuska pisarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leska, Leonka, Leosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leonia (wł., hiszp.), Léonie (franc.), Леония (ros.)</p></div>',

  "Alban": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alban pochodzi z języka <strong>łacińskiego</strong> — od nazwy miasta <em>Alba Longa</em> lub od <em>albus</em> (biały). Znaczenie: <strong>„biały, jasny"</strong> lub „z Alby". Imię historyczne i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Alban</strong> — pierwszy chrześcijański męczennik Brytanii (III w.), patron Anglii. Miasto St Albans w Anglii wzięło od niego nazwę. <strong>Alban Berg</strong> — austriacki kompozytor ekspresjonistyczny, uczeń Arnolda Schönberga. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Albanek, Albi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alban (ang., franc., niem.), Albano (wł., hiszp.), Альбан (ros.)</p></div>',

  "Donat": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Donat pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>donatus</em> (darowany, dany w darze). Znaczenie: <strong>„dar Boży"</strong>. Jest łacińskim odpowiednikiem słowiańskiego Bogdana i hebrajskiego Natanaela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Donat z Arezzo</strong> — chrześcijański męczennik z IV w., patron Arezzo. <strong>Aelius Donatus</strong> — rzymski gramatyk z IV w., autor <em>Ars grammatica</em> — podręcznika łaciny używanego przez całe średniowiecze. W Polsce imię rzadkie, historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Donatek, Donacik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Donatus (łac.), Donat (franc., niem.), Donato (wł., hiszp.), Донат (ros.)</p></div>',

  "Wirgiliusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wirgiliusz pochodzi z języka <strong>łacińskiego</strong> — od rodu Wergiliuszów (<em>Vergilius</em>). Etymologia niepewna, możliwy związek z <em>virga</em> (laska, gałąź) lub z etruskim. Znaczenie: <strong>„z rodu Wergiliuszów"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Publiusz Wergiliusz Maro</strong> (70–19 p.n.e.) — największy poeta łaciński, autor <em>Eneidy</em>, <em>Georgik</em> i <em>Bukolik</em>. W <em>Boskiej Komedii</em> Dantego Wirgiliusz jest przewodnikiem przez piekło i czyściec. <strong>Vergil</strong> — postać z gry Devil May Cry. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wirgilek, Wirgi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Virgil (ang.), Virgile (franc.), Virgilio (wł., hiszp.), Вергилий (ros.)</p></div>',

  "Bonawentura": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bonawentura pochodzi z języka <strong>włoskiego lub łacińskiego</strong> — od <em>bona ventura</em>, co znaczy <strong>„dobra przyszłość, szczęście"</strong>. Imię wyraża życzenie pomyślności i dobrego losu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Bonawentura</strong> (1221–1274) — włoski franciszkanin, doktor Kościoła, kardynał, generał zakonu franciszkańskiego. Autor <em>Drogi duszy do Boga</em>. Wybitny teolog i mistyk. W Polsce imię rzadkie, obecne w tradycji kościelnej i kalendarzu imienin.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bona, Wenturek, Bonek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bonaventure (ang., franc.), Bonaventura (wł., hiszp., łac.), Бонавентура (ros.)</p></div>',

  "Kryspin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kryspin pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>crispus</em>, oznaczającego <strong>„kędzierzawy, kręcone włosy"</strong>. Wywodzi się od cechy wyglądu, która stała się imieniem rodu i świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Kryspin i Kryspinian</strong> — bracia i szewcy, chrześcijańscy męczennicy z III w., patroni szewców i rymarzów. Szekspir w <em>Henryku V</em> wymienia dzień świętego Kryspina (25 października) — dzień bitwy pod Azincourt. W Polsce imię rzadkie, historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kryspek, Kryś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Crispin (ang.), Crépin (franc.), Crispino (wł.), Crispín (hiszp.), Криспин (ros.)</p></div>',

  "Aaron": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aaron pochodzi z języka <strong>hebrajskiego</strong> — od <em>Aharon</em>. Etymologia niepewna: możliwe znaczenia to <strong>„górski"</strong>, „oświecony" lub „wysoki". Imię biblijne, brata Mojżesza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Aaron</strong> — brat Mojżesza, pierwszy arcykapłan Izraela. Znani Aaronowie to <strong>Aaron Copland</strong> — amerykański kompozytor, i <strong>Hank Aaron</strong> — legenda baseballu. W Polsce imię rzadkie, zyskuje popularność w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arek, Aarko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aaron (ang., franc., niem., hiszp.), Aarón (hiszp.), Аарон (ros.), אַהֲרֹן (hebr.)</p></div>',

  "Abel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Abel pochodzi z języka <strong>hebrajskiego</strong> — od <em>Hevel</em> (הֶבֶל), oznaczającego <strong>„tchnienie, para, nicość"</strong>. Imię może też nawiązywać do asyryjskiego <em>ablu</em> (syn). Jedno z najstarszych imion biblijnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Abel</strong> — drugi syn Adama i Ewy, pasterz, zabity przez brata Kaina. Pierwszy człowiek, który poniósł śmierć. Jego imię stało się symbolem niewinnej ofiary. <strong>Abel Tasman</strong> — holenderski żeglarz, odkrywca Tasmanii i Nowej Zelandii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Abelek, Abi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Abel (ang., franc., hiszp., niem.), Abele (wł.), Авель (ros.), הֶבֶל (hebr.)</p></div>',

  "Abraham": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Abraham pochodzi z języka <strong>hebrajskiego</strong> — od <em>Avraham</em>: <em>av</em> (ojciec) + <em>hamon</em> (tłum, mnóstwo). Znaczenie: <strong>„ojciec wielu narodów"</strong>. Pierwotna forma to Abram — „ojciec jest wysoki".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Abraham</strong> — patriarcha i praojciec trzech religii: judaizmu, chrześcijaństwa i islamu. Bóg zmienił mu imię z Abrama na Abrahama zawierając przymierze. <strong>Abraham Lincoln</strong> — 16. prezydent USA, który zniósł niewolnictwo. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Abram, Abi, Bram</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Abraham (ang., franc., hiszp., niem.), Abramo (wł.), Авраам (ros.), אַבְרָהָם (hebr.)</p></div>',

  "Ada": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ada to imię o kilku możliwych źródłach: może być zdrobnieniem imion <strong>Adela, Adelajda lub Adrianna</strong>, lub wywodzić się z hebrajskiego <em>adah</em> (ozdoba). Może też być samodzielną formą germańskiego <em>adal</em> (szlachetny). Znaczenie: <strong>„ozdoba"</strong> lub „szlachetna".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ada Lovelace</strong> (1815–1852) — córka Byrona, matematyczka, uważana za pierwszą programistkę w historii — opracowała algorytm dla maszyny Babbage&#39;a. Język programowania <em>Ada</em> nosi jej imię. W Polsce Ada to modne imię XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adzia, Adusia, Adka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ada (ang., niem., wł., franc.), Ада (ros.)</p></div>',

  "Adela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adela pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>adal</em>, oznaczającego <strong>„szlachetny, z wyższego rodu"</strong>. Jest skróconą formą złożonych imion germańskich jak Adelajda. Imię symbolizuje arystokratyczne urodzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Adela z Normandii</strong> (ok. 1067–1137) — córka Wilhelma Zdobywcy, hrabina Blois. <strong>Adèle</strong> — brytyjska piosenkarka, jedna z najlepiej sprzedających się artystek w historii muzyki (<em>Hello</em>, <em>Rolling in the Deep</em>). W Polsce imię znane od średniowiecza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adelka, Adzia, Dela</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adele (ang., niem., wł.), Adèle (franc.), Adela (hiszp.), Аделa (ros.)</p></div>',

  "Adelajda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adelajda pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Adalheidis</em>: <em>adal</em> (szlachetny) + <em>heid</em> (rodzaj, stan). Znaczenie: <strong>„szlachetna, wysokiego stanu"</strong>. Przez łacinę Adelaide trafiło do wielu języków europejskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Adelajda</strong> (931–999) — cesarzowa Świętego Cesarstwa Rzymskiego, żona Ottona Wielkiego, patronka wdów i wygnańców. Miasto <em>Adelaide</em> w Australii nosi jej imię. <strong>Adelaide Kane</strong> — aktorka znana z serialu <em>Reign</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adela, Heidi, Hela</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adelaide (ang., wł.), Adélaïde (franc.), Adelheid (niem.), Аделаида (ros.)</p></div>',

  "Adelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Adelina to zdrobnienie imienia <strong>Adela lub Adelajda</strong>, wywodzących się ze starowysokoniemieckiego <em>adal</em> (szlachetny). Znaczenie: <strong>„mała szlachcianka"</strong>. Forma elegancka i romantyczna.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w operze — <strong>Adelina Patti</strong> (1843–1919) była najsłynniejszą śpiewaczką operową XIX w., uwielbianą przez publiczność całej Europy. <strong>Adeline</strong> — utwór muzyczny wielu artystów. W Polsce imię rzadkie, eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adela, Lina, Adelinka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adeline (ang., franc.), Adelina (wł., hiszp., niem.), Аделина (ros.)</p></div>',

  "Adolf": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adolf pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Athalwulf</em>: <em>adal</em> (szlachetny) + <em>wolf</em> (wilk). Znaczenie: <strong>„szlachetny wilk"</strong>. Imię było popularne w Europie do XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili szwedzcy królowie (Adolf Fryderyk) i biskupi. <strong>Adolf von Harnack</strong> — wybitny teolog. W XX w. imię zostało całkowicie zdyskredytowane przez <strong>Adolfa Hitlera</strong> (1889–1945) — dyktatora, który doprowadził do II wojny światowej i Holokaustu. Dziś niemal nigdzie niestosowane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adek, Adolfek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adolf (niem., skandynaw.), Adolphe (franc.), Adolfo (wł., hiszp.), Адольф (ros.)</p></div>',

  "Albert": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Albert pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Adalbert</em>: <em>adal</em> (szlachetny) + <em>beraht</em> (jasny, błyszczący). Znaczenie: <strong>„jasny i szlachetny"</strong>. Imię popularne wśród europejskiej arystokracji.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Albert Einstein</strong> (1879–1955) — fizyk, twórca teorii względności, noblista. <strong>Albert Camus</strong> — francuski pisarz i filozof egzystencjalny. <strong>Książę Albert</strong> — mąż królowej Wiktorii. W Polsce znany jest <strong>Albertus Magnus</strong> — średniowieczny uczony i teolog.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alek, Albertek, Alber</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Albert (ang., franc., hiszp.), Alberto (wł.), Albrecht (niem.), Альберт (ros.)</p></div>',

  "Albin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Albin pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>albus</em> (biały). Znaczenie: <strong>„biały, jasny, blady"</strong>. Imię nadawane pierwotnie osobom o jasnej karnacji lub włosach.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Albin z Angers</strong> (469–550) — biskup Angers, znany z łagodności wobec jeńców. W Polsce imię Albin było popularne w XIX i pierwszej połowie XX w. Forma żeńska to Albina. Znany jest też <strong>Albin Polášek</strong> — czeski rzeźbiarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Albinek, Albineczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Albin (franc., niem.), Albino (wł., hiszp.), Альбин (ros.)</p></div>',

  "Aldona": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aldona pochodzi z języka <strong>litewskiego lub germańskiego</strong> — możliwe związki z <em>ald</em> (stary) lub <em>adal</em> (szlachetny). Znaczenie: <strong>„stara, dojrzała"</strong> lub „szlachetna". Imię litewskie spopularyzowane w Polsce przez Mickiewicza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Aldona</strong> — imię rozsławił Adam Mickiewicz w poemacie <em>Konrad Wallenrod</em> (1828), gdzie Aldona jest ukochaną głównego bohatera, zamurowaną w wieży. Historyczna <strong>Aldona Anna</strong> — córka Giedymina, żona króla Kazimierza Wielkiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alda, Aldonka, Ala</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aldona (litew., niem.) — imię znane przez polsko-litewską tradycję</p></div>',

  "Alfred": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alfred pochodzi ze <strong>staroangielskiego</strong> — od <em>Ælfrēd</em>: <em>ælf</em> (elf, duch) + <em>rǣd</em> (rada, mądrość). Znaczenie: <strong>„mądrość elfów"</strong> lub „radzący się duchów". Imię anglosaskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Alfred Wielki</strong> (849–899) — król Wessexu, jedyny anglosaski król zwany Wielkim. <strong>Alfred Nobel</strong> — szwedzki wynalazca dynamitu, fundator Nagród Nobla. <strong>Alfred Hitchcock</strong> — mistrz kina grozy. <strong>Alfred de Musset</strong> — francuski poeta romantyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alfredek, Fred, Fredek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alfred (ang., niem., franc., hiszp., wł.), Альфред (ros.)</p></div>',

  "Alma": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alma ma kilka źródeł: po <strong>łacinie</strong> <em>alma</em> oznacza <strong>„żywicielka, dobrotliwa"</strong> (od <em>alere</em> — karmić), po <strong>hebrajsku</strong> <em>almah</em> — „dziewica, panna młoda", a po <strong>arabsku</strong> <em>alma</em> — „uczona".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię zyskało popularność po krwawej Bitwie pod Almą (1854) w czasie wojny krymskiej — wiele dziewczynek urodzonych tamtego roku nazwano Alma. <strong>Alma Mahler</strong> — muza wiedeńskiej secesji, żona Gustava Mahlera. W Polsce imię rzadkie, eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Almusia, Almka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alma (ang., franc., niem., hiszp., wł.), Альма (ros.)</p></div>',

  "Amadeusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amadeusz pochodzi z języka <strong>łacińskiego</strong> — złożone z <em>amare</em> (kochać) + <em>Deus</em> (Bóg). Znaczenie: <strong>„miłujący Boga"</strong>. Jest łacińskim odpowiednikiem hebrajskiego Jedidja (umiłowany Boga).</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Wolfgang Amadeus Mozart</strong> (1756–1791) — austriacki kompozytor, jeden z największych geniuszy muzycznych w historii. Jego drugie imię Amadeus rozsławił na cały świat film <strong>Miloša Formana <em>Amadeus</em></strong> (1984). W Polsce imię rzadkie, o muzycznym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amadek, Amadio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amadeus (łac., ang., niem.), Amédée (franc.), Amedeo (wł.), Amadeo (hiszp.), Амадей (ros.)</p></div>',

  "Amalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amalia pochodzi ze <strong>starogermańskiego</strong> — od <em>Amal</em>, nazwy dynastii Ostrogotów, lub od <em>amal</em> (praca, trud). Znaczenie: <strong>„pracowita"</strong>. Nie należy mylić z Amelią — oba imiona mają różne korzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne wśród europejskich dynastii. <strong>Amalia Wilhelmina</strong> — cesarzowa Świętego Cesarstwa. <strong>Amalia</strong> — księżniczka Holandii, następczyni tronu. Ojciec Goethego nazwał swoją córkę Amalią. W Polsce imię rzadkie, eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amalia, Amalka, Mala</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amalia (ang., wł., hiszp.), Amélie (franc.), Amalie (niem., skandynaw.), Амалия (ros.)</p></div>',

  "Amanda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Amanda pochodzi z języka <strong>łacińskiego</strong> — od <em>amandus/amanda</em> (godzien/godna miłości), od <em>amare</em> (kochać). Znaczenie: <strong>„ta, którą należy kochać"</strong>. Imię wyrażające urок i miłość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w literaturze angielskiej i skandynawskiej. <strong>Amanda</strong> — bohaterka wielu seriali i powieści. <strong>Amanda Seyfried</strong> — aktorka. <strong>Amanda Palmer</strong> — piosenkarka. W Polsce imię Amanda pojawiło się w latach 80.–90. XX w. i jest dziś umiarkowanie popularne.</p></div><div class="name-desc-section"><div name="name-desc-label">Zdrobnienia</div><p>Manda, Mandy, Amandka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amanda (ang., franc., niem., wł., hiszp.), Аманда (ros.)</p></div>',

  "Anastazja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anastazja pochodzi z języka <strong>greckiego</strong> — od <em>anastasis</em> (zmartwychwstanie, powstanie). Znaczenie: <strong>„ta, która zmartwychwstała"</strong> lub „odrodzenie". Imię głęboko chrześcijańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Anastazja</strong> — chrześcijańska męczennica, patronka tkaczy. <strong>Anastazja Romanow</strong> — najmłodsza córka cara Mikołaja II, zamordowana w 1918 r., bohaterka licznych legend o rzekomym ocaleniu. Film animowany <em>Anastazja</em> (1997) opowiada tę historię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nastka, Nastusia, Nastia, Ania</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anastasia (ang., wł., hiszp.), Anastasie (franc.), Анастасия (ros.)</p></div>',

  "Anatol": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anatol pochodzi z języka <strong>greckiego</strong> — od <em>Anatolē</em>, oznaczającego <strong>„wschód słońca, Orient"</strong>. Anatolia to historyczna nazwa Azji Mniejszej (dziś Turcja). Imię nawiązuje do wschodnich stron świata.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Anatol</strong> — patriarcha Konstantynopola z V w. <strong>Anatole France</strong> — francuski pisarz, noblista (1921), autor <em>Wyspy pingwinów</em>. W Polsce imię rzadkie, literackie. Znany jest <strong>Anatol Stern</strong> — polski poeta futurystyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anatolek, Tolek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anatole (franc.), Anatoli (ang., ros.), Anatolo (wł.), Анатолий (ros.)</p></div>',

  "Andrea": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Andrea to forma imienia <strong>Andrzej</strong> lub żeńska forma od łacińskiego <em>Andreas</em>, wywodzącego się z greckiego <em>andreios</em> (mężny). Znaczenie: <strong>„mężna, dzielna"</strong>. W Polsce używane zarówno dla kobiet, jak i mężczyzn.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Znane Andree to <strong>Andrea Bocelli</strong> — włoski tenor (forma męska), <strong>Andrea del Sarto</strong> — malarz renesansowy, i <strong>Andrea Mitchell</strong> — dziennikarka NBC. W Polsce Andrea zyskała popularność szczególnie w latach 80.–90. jako imię żeńskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Andzia, Andea, Dea</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Andrea (ang., wł., niem., hiszp.), Андреа (ros.) — forma neutralna płciowo we Włoszech</p></div>',

  "Angela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Angela pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>angelus</em> (anioł, posłaniec), wywodzącego się od greckiego <em>angelos</em> (posłaniec). Znaczenie: <strong>„anielska, posłanniczka"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Angela Merkel</strong> — kanclerz Niemiec przez 16 lat (2005–2021), jedna z najpotężniejszych kobiet świata. <strong>Angela Davis</strong> — afroamerykańska działaczka. <strong>Święta Angela Merici</strong> — założycielka urszulanek. W Polsce Angela jest rzadsza od polskiej formy Aniela.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ania, Angie, Angelka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Angela (ang., niem., wł., hiszp.), Angèle (franc.), Ангела (ros.)</p></div>',

  "Angelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Angelina to zdrobnienie imienia <strong>Angela</strong>, wywodzącego się z greckiego <em>angelos</em> (posłaniec, anioł). Znaczenie: <strong>„mała anielska"</strong> lub „posłanniczka Boża". Forma pieszczotliwa od Angela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Angelina Jolie</strong> — amerykańska aktorka, laureatka Oscara, ambasadorka dobrej woli UNHCR. <strong>Angelina Ballerina</strong> — popularna postać animowana dla dzieci. W Polsce Angelina jest mniej popularna od Angela, ale znana i używana szczególnie od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Angie, Angelinka, Lina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Angelina (ang., wł., hiszp., niem.), Angéline (franc.), Ангелина (ros.)</p></div>',

  "Anicet": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anicet pochodzi z języka <strong>greckiego</strong> — od <em>aniketos</em>, oznaczającego <strong>„niepokonany, niezwyciężony"</strong> (a- + nikē = negacja + zwycięstwo). Imię wyraża niezłomność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Anicet</strong> (zm. ok. 166) — jeden z pierwszych biskupów Rzymu, jest patronem imienia. Bł. <strong>Anicet Kopliński</strong> — polski kapucyn, męczennik z Auschwitz, beatyfikowany w 1999 r. W Polsce imię rzadkie, obecne w tradycji kościelnej i kalendarzu imienin.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anicetko, Anicek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anicetus (łac.), Anicet (franc.), Aniceto (wł., hiszp.), Аникит (ros.)</p></div>',

  "Antonia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Antonia to forma imienia <strong>Antoni</strong>, wywodzącego się od łacińskiego rodu Antoniuszów (<em>Antonius</em>). Znaczenie: <strong>„z rodu Antoniuszów"</strong> lub „bezcenna". Forma ta jest popularna w krajach romańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Antonia Minor</strong> — córka Marka Antoniusza i Oktawii, babcia cesarza Kaliguli. <strong>Antonia Fraser</strong> — angielska historyczka i pisarka. W Polsce Antonia to rzadsza, bardziej elegancka forma od Antoniny. Imię popularne we Włoszech i Hiszpanii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tonia, Tosia, Nina</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Antonia (ang., wł., hiszp., niem.), Antoinette (franc.), Антония (ros.)</p></div>',

  "Arabela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Arabela pochodzi ze <strong>szkockiego lub łacińskiego</strong> — możliwe formy to <em>Orabilis</em> (błagalna) lub <em>Arabella</em> z łaciny. Znaczenie: <strong>„błagająca"</strong> lub nawiązanie do Arabii. Imię romantyczne i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Polsce imię Arabela rozsławił serial <strong><em>Arabela</em></strong> (1979) — czechosłowacki serial fantastyczny dla dzieci, w którym Arabela to księżniczka z bajki. Serial był niezwykle popularny w Polsce lat 80. <strong>Arabella Stuart</strong> — angielska arystokratka z XVII w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ara, Arabelka, Bella</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arabella (ang., niem.), Arabelle (franc.), Arabela (wł., hiszp.), Арабелла (ros.)</p></div>',

  "Artur": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Artur pochodzi z języka <strong>celtyckiego</strong> — prawdopodobnie od <em>artos</em> (niedźwiedź) lub od łacińskiego <em>Artorius</em>. Znaczenie: <strong>„niedźwiedź"</strong> lub „szlachetny". Imię legendarnego króla Brytanii.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Legendarny <strong>Król Artur</strong> — władca Camelotu, rycerze Okrągłego Stołu. <strong>Arthur Conan Doyle</strong> — twórca Sherlocka Holmesa. <strong>Arthur Rimbaud</strong> — francuski poeta. W Polsce znany jest <strong>Artur Rubinstein</strong> — wybitny pianista i <strong>Artur Grottger</strong> — malarz romantyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arturek, Arek, Turek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arthur (ang., franc., niem.), Arturo (wł., hiszp.), Артур (ros.)</p></div>',

  "August": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię August pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>augustus</em>, oznaczającego <strong>„majestatyczny, czcigodny, święty"</strong>. Od niego pochodzi nazwa miesiąca sierpnia oraz tytuł cesarski.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oktawian August</strong> — pierwszy cesarz Rzymu, od którego imię stało się tytułem. <strong>August II Mocny</strong> i <strong>August III</strong> — królowie Polski. <strong>Auguste Rodin</strong> — rzeźbiarz (<em>Myśliciel</em>). <strong>August Strindberg</strong> — szwedzki dramaturg. <strong>August Cieszkowski</strong> — polski filozof.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gucio, Gutek, Augustek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Augustus (łac., ang.), Auguste (franc.), Augusto (wł., hiszp.), August (niem.), Август (ros.)</p></div>',

  "Aurelia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aurelia pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>aureus</em> (złoty), wywodzącego się od <em>aurum</em> (złoto). Znaczenie: <strong>„złota, złocista"</strong>. Żeńska forma imienia Aureliusz.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Aurelia</strong> — matka Juliusza Cezara, uważana za wzór rzymskiej matki i kobiety. <strong>Aurélie</strong> — popularne imię we Francji. W Polsce Aurelia to imię rzadkie, eleganckie, wracające do mody w XXI w. jako imię o antycznym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aurka, Auria, Relia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aurelia (ang., wł., hiszp.), Aurélie (franc.), Aurelia (niem.), Аурелия (ros.)</p></div>',

  "Basia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Basia to zdrobnienie imienia <strong>Barbara</strong>, wywodzącego się z języka greckiego — od <em>barbaros</em> (obcy, cudzoziemiec). Znaczenie: <strong>„obca, cudzoziemka"</strong>. Basia funkcjonuje dziś w Polsce jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Basia jako samodzielne imię jest typowo polskim zjawiskiem. Rozsławiła je <strong>Basia</strong> (Barbara Trzetrzelewska) — polska piosenkarka jazzowa i popowa, odnosząca sukcesy na rynku brytyjskim i amerykańskim w latach 80.–90. W Polsce imię Basia jest przez wielu traktowane jako pełnoprawne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Basieńka, Baśka, Basiunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Barbara (forma pełna), Barbe (franc.), Bärbel (niem. zdrobnienie), Варвара (ros.)</p></div>',

  "Beatrycze": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Beatrycze pochodzi z języka <strong>łacińskiego</strong> — od <em>Viatrix</em> lub <em>Beatrix</em>: <em>beatus</em> (szczęśliwy, błogosławiony). Znaczenie: <strong>„ta, która daje szczęście"</strong> lub „błogosławiona".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Beatrycze Portinari</strong> — muza Dantego Alighieri, której miłość zainspirowała <em>Boską Komedię</em>. W poemacie Beatrycze prowadzi poetę przez Raj. <strong>Beatrix Potter</strong> — angielska pisarka i ilustratorka (<em>Piotruś Królik</em>). Księżniczka <strong>Beatrice</strong> — córka Edwarda VII.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Beatka, Becia, Bea</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Beatrice (ang., wł.), Béatrice (franc.), Beatriz (hiszp., port.), Беатриче (ros.)</p></div>',

  "Beata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Beata pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>beatus/beata</em> (szczęśliwy, błogosławiony). Znaczenie: <strong>„szczęśliwa, błogosławiona"</strong>. Forma żeńska od Beatus.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Błogosławiona Beata</strong> — patronka imienia. W Polsce Beata była bardzo popularna w latach 60.–80. XX w. Znane Beaty to <strong>Beata Kozidrak</strong> — piosenkarka, liderka Bajmu, i <strong>Beata Szydło</strong> — polska premier. Imię wciąż popularne, choć rzadziej nadawane nowym pokoleniom.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Beatka, Beatunia, Becia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Beata (niem., wł., ang.), Béate (franc.), Беата (ros.)</p></div>',

  "Bella": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bella to imię o kilku źródłach: może być zdrobnieniem imion <strong>Izabela, Arabela</strong> lub niezależnym imieniem włoskim od <em>bella</em> — <strong>„piękna"</strong>. Imię wyraża urodę i wdzięk.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławiła saga <em>Zmierzch</em> Stephenie Meyer — bohaterka Bella Swan. <strong>Bella Hadid</strong> — modelka. <strong>Bella Thorne</strong> — aktorka. W Polsce Bella to imię rzadkie, ale modne w XXI w. jako krótka, nowoczesna forma. Znana polska fryzjerka <strong>Bella Dahl</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Belka, Bellusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bella (ang., wł., franc., niem.), Белла (ros.)</p></div>',

  "Benedykta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Benedykta to polska żeńska forma imienia Benedykt, wywodząca się z języka <strong>łacińskiego</strong> — od <em>benedictus</em> (błogosławiony). Znaczenie: <strong>„błogosławiona"</strong>. Imię z tradycji benedyktyńskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia patrona Europy — <strong>świętego Benedykta z Nursji</strong>. W Polsce Benedykta to imię rzadkie, historyczne, używane głównie jako imię zakonne i chrzcielne. Elegancka alternatywa dla popularniejszych imion żeńskich z korzeniami w tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benka, Benia, Necia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benedicta (ang., łac.), Bénédicte (franc.), Benedetta (wł.), Benedicta (hiszp.)</p></div>',

  "Beniamin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Beniamin pochodzi z języka <strong>hebrajskiego</strong> — od <em>Ben-Yamin</em>: <em>ben</em> (syn) + <em>yamin</em> (prawa ręka, południe). Znaczenie: <strong>„syn prawej ręki"</strong> lub „syn południa". Imię biblijne i bardzo popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Beniamin</strong> — najmłodszy syn Jakuba i Racheli, ulubieniec ojca. Dwanaście pokoleń Izraela — jedno nosi jego imię. <strong>Benjamin Franklin</strong> — Ojciec Założyciel USA, wynalazca piorunochronu. <strong>Benjamin Britten</strong> — angielski kompozytor. W Polsce imię modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Benio, Benek, Beniu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Benjamin (ang., franc., niem.), Beniamino (wł.), Benjamín (hiszp.), Вениамин (ros.)</p></div>',

  "Bianka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bianka pochodzi z języka <strong>włoskiego</strong> — od <em>bianca</em> (biała). Znaczenie: <strong>„biała, jasna"</strong>. Jest włoską odpowiedniczką imienia Blanka. Imię symbolizuje czystość i niewinność.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Bianca Jagger</strong> — była żona Micka Jaggera, działaczka praw człowieka. W Szekspirowskim <em>Ukroczeniu złośnicy</em> Bianca to siostra Katarzyny. W Polsce Bianka jest mniej popularna od Blanki, ale zyskuje na popularności w XXI w. jako elegancka forma włoska.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bianka, Bianeczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Bianca (ang., wł.), Blanche (franc.), Blanka (pol., hiszp., niem.), Бьянка (ros.)</p></div>',

  "Blanka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Blanka pochodzi ze <strong>starogermańskiego lub starofrancuskiego</strong> — od <em>blanc/blanka</em> (biały, jasny). Znaczenie: <strong>„biała, jasna"</strong>. Włoska forma to Bianca.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Blanka Kastylijska</strong> (1188–1252) — królowa Francji, matka Ludwika Świętego, słynna regentka. <strong>Blanka z Valois</strong> — pierwsza żona Karola IV, króla Czech. W Polsce imię popularne od lat 90. XX w., dziś jedno z modniejszych imion żeńskich. Znana jest <strong>Blanka Lipińska</strong> — polska pisarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Blankusia, Blanka, Blaneczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Blanche (franc.), Bianca (wł.), Blanca (hiszp.), Blanka (niem., czes.), Бланка (ros.)</p></div>',

  "Bogna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bogna to skrócona forma imion słowiańskich z członem <strong>Bogu-</strong> (Bóg) — jak Bogumił, Bogusław, Bogna. Znaczenie: <strong>„Boża, Bogu oddana"</strong>. Imię typowo polskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce w XX w. jako samodzielna forma lub zdrobnienie imion Bogusława, Bogumiła. Znana jest <strong>Bogna Sworowska</strong> — polska aktorka. Imię dziś rzadziej nadawane, ale wciąż obecne w Polsce jako imię o słowiańskim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bognka, Bogniuśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie i słowiańskie bez odpowiedników</p></div>',

  "Bolesław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bolesław to staropolskie imię dwuczłonowe — złożone z <em>Bole-</em> (bardziej, więcej — od <em>bolje</em>) i <em>-sław</em> (sława). Znaczenie: <strong>„bardziej sławny"</strong> lub „ten, kto zdobywa większą sławę". Imię dynastycznych Piastów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Bolesław I Chrobry</strong> (967–1025) — pierwszy król Polski, zjednoczyciel ziem polskich, pogromca Rusi i Czech. <strong>Bolesław III Krzywousty</strong> — podzielił Polskę na dzielnice. <strong>Bolesław Prus</strong> — pisarz, autor <em>Lalki</em>. <strong>Bolesław Leśmian</strong> — wybitny poeta.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bolek, Bolus, Bolesiek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Boleslaus (łac.), Boleslav (czes.), Boleslao (wł., hiszp.), Болеслав (ros.)</p></div>',

  "Bożena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Bożena jest imieniem <strong>słowiańskim</strong> — wywodzi się od rdzenia <em>boż-</em> (Bóg), co oznacza <strong>„Boża, dana przez Boga"</strong>. Jest słowiańskim odpowiednikiem łacińskiego Donata.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię znane w historycznych dokumentach jako Bożana i Bożechna. Czeska pisarka <strong>Božena Němcová</strong> — autorka <em>Babci</em>. W Polsce imię popularne w XX w. — Bożena Dykiel — aktorka, Bożena Walter — dziennikarka. Dziś rzadziej nadawane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Bożka, Bożenka, Bozia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Božena (czes., słowac., chorwac.) — imię typowo słowiańskie</p></div>',

  "Brygida": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Brygida pochodzi z języka <strong>staroirlandzkiego</strong> — od celtyckiej bogini <em>Brighid</em>, wywodzącej się od rdzenia <em>brig</em> (moc, wzniosłość, wysokość). Znaczenie: <strong>„potężna, wzniosła"</strong>. Imię przybyło do Europy kontynentalnej przez kult irlandzkich świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Brygida z Kildare</strong> (ok. 451–525) — patronka Irlandii, obok Patryka i Kolumby; założycielka klasztoru w Kildare. <strong>Święta Brygida Szwedzka</strong> (1303–1373) — mistyczka, założycielka zakonu birgitynek, patronka Europy (ogłoszona przez Jana Pawła II w 1999 r. razem z Edytą Stein i Katarzyną ze Sieny). <strong>Brigitte Bardot</strong> — francuska ikona kina lat 60. W Polsce imię historyczne, dziś rzadziej nadawane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Brygidka, Brysia, Gida, Bryta, Bryśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Brigid / Bridget (ang., irland.), Brigitte (franc., niem.), Brigida (wł., hiszp., port.), Birgitta (szw., norw.), Бригита (ros.)</p></div>',

  "Celeste": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Celeste pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>caelestis</em> (niebiański, boski), wywodzącego się od <em>caelum</em> (niebo). Znaczenie: <strong>„niebiańska, boska"</strong>. Forma zbliżona do Celestyny.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne we Włoszech i Francji. <strong>Celeste Holm</strong> — amerykańska aktorka, laureatka Oscara. Postać słonia <strong>Celeste</strong> z serii <em>Babar</em> nosiła to imię. W Polsce Celeste to imię rzadkie, egzotyczne, kojarzone z francuską elegancją.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cela, Celestka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Celeste (ang., wł., franc.), Celestia (ang.), Целеста (ros.)</p></div>',

  "Daria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Daria pochodzi z języka <strong>perskiego</strong> — żeńska forma od Dariusz (<em>Dārayavahush</em>): <em>daraya</em> (posiadać) + <em>vahu</em> (dobry). Znaczenie: <strong>„posiadająca dobro"</strong> lub „podtrzymująca dobro".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Daria</strong> — chrześcijańska męczennica z III w., patronka imienia. Znana jest seria kreskówek <strong><em>Daria</em></strong> (MTV, 1997–2001) — o inteligentnej nastolatce. W Polsce imię popularne od lat 80.–90. XX w. Znana jest <strong>Daria Widawska</strong> — polska aktorka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dareczka, Darka, Darusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Daria (ang., wł., hiszp., niem.), Darya (ros.), Дарья (ros.)</p></div>',

  "Dariusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dariusz pochodzi z języka <strong>perskiego</strong> — od <em>Dārayavahush</em>: <em>daraya</em> (posiadać, podtrzymywać) + <em>vahu</em> (dobry). Znaczenie: <strong>„podtrzymujący dobro"</strong>. Imię wielkich królów perskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Dariusz I Wielki</strong> (550–486 p.n.e.) — król Persji, który zorganizował pierwszą wyprawę na Grecję (Maraton 490 p.n.e.). <strong>Dariusz III</strong> — ostatni król Persji, pokonany przez Aleksandra Macedońskiego. W Polsce imię popularne od lat 70. XX w. Znany jest <strong>Dariusz Michalczewski</strong> — bokser.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Darek, Dario, Dareczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Darius (ang., łac.), Dario (wł.), Darío (hiszp.), Дарий (ros.)</p></div>',

  "Dawid": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dawid pochodzi z języka <strong>hebrajskiego</strong> — od <em>David</em> (דָּוִד), co tłumaczy się jako <strong>„umiłowany, kochany"</strong>. Jedno z najpopularniejszych imion biblijnych na świecie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Dawid</strong> — drugi król Izraela, pogromca Goliata, psalmista. Gwiazda Dawida nosi jego imię. <strong>Michał Anioł</strong> stworzył słynny posąg <em>Dawid</em>. Znani Dawidowie to <strong>David Bowie</strong> — muzyk, i <strong>David Beckham</strong> — piłkarz. W Polsce imię popularne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dawidek, Dawuś, Dawi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>David (ang., franc., hiszp., niem.), Davide (wł.), Давид (ros.), דָּוִד (hebr.)</p></div>',

  "Denise": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Denise to żeńska forma imienia Dionizy, wywodząca się z języka <strong>greckiego</strong> — od imienia boga Dionizosa (<em>Dionysos</em>). Znaczenie: <strong>„należąca do Dionizosa"</strong>, boga wina i radości.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne we Francji i krajach anglojęzycznych. <strong>Denise Richards</strong> — amerykańska aktorka. <strong>Denise Lewis</strong> — brytyjska mistrzyni olimpijska w siedmioboju. W Polsce Denise to imię rzadkie, egzotyczne, kojarzone z kulturą zachodnią. Polska forma to Denis lub Deniz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Deni, Denka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Denise (ang., franc.), Dionisia (wł., hiszp.), Дионисия (ros.)</p></div>',

  "Dobromił": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Dobromił to staropolskie imię dwuczłonowe — złożone z <em>Dobro-</em> (dobry, dobroć) i <em>-mił</em> (miły). Znaczenie: <strong>„dobry i miły"</strong> lub „miły w swej dobroci". Imię z dawnej tradycji słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rzadkie w Polsce, należy do warstwy archaicznych imion słowiańskich. Pokrewne imiona to Dobromir, Dobrosław, Dobromir. Dobromił przeżywa mały renesans w XXI w. jako imię nawiązujące do starej słowiańskiej tradycji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dobrek, Miłek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dobromiło (wł.), Dobromil (czes., serb.) — imię typowo słowiańskie</p></div>',

  "Efrem": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Efrem pochodzi z języka <strong>hebrajskiego</strong> — od <em>Efrayim</em> (אֶפְרַיִם), co tłumaczy się jako <strong>„podwójnie płodny"</strong> lub „kraj Efraima". Imię biblijne, syna Józefa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Efrem</strong> — syn Józefa Egipskiego i Asnat, jedno z dwunastu pokoleń Izraela. <strong>Efrem Syryjczyk</strong> (IV w.) — doktor Kościoła wschodniego, poeta i teolog. W Polsce imię bardzo rzadkie, obecne w kalendarzu imienin i tradycji prawosławnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Efremek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ephrem (ang., franc.), Efraim (niem., hiszp.), Ефрем (ros.), אֶפְרַיִם (hebr.)</p></div>',

  "Elias": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Elias to grecko-łacińska forma imienia <strong>Eliasz</strong>, wywodząca się z hebrajskiego <em>Eliyahu</em>: <em>El</em> (Bóg) + <em>yahu</em> (Jahwe). Znaczenie: <strong>„moim Bogiem jest Jahwe"</strong>. Imię biblijnego proroka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Eliasz</strong> — wielki prorok Starego Testamentu, który nie zaznał śmierci (zabrany do nieba w ognistym rydwanie). <strong>Elias Canetti</strong> — bułgarski pisarz, noblista. W Polsce forma Eliasz popularna, Elias — rzadsza, ale modna w XXI w. jako forma kosmopolityczna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Eli, Eliaś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elias (ang., niem., hiszp.), Élie (franc.), Elia (wł.), Илья (ros.), אֵלִיָּה (hebr.)</p></div>',

  "Eliasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eliasz pochodzi z języka <strong>hebrajskiego</strong> — od <em>Eliyahu</em>: <em>El</em> (Bóg) + <em>yahu</em> (Jahwe). Znaczenie: <strong>„moim Bogiem jest Jahwe"</strong>. Imię jednego z największych proroków Starego Testamentu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Eliasz</strong> — prorok Izraela z IX w. p.n.e., który walczył z kultem Baala. Zabrany do nieba w ognistym rydwanie, miał powrócić przed końcem świata (stąd utożsamiany przez uczniów z Janem Chrzcicielem). W Polsce imię modne w XXI w. jako nawiązanie do tradycji biblijnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Eli, Eliaś, Eliszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elijah (ang.), Élie (franc.), Elia (wł.), Elías (hiszp.), Илья (ros.)</p></div>',

  "Elżbieta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Elżbieta to polska forma imienia Elisabeth, które pochodzi z języka <strong>hebrajskiego</strong> — od <em>Elisheba</em>: <em>El</em> (Bóg) + <em>sheba</em> (przysięga). Znaczenie: <strong>„Bogu poświęcona"</strong> lub „Bóg jest moją przysięgą".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Jedno z najpopularniejszych imion w historii Europy. <strong>Elżbieta I</strong> i <strong>Elżbieta II</strong> — królowe Anglii. W Polsce <strong>Elżbieta Łokietkówna</strong> — królowa, i <strong>Elżbieta Czyżewska</strong> — aktorka. <strong>Elisabeth Kübler-Ross</strong> — psychiatra, autorka teorii etapów żałoby.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elka, Elusia, Betka, Besia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elizabeth (ang.), Elisabeth (niem., franc.), Elisabetta (wł.), Isabel (hiszp.), Елизавета (ros.)</p></div>',

  "Emanuel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emanuel pochodzi z języka <strong>hebrajskiego</strong> — od <em>Immanuel</em> (עִמָּנוּאֵל): <em>im</em> (z) + <em>anu</em> (nas) + <em>El</em> (Bóg). Znaczenie: <strong>„Bóg z nami"</strong>. Imię biblijne i mesjańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Księdze Izajasza <strong>Emanuel</strong> — prorocze imię Mesjasza. W tradycji chrześcijańskiej tożsame z Jezusem. <strong>Emmanuel Macron</strong> — prezydent Francji. <strong>Emanuel Schikaneder</strong> — librecista <em>Czarodziejskiego fletu</em> Mozarta. W Polsce imię rzadkie, o biblijnym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mano, Emanek, Eman</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emmanuel (ang., franc.), Emmanuele (wł.), Emanuel (niem., hiszp.), Иммануил (ros.)</p></div>',

  "Ewa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ewa pochodzi z języka <strong>hebrajskiego</strong> — od <em>Chavah</em> (חַוָּה), co znaczy <strong>„żyjąca, dająca życie"</strong>. Wywodzi się od <em>chayah</em> (żyć). Pierwsza kobieta w Biblii.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Ewa</strong> — pierwsza kobieta, matka wszystkich ludzi, stworzona z żebra Adama. W Polsce imię niezwykle popularne przez wieki. Wybitne Ewy to <strong>Ewa Demarczyk</strong> — piosenkarka, i <strong>Ewa Kopacz</strong> — premier. <strong>Eva Perón</strong> — Evita, pierwsza dama Argentyny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewka, Ewunia, Ewcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eve (ang., franc.), Eva (niem., hiszp., wł., skandynaw.), Ева (ros.)</p></div>',

  "Ewelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ewelina pochodzi z języka <strong>irlandzkiego lub celtyckiego</strong> — od <em>Aibhlín</em>, formy imienia Aveline, powiązanego z germańskim <em>avala</em> (siła, życie). Możliwe też połączenie z hebrajskim Ewa. Znaczenie: <strong>„pełna życia"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił sentymentalny romans <strong><em>Evelina</em></strong> Frances Burney (1778). W Polsce Ewelina była popularna szczególnie w latach 80.–90. XX w. Znana jest <strong>Ewelina Flinta</strong> — polska piosenkarka. Imię o literackim i romantycznym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewcia, Ewa, Ewelineczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Evelyn (ang.), Évelyne (franc.), Evelina (wł.), Evelina (hiszp., niem.), Эвелина (ros.)</p></div>',

  "Ezechiel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ezechiel pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yechezqel</em>: <em>chazaq</em> (silny) + <em>El</em> (Bóg). Znaczenie: <strong>„Bóg jest mocny"</strong> lub „Bóg mnie wzmocnił". Imię jednego z czterech wielkich proroków.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ezechiel</strong> — prorok biblijny z VI w. p.n.e., działający wśród wygnańców w Babilonie. Autor Księgi Ezechiela, słynącej z wizji rydwanu Bożego (<em>merkawa</em>). Jego wizja czterech żywych istot stała się symbolem czterech Ewangelistów. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ezek, Ezechio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ezekiel (ang.), Ézéchiel (franc.), Ezechiele (wł.), Ezequiel (hiszp.), Иезекиль (ros.)</p></div>',

  "Ferdynand": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ferdynand pochodzi ze <strong>starogermańskiego</strong> — od <em>Fridunand</em> lub wizygockiego <em>Fredenandus</em>: <em>frid</em> (pokój) + <em>nand</em> (odważny, gotowy). Znaczenie: <strong>„odważny w pokoju"</strong> lub „śmiały obrońca".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ferdynand II Aragoński</strong> — król Hiszpanii, mąż Izabeli, który sfinansował wyprawę Kolumba. <strong>Ferdinand Magellan</strong> — pierwszy żeglarz, który opłynął kulę ziemską. <strong>Ferdynand Kiepski</strong> — bohater kultowego polskiego serialu <em>Świat według Kiepskich</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ferdek, Ferdi, Nando</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ferdinand (ang., niem.), Fernand (franc.), Ferdinando (wł.), Fernando (hiszp.), Фердинанд (ros.)</p></div>',

  "Filomena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Filomena pochodzi z języka <strong>greckiego</strong> — od <em>philomenos</em>: <em>philein</em> (kochać) + <em>menos</em> (siła, moc). Znaczenie: <strong>„kochająca siłę"</strong> lub „ta, którą się miłuje". Imię o poetyckim brzmieniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Filomena</strong> — tajemnicza chrześcijańska męczennica, odkryta w XIX w. przez wykopaliska w Rzymie. Jej kult był bardzo żywy do 1961 r., gdy Kościół wycofał ją z kalendarza. W Grecji Filomela to mitologiczna postać — córka króla Pandiona, zamieniona w słowika.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fila, Filo, Filomenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Philomena (ang.), Philomène (franc.), Filomena (wł., hiszp.), Филомена (ros.)</p></div>',

  "Gedeon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gedeon pochodzi z języka <strong>hebrajskiego</strong> — od <em>Gideon</em> (גִּדְעוֹן), co tłumaczy się jako <strong>„ten, który sieka"</strong> lub „dzielny wojownik". Imię biblijnego sędziego Izraela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Gedeon (Gideon)</strong> — sędzia i bohater biblijny, który z garścią 300 żołnierzy pokonał wojska Madianitów dzięki Bożej pomocy. Organizacja <em>Gideons International</em> rozdziela Biblie w hotelach. W Polsce imię rzadkie, znane przez tradycję biblijną.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gedek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gideon (ang., hebr.), Gédéon (franc.), Gedeon (wł., hiszp.), Гедеон (ros.)</p></div>',

  "Gracja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gracja pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>gratia</em> (łaska, wdzięk, piękno). Znaczenie: <strong>„pełna łaski, wdzięczna"</strong>. Trzy Gracje — Charyty — były boginkami piękna w mitologii.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Grace Kelly</strong> (1929–1982) — hollywoodzka aktorka, która została księżną Monako. Jej imieniem Grace (pol. Gracja) żyją miliony fanów. W Polsce imię Gracja rzadkie, ale znane. Nosić je miała też polska artystka. Forma Grace popularna w krajach anglojęzycznych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gracka, Grazia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Grace (ang.), Grâce (franc.), Grazia (wł.), Gracia (hiszp.), Грация (ros.)</p></div>',

  "Gustaw": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gustaw pochodzi ze <strong>staronordyjskiego lub szwedzkiego</strong> — od <em>Gustav</em>: <em>Gautr</em> (Goci) + <em>stafr</em> (personel, laska). Znaczenie: <strong>„laska Gotów"</strong> lub „wsparcie Gotów".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili szwedzcy królowie: <strong>Gustaw Waza, Gustaw II Adolf</strong> — jeden z najwybitniejszych wodzów Europy. W Polsce <strong>Gustaw Mahler</strong> (Gustaw) — kompozytor, i <strong>Gustaw Klimt</strong> — malarz secesji. W literaturze polskiej Gustaw to bohaer <em>Dziadów</em> Mickiewicza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gucio, Gutek, Gustek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gustav (niem., skandynaw.), Gustave (franc.), Gustavo (wł., hiszp.), Густав (ros.)</p></div>',

  "Gwido": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gwido pochodzi ze <strong>starowysokoniemieckiego lub galijskiego</strong> — od <em>Wido/Guido</em>, wywodzącego się od <em>widu</em> (las) lub <em>vit</em> (szeroki). Znaczenie: <strong>„leśny"</strong> lub „szeroki". Włoska forma to Guido.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Guido d&#39;Arezzo</strong> (ok. 991–1033) — włoski mnich, twórca notacji muzycznej i solmizacji (do-re-mi). <strong>Guido Reni</strong> — włoski malarz barokowy. <strong>Gwido z Pompei</strong> — błogosławiony. W Polsce imię rzadkie, historyczne, obecne w tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gwiduś, Gwid</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Guy (ang., franc.), Guido (wł., niem.), Gvido (czes.), Гвидо (ros.)</p></div>',

  "Hildegarda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hildegarda pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hildegard</em>: <em>hild</em> (bitwa, walka) + <em>gard</em> (twierdza, ochrona). Znaczenie: <strong>„ochrona w walce"</strong> lub „strażniczka bitwy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Hildegarda z Bingen</strong> (1098–1179) — niemiecka benedyktynka, mistyczka, kompozytorka, lekarka i teolożka. Jedna z najwybitniejszych kobiet średniowiecza. Jej muzyka przeżywa renesans. <strong>Hildegarda</strong> — żona Karola Wielkiego. W Polsce imię bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hilda, Hildka, Garda</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hildegard (niem.), Hildegarde (franc., ang.), Ильдегарда (ros.)</p></div>',

  "Honorat": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Honorat pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>honoratus</em> (zaszczycony, uhonorowany), od <em>honor</em> (cześć, szacunek, godność). Znaczenie: <strong>„uhonorowany, zaszczycony"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Błogosławiony Honorat Koźmiński</strong> (1829–1916) — polski kapucyn, założyciel licznych zgromadzeń zakonnych, kandydat na ołtarze. <strong>Honorat z Arles</strong> — biskupi z V w. W Polsce imię rzadkie, lecz znane dzięki błog. Honoratowi Koźmińskiemu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Honiek, Honoratek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Honoratus (łac.), Honoré (franc.), Onorato (wł.), Honorato (hiszp.), Гонорат (ros.)</p></div>',

  "Hubert": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hubert pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hugibert</em>: <em>hug</em> (myśl, umysł, duch) + <em>beraht</em> (jasny, błyszczący). Znaczenie: <strong>„o jasnym umyśle"</strong> lub „błyszczący duchem".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Hubert</strong> (ok. 656–727) — patron myśliwych, którego nawrócenie nastąpiło po ujrzeniu jelenia z krzyżem między rogami. Towarzystwo Hubertowskie i Hubertus (imieniny myśliwych 3 listopada) wywodzą się od niego. <strong>Hubert de Givenchy</strong> — projektant mody.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hubertus, Hubek, Hubuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hubert (ang., franc., niem.), Uberto (wł.), Huberto (hiszp.), Губерт (ros.)</p></div>',

  "Ida": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ida pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>id</em> lub <em>idal</em>, związanego z pracą i aktywnością. Możliwe też połączenie ze skandynawską boginią <em>Iðunn</em> — strażniczką jabłek wiecznej młodości. Znaczenie: <strong>„pracowita"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Ida z Herzfeld</strong> — frankijska arystokratka z IX w. <strong>Ida Lupino</strong> — hollywoodzka aktorka i reżyserka. <strong>Ida Kamińska</strong> — wybitna polska aktorka żydowska. W Polsce imię Ida rzadkie, ale eleganckie i modne jako krótka forma.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Idzia, Ideczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ida (ang., niem., wł., franc., hiszp.), Ида (ros.)</p></div>',

  "Ingrid": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ingrid pochodzi ze <strong>staronordyjskiego</strong> — od <em>Ingríðr</em>: <em>Ing</em> (nordycki bóg płodności) + <em>ríðr</em> (piękna, ukochana). Znaczenie: <strong>„piękna Inga"</strong> lub „umiłowana przez boga Inga".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ingrid Bergman</strong> (1915–1982) — szwedzka aktorka, jedna z największych gwiazd Hollywood (<em>Casablanca</em>, <em>Strach na wróble</em>). <strong>Ingrid</strong> — królowa Danii, żona Fryderyka IX. W Polsce Ingrid to imię rzadkie, skandynawskie, eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Inga, Ingusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ingrid (skandynaw., niem., ang.), Инґрід (ukr.), Ингрид (ros.) — imię typowo nordyckie</p></div>',

  "Irma": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Irma to skrócona forma imion germańskich z członem <strong><em>Irm-/Erm-</em></strong> — jak Irmgarda lub Ermengarda — wywodzącym się od <em>ermen</em> (wielki, potężny, cały). Znaczenie: <strong>„wielka, potężna"</strong>. Imię germańskie i skandynawskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Niemczech i krajach skandynawskich. <strong>Irma la Douce</strong> — bohaterka kultowego musicalu i filmu Billy&#39;ego Wildera (1963) z Shirley MacLaine. W Polsce Irma to imię rzadkie, kojarzone z elegancją lat 20.–30. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Irmka, Irmusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Irma (ang., niem., franc., wł., hiszp.), Ирма (ros.) — imię typowo germańskie</p></div>',

  "Iwan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Iwan to słowiańska (rosyjska i ukraińska) forma imienia <strong>Jan</strong>, wywodząca się z hebrajskiego <em>Johanan</em>: <em>Yah</em> (Bóg) + <em>hanan</em> (łaskawy). Znaczenie: <strong>„Bóg jest łaskawy"</strong>. Odpowiednik polskiego Jana.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Iwan Groźny</strong> (1530–1584) — pierwszy car Rosji, słynący z okrucieństwa. <strong>Iwan Turgieniow</strong> — rosyjski pisarz. W Polsce imię Iwan rzadkie, ale znane przez kulturę słowiańską. Postać <strong>Iwana z bajki</strong> to archetyp najmłodszego, na pozór głupiego syna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iwanko, Iwanek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ivan (ang., hiszp., czes.), Giovanni (wł.), Иван (ros.), Jan (pol.)</p></div>',

  "Iwona": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Iwona to polska forma imienia <strong>Yvonne</strong>, wywodzącego się ze starogermańskiego <em>ivo</em> (cis, drewno cisowe) — z którego robiono łuki. Znaczenie: <strong>„z drzewa cisowego"</strong>. Forma żeńska od Yves/Iwo.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Yvonne de Gaulle</strong> — żona gen. Charles&#39;a de Gaulle&#39;a. <strong>Yvonne Printemps</strong> — francuska piosenkarka i aktorka. W Polsce Iwona była bardzo popularna w latach 60.–80. XX w. Znana jest <strong>Iwona Pavlović</strong> — jurorka programu <em>Taniec z gwiazdami</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iwonka, Iwa, Iwcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Yvonne (franc.), Yvonne (ang., niem.), Ivonne (wł., hiszp.), Ивонна (ros.)</p></div>',

  "Jadwiga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jadwiga pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hedwig</em>: <em>hadu</em> (walka) + <em>wig</em> (walka, bitwa). Znaczenie: <strong>„ta, która walczy"</strong>. Do Polski trafiło w XIII w. przez dynastię Piastów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Jadwiga Andegaweńska</strong> (1374–1399) — pierwsza kobieta-król Polski, żona Jagiełły, kanonizowana przez Jana Pawła II w 1997 r. <strong>Święta Jadwiga Śląska</strong> — patronka Polski. <strong>Jadwiga Smosarska</strong> — polska aktorka kina niemego, gwiazda lat 20.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jadzia, Hadzka, Iga, Jagoda</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hedwig (niem.), Hedwige (franc.), Edwige (wł.), Hedvig (skandynaw., węg.)</p></div>',

  "Jakub": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jakub pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yaakov</em> (יַעֲקֹב), co tłumaczy się jako <strong>„trzymający za piętę"</strong> lub „podstępny". Jakub chwycił brata za piętę przy narodzinach. Imię patriarchy Izraela.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Jakub</strong> — patriarcha, ojciec dwunastu synów (dwanaście pokoleń Izraela), którego imię zmieniono na Izrael. <strong>Święty Jakub Apostoł</strong> — patron Hiszpanii, pielgrzymi podążają Drogą św. Jakuba do Santiago de Compostela. W Polsce jedno z najpopularniejszych imion XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kuba, Kubuś, Jakubek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>James (ang.), Jacques (franc.), Giacomo (wł.), Jaime (hiszp.), Яков (ros.)</p></div>',

  "Janusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Janusz to polska forma imienia <strong>Jan</strong>, wywodzącego się z hebrajskiego <em>Johanan</em>: <strong>„Bóg jest łaskawy"</strong>. Forma Janusz to zdrobnienie lub specyficznie polska adaptacja, traktowana jako samodzielne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Janusz Korczak</strong> (właśc. Henryk Goldszmit, 1878–1942) — pedagog, pisarz i działacz, który odmówił opuszczenia swoich wychowanków i zginął z nimi w Treblince. Symbol heroizmu wychowawcy. <strong>Janusz Gajos</strong> — wybitny polski aktor. Dziś imię stało się memem kulturowym.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Januszek, Janusio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, bez odpowiedników w innych językach</p></div>',

  "Jędrzej": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Jędrzej to staropolska forma imienia <strong>Andrzej</strong>, wywodząca się z języka greckiego — od <em>andreios</em> (mężny, dzielny). Znaczenie: <strong>„mężny, dzielny"</strong>. Forma archaiczna, dziś rzadsza od Andrzeja.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili <strong>Jędrzej Śniadecki</strong> — polski chemik i biolog z XIX w., brat Jana Śniadeckiego. <strong>Jędrzej Kitowicz</strong> — pisarz i pamiętnikarz epoki saskiej. W Polsce Jędrzej to imię archaiczne, ale wracające do mody w XXI w. jako oryginalnie polskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jędrek, Jędruś, Jędrzejek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Andrew (ang.), André (franc.), Andrea (wł.), Andrés (hiszp.), Андрей (ros.)</p></div>',

  "Jonasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Jonasz pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yonah</em> (יוֹנָה), oznaczającego <strong>„gołąb"</strong>. Gołąb jest symbolem pokoju i Ducha Świętego. Imię biblijnego proroka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Jonasz</strong> — prorok, który uciekał przed misją Bożą i został połknięty przez wielką rybę, po trzech dniach wyrzucony na ląd — zapowiedź zmartwychwstania Jezusa. Powiedzenie „mieć Jonasza na pokładzie" oznacza pechowca. W Polsce imię modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Jonas, Jonaszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jonah (ang.), Jonas (franc., niem., hiszp.), Giona (wł.), Иона (ros.), יוֹנָה (hebr.)</p></div>',

  "Józefat": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Józefat pochodzi z języka <strong>hebrajskiego</strong> — od <em>Yehoshafat</em>: <em>Yah</em> (Bóg) + <em>shafat</em> (sądzić). Znaczenie: <strong>„Bóg osądził"</strong> lub „Jahwe jest sędzią". Imię biblijnego króla.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Josafat</strong> — król Judy z IX w. p.n.e. <strong>Dolina Józefata</strong> — biblijna dolina Ostatecznego Sądu. <strong>Święty Józefat Kuncewicz</strong> (1580–1623) — arcybiskup Połocka, męczennik unicki, kanonizowany — pierwszy wschodni święty kanonizowany przez Rzym. Patron unii kościelnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Józefatek, Józek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Jehoshaphat (ang., hebr.), Josaphat (franc.), Giosafat (wł.), Josafat (hiszp.), Иосафат (ros.)</p></div>',

  "Kamil": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Kamil pochodzi z języka <strong>łacińskiego lub etruskiego</strong> — od <em>camillus</em>, oznaczającego <strong>„ministrant, służący przy ołtarzu"</strong> lub młodego szlachcica wychowującego się na dworze. Imię liturgiczne i religijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Kamil de Lellis</strong> (1550–1614) — włoski zakonnik, założyciel Kamilian — zakonu opiekującego się chorymi. Patron chorych i pracowników służby zdrowia. W Polsce Kamil to jedno z najpopularniejszych imion, szczególnie od lat 90. Forma żeńska to Kamila.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kamczek, Kamilek, Kami</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Camille (franc., forma neutralna), Camillo (wł.), Camilo (hiszp.), Camillus (łac.), Камиль (ros.)</p></div>',

  "Kamila": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kamila to żeńska forma imienia Kamil, wywodząca się z języka <strong>łacińskiego</strong> — od <em>camillus</em> (ministrant, służący). Znaczenie: <strong>„służebnica ołtarza"</strong>. Forma żeńska bardzo popularna w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii <strong>Camilla</strong> — wojownicza królowa Wolsków z <em>Eneidy</em> Wergiliusza. Znane Kamile to <strong>Camille Saint-Saëns</strong> (forma męska) — kompozytor, i <strong>Kamila Skolimowska</strong> — polska mistrzyni olimpijska w rzucie młotem. W Polsce jedno z najpopularniejszych imion żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kamilka, Milka, Kami</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Camille (franc.), Camilla (ang., wł., skandynaw.), Camila (hiszp.), Камила (ros.)</p></div>',

  "Aleksy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Aleksy to forma imienia wywodząca się z języka <strong>greckiego</strong> — od <em>alexein</em> (bronić, pomagać). Znaczenie: <strong>„obrońca, pomocnik"</strong>. Forma pokrewna Aleksandrowi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Aleksy</strong> — asceta z V w., syn patrycjusza, który porzucił majątek i żył jako żebrak — patron ubogich. <strong>Aleksy Rżewski</strong> — bohater z dziejów dawnej Rzeczypospolitej. Car Rosji <strong>Aleksiej Romanow</strong> nosił tę formę imienia. W Polsce imię rzadkie, obecne w kalendarzu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alek, Aleksek, Oleś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alexis (ang., franc.), Alessio (wł.), Alexio (hiszp.), Алексей (ros.)</p></div>',

  "Alberta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Alberta to żeńska forma imienia Albert, wywodząca się ze <strong>starowysokoniemieckiego</strong> — od <em>adal</em> (szlachetny) + <em>beraht</em> (jasny). Znaczenie: <strong>„jasna i szlachetna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Prowincja <strong>Alberta</strong> w Kanadzie nazwana na cześć księżniczki Luizy Karoliny Alberty — córki królowej Wiktorii. <strong>Alberta Hunter</strong> — amerykańska piosenkarka bluesowa. W Polsce imię rzadkie, eleganckie, o germańskim rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Albertka, Berta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alberta (ang., wł., hiszp.), Alberte (franc.), Альберта (ros.)</p></div>',

  "Albertyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Albertyna to zdrobniała forma imienia Albert, wywodząca się ze <strong>starowysokoniemieckiego</strong> — od <em>adal</em> (szlachetny) + <em>beraht</em> (jasny). Znaczenie: <strong>„mała i szlachetna"</strong>. Forma elegancka i literacka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Albertyna</strong> — postać z cyklu <em>W poszukiwaniu straconego czasu</em> Marcela Prousta, ukochana narratora. W Polsce imię rzadkie, literackie, kojarzone z kulturą fin de siècle.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Albertynka, Berta, Tyna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Albertine (franc., ang.), Albertina (wł., hiszp.), Альбертина (ros.)</p></div>',

  "Ariadna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ariadna pochodzi z języka <strong>greckiego</strong> — prawdopodobnie oznacza <strong>„bardzo świętą"</strong> (od <em>ari-</em> = bardzo + <em>adnos</em> = święty). Imię mitologiczne związane z labiryntem i nicią.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii greckiej <strong>Ariadna</strong> — córka króla Minosa, która dała Tezeuszowi nić, dzięki której wydostał się z labiryntu po zabiciu Minotaura. „Nić Ariadny" — do dziś oznacza wskazówkę wyjaśniającą problem. Poślubiona Dionizosowi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aria, Ariadka, Adna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ariadne (ang., niem., franc.), Arianna (wł.), Ariana (hiszp.), Ариадна (ros.)</p></div>',

  "Ariel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ariel pochodzi z języka <strong>hebrajskiego</strong> — od <em>Ariel</em>: <em>ari</em> (lew) + <em>El</em> (Bóg). Znaczenie: <strong>„lew Boży"</strong>. Imię poetyckie, anielskie i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii Ariel — symboliczna nazwa Jerozolimy. U Szekspira w <em>Burzy</em> <strong>Ariel</strong> to duch powietrza. Znana jest <strong>Ariel</strong> — Mała Syrenka Disney&#39;a (1989). W Polsce imię używane dla obu płci, modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ari, Arielka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ariel (ang., franc., hiszp.), Ariela (żeńska forma), Ариэль (ros.)</p></div>',

  "Ariela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ariela to żeńska forma imienia Ariel, z języka <strong>hebrajskiego</strong> — od <em>ari</em> (lew) + <em>El</em> (Bóg). Znaczenie: <strong>„lwica Boża"</strong>. Imię poetyckie i anielskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię spopularyzowane przez <strong>Małą Syrenkę</strong> Disneya — Ariel/Ariela to imię głównej bohaterki (1989). W Polsce forma Ariela zyskała popularność w latach 90. i XXI w. Imię o bajkowym i mistycznym charakterze, używane też w Izraelu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ari, Arielka, Ela</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ariela (pol., hiszp., hebr.), Arielle (franc.), Ariel (ang.) — żeńska forma</p></div>',

  "Arleta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Arleta pochodzi z języka <strong>normańskiego lub starofrancuskiego</strong> — od formy <em>Arlette</em>, prawdopodobnie wywodzącej się od germańskiego <em>arn</em> (orzeł) lub celtyckiego rdzenia związanego z wolnością. Znaczenie: <strong>„mała orlica"</strong>. Imię o romantycznym, prowansalskim brzmieniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Arlette</strong> (zm. ok. 1050) — matka Wilhelma Zdobywcy, córka normandzkiego garbarza, kochanka księcia Roberta I. Jej syn podbił Anglię w 1066 r. <strong>Arletty</strong> (1898–1992) — prawdziwe nazwisko Léonie Bathiat, legendarna aktorka francuska, gwiazda arcydzieła kina <em>Dzieci raju</em> (1945). W Polsce imię Arleta popularne szczególnie w latach 70.–80. XX w., cenione za brzmieniową elegancję i niepowtarzalny charakter.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arletka, Arka, Arcia, Arlcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arlette / Arletty (franc.), Arletta (wł.), Arleta (hiszp., czes.), Арлета (ros.)</p></div>',

  "Arnold": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Arnold pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Arnwald</em>: <em>arn</em> (orzeł) + <em>wald</em> (władca). Znaczenie: <strong>„władca orłów"</strong>. Imię germańskie symbolizujące potęgę.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Arnold Schwarzenegger</strong> — kulturysta, aktor (<em>Terminator</em>) i gubernator Kalifornii. <strong>Arnold Schönberg</strong> — kompozytor, twórca dodekafonii. <strong>Benedict Arnold</strong> — kontrowersyjny generał rewolucji amerykańskiej. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arnek, Arnoldek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Arnold (ang., niem., hiszp.), Arnaud (franc.), Arnoldo (wł.), Арнольд (ros.)</p></div>',

  "Aurora": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aurora pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>aurora</em> (świt, zorza). Znaczenie: <strong>„zorza, brzask, świt"</strong>. Imię rzymskiej bogini świtu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Aurora</strong> — w mitologii bogini świtu. <strong>Aurora Borealis</strong> — zorza polarna. Księżniczka <strong>Aurora</strong> to <em>Śpiąca Królewna</em> Disneya. W Polsce imię modne w XXI w. jako elegancka, lekka forma. Symbolizuje świeżość i nowy początek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aura, Rora, Aurorka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aurora (ang., wł., hiszp.), Aurore (franc.), Аврора (ros.)</p></div>',

  "Augusta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Augusta to żeńska forma imienia August, z języka <strong>łacińskiego</strong> — od <em>augustus</em> (majestatyczny, czcigodny). Znaczenie: <strong>„majestatyczna, czcigodna"</strong>. Tytuł cesarski w formie żeńskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Augusta</strong> — tytuł żon cesarzy rzymskich. <strong>Augusta Wiktoria</strong> — ostatnia cesarzowa Niemiec. <strong>Augusta Ada Lovelace</strong> — pełne imię pierwszej programistki. W Polsce imię Augusta rzadkie, historyczne, o arystokratycznym brzmieniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gustka, Gusia, Usta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Augusta (ang., wł., hiszp.), Auguste (franc.), Августа (ros.)</p></div>',

  "Augustyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Augustyna to polska żeńska forma imienia Augustyn, z języka <strong>łacińskiego</strong> — od <em>Augustinus</em>, zdrobnienia od Augustus (majestatyczny). Znaczenie: <strong>„mała, majestatyczna"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska od imienia <strong>Świętego Augustyna z Hippony</strong> — biskupa i filozofa, autora <em>Wyznań</em>. W Polsce Augustyna to imię rzadkie. <em>Ach, du lieber Augustin</em> — wiedeńska piosenka z XVII w. o człowieku, który przeżył zarazę.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gustka, Tyna, Gustynia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Augustina (ang., hiszp.), Augustine (franc.), Augustina (wł.), Августина (ros.)</p></div>',

  "Aida": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Aida pochodzi z języka <strong>arabskiego lub etiopskiego</strong> — od arabskiego <em>aida</em> (wracająca) lub etiopskiego słowa oznaczającego <strong>„córkę króla"</strong>. Imię znane głównie dzięki operze Verdiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Aida</strong> — opera Giuseppe Verdiego z 1871 r., jedna z najczęściej wystawianych oper świata. Tytułowa bohaterka to etiopska księżniczka uwięziona w Egipcie, zakochana w wodzicielonym Egipcjaninie Radamesie. Spektakularne wystawienia pod piramidami.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aidka, Aidusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aida (ang., franc., wł., hiszp., niem.), Аида (ros.)</p></div>',

  "Carmen": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Carmen pochodzi z języka <strong>łacińskiego</strong> — od <em>carmen</em> (pieśń, wiersz) lub z <strong>hebrajskiego</strong> Karmel (ogród, winnica). Znaczenie: <strong>„pieśń"</strong> lub „kobieta z Karmelu". Imię hiszpańskie i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Carmen</strong> — nowela Prospera Mérimée (1845) i opera Georgesa Bizeta (1875). Tytułowa bohaterka — namiętna Cyganka z Sewilli — stała się jednym z największych symboli kobiecości w kulturze europejskiej. <strong>Carmen Miranda</strong> — brazylijsko-portugalska aktorka i piosenkarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Carmenita, Karmena</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Carmen (ang., wł., hiszp., franc.), Кармен (ros.)</p></div>',

  "Celestyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Celestyna to żeńska forma imienia Celestyn, z języka <strong>łacińskiego</strong> — od <em>caelestinus</em> (niebiański), od <em>caelum</em> (niebo). Znaczenie: <strong>„niebiańska"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię kilku papieży, m.in. <strong>Celestyn V</strong> — który abdykował dobrowolnie w XIII w., jedyny papież, który to uczynił w średniowieczu, kanonizowany. <em>La Celestina</em> (1499) — słynna hiszpańska powieść dialogowa. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cela, Celestynka, Tyna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Celestine (ang., franc.), Celestina (wł., hiszp.), Целестина (ros.)</p></div>',

  "Chloe": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Chloe pochodzi z języka <strong>greckiego</strong> — od <em>khloe</em>, oznaczającego <strong>„świeże, zielone pędy"</strong> lub „młoda trawa wiosną". Imię bogini Demeter, symbolizujące wiosnę i rozkwit.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii <strong>Chloe</strong> — przydomek bogini Demeter oznaczający wiosenną zieleń. W Biblii Chloe — chrześcijanka wspomniana przez Pawła. Powieść <em>Dafnis i Chloe</em> Longosa to najstarsza europejska powieść pasterska. Dziś imię popularne na zachodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Chlosia, Chloe (niepodzielne)</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Chloe (ang., niem.), Chloé (franc.), Cloe (wł., hiszp.), Хлоя (ros.)</p></div>',

  "Cyntia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Cyntia to spolszczona forma imienia Cynthia, z języka <strong>greckiego</strong> — od nazwy góry Cyntos na Delos. Znaczenie: <strong>„z góry Kynthos"</strong> — przydomek bogini Artemidy urodzonej na tej górze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Cynthia</strong> — poetycki przydomek Artemidy/Diany, bogini księżyca. Imię popularne w literaturze renesansowej jako symbol księżyca. W Polsce Cyntia to imię rzadkie. <strong>Cynthia Nixon</strong> — aktorka z <em>Seksu w wielkim mieście</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cynka, Tia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cynthia (ang.), Cintia (hiszp., wł.), Синтия (ros.)</p></div>',

  "Dagmara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Dagmara pochodzi ze <strong>staronordyjskiego</strong> — od <em>Dagmær</em>: <em>dagr</em> (dzień) + <em>mær</em> (sławna). Znaczenie: <strong>„sławna jak dzień"</strong>. Imię skandynawskie popularne w Polsce i Czechach.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Dagmar</strong> — czeska księżniczka, żona króla Danii Waldemara II, ulubienica Duńczyków. <strong>Maria Dagmar</strong> — duńska księżniczka, jako <strong>Maria Fiodorowna</strong> cesarzowa Rosji. W Polsce Dagmara popularna w latach 80.–90. i wciąż używana.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Daga, Dagmarka, Mara</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dagmar (skandynaw., niem., czes.), Дагмара (ros.)</p></div>',

  "Dalila": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dalila pochodzi z języka <strong>hebrajskiego</strong> — od <em>Delilah</em>, co znaczy <strong>„słabość, delikatna"</strong>. Imię biblijnej kochanki Samsona, symbol kobiety fatalnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Dalila</strong> — Filistynka, kochanka Samsona, która odkryła tajemnicę jego siły i zdradziła go wrogom. Symbol zdrady i kobiety fatalnej. Opera <em>Samson i Dalila</em> Saint-Saënsa. Piosenka <em>Delilah</em> Toma Jonesa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lila, Dalilka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Delilah (ang.), Dalila (franc., hiszp., wł.), Далила (ros.)</p></div>',

  "Daniela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Daniela to żeńska forma imienia Daniel, wywodząca się z języka <strong>hebrajskiego</strong>. Złożona z członów <em>din</em> (sąd, sprawiedliwość) i <em>El</em> (Bóg), co oznacza <strong>„Bóg jest moim sędzią"</strong>. Imię o głębokim znaczeniu biblijnym, podkreślające wiarę w Boską sprawiedliwość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma imienia proroka <strong>Daniela</strong> — który przetrwał lwią jamę mocą wiary. W Europie imię znane od średniowiecza, w Polsce upowszechniło się w XX w. <strong>Daniela Mercury</strong> — brazylijska piosenkarka i ikona muzyki axé. <strong>Daniela Pestova</strong> — czeska supermodelka. Dziś w Polsce nosi je ok. 60 tysięcy kobiet; popularne w krajach romańskich, zwłaszcza we Włoszech i Czechach.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dania, Danielka, Ela, Danka, Daniusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Daniela (niem., wł., hiszp., czes., słowac.), Danièle / Danielle (franc.), Daniella (ang.), Даниэла (ros.)</p></div>',

  "Debora": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Debora pochodzi z języka <strong>hebrajskiego</strong> — od <em>Devorah</em>, co znaczy <strong>„pszczoła"</strong>. Pszczoła w tradycji biblijnej symbolizuje pracowitość, mądrość, wymowę i słodycz. Imię należy do najstarszych kobiecych imion Starego Testamentu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Debora</strong> — prorokini i jedyna kobieta-sędzia Izraela, która poprowadziła naród do zwycięstwa nad Kananejczykami (Ks. Sędziów 4–5). Jej pieśń zwycięstwa to jeden z najstarszych tekstów literackich Starego Testamentu. <strong>Deborah Harry</strong> — wokalistka Blondie, ikona punk i new wave lat 70. <strong>Deborah Kerr</strong> — brytyjska aktorka, sześciokrotna nominacja do Oscara. W Polsce Debora to imię rzadkie, o biblijnym, ponadczasowym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Deba, Deborka, Debcia, Deby</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Deborah (ang.), Déborah (franc.), Debora (wł., hiszp., niem., port.), Девора (ros.)</p></div>',

  "Delfina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Delfina pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>Delphinus</em> (delfin) lub od starożytnych Delf. Znaczenie: <strong>„delfin"</strong> lub „z Delf". Imię morskie i mitologiczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Delfina Potocka</strong> — polska arystokratka, muza Fryderyka Chopina i Zygmunta Krasińskiego. <strong>Święta Delfina</strong> — prowansalska błogosławiona z XIV w. W Polsce Delfina to imię rzadkie, eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Delka, Fina, Delfineczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Delphine (franc.), Delfina (wł., hiszp.), Дельфина (ros.)</p></div>',

  "Donald": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Donald pochodzi z języka <strong>szkockiego gaelickiego</strong> — od <em>Domhnall</em>: <em>dumno</em> (świat) + <em>val</em> (władza). Znaczenie: <strong>„władca świata"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Donald Duck</strong> — kaczor Donald, kultowa postać Disneya od 1934 r. <strong>Donald Trump</strong> — 45. i 47. prezydent USA. <strong>Donald Tusk</strong> — polski premier i przewodniczący Rady Europejskiej. W Polsce imię rzadkie, kojarzone z kulturą anglosaską.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Don, Doniek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Donald (ang., szkoc.), Domhnall (gaelicki), Дональд (ros.)</p></div>',

  "Dorian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dorian pochodzi z języka <strong>greckiego</strong> — od <em>Dorieus</em>, nazwy starożytnego plemienia <strong>Dorów</strong>, jednego z głównych ludów greckich. Znaczenie: <strong>„z ludu Dorów"</strong>. Imię o kulturowym i literackim wydźwięku, znane przede wszystkim dzięki powieści Oscara Wilde&#39;a.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię rozsławił Oscar Wilde powieścią <strong><em>Portret Doriana Graya</em></strong> (1890) — o młodzieńcu, który zawarł faustowski pakt: on sam nie starzeje się, natomiast jego portret odbija moralne zepsucie. Symbol narcyzmu, estetyzmu i pogoni za wieczną młodością. <strong>Dorian Gray</strong> to jedna z najbardziej rozpoznawalnych postaci literatury angielskiej. W Polsce imię pojawia się od końca XX w. — eleganckie, literackie, niepospolite.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dorianek, Dori, Dorek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dorian (ang., franc., hiszp., wł., niem.), Дориан (ros.)</p></div>',

  "Dolores": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Dolores pochodzi z języka <strong>hiszpańskiego</strong> — od <em>dolores</em> (bóle, cierpienia). Pełna forma: <em>María de los Dolores</em>. Znaczenie: <strong>„bóle, cierpienie"</strong>, nawiązanie do Matki Bożej Bolesnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Dolores O&#39;Riordan</strong> — wokalistka The Cranberries (<em>Zombie</em>, <em>Linger</em>). <strong>Dolores Ibárruri</strong> — „La Pasionaria", symbol republiki w wojnie domowej w Hiszpanii. W Polsce imię rzadkie, kojarzone z kulturą hiszpańską.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lola, Lolita, Dola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dolores (ang., hiszp., wł.), Долорес (ros.)</p></div>',

  "Edgar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Edgar pochodzi ze <strong>staroangielskiego</strong> — od <em>Ēadgār</em>: <em>ēad</em> (bogactwo) + <em>gār</em> (włócznia). Znaczenie: <strong>„szczęśliwa włócznia"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Edgar Allan Poe</strong> — amerykański pisarz romantyczny, mistrz grozy (<em>Kruk</em>, <em>Zagłada domu Usherów</em>). <strong>Edgar Degas</strong> — francuski malarz impresjonistyczny. <strong>Edgar Wielki</strong> — pierwszy król całej Anglii (X w.). W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Edek, Edgarek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edgar (ang., franc., niem., hiszp., wł.), Эдгар (ros.)</p></div>',

  "Edmund": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Edmund pochodzi ze <strong>staroangielskiego</strong> — od <em>Ēadmund</em>: <em>ēad</em> (bogactwo) + <em>mund</em> (ochrona). Znaczenie: <strong>„obrońca szczęścia"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Edmund Halley</strong> — astronom, odkrywca komety Halleya. <strong>Edmund Hillary</strong> — zdobywca Everestu (1953). <strong>Edmund Niziurski</strong> — polski pisarz dziecięcy. <strong>Święty Edmund</strong> — król Anglii Wschodniej zamęczony przez Wikingów (869 r.).</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mundek, Edek, Edmundek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edmund (ang., niem.), Edmond (franc.), Edmondo (wł.), Edmundo (hiszp.), Эдмунд (ros.)</p></div>',

  "Edwin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Edwin pochodzi ze <strong>staroangielskiego</strong> — od <em>Ēadwine</em>: <em>ēad</em> (bogactwo) + <em>wine</em> (przyjaciel). Znaczenie: <strong>„bogaty przyjaciel"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Edwin Hubble</strong> — astronom, odkrywca galaktyk i rozszerzania się Wszechświata; teleskop Hubble&#39;a nosi jego imię. <strong>Edwin</strong> — król Nortumbrii (VII w.), jeden z pierwszych chrześcijańskich królów Anglii. W Polsce Edwin to imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Edek, Edwinek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edwin (ang., niem., hiszp.), Эдвин (ros.)</p></div>',

  "Egon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Egon pochodzi ze <strong>starowysokoniemieckiego</strong> — od rdzenia <em>ag</em> lub <em>eg</em>, oznaczającego „ostrze miecza, krawędź". Znaczenie: <strong>„dzierżący miecz"</strong> lub „ostry jak ostrze". Imię germańskie, popularne w krajach niemieckojęzycznych i skandynawskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Egon Schiele</strong> (1890–1918) — austriacki malarz i rysownik ekspresjonistyczny, uczeń Gustava Klimta. Jego śmiałe, surowe autoportrety i akty zrewolucjonizowały sztukę europejską. Zmarł na grypę hiszpankę w wieku zaledwie 28 lat, pozostawiając ogromny dorobek. <strong>Egon Krenz</strong> — ostatni sekretarz generalny SED w NRD (1989). <strong>Egon Bondy</strong> — czeski poeta i filozof. W Polsce imię rzadkie, kojarzące się z kulturą środkowoeuropejską i artystycznym temperamentem.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Egoneczek, Egi, Egek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Egon (niem., duń., szw., norw., ang.), Эгон (ros.)</p></div>',

  "Eliza": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Eliza to skrócona forma imienia Elżbieta/Elisabeth, z hebrajskiego <em>Elisheba</em>: Bóg + przysięga. Znaczenie: <strong>„Bogu poświęcona"</strong>. Elegancka, krótka forma.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Eliza Doolittle</strong> — bohaterka sztuki <em>Pygmalion</em> Shawa i musicalu <em>My Fair Lady</em> — dziewczyna z ludu przemieniona w damę. <strong>Eliza Orzeszkowa</strong> — polska pisarka pozytywistyczna (<em>Nad Niemnem</em>). W Polsce imię eleganckie i popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ela, Elizka, Elisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eliza (ang., wł.), Élise (franc.), Elisa (hiszp., niem.), Элиза (ros.)</p></div>',

  "Emil": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emil pochodzi z języka <strong>łacińskiego</strong> — od rodu <em>Aemilius</em>, możliwie od <em>aemulus</em> (rywalizujący). Znaczenie: <strong>„gorliwy, rywalizujący"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Émile Zola</strong> — francuski pisarz naturalistyczny. <strong>Emil</strong> z powieści Kästnera — dziecięcy bohater. Rousseau&#39;s <em>Emil, czyli o wychowaniu</em> (1762) — traktat pedagogiczny. W Polsce Emil to imię eleganckie i ponadczasowe.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Emilek, Emileczek, Miluszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emil (niem., skandynaw.), Émile (franc.), Emilio (wł., hiszp.), Эмиль (ros.)</p></div>',

  "Erazm": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Erazm pochodzi z języka <strong>greckiego</strong> — od <em>erasmios</em> (miły, godny miłości). Znaczenie: <strong>„miły, lubiany"</strong>. Imię o humanistycznym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Erazm z Rotterdamu</strong> (ok. 1467–1536) — holenderski humanista, autor <em>Pochwały głupoty</em>. Program wymiany studenckiej <strong>Erasmus</strong> nosi jego imię. <strong>Święty Erazm</strong> — patron marynarzy. W Polsce imię historyczne, rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Erazmek, Raź</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Erasmus (łac., ang., niem.), Érasme (franc.), Erasmo (wł., hiszp.), Эразм (ros.)</p></div>',

  "Ernest": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ernest pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Ernust</em>, oznaczającego <strong>„powaga, gorliwość"</strong>. Imię germańskie popularne w XIX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ernest Hemingway</strong> — amerykański pisarz, noblista, autor <em>Starego człowieka i morza</em>. <strong>Ernest Rutherford</strong> — fizyk, odkrywca struktury atomu. Oscar Wilde napisał <em>Bądźmy poważni na serio</em> — gdzie imię Ernest jest kluczem fabuły.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ernestuś, Ernestek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ernest (ang., franc., hiszp.), Ernesto (wł.), Ernst (niem.), Эрнест (ros.)</p></div>',

  'Esmeralda': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Esmeralda pochodzi z języka <strong>hiszpańskiego</strong> — od słowa <em>esmeralda</em>, oznaczającego <strong>„szmaragd"</strong>. Wywodzi się z greckiego <em>smaragdos</em> — kamień o intensywnie zielonym kolorze, symbol nadziei i wiosny.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię rozsławiła Esmeralda — piękna tancerka Romka z powieści Wiktora Hugo <em>Katedra Marii Panny w Paryżu</em> (1831). W Polsce imię egzotyczne, nadawane sporadycznie. Popularne w Ameryce Łacińskiej i krajach hiszpańskojęzycznych.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Esmera, Esme, Eralda</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Esmeralda (hiszp., port., ang.), Émeraude (franc.), Смерaльда (ros.)</p></div>',

  "Estera": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Estera pochodzi z języka <strong>perskiego lub hebrajskiego</strong> — od perskiego <em>stara</em> (gwiazda). Znaczenie: <strong>„gwiazda"</strong>. Imię biblijnej bohaterki.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Estera</strong> — żydowska dziewczyna, żona perskiego króla Kserksesa, która uratowała swój naród przed zagładą. Czytana na Purim. <strong>Estée Lauder</strong> — założycielka imperium kosmetycznego. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Esterka, Esta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Esther (ang., niem., franc.), Ester (wł., hiszp., skandynaw.), Эстер (ros.)</p></div>',

  "Eugenia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Eugenia pochodzi z języka <strong>greckiego</strong> — od <em>eugenes</em>: <em>eu</em> (dobry) + <em>genos</em> (ród). Znaczenie: <strong>„z dobrego rodu, szlachetnie urodzona"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Eugenia</strong> — żona Napoleona III, ostatnia cesarzowa Francji. W Polsce Eugenia popularna do połowy XX w. <strong>Eugenia Ginzburg</strong> — rosyjska pisarka, autorka <em>Stromej drogi</em>. Zdrobnienie Genia bardzo popularne w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Genia, Geniusia, Eugeńka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eugénie (franc.), Eugenia (ang., wł., hiszp.), Евгения (ros.)</p></div>',

  "Ewangelina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ewangelina pochodzi z języka <strong>greckiego</strong> — od <em>euangelion</em> (dobra nowina): <em>eu</em> (dobry) + <em>angelos</em> (posłaniec). Znaczenie: <strong>„głosząca dobrą nowinę"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Evangeline</strong> — poemat Longfellowa (1847) o miłości i tułaczce. <strong>Evangeline Lilly</strong> — aktorka z serialu <em>Zaginieni</em>. W Polsce Ewangelina to imię rzadkie, ale piękne brzmieniowo i modne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ewa, Lina, Ewangela</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Evangeline (ang., franc.), Evangelina (hiszp., wł.), Евангелина (ros.)</p></div>',

  'Faustyna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Faustyna pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Faustyn, wywodzącego się od <em>faustus</em> (<strong>„szczęśliwy"</strong>, pomyślny, błogosławiony). Wywodzi się z <em>favere</em> — sprzyjać, błogosławić.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię świętej Faustyny Kowalskiej (1905–1938) — polskiej zakonnicy ze Zgromadzenia Sióstr Matki Bożej Miłosierdzia, mistyczki i autorki <em>Dzienniczka</em>. Propagatorka kultu Miłosierdzia Bożego, kanonizowana przez Jana Pawła II w 2000 r. Patronka Polski.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Faustynka, Faustysia, Fausta</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Faustina (ang., wł., hiszp.), Faustine (franc.), Фаустина (ros.)</p></div>',

  "Flora": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Flora pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>flos/floris</em> (kwiat). Znaczenie: <strong>„kwiat, kwitnąca"</strong>. Imię bogini kwiatów w mitologii rzymskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Flora</strong> — bogini kwiatów i wiosny, czczona podczas Floraliów. <strong>Flora MacDonald</strong> — szkocka bohaterka. W Polsce Flora to imię rzadkie, eleganckie, naturalne — należy do grupy imion kwiatowych i przyrodniczych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Florka, Flo, Flosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Flora (ang., franc., wł., hiszp., niem.), Флора (ros.)</p></div>',

  "Florentyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Florentyna pochodzi z języka <strong>łacińskiego</strong> — od <em>florens</em> (kwitnący). Znaczenie: <strong>„kwitnąca"</strong>. Imię nawiązujące do Florencji.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Florence Nightingale</strong> — twórczyni nowoczesnego pielęgniarstwa, urodzona we Florencji. W Polsce Florentyna to imię eleganckie, rzadkie, o literackim brzmieniu. <strong>Florentyna</strong> — bohaterka powieści historycznych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Florka, Flo, Tyna</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Florence (ang., franc.), Fiorenza (wł.), Florencia (hiszp.), Флорентина (ros.)</p></div>',

  "Anastazy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Anastazy to męska forma imienia Anastazja, z języka <strong>greckiego</strong> — od <em>anastasis</em> (zmartwychwstanie). Znaczenie: <strong>„zmartwychwstały"</strong>. Imię o głęboko chrześcijańskim rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Anastazy I</strong> — wczesnochrześcijański biskup Rzymu. <strong>Anastazy Siniarski</strong> — błogosławiony kapucyn, męczennik II wojny. W Polsce imię rzadkie, obecne w tradycji kościelnej. Znany jest zdrobnienie <em>Nastka</em> — typowo dla form żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nastka (żeńskie), Anastek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anastasius (łac., ang.), Anastase (franc.), Anastasio (wł., hiszp.), Анастасий (ros.)</p></div>',

  "Damiana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Damiana to żeńska forma imienia Damian, z języka <strong>greckiego</strong> — od <em>damazein</em>, co znaczy „ujarzmić, oswoić, poskromić". Znaczenie: <strong>„ta, która poskramia"</strong> lub „oswajaczka". Imię kościelne, związane z kultem świętych bliźniaków patronów lekarzy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię wywodzi się od kultu świętych <strong>Kosmy i Damiana</strong> — arabskich bliźniaków, lekarzy leczących bezpłatnie, zamordowanych ok. 303 r. Są patronami lekarzy i aptekarzy. Żeńska forma Damiana pojawia się w literaturze romańskiej i kościelnej. W Polsce imię rzadkie, eleganckie, o wyraźnym kościelnym rodowodzie, używane głównie w krajach włoskojęzycznych i hiszpańskojęzycznych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dami, Damianka, Damcia, Damia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Damiana (ang., wł., hiszp., port.), Damiane (franc.), Дамиана (ros.)</p></div>',

  'Dagna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Dagna pochodzi z języka <strong>staronordyjskiego</strong> — od <em>dagny</em>, złożonego z <em>dagr</em> (dzień) i <em>ny</em> (nowy). Oznacza <strong>„nowy dzień"</strong> lub „blask nowego dnia". Imię pełne świeżości i optymizmu.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię skandynawskie, w Polsce znane od XX w., cenione za oryginalność i brzmieniową elegancję. Noszone przez postacie literackie i sceniczne w kulturze polskiej. Popularne jako imię rzadkie, ale zapamiętywalne.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Dagusia, Dagienka, Daga</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Dagny (norwes., szwedz., duń.), Dagna (pol.) — forma spolszczona</p></div>',

  "Faust": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Faust pochodzi z języka <strong>łacińskiego</strong> — od <em>faustus</em> (pomyślny, szczęśliwy). Znaczenie: <strong>„szczęśliwy, pomyślny"</strong>. Imię o literackim i legendowym wymiarze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Faust</strong> — legendarny alchemik z XVI w., który sprzedał duszę diabłu. Johann Wolfgang von <strong>Goethe</strong> uczynił go bohaterem swojego arcydzieła <em>Faust</em> (1808–1832). Opera <em>Faust</em> Gounoda. W Polsce imię rzadkie, literackie, filozoficzne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fausteczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Faustus (łac.), Fausto (wł., hiszp.), Fauste (franc.), Фауст (ros.)</p></div>',

  "Felicja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Felicja pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>Felix</em> (szczęśliwy, pomyślny). Znaczenie: <strong>„szczęśliwa"</strong>. Imię kościelne i polskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Błogosławiona Felicja Meda</strong> — tercjarka franciszkańska. W Polsce Felicja była popularna w XIX i pierwszej połowie XX w. Zdrobnienie <em>Fela</em> bardzo charakterystyczne. <strong>Felicja Burak</strong> — postać z polskiej kultury popularnej. Imię o szczęśliwym znaczeniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fela, Felka, Felicka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Felicia (ang.), Félicie (franc.), Felicia (wł., hiszp.), Феличия (ros.)</p></div>',

  "Filemon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Filemon pochodzi z języka <strong>greckiego</strong> — od <em>philemon</em> (przyjacielski, lubiący), od <em>philein</em> (kochać). Znaczenie: <strong>„przyjazny, kochający"</strong>. Imię biblijne i mitologiczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Filemon</strong> — chrześcijanin, do którego Paweł napisał list (Filemona). W mitologii <strong>Filemon i Baucis</strong> — para staruszków, którzy ugościli bogów i zostali zamienieni w drzewa. W Polsce imię rzadkie, biblijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Filemek, Filo</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Philemon (ang., franc.), Filemone (wł.), Filemón (hiszp.), Филимон (ros.)</p></div>',

  "Grzegorz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Grzegorz pochodzi z języka <strong>greckiego</strong> — od <em>gregorios</em> (czujny, czuwający), od <em>gregorein</em> (czuwać, być czujnym). Znaczenie: <strong>„czujny, czuwający"</strong>. Imię papieskie i powszechne w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Grzegorz I Wielki</strong> — reformator liturgii, twórca chorału gregoriańskiego. <strong>Grzegorz XIII</strong> — wprowadził kalendarz gregoriański (1582). W Polsce <strong>Grzegorz z Sanoka</strong> — humanista, arcybiskup lwowski. Imię bardzo popularne w Polsce w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Grześ, Grzesiek, Grześko</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gregory (ang.), Grégoire (franc.), Gregorio (wł., hiszp.), Gregor (niem.), Григорий (ros.)</p></div>',

  "Henryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Henryk pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Heimrich</em>: <em>heim</em> (dom) + <em>rich</em> (władca, potężny). Znaczenie: <strong>„władca domu"</strong> lub „potężny pan". Imię dynastyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nosili władcy europejscy — <strong>ośmiu Henryków angielskich</strong>, <strong>czterech cesarzy</strong>. W Polsce <strong>Henryk Brodaty</strong> i <strong>Henryk Pobożny</strong>. <strong>Henryk Sienkiewicz</strong> — noblista, autor <em>Trylogii</em>. <strong>Henryk Sławik</strong> — „polski Schindler".</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Henio, Heniuś, Heniek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Henry (ang.), Henri (franc.), Heinrich (niem.), Enrico (wł.), Enrique (hiszp.), Генрих (ros.)</p></div>',

  "Izabela": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Izabela to romańska forma imienia Elisabeth/Elżbieta, z języka <strong>hebrajskiego</strong> — od <em>Elisheba</em>: Bóg + przysięga. Znaczenie: <strong>„Bogu poświęcona"</strong>. Forma przez Hiszpanię weszła do Polski.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Izabela Kastylijska</strong> — królowa Hiszpanii, która sfinansowała wyprawę Kolumba. <strong>Izabela Braganzy</strong> — cesarzowa Brazylii. W Polsce <strong>Izabela Czartoryska</strong> — założycielka muzeum w Puławach. Imię eleganckie, wciąż popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Iza, Izka, Bela, Izunia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Isabel (hiszp., ang.), Isabella (wł., ang.), Isabelle (franc.), Изабелла (ros.)</p></div>',

  "Izydor": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Izydor pochodzi z języka <strong>greckiego</strong> — od <em>Isidoros</em>: <em>Isis</em> (egipska bogini) + <em>doron</em> (dar). Znaczenie: <strong>„dar Izydy"</strong>. Imię o starożytnych korzeniach egipsko-greckich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Izydor z Sewilli</strong> (ok. 560–636) — encyklopedysta średniowiecza, patron internetu (Jan Paweł II). <strong>Izydor Oracz</strong> — hiszpański patron rolników. W Polsce imię rzadkie. <strong>Patron informatyków</strong> — z racji, że Izydor z Sewilli skompilował pierwszą encyklopedię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Izio, Izek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Isidore (ang., franc.), Isidoro (wł., hiszp.), Исидор (ros.)</p></div>',

  "Juliusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Juliusz pochodzi z języka <strong>łacińskiego</strong> — od rodu Juliuszów (<em>Iulius</em>), możliwie od greckiego <em>ioulos</em> (owłosiony, brodaty) lub od boga Jowisza. Znaczenie: <strong>„z rodu Juliuszów"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Juliusz Cezar</strong> — największy wódz Rzymu, dyktator. <strong>Juliusz Verne</strong> — ojciec science-fiction. <strong>Juliusz Słowacki</strong> — wielki polski poeta romantyczny. Nazwa miesiąca <em>lipiec</em> pochodzi właśnie od Juliusza Cezara. W Polsce imię popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Julek, Juleczek, Juliuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Julius (ang., niem.), Jules (franc.), Giulio (wł.), Julio (hiszp.), Юлий (ros.)</p></div>',

  "Karol": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Karol pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Karl</em>, oznaczającego <strong>„mężczyzna, wolny człowiek"</strong>. Imię dynastyczne, od Karola Wielkiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Karol Wielki</strong> — cesarz, twórca Europy. <strong>Karol Darwin</strong> — autor teorii ewolucji. W Polsce imię nosi wielu wybitnych: <strong>Karol Szymanowski</strong> — kompozytor, <strong>Karol Wojtyła</strong> — Jan Paweł II, <strong>Karol Kurpiński</strong> — muzyk. Imię wciąż popularne w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Karolek, Karoluś, Karolczyk</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Charles (ang., franc.), Karl (niem.), Carlo (wł.), Carlos (hiszp.), Карл (ros.)</p></div>',

  "Kazimierz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kazimierz to imię <strong>słowiańskie</strong> — od <em>Kazimir</em>: <em>kazić</em> (niszczyć, karać) + <em>mir</em> (pokój, świat). Interpretowane też jako <strong>„ogłaszający pokój"</strong>. Imię piastowskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Kazimierz Wielki</strong> (1310–1370) — jedyny polski król zwany Wielkim, twórca ustroju i prawa. „Zastał Polskę drewnianą, zostawił murowaną". <strong>Kazimierz Jagiellończyk</strong>. <strong>Kazimierz Pułaski</strong> — bohater rewolucji amerykańskiej. <strong>Kazimierz Górski</strong> — trener piłkarski.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kazik, Kazio, Kaziu</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Casimir (ang., franc.), Casimiro (wł., hiszp.), Kasimir (niem.), Казимир (ros.)</p></div>',


  "Leon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Leon pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>leon</em> (lew). Znaczenie: <strong>„lew"</strong>. Imię symbolizujące siłę, odwagę i królewskość.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Leon I Wielki</strong> — powstrzymał Attylę od ataku na Rzym (452 r.). Wielu papieży nosiło to imię. <strong>Leon Tolstoj</strong> — rosyjski pisarz (<em>Wojna i pokój</em>). <strong>Leon Wyczółkowski</strong> — polski malarz. W Polsce Leon to imię popularne, wracające do mody w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leonek, Leoni, Leoś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leo (ang., niem.), Léon (franc.), Leone (wł.), León (hiszp.), Лев / Леон (ros.)</p></div>',

  "Leopold": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leopold pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Liutbald</em>: <em>liut</em> (lud) + <em>bald</em> (odważny). Znaczenie: <strong>„odważny lud"</strong> lub „lider ludu". Imię dynastyczne Habsburgów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię habsburskie: <strong>Leopold I, II, III</strong> — cesarze i królowie. <strong>Leopold Staff</strong> — wybitny polski poeta. <strong>Leopold von Ranke</strong> — ojciec nowoczesnej historiografii. <strong>Leopold Bloom</strong> — bohater <em>Ulissesa</em> Joyce&#39;a. W Polsce imię rzadkie, prestiżowe.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lolek, Poldo, Leopoldek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leopold (ang., niem., franc.), Leopoldo (wł., hiszp.), Леопольд (ros.)</p></div>',

  "Lidia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Lidia pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od nazwy krainy Lidia (<em>Lydia</em>) w Azji Mniejszej. Znaczenie: <strong>„kobieta z Lidii"</strong>. Imię geograficzne i biblijne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Lidia</strong> — pierwsza europejska chrześcijanka, handlarka purpurą z Filippi, ochrzczona przez Pawła. <strong>Lidia Wysocka</strong> — polska aktorka. W Polsce Lidia bardzo popularna w XX w., zwłaszcza w latach 50.–70. <strong>Lydia Davis</strong> — amerykańska pisarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lidka, Lida, Lidi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Lydia (ang., niem.), Lydie (franc.), Lidia (wł., hiszp.), Лидия (ros.)</p></div>',

  "Longin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Longin pochodzi z języka <strong>łacińskiego</strong> — od <em>longinus</em>, związanego z <em>longus</em> (długi). Znaczenie: <strong>„długi, wysoki"</strong>. Imię tradycyjnie wiązane z żołnierzem pod krzyżem.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Longin</strong> — według tradycji żołnierz, który przebił bok Jezusa włócznią (Ewangelia Jana 19,34). Włócznia Longina — jedno z najważniejszych relikwii chrześcijaństwa. W Polsce imię rzadkie, historyczne, o biblijnym i legendarnym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Longo, Longineczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Longinus (łac.), Longin (franc.), Longino (wł., hiszp.), Лонгин (ros.)</p></div>',

  "Łukasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Łukasz to polska forma imienia Łukasz/Lucas, z języka <strong>greckiego lub łacińskiego</strong> — od <em>Loukas</em>, nawiązania do Lukanii (<em>Lucania</em>) — krainy w Italii. Znaczenie: <strong>„człowiek ze światła"</strong> lub „z Lukanii".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Łukasz</strong> — autor Ewangelii i Dziejów Apostolskich, lekarz i malarz (tradycja przypisuje mu obraz Czarnej Madonny Częstochowskiej). Patron lekarzy i malarzy. W Polsce jedno z najpopularniejszych imion XXI w. <strong>Lucas van Leyden</strong> — holenderski malarz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Łukaszek, Łutek, Luka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Luke, Lucas (ang.), Luc (franc.), Luca (wł.), Lucas (hiszp., niem.), Лука (ros.)</p></div>',

  "Maksymilian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Maksymilian pochodzi z języka <strong>łacińskiego</strong> — od <em>Maximilianus</em>, złożonego z <em>Maximus</em> (największy) i <em>Aemilianus</em>. Znaczenie: <strong>„największy"</strong>. Imię cesarskie i dynastyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Maksymilian I</strong> — cesarz Świętego Cesarstwa, jeden z największych Habsburgów. <strong>Maksymilian Kolbe</strong> — polski franciszkanin, oddał życie za współwięźnia w Auschwitz, kanonizowany 1982 r. — symbol miłości bliźniego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maks, Maksio, Maksymek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maximilian (ang., niem.), Maximilien (franc.), Massimiliano (wł.), Maximiliano (hiszp.), Максимилиан (ros.)</p></div>',

  "Małgorzata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Małgorzata to polska forma imienia Margareta, z języka <strong>greckiego</strong> — od <em>margarites</em> (perła). Znaczenie: <strong>„perła"</strong>. Jedno z najpopularniejszych imion żeńskich w historii Europy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Małgorzata z Antiochii</strong> — święta i patronka. <strong>Margaret Thatcher</strong> — pierwsza kobieta-premier Wielkiej Brytanii. W Polsce <strong>Małgorzata Szumowska</strong> — reżyserka filmowa. Imię przez wieki w ścisłej czołówce polskich imion żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gosia, Małgosia, Margosia, Marta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Margaret (ang.), Marguerite (franc.), Margherita (wł.), Margarita (hiszp.), Маргарита (ros.)</p></div>',

  "Marcin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Marcin to polska forma imienia Martinus, z języka <strong>łacińskiego</strong> — od <em>Mars</em> (bóg wojny). Znaczenie: <strong>„należący do Marsa"</strong> lub „wojowniczy". Imię o korzeniach w antycznym Rzymie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Marcin z Tours</strong> — patron Francji, podzielił płaszcz z żebrakiem. <strong>Martin Luther King</strong> — działacz praw obywatelskich. <strong>Marcin Luter</strong> — reformator Kościoła. W Polsce Marcin to jedno z najpopularniejszych imion, szczególnie w XIX–XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marcinek, Marcineczek, Marek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Martin (ang., niem., franc.), Martino (wł.), Martín (hiszp.), Мартин (ros.)</p></div>',

  "Mariusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mariusz pochodzi z języka <strong>łacińskiego</strong> — od rodu Mariuszów (<em>Marius</em>), możliwie od <em>Mars</em> (bóg wojny). Znaczenie: <strong>„z rodu Mariuszów"</strong> lub „wojowniczy".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Gajusz Mariusz</strong> — reformator armii rzymskiej, siedmiokrotny konsul. <strong>Mariusz Pudzianowski</strong> — wielokrotny mistrz świata strongman i zawodnik MMA. <strong>Mariusz Treliński</strong> — reżyser operowy. W Polsce Mariusz popularny od lat 70. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mario, Mariuszek, Maro</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marius (ang., franc., niem.), Mario (wł., hiszp.), Марий (ros.)</p></div>',

  "Mieczysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mieczysław to polskie imię dwuczłonowe — złożone z <em>miecz</em> (broń sieczna) + <em>-sław</em> (sława). Znaczenie: <strong>„sławny z miecza"</strong>. Imię typowo słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Mieszko I</strong> — pierwszy historyczny władca Polski, twórca państwa polskiego (966 — chrzest). <strong>Mieczysław Fogg</strong> — legendarny polski śpiewak. <strong>Mieczysław Weinberg</strong> — kompozytor. W Polsce imię popularne do połowy XX w., dziś rzadsze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mietek, Miecio, Mieciek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mieszko / Mieczysław — imię typowo polskie i słowiańskie</p></div>',

  "Mikołaj": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mikołaj to polska forma imienia Nikolaos, z języka <strong>greckiego</strong> — od <em>nike</em> (zwycięstwo) + <em>laos</em> (lud). Znaczenie: <strong>„zwycięzca ludu"</strong>. Jedno z najpopularniejszych imion chrześcijańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Mikołaj z Miry</strong> — patron dzieci, żeglarzy i kupców. Jako Święty Mikołaj — przynosi prezenty 6 grudnia. <strong>Mikołaj Kopernik</strong> — odkrył, że Ziemia krąży wokół Słońca. <strong>Niccolò Machiavelli</strong> — włoska forma. W Polsce Mikołaj popularny przez wieki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mikoś, Nikolas, Mikołajek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicholas (ang.), Nicolas (franc.), Nicola (wł.), Nicolás (hiszp.), Николай (ros.)</p></div>',

  "Milena": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Milena to imię <strong>słowiańskie</strong> — od rdzenia <em>mil-</em> (miły, drogi, kochany). Znaczenie: <strong>„miła, kochana"</strong>. Forma żeńska od Miłosław lub pokrewnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Milena Jesenská</strong> — czeska dziennikarka i tłumaczka, korespondentka Franza Kafki, ofiara Holokaustu. <strong>Milena Vukotic</strong> — włoska aktorka. W Polsce Milena popularna od lat 80.–90. XX w. i wciąż w czołówce imion żeńskich XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Milka, Milenka, Mila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Milena (ang., wł., franc., niem., hiszp.), Милена (ros., bułg.)</p></div>',

  "Mirosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Mirosław to polskie imię dwuczłonowe — złożone z <em>mir</em> (pokój, świat) + <em>-sław</em> (sława). Znaczenie: <strong>„sławny pokojem"</strong>. Imię typowo słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Mirosław Hermaszewski</strong> — jedyny Polak w kosmosie (1978). <strong>Mirosław Klose</strong> — piłkarz, rekordzista strzelecki mistrzostw świata. <strong>Mirosław Baka</strong> — aktor, znany z filmów Kieślowskiego. W Polsce imię popularne w XX w., zdrobnienie Mirek bardzo charakterystyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mirek, Mirosiek, Miruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Miroslav (czes., serb., słowac.), Miroslao (wł.), Мирослав (ros.)</p></div>',

  "Modesta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Modesta pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>modestus</em> (umiarkowany, skromny). Znaczenie: <strong>„skromna, umiarkowana"</strong>. Imię kościelne i staropolskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Modesta</strong> — chrześcijańska święta z tradycji kościelnej. W Polsce Modesta to imię rzadkie, archaiczne, znane z historii i kalendarza imienin. Symbolizuje cnotę pokory i umiarkowania. Imię o eleganckim, łacińskim brzmieniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Modzia, Desta</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Modesta (ang., wł., hiszp.), Modeste (franc.), Модеста (ros.)</p></div>',

  "Nadia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Nadia to skrócona forma imienia Nadieżda, z języka <strong>rosyjskiego lub słowiańskiego</strong> — od <em>nadezhda</em> (nadzieja). Znaczenie: <strong>„nadzieja"</strong>. Imię popularne w Europie przez kulturę słowiańską i francuską.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Nadia Comaneci</strong> — rumuńska gimnastyczka, pierwsza sportsmenka z oceną 10,0 na olimpiadzie (1976). <strong>Nadia Boulanger</strong> — wybitna francuska dyrygentka i pedagog muzyczny. W Polsce Nadia to imię modne od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nadi, Nadziuśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nadia (franc., ang., wł.), Nadya (ros.), Надя (ros.)</p></div>',

  "Naomi": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Naomi pochodzi z języka <strong>hebrajskiego</strong> — od <em>Naomi</em> (נָעֳמִי), co znaczy <strong>„miła, przyjemna"</strong>. Imię biblijnej bohaterki Księgi Rut.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Naomi</strong> — teściowa Rut, z którą Rut nie rozstała się słowami „dokąd ty, tam i ja". <strong>Naomi Campbell</strong> — supermodelka, jedna z ikon lat 90. <strong>Naomi Judd</strong> — piosenkarka country. W Polsce Naomi to imię rzadkie, modne i nowoczesne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Naomika, Nao</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Naomi (ang., franc., niem., wł., hiszp.), Наоми (ros.), נָעֳמִי (hebr.)</p></div>',

  "Natalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Natalia pochodzi z języka <strong>łacińskiego</strong> — od <em>natalis dies Domini</em> (dzień narodzin Pana), od <em>natalis</em> (narodziny). Znaczenie: <strong>„urodzona w Boże Narodzenie"</strong>. Imię związane ze świętami.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Natalia</strong> — męczennica z IV w. <strong>Natalia Gonczarowa</strong> — żona Aleksandra Puszkina. <strong>Natalia Oreiro</strong> — argentyńska aktorka i piosenkarka. W Polsce Natalia to jedno z najpopularniejszych imion żeńskich od lat 90. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nata, Natka, Natusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Natalie (ang., franc., niem.), Natalia (wł., hiszp.), Наталья (ros.)</p></div>',

  "Nikodem": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Nikodem pochodzi z języka <strong>greckiego</strong> — od <em>Nikodemos</em>: <em>nike</em> (zwycięstwo) + <em>demos</em> (lud). Znaczenie: <strong>„zwycięzca ludu"</strong>. Imię biblijne i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Nikodem</strong> — faryzeusz i członek Sanhedrynu, który przyszedł do Jezusa w nocy (J 3) i uczestniczył w Jego pogrzebie. <strong>Nikodem Sulik</strong> — polski generał. <strong>Nikodem Dyzma</strong> — bohater powieści Tadeusza Dołęgi-Mostowicza, symbol karierowicza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nikodek, Nico, Nikoś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Nicodemus (ang., łac.), Nicodème (franc.), Nicodemo (wł., hiszp.), Никодим (ros.)</p></div>',

  "Norberta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Norberta to żeńska forma imienia Norbert, z języka <strong>starowysokoniemieckiego</strong> — od <em>nord</em> (północ) + <em>beraht</em> (jasny, błyszczący). Znaczenie: <strong>„jasność północy"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska od imienia <strong>Świętego Norberta z Xanten</strong> — założyciela zakonu premonstratensów (norbertanów). W Polsce norbertanki to zakon wywodzący się od tego świętego. Imię Norberta rzadkie w Polsce, historyczne i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Norka, Berta, Norbertka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Norberta (ang., wł., hiszp.), Norbert (forma męska), Нoрберта (ros.)</p></div>',

  "Oktawia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Oktawia pochodzi z języka <strong>łacińskiego</strong> — od <em>octavus</em> (ósmy). Znaczenie: <strong>„ósma"</strong>. Żeńska forma imienia Oktawiusz, związana z rodem cesarskim.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oktawia Młodsza</strong> — siostra Augusta, żona Marka Antoniusza, wzór rzymskiej kobiety. <strong>Octavia Spencer</strong> — amerykańska aktorka, laureatka Oscara (<em>Służące</em>). W Polsce Oktawia to imię rzadkie, ale modne w XXI w. jako imię starożytne i eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oka, Tawia, Oktawka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Octavia (ang.), Octavie (franc.), Ottavia (wł.), Octavia (hiszp.), Октавия (ros.)</p></div>',

  "Olaf": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Olaf pochodzi ze <strong>staronordyjskiego</strong> — od <em>Ánleifr</em>: <em>anu</em> (przodek) + <em>leifr</em> (pozostałość, spadkobierca). Znaczenie: <strong>„dziedzic przodków"</strong>. Imię skandynawskich królów i świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Olaf II Haraldsson</strong> — patron Norwegii, chrystianizował kraj (XI w.). <strong>Olaf</strong> — bałwanek ze <em>Krainy lodu</em> Disneya, symbol niewinności i ciepła. <strong>Olaf Palme</strong> — szwedzki premier, zamordowany w 1986 r. W Polsce imię rzadkie, nordyckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Olafek, Olf</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Olaf (skandynaw., niem., ang.), Olave (ang.), Олаф (ros.)</p></div>',

  "Olimpia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Olimpia pochodzi z języka <strong>greckiego</strong> — od nazwy góry Olimp (<em>Olympos</em>), siedziby bogów greckich. Znaczenie: <strong>„olimpijska, z Olimpu"</strong>. Imię o boskim rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Olimpias</strong> — matka Aleksandra Macedońskiego, potężna królowa Epiru. <strong>Olimpia</strong> — bohaterka opery Offenbacha (<em>Opowieści Hoffmanna</em>) — piękna lalka-automaton. W Polsce Olimpia to imię rzadkie, o antycznym brzmieniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Olka, Olimpka, Pia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Olympia (ang., franc., niem.), Olimpia (wł., hiszp.), Олимпия (ros.)</p></div>',

  "Onufry": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Onufry pochodzi z języka <strong>egipskiego lub koptyjskiego</strong> — od <em>Onnophris</em> (Onnophrios): imię Ozyrysa w formie wiecznej. Znaczenie: <strong>„wiecznie szczęśliwy"</strong>. Imię przez Egipt weszło do chrześcijaństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Onufry</strong> — egipski pustelnik z IV w., żyjący w głębokiej puszczy. Patron wszelkiej pracy fizycznej i rolników. W Polsce imię Onufry znane z komedii i literatury — <strong>Onufry Zagłoba</strong> ze <em>Trylogii</em> Sienkiewicza — postać rubaszna i komiczna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Onufek, Nufek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Onophrius (łac.), Onuphre (franc.), Onofrio (wł.), Onofre (hiszp.), Онуфрий (ros.)</p></div>',

  "Orest": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Orest pochodzi z języka <strong>greckiego</strong> — od <em>oros</em> (góra). Znaczenie: <strong>„górski, zamieszkały w górach"</strong>. Imię mitologicznego bohatera tragedii greckiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W mitologii <strong>Orestes</strong> — syn Agamemnona i Klitajmestry, który zabił matkę, by pomścić ojca. Prześladowany przez Erynie, uniewinniony przez Atenę. Bohater tragedii Ajschylosa (<em>Oresteja</em>). W Polsce imię rzadkie, związane z kulturą antyczną.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oresteczek, Ores</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Orestes (ang., łac., wł., hiszp.), Oreste (franc., wł.), Орест (ros.)</p></div>',

  "Oskar": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Oskar pochodzi ze <strong>staroirlandzkiego lub staronordyjskiego</strong> — od <em>Osgar</em>: <em>os</em> (bóg) + <em>gār</em> (włócznia). Znaczenie: <strong>„włócznia bogów"</strong>. Imię celtyckie i nordyckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oscar Wilde</strong> — irlandzki pisarz i dandys. <strong>Oscar</strong> — nagroda filmowa (statuetka przyznawana przez Akademię Hollywood). <strong>Oskar Schindler</strong> — Niemiec, który uratował ponad tysiąc Żydów (<em>Lista Schindlera</em>). W Polsce Oskar popularne imię XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oskarek, Osio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Oscar (ang., hiszp., wł., franc.), Оскар (ros.)</p></div>',

  "Patrycja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Patrycja pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>patricius</em> (szlachcic, patrycjusz). Znaczenie: <strong>„szlachcianka, z wyższej klasy"</strong>. Imię arystokratyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Patrycja</strong> — patronka Neapolu. <strong>Patrycja</strong> — polska forma popularnego na zachodzie imienia Patricia. W Polsce Patrycja bardzo popularna od lat 80.–90. XX w. <strong>Patrycja Markowska</strong> — polska piosenkarka. Imię wciąż w czołówce imion nadawanych dziewczynkom.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Patka, Patryczka, Pati</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Patricia (ang., hiszp., wł.), Patrizia (wł.), Patricija (franc.), Патриция (ros.)</p></div>',

  "Paweł": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Paweł pochodzi z języka <strong>łacińskiego</strong> — od <em>Paulus</em> (mały, skromny), od <em>paulus</em> (mały). Znaczenie: <strong>„mały, skromny"</strong>. Imię apostoła i wielu świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Paweł</strong> — Apostoł Narodów, nawrócony pod Damaszkiem, autor listów Nowego Testamentu, patron wielu krajów. <strong>Jan Paweł II</strong> — Karol Wojtyła. <strong>Paul McCartney</strong> — Beatle. W Polsce Paweł jedno z najpopularniejszych imion przez całe XX i XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Pawełek, Pawuś, Picio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Paul (ang., niem., franc.), Paolo (wł.), Pablo (hiszp.), Павел (ros.)</p></div>',

  "Piotr": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Piotr pochodzi z języka <strong>greckiego</strong> — od <em>petra</em> (skała, kamień). Znaczenie: <strong>„skała"</strong>. Imię nadane Szymonowi przez Jezusa — fundamentowi Kościoła.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Piotr Apostoł</strong> — pierwszy papież, klucze do nieba. <strong>Piotr Wielki</strong> — car Rosji, modernizator. <strong>Piotr Chopin</strong> (choć imię Fryderyk). <strong>Piotr Skarga</strong> — kaznodzieja jezuicki. W Polsce jedno z najczęstszych imion przez wieki. Zdrobnienie Pietrek i Piotrek charakterystyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Piotrek, Pietrek, Piotruś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Peter (ang., niem.), Pierre (franc.), Pietro (wł.), Pedro (hiszp.), Пётр (ros.)</p></div>',

  "Przemysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Przemysław to polskie imię dwuczłonowe — złożone z <em>przemysł</em> (przezorność, pomysł) + <em>-sław</em> (sława). Znaczenie: <strong>„sławny z przemyślności"</strong>. Imię piastowskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Przemysł I</strong> i <strong>Przemysł II</strong> — władcy piastowscy. Przemysł II koronował się na króla Polski w 1295 r. <strong>Przemysław Gintrowski</strong> — piosenkarz. <strong>Przemek</strong> — bardzo popularne zdrobnienie. Imię popularne w Polsce, szczególnie w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Przemek, Przemo, Przemeczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Přemysl (czes.) — imię typowo polskie i słowiańskie</p></div>',

  "Radosław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Radosław to polskie imię dwuczłonowe — złożone z <em>rado-</em> (radość) + <em>-sław</em> (sława). Znaczenie: <strong>„sławny radością"</strong> lub „ten, komu radość przynosi sławę". Imię słowiańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Polsce od wieków. <strong>Radosław Sikorski</strong> — polski polityk, minister spraw zagranicznych. <strong>Radosław</strong> (Radek) — zdrobnienie bardzo charakterystyczne. Imię słowiańskie, wciąż nadawane w Polsce, kojarzące się z optymizmem i słonecznością.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Radek, Radosiek, Radusio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Radoslav (czes., serb.), Radosław — imię słowiańskie</p></div>',

  "Rafał": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rafał pochodzi z języka <strong>hebrajskiego</strong> — od <em>Rafa&#39;el</em>: <em>rafa</em> (leczyć) + <em>El</em> (Bóg). Znaczenie: <strong>„Bóg leczy"</strong>. Imię archanioła, patrona lekarzy i podróżnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Archanioł Rafał</strong> — jeden z trzech archaniołów (Michał, Gabriel, Rafał), patron lekarzy i podróżujących (Księga Tobiasza). <strong>Raffaello Santi</strong> — włoski malarz renesansowy, autor <em>Madonny Sykstyńskiej</em>. W Polsce Rafał bardzo popularny w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rafałek, Rafcio, Rafi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Raphael (ang., franc., niem.), Raffaele (wł.), Rafael (hiszp.), Рафаил (ros.)</p></div>',

  "Renata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Renata pochodzi z języka <strong>łacińskiego</strong> — od <em>renatus</em> (odrodzony, narodzony na nowo). Znaczenie: <strong>„odrodzona"</strong>. Imię chrzcielne nawiązujące do odrodzenia przez chrzest.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Renata</strong> — imię popularne we Francji, Włoszech i Polsce. <strong>Renata Tebaldi</strong> — słynna włoska soprano, rywalka Marii Callas. <strong>Renata Przemyk</strong> — polska piosenkarka. W Polsce Renata bardzo popularna w latach 60.–80. XX w., dziś rzadsza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Renka, Renia, Renatka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Renata (wł., hiszp.), Renée (franc.), Renata (niem.), Рената (ros.)</p></div>',

  "Remigiusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Remigiusz pochodzi z języka <strong>łacińskiego</strong> — od <em>Remigius</em>, związanego z <em>remigare</em> (wiosłować) lub od <em>Remi</em> — nazwy ludu galickiego. Znaczenie: <strong>„wioślarz"</strong> lub „z ludu Remów".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Remigiusz</strong> (ok. 437–533) — arcybiskup Reims, który ochrzcił Chlodwiga — króla Franków — w 496 r. Jedno z najważniejszych wydarzeń w historii Europy. W Polsce imię rzadkie, kojarzone z historią chrześcijaństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Remi, Remek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Remigius (łac., niem.), Rémi/Remy (franc.), Remigio (wł., hiszp.), Ремигий (ros.)</p></div>',

  "Roland": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Roland pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hruodland</em>: <em>hruod</em> (sława) + <em>land</em> (kraj, ziemia). Znaczenie: <strong>„sławna ziemia"</strong>. Imię rycerskie i epiczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Roland</strong> — rycerz Karola Wielkiego, bohater epopei <em>Pieśń o Rolandzie</em> (XI w.), który poległ w wąwozie Ronceval. Dmuchał w róg Olifant, choć mógł wezwać pomoc. Symbol rycerskiej odwagi i honoru. <strong>Roland Garros</strong> — pilot i kort tenisowy.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rolek, Rolando</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Roland (ang., franc., niem.), Orlando (wł., hiszp.), Роланд (ros.)</p></div>',

  "Roman": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Roman pochodzi z języka <strong>łacińskiego</strong> — od <em>Romanus</em> (Rzymianin, z Rzymu). Znaczenie: <strong>„Rzymianin"</strong>. Imię nawiązujące do Imperium Rzymskiego i jego kultury.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Roman Polański</strong> — reżyser, laureat Oscara (<em>Pianista</em>). <strong>Roman Dmowski</strong> — ojciec polskiej demokracji narodowej. <strong>Roman Ingarden</strong> — wybitny polski filozof. W Polsce Roman bardzo popularne w XX w., dziś rzadziej nadawane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Romek, Romuś, Romcio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Roman (ang., niem., franc.), Romano (wł.), Román (hiszp.), Роман (ros.)</p></div>',

  "Rozalia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rozalia pochodzi z języka <strong>łacińskiego</strong> — od <em>rosalia</em> (święto róż) lub bezpośrednio od <em>rosa</em> (róża). Znaczenie: <strong>„różana"</strong>. Imię kwiatowe i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Rozalia</strong> — patronka Palermo, która żyła jako pustelnica w jaskini. Jej relikwie uratowały miasto od zarazy w 1625 r. <strong>Rozalia</strong> — bohaterka wielu polskich powieści i filmów. W Polsce imię Rozalia popularne do XX w., dziś rzadsze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rozia, Roza, Rozalka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rosalia (ang., wł., hiszp.), Rosalie (franc., niem.), Розалия (ros.)</p></div>',

  "Rudolf": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rudolf pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Hrodwulf</em>: <em>hruod</em> (sława) + <em>wulf</em> (wilk). Znaczenie: <strong>„sławny wilk"</strong>. Imię dynastyczne Habsburgów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Rudolf I Habsburg</strong> — założyciel dynastii, król Niemiec. <strong>Rudolf Valentino</strong> — gwiazda kina niemego, symbol romantyzmu. <strong>Rudolf</strong> — czerwononosy renifer Świętego Mikołaja (ballada z 1939 r.). W Polsce Rudolf to imię rzadkie, kojarzone z Austro-Węgrami.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rudzio, Rudi, Rudolfek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Rudolf (niem.), Rodolphe (franc.), Rodolfo (wł., hiszp.), Рудольф (ros.)</p></div>',

  "Ryszard": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ryszard pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Ricohard</em>: <em>ric</em> (władca, potężny) + <em>hard</em> (dzielny, twardy). Znaczenie: <strong>„dzielny władca"</strong>. Imię angielskich królów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Ryszard I Lwie Serce</strong> — król Anglii, bohater krucjat. <strong>Ryszard III</strong> — ostatni Plantagenet, bohater dramatu Szekspira. <strong>Richard Wagner</strong> — kompozytor operowy. <strong>Ryszard Kapuściński</strong> — wybitny polski dziennikarz reportażysta. W Polsce Ryszard popularny w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rysiek, Ryś, Rysio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Richard (ang., franc., niem.), Riccardo (wł.), Ricardo (hiszp.), Ричард (ros.)</p></div>',

  "Salomea": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Salomea pochodzi z języka <strong>hebrajskiego</strong> — od <em>Shlomit</em>, żeńskiej formy od <em>shalom</em> (pokój). Znaczenie: <strong>„pokojowa, spokojna"</strong>. Imię biblijne i polskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Salome</strong> — córka Herodiady, która tańcem skłoniła Heroda do ścięcia Jana Chrzciciela. Opera <strong>Ryszarda Straussa <em>Salome</em></strong>. <strong>Błogosławiona Salomea</strong> — polska księżna, siostra Bolesława Wstydliwego. W Polsce imię Salomea historyczne i rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Salcia, Salka, Salomcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Salome (ang., franc., niem.), Salomé (hiszp., franc.), Salomea (wł.), Саломея (ros.)</p></div>',

  "Sara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sara pochodzi z języka <strong>hebrajskiego</strong> — od <em>Sarah</em> (שָׂרָה), co znaczy <strong>„księżna, pani, wielka"</strong>. Pierwotna forma to Saraj (kłótliwa), zmieniona przez Boga na Sara.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Sara</strong> — żona Abrahama, matka Izaaka, pramatka Izraela. Urodziła syna w wieku 90 lat. <strong>Sara Bernhardt</strong> — najsłynniejsza aktorka XIX w. W Polsce Sara modna od lat 90. XX w. i jedna z popularniejszych imion żeńskich XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sarusia, Sareczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sarah (ang., niem., franc.), Sara (wł., hiszp., skandynaw.), Сара (ros.)</p></div>',

  "Sebastian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sebastian pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>Sebastianos</em>, nawiązania do miasta Sebaste (dzisiejszy Sivas w Turcji) lub od greckiego <em>sebastos</em> (czcigodny). Znaczenie: <strong>„czcigodny"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Sebastian</strong> — żołnierz, przeszyty strzałami za wiarę (III w.), patron sportowców. <strong>Johann Sebastian Bach</strong> — kompozytor baroku. W Polsce Sebastian bardzo popularny w XXI w. <strong>Sebastian Vettel</strong> — czterokrotny mistrz świata F1.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Seba, Sebastianek, Bastek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sebastian (ang., niem., hiszp.), Sébastien (franc.), Sebastiano (wł.), Себастьян (ros.)</p></div>',

  "Serafin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Serafin pochodzi z języka <strong>hebrajskiego</strong> — od <em>seraph</em> (שָׂרָף), oznaczającego <strong>„płonący"</strong>. Serafini — najwyższy rząd aniołów otaczających tron Boga, opisani w Księdze Izajasza jako sześcioskrzydłe stworzenia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Serafin z Sarowa</strong> (1754–1833) — rosyjski pustelnik i mistyk, jedna z najważniejszych postaci prawosławia. <strong>Serafin</strong> — imię kilku papieży i świętych. W Polsce imię rzadkie, o anielskim i mistycznym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Serafinek, Seraf</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Seraphim (ang.), Séraphin (franc.), Serafino (wł.), Serafín (hiszp.), Серафим (ros.)</p></div>',

  "Sonia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sonia to zdrobnienie imienia Zofia (przez formę Sofja → Sonja), z języka <strong>greckiego</strong> — od <em>sophia</em> (mądrość). Znaczenie: <strong>„mądrość"</strong>. Forma popularna w Europie Wschodniej i Zachodniej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Sonja Henie</strong> — norweska łyżwiarka figurowa, trzykrotna mistrzyni olimpijska. <strong>Sonia Rykiel</strong> — francuska projektantka mody. W Polsce Sonia to imię rzadkie, elegankie. <strong>Sonja</strong> — skandynawska forma używana szczególnie w Norwegii i Szwecji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sonka, Soniuśka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sonya (ang.), Sonja (niem., skandynaw.), Sonia (wł., hiszp., franc.), Соня (ros.)</p></div>',

  "Stanisław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Stanisław to polskie imię dwuczłonowe — złożone z <em>stani-</em> (stać się) + <em>-sław</em> (sława). Znaczenie: <strong>„stać się sławnym"</strong>. Imię patrona Polski, jedno z najbardziej polskich imion.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Stanisław</strong> — biskup krakowski, zabity przez Bolesława Śmiałego (1079), patron Polski. <strong>Stanisław August Poniatowski</strong> — ostatni król Polski. <strong>Stanisław Wyspiański</strong> — malarz i dramaturg. <strong>Stanisław Lem</strong> — pisarz science-fiction. Jedno z fundamentalnych imion polskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Staś, Stasio, Staszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Stanislaus (łac., ang., niem.), Stanislas (franc.), Stanislao (wł.), Estanislao (hiszp.), Станислав (ros.)</p></div>',

  "Sylwia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Sylwia pochodzi z języka <strong>łacińskiego</strong> — od <em>silva</em> (las). Znaczenie: <strong>„leśna, z lasu"</strong>. Imię mitologiczne, nawiązujące do matki Romulusa i Remusa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Rea Sylwia</strong> — westalna, matka Romulusa i Remusa, założycieli Rzymu. <strong>Sylvia Plath</strong> — amerykańska poetka i pisarka (<em>Szklany klosz</em>). W Polsce Sylwia bardzo popularna w latach 80.–90. XX w. <strong>Sylwia Grzeszczak</strong> — polska piosenkarka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sylwka, Sylweczka, Sylwusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sylvia (ang., niem., hiszp., wł.), Sylvie (franc.), Сильвия (ros.)</p></div>',

  "Szymon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Szymon pochodzi z języka <strong>hebrajskiego</strong> — od <em>Shimon</em> (שִׁמְעוֹן), od <em>shama</em> (słyszeć). Znaczenie: <strong>„Bóg wysłuchał"</strong>. Imię biblijne, polskie odpowiednika Szymona Piotra.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Szymon Piotr</strong> — Apostoł, któremu Jezus zmienił imię na Piotr. <strong>Szymon z Cyreny</strong> — pomógł nieść krzyż Jezusowi. <strong>Szymon Bar Kochba</strong> — przywódca powstania żydowskiego. W Polsce Szymon bardzo popularny w XXI w. — jedno z czołowych imion chłopięcych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Szymek, Szymeczek, Szymek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Simon (ang., franc., niem.), Simone (wł.), Simón (hiszp.), Симон (ros.)</p></div>',

  "Tadeusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Tadeusz pochodzi z języka <strong>aramejskiego lub greckiego</strong> — od <em>Thaddaios</em>, możliwie od hebrajskiego <em>Todah</em> (pochwała) lub <em>Lebbaeus</em> (serdeczny). Znaczenie: <strong>„odważny"</strong> lub „pochwała Boga".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Apostoł Tadeusz</strong> — jeden z Dwunastu, autor Listu. <strong>Tadeusz Kościuszko</strong> — naczelnik insurekcji, bohater trzech narodów (Polska, USA, Litwa). <strong>Adam Mickiewicz</strong> napisał <em>Pana Tadeusza</em>. <strong>Tadeusz Kantor</strong> — reżyser. Imię głęboko zakorzenione w polskiej kulturze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tadek, Taduś, Tadzik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thaddeus (ang., łac.), Thaddée (franc.), Taddeo (wł.), Tadeo (hiszp.), Фаддей (ros.)</p></div>',

  "Tamara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Tamara pochodzi z języka <strong>hebrajskiego</strong> — od <em>Tamar</em> (תָּמָר), co znaczy <strong>„palma daktylowa"</strong>. Symbol piękna i smukłości. Imię biblijne i gruzińskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Tamar</strong> — córka Dawida, siostrzenica Absaloma. <strong>Tamara de Lempicka</strong> — polska malarka art déco, mieszkająca w Paryżu. <strong>Tamara</strong> — poemat Michaiła Lermontowa. W Polsce Tamara popularna od lat 60. XX w., eleganckie i egzotyczne imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tamarka, Tama, Tamka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Tamara (ang., franc., niem., wł., hiszp.), Тамара (ros.)</p></div>',

  "Tomasz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Tomasz pochodzi z języka <strong>aramejskiego</strong> — od <em>Toma</em> (תּוֹמָא), co znaczy <strong>„bliźniak"</strong>. Grecka forma <em>Thomas</em>. Imię Apostoła Niedowierzającego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Apostoł Tomasz</strong> — „niedowierzający Tomasz", dotknął ran Chrystusa. <strong>Tomasz Akwinaty</strong> — największy teolog Kościoła, autor <em>Sumy teologicznej</em>. <strong>Thomas Edison</strong> — wynalazca. <strong>Tomasz Stańko</strong> — wybitny polski jazzman. W Polsce Tomasz jedno z czołowych imion.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tomek, Tomcio, Tomasik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Thomas (ang., franc., niem.), Tommaso (wł.), Tomás (hiszp.), Фома (ros.)</p></div>',

  "Urszula": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Urszula pochodzi z języka <strong>łacińskiego</strong> — zdrobnienie od <em>ursa</em> (niedźwiedzica). Znaczenie: <strong>„mała niedźwiedzica"</strong>. Imię świętej z legend średniowiecza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Urszula</strong> — legendarna księżniczka brytyjska, która zginęła z 11 000 dziewicami pod Kolonią. Zakon urszulanek nosi jej imię. <strong>Urszula Dudziak</strong> — polska wokalistka jazzowa. W Polsce Urszula popularna w XX w. Zdrobnienie Ula bardzo charakterystyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ula, Ulka, Urszulka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ursula (ang., niem.), Ursule (franc.), Orsola (wł.), Úrsula (hiszp.), Урсула (ros.)</p></div>',

  "Walentyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Walentyna pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>Valentinus</em>, od <em>valens</em> (silny, zdrowy). Znaczenie: <strong>„silna, zdrowa"</strong>. Imię od patrona zakochanych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma żeńska imienia <strong>Świętego Walentego</strong> — patrona zakochanych (14 lutego). <strong>Walentyna Tierieszkowa</strong> — pierwsza kobieta w kosmosie (1963, ZSRR). W Polsce Walentyna to imię rzadkie, historyczne. Forma Walentynki (kartki walentynkowe) pochodzi od Walentego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Walka, Walenia, Walentynka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Valentina (ang., wł., hiszp.), Valentine (franc.), Валентина (ros.)</p></div>',

  "Weronika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Weronika pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>Berenikē</em> (Βερενίκη): <em>phere</em> (przynosić) + <em>nike</em> (zwycięstwo). Znaczenie: <strong>„przynosząca zwycięstwo"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Weronika</strong> — kobieta, która przetarła twarz Jezusa chustą na drodze krzyżowej; na chuście odbiła się podobizna Chrystusa (<em>Chusta Weroniki</em>). <strong>Weronika</strong> z komiksów Archiego. W Polsce Weronika bardzo popularna w XXI w. — jedno z czołowych imion żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Weronka, Wera, Nika</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Veronica (ang., wł.), Véronique (franc.), Verónica (hiszp.), Вероника (ros.)</p></div>',

  "Władysław": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Władysław to polskie imię dwuczłonowe — złożone z <em>włada-</em> (władać) + <em>-sław</em> (sława). Znaczenie: <strong>„sławny władcą"</strong>. Imię dynastyczne Piastów i Jagiellonów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Władysław Łokietek</strong> — zjednoczył Polskę po rozkawałkowaniu dzielnicowym. <strong>Władysław II Jagiełło</strong> — zwycięzca spod Grunwaldu. <strong>Władysław IV Waza</strong>. <strong>Władysław Reymont</strong> — noblista, autor <em>Chłopów</em>. <strong>Władysław Szpilman</strong> — pianista z <em>Pianisty</em> Polańskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Władek, Właduś, Włodzio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ladislaus (łac.), Ladislas (franc.), Ladislao (wł.), Władisław (czes., ros.)</p></div>',

  "Zofia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zofia pochodzi z języka <strong>greckiego</strong> — od <em>sophia</em> (mądrość). Znaczenie: <strong>„mądrość"</strong>. Jedno z najważniejszych imion w historii chrześcijaństwa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Hagia Sophia</strong> — kościół Mądrości Bożej w Konstantynopolu (537 r.). <strong>Zofia Nałkowska</strong> — pisarka. <strong>Zofia Kossak-Szczucka</strong> — pisarka, ratowała Żydów. <strong>Sophia Loren</strong> — włoska aktorka. W Polsce Zofia wśród czołowych imion żeńskich przez wieki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zosia, Zośka, Zocha</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sophia (ang., niem.), Sophie (franc.), Sofia (wł., hiszp., skandynaw.), София (ros.)</p></div>',

  "Zygmunt": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zygmunt pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Sigismund</em>: <em>sigu</em> (zwycięstwo) + <em>mund</em> (ochrona). Znaczenie: <strong>„zwycięski obrońca"</strong>. Imię dynastyczne Jagiellonów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Zygmunt I Stary</strong> i <strong>Zygmunt II August</strong> — ostatni Jagiellonowie, złoty wiek Polski. <strong>Zygmunt III Waza</strong> — przeniósł stolicę do Warszawy. <strong>Zygmunt Freud</strong> — twórca psychoanalizy. <strong>Kolumna Zygmunta</strong> w Warszawie — symbol stolicy. Dzwon <em>Zygmunt</em> na Wawelu — największy w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zygmuś, Zygmundek, Zymek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Sigismund (ang., niem., łac.), Sigismond (franc.), Sigismondo (wł.), Сигизмунд (ros.)</p></div>',

  "Clara": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Clara to łacińska forma imienia Klara, od <em>clarus</em> (jasny, sławny, wyraźny). Znaczenie: <strong>„jasna, sławna"</strong>. Forma międzynarodowa polskiej Klary.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Klara z Asyżu</strong> — założycielka klarysek, przyjaciółka Franciszka. <strong>Clara Schumann</strong> — wybitna pianistka i kompozytorka XIX w. <strong>Clara Bow</strong> — gwiazda kina niemego. W Polsce forma Clara rzadsza od Klary, ale elegancka i kosmopolityczna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Clareczka, Clare</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Clara (ang., wł., hiszp., niem.), Claire (franc.), Klara (pol., niem.), Клара (ros.)</p></div>',

  "Marcel": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Marcel pochodzi z języka <strong>łacińskiego</strong> — od <em>Marcellus</em>, zdrobnienia od Marcus (Marek), związanego z Marsem. Znaczenie: <strong>„mały Mars"</strong> lub „wojowniczy". Imię papieskie i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Marceli I</strong> — wczesnochrześcijański papież. <strong>Marcel Proust</strong> — autor <em>W poszukiwaniu straconego czasu</em>. <strong>Marcel Duchamp</strong> — dadaistyczny artysta. W Polsce Marcel popularny szczególnie w XXI w. Zdrobnienie Marcelo i Marcelek.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Marcelek, Marcelo, Marek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Marcellus (łac.), Marcel (ang., franc., niem.), Marcello (wł.), Marcelo (hiszp.), Марсель (ros.)</p></div>',

  "Paula": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Paula to żeńska forma imienia Paweł, z języka <strong>łacińskiego</strong> — od <em>paulus</em> (mały, skromny). Znaczenie: <strong>„mała, skromna"</strong>. Imię kościelne i popularne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Paula</strong> — rzymska wdowa, fundatorka klasztorów w Betlejem, współpracownica Hieronima przy tłumaczeniu Biblii. <strong>Paula Abdul</strong> — piosenkarka i tancerka. <strong>Paula Radcliffe</strong> — biegaczka maratońska. W Polsce Paula popularna w XXI w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Paulka, Paulinka, Ula</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Paula (ang., hiszp., niem.), Paule (franc.), Paola (wł.), Паула (ros.)</p></div>',

  "Celestyn": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Celestyn to męska forma imienia wywodząca się z języka <strong>łacińskiego</strong> — od <em>caelestinus</em> (niebiański), od <em>caelum</em> (niebo). Znaczenie: <strong>„niebiański"</strong>. Imię papieskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Celestyn V</strong> (1215–1296) — jedyny papież, który dobrowolnie abdykował w średniowieczu, pustelnik — kanonizowany. Dante umieścił go w piekle za „wielką odmowę". <strong>Papież Celestyn I</strong> — zlecił Augustynowi chrystianizację Irlandii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Celo, Celestynek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Celestinus (łac.), Celestino (wł., hiszp.), Célestin (franc.), Целестин (ros.)</p></div>',

  "Cyprian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Cyprian pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od nazwy wyspy Cypr (<em>Kypros</em>), wiązanej z boginią Afrodytą. Znaczenie: <strong>„z wyspy Cypr"</strong>. Imię świętego biskupa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Cyprian z Kartaginy</strong> (ok. 200–258) — biskup, jeden z Ojców Kościoła, autor listów i traktatów, męczennik. Jego aforyzm „extra Ecclesiam nulla salus" jest jednym z najsłynniejszych w teologii. <strong>Cyprian Kamil Norwid</strong> — polski poeta romantyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cypek, Cyprio</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cyprian (ang.), Cyprien (franc.), Cipriano (wł., hiszp.), Киприан (ros.)</p></div>',

  "Linda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Linda pochodzi ze <strong>starogermańskiego lub hiszpańskiego</strong> — od <em>lind</em> (wąż, lipa, giętki) lub <em>linda</em> (piękna po hiszpańsku). Znaczenie: <strong>„piękna"</strong> lub „łagodna". Imię popularne w XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Linda Ronstadt</strong> — amerykańska piosenkarka. <strong>Linda Hamilton</strong> — aktorka (<em>Terminator</em>). W Polsce Linda popularna w latach 70.–90. XX w. Znany jest też <strong>Bogusław Linda</strong> — aktor (forma męska, od popularności imienia). Imię kosmopolityczne i nowoczesne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lindka, Lindi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Linda (ang., niem., wł., hiszp., franc.), Линда (ros.)</p></div>',

  "Hilary": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Hilary pochodzi z języka <strong>łacińskiego</strong> — od <em>hilaris</em> (wesoły, radosny). Znaczenie: <strong>„wesoły, radosny"</strong>. Od tego imienia pochodzi słowo „hilaryczny".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Hilary z Poitiers</strong> — Ojciec Kościoła z IV w., obrońca ortodoksji przeciw arianizmowi. <strong>Hillary Clinton</strong> — polityczka, pierwsza kobieta kandydatka na prezydenta USA z ramienia partii. W Polsce Hilary to imię rzadkie. <em>Hilarious</em> (ang.) — śmieszny — pochodzi od tego imienia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hilarek, Hilka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hilary, Hillary (ang.), Hilaire (franc.), Ilario (wł.), Hilario (hiszp.), Иларий (ros.)</p></div>',

  "Fryderyk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Fryderyk pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Fridurih</em>: <em>frid</em> (pokój) + <em>rich</em> (władca, potężny). Znaczenie: <strong>„władca pokoju"</strong>. Imię pruskich królów i polskiego geniusza.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Fryderyk Chopin</strong> (1810–1849) — największy polski kompozytor, geniusz fortepianu, autor nokturnów, mazurków i polonezów. <strong>Fryderyk II Wielki</strong> — król Prus, oświecony despota. <strong>Friedrich Nietzsche</strong> — filozof. W Polsce Fryderyk kojarzony głównie z Chopinem.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fredzio, Fred, Fryc</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Frederick (ang.), Frédéric (franc.), Friedrich (niem.), Federico (wł., hiszp.), Фридрих (ros.)</p></div>',

  "Rajmund": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Rajmund pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Raginmund</em>: <em>ragin</em> (rada, mądrość) + <em>mund</em> (ochrona). Znaczenie: <strong>„mądry obrońca"</strong>. Imię krzyżowców i świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Rajmund z Penyafort</strong> — dominikanin, wielki mistrz zakonu, kanonista. <strong>Raimund von Sabunde</strong> — teolog. <strong>Raymond Chandler</strong> — pisarz kryminałów (<em>Wielki sen</em>). W Polsce Rajmund to imię rzadkie, historyczne, kojarzone z tradycją rycerską.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Rajmundek, Raj</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Raymond (ang., franc.), Raimondo (wł.), Raimundo (hiszp.), Раймунд (ros.)</p></div>',

  "Ulryk": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Ulryk pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Uodalrich</em>: <em>uodal</em> (dziedzictwo, majątek) + <em>rich</em> (potężny, władca). Znaczenie: <strong>„potężny dziedzic"</strong>. Imię biskupów i świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Ulryk z Augsburga</strong> (890–973) — pierwszy kanonizowany przez papieża święty (993 r.) — inauguracja papieskiej kanonizacji. Biskup, patron Augsburga. W Polsce Ulryk to imię rzadkie, historyczne, znane z historii Kościoła.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ulko, Ulryczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ulrich (niem.), Ulric (ang.), Ulrico (wł., hiszp.), Ульрих (ros.)</p></div>',

  "Zenobia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zenobia pochodzi z języka <strong>greckiego</strong> — od <em>Zenobia</em>: <em>Zeus</em> (bóg) + <em>bios</em> (życie). Znaczenie: <strong>„siła Zeusa"</strong> lub „żyjąca mocą bogów". Imię królowej Palmiry.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Zenobia</strong> (ok. 240–274) — królowa Palmiry (dzisiejsza Syria), jedna z największych władczyń starożytności. Podbiła Egipt i część Azji, zanim pokonał ją Aurelian. Symbol niezależnej kobiety-władczyni. W Polsce imię rzadkie, antyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zenia, Zenosia, Zenka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zenobia (ang., wł., hiszp.), Zénobie (franc.), Зенобия (ros.)</p></div>',

  "Absalon": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Absalon pochodzi z języka <strong>hebrajskiego</strong> — od <em>Avshalom</em>: <em>av</em> (ojciec) + <em>shalom</em> (pokój). Znaczenie: <strong>„ojciec pokoju"</strong>. Imię biblijnego syna króla Dawida.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>W Biblii <strong>Absalon</strong> — trzeci syn króla Dawida, słynący z urody. Zbuntował się przeciw ojcu i zginął podczas ucieczki, gdy wplątał się włosami w drzewo. Opłakiwany przez ojca słowami: „Synu mój Absalonie!". Symbol pięknego, lecz buntowniczego syna.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Abek, Absalek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Absalom (ang., niem.), Absalon (franc., skandynaw.), Assalonne (wł.), Авессалом (ros.)</p></div>',

  "Aidan": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Aidan pochodzi z języka <strong>irlandzkiego gaelickiego</strong> — od <em>Aodhán</em>, zdrobnienia od <em>Aodh</em> (ogień). Znaczenie: <strong>„mały ogień"</strong>. Imię irlandzkich świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Aidan z Lindisfarne</strong> (zm. 651) — irlandzki mnich, który chrystianizował Anglię Północną, założył klasztor na wyspie Lindisfarne. <strong>Aidan Quinn</strong> — aktor irlandzkiego pochodzenia. W Polsce Aidan to imię rzadkie, kojarzone z kulturą celtycką i irlandzką.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aid, Aidanek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aidan (ang., irland.), Аidan (ros. transkrypcja) — imię typowo celtyckie</p></div>',

  "Alana": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Alana to żeńska forma imienia Alan, z języka <strong>celtyckiego lub gaelickiego</strong> — od <em>ail</em> (skała) lub od bretońskiego <em>Alan</em> (harmonia). Znaczenie: <strong>„harmonijna"</strong> lub „ze skały". Imię celtyckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Alana to żeńska forma popularnego w krajach anglojęzycznych imienia Alan. <strong>Alana Haim</strong> — aktorka z HAIM. W Polsce Alana to imię rzadkie, nowoczesne, kojarzone z kulturą anglosaską i celtycką. Oryginalna alternatywa dla popularnych imion żeńskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alaneczka, Lana</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alana (ang., franc.), Alanna (irland.), Алана (ros.)</p></div>',

  "Alba": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Alba pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>alba</em> (biała, świt). Znaczenie: <strong>„biała"</strong> lub „świt, brzask". Imię geograficzne (Alba Longa — pramatka Rzymu) i literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Alba Longa</strong> — mityczne miasto założone przez syna Eneasza, poprzedniczka Rzymu. <strong>Jessica Alba</strong> — amerykańska aktorka. <strong>Księżna Alba</strong> — jedna z najbardziej utytułowanych arystokratek Europy. W Polsce Alba to imię rzadkie, eleganckie i nowoczesne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alka, Albeczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alba (ang., wł., hiszp.), Альба (ros.) — imię romańskie</p></div>',

  "Amadea": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Amadea to żeńska forma imienia Amadeusz, z języka <strong>łacińskiego</strong> — od <em>amare</em> (kochać) + <em>Deus</em> (Bóg). Znaczenie: <strong>„miłująca Boga"</strong>. Elegancka żeńska forma imienia muzycznego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma imienia <strong>Wolfganga Amadeusa Mozarta</strong> — geniusza muzycznego. <strong>Amadea</strong> to imię kojarzone z pięknem, muzyką i boską miłością. W Polsce bardzo rzadkie — egzotyczna, elegancka alternatywa. Nosi je m.in. córka jednego z europejskich muzyków.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Mada, Amadka, Dea</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amadea (ang., wł., hiszp.), Амадея (ros.) — żeńska forma Amadeusza</p></div>',

  "Amaranta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Amaranta pochodzi z języka <strong>greckiego</strong> — od <em>amarantos</em> (niewiędnący, nieśmiertelny): <em>a-</em> (nie) + <em>marainein</em> (więdnąć). Znaczenie: <strong>„niewiędnąca, nieśmiertelna"</strong>. Imię kwiatowe.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Amarant — piękna roślina o trwałych kwiatach, od wieków symbol nieśmiertelności i miłości. <strong>Amaranta</strong> — postać z <em>Stu lat samotności</em> Gabriela Garcíi Márqueza. W Polsce imię bardzo rzadkie, romantyczne i poetyckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Amara, Ranta, Amarantka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Amaranta (wł., hiszp.), Amarante (franc.), Amaranth (ang.), Амаранта (ros.)</p></div>',

  "Anika": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Anika to zdrobnienie imienia Anna/Hanna, z języka <strong>hebrajskiego lub słowiańskiego</strong> — od <em>hannāh</em> (łaska). Znaczenie: <strong>„mała łaskawa"</strong>. Forma popularna w krajach skandynawskich i słowiańskich.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Anika to forma imienia Anna używana w Skandynawii, Holandii i krajach słowiańskich jako samodzielne imię. <strong>Anika Noni Rose</strong> — aktorka znana z <em>Princess and the Frog</em>. W Polsce Anika to imię rzadkie, ale modne jako krótka, nowoczesna forma.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Anikka, Ani</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anika (skandynaw., niem., ang.), Аника (ros.)</p></div>',

  "Atanazy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Atanazy pochodzi z języka <strong>greckiego</strong> — od <em>Athanasios</em>: <em>a-</em> (nie) + <em>thanatos</em> (śmierć). Znaczenie: <strong>„nieśmiertelny"</strong>. Imię teologa, który bronił ortodoksji chrześcijańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Atanazy Wielki</strong> (ok. 296–373) — Ojciec Kościoła, patriarcha Aleksandrii, który przez całe życie bronił dogmatu o Trójcy Świętej przeciw arianizmowi (stąd powiedzenie <em>Athanasius contra mundum</em>). Skład apostolski znany jako Symbol Atanazjański.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Atanazek, Nazy</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Athanasius (ang., łac.), Athanase (franc.), Atanasio (wł., hiszp.), Афанасий (ros.)</p></div>',

  "Attyla": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Attyla (łac. Attila) pochodzi z języka <strong>huńskiego lub gotyckiego</strong> — od gotyckiego <em>atta</em> (ojciec) + <em>ila</em> (zdrobnienie). Możliwe znaczenie: <strong>„mały ojczulek"</strong>. Imię legendarnego wodza Hunów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Attyla</strong> (ok. 406–453) — „Bicz Boży", wódz Hunów, który spustoszył Europę. Papież Leon I powstrzymał go przed atakiem na Rzym (452 r.). W Polsce i na Węgrzech (Attila) imię używane — na Węgrzech popularne jako nawiązanie do historycznych korzeni.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Atek, Attylka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Attila (łac., węg., ang.), Attilo (wł.), Аттила (ros.)</p></div>',

  "Aureli": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Aureli pochodzi z języka <strong>łacińskiego</strong> — od rodu Aureliuszów (<em>Aurelius</em>), od <em>aurum</em> (złoto). Znaczenie: <strong>„złoty"</strong>. Forma skrócona imienia Aureliusz.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Marek Aureliusz</strong> (121–180) — cesarz-filozof, autor <em>Rozmyślań</em>, jeden z największych Stoików. <strong>Aureliusz Augustyn</strong> — pełne imię Świętego Augustyna. W Polsce Aureli to imię rzadkie, historyczne, o antycznym rodowodzie. Znany jest też <strong>Aurélie Filippetti</strong> — francuska polityczka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aurek, Aureli</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aurelius (łac.), Aurèle (franc.), Aurelio (wł., hiszp.), Аврелий (ros.)</p></div>',

  "Aurelian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Aurelian pochodzi z języka <strong>łacińskiego</strong> — od rodu Aureliuszów, od <em>aurum</em> (złoto). Znaczenie: <strong>„złoty, ze złotego rodu"</strong>. Imię cesarza Rzymu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Cesarz Aurelian</strong> (214–275) — przywrócił jedność Cesarstwa Rzymskiego po epoce kryzysu, pokonał królową Zenobię. Zbudował mury Aureliana wokół Rzymu. W Polsce Aurelian to imię rzadkie, historyczne. <strong>Aurélien</strong> — popularniejsza forma we Francji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aurel, Aurelianek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aurelian (ang.), Aurélien (franc.), Aureliano (wł., hiszp.), Аврелиан (ros.)</p></div>',

  "Apollo": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Apollo pochodzi z języka <strong>greckiego</strong> — od <em>Apollon</em>, etymologia niepewna: być może od <em>apollynai</em> (niszczyć) lub od <em>apella</em> (zgromadzenie). Znaczenie: <strong>„ten który niszczy"</strong> lub „piękny". Imię boga słońca i sztuk.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Apollo</strong> — grecki bóg słońca, muzyki, poezji, przepowiedni i uzdrawiania. Wyrocznia delficka była jego sanktuarium. <strong>Program Apollo</strong> — misje kosmiczne NASA (1961–1972), Apollo 11 wysłał pierwszych ludzi na Księżyc. W Polsce imię rzadkie, literackie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Apolo, Apollek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apollo (ang., wł., hiszp.), Apollon (franc.), Аполлон (ros.)</p></div>',

  "Apolinary": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Apolinary pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od boga Apollona, przez <em>Apollinaris</em>. Znaczenie: <strong>„poświęcony Apollinowi"</strong>. Imię świętych i biskupa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Apolinary z Rawenny</strong> — pierwszy biskup Rawenny, patron miasta. Bazylika Sant&#39;Apollinare Nuovo i Sant&#39;Apollinare in Classe w Rawennie są arcydziełami mozaiki. <strong>Guillaume Apollinaire</strong> — fr. poeta, twórca <em>Kaligramów</em>. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Apol, Polinary</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apollinaris (łac.), Apollinaire (franc.), Apollinare (wł.), Apolinar (hiszp.), Аполлинарий (ros.)</p></div>',

  "Antonin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Antonin to zdrobnienie imienia Antoni, z języka <strong>łacińskiego</strong> — od rodu Antoniuszów (<em>Antonius</em>). Znaczenie: <strong>„z rodu Antoniuszów"</strong>. Imię cesarzy i świętych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Antonin Pius</strong> (86–161) — cesarz rzymski, jeden z „dobrych cesarzy", rządy bez wojen i tyranii — „złoty wiek" cesarstwa. <strong>Antonin Artaud</strong> — teatralny twórca „teatru okrucieństwa". <strong>Antonín Dvořák</strong> — czeski kompozytor. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tonek, Antoninek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Antoninus (łac.), Antonin (franc.), Antonino (wł., hiszp.), Антонин (ros.)</p></div>',

  "Leokadia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leokadia pochodzi z języka <strong>greckiego</strong> — od <em>Leukadia</em>, nawiązania do wyspy Leukas (<em>leukos</em> — biały) lub od <em>leukos</em> + <em>kadios</em> (biała, czysta). Znaczenie: <strong>„jasna, czysta"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Leokadia</strong> — Rzeźnica z Toledo (III w.), patronka Toledo i Belgii. <strong>Leokadia Pancewicz-Leszczewska</strong> — polska pianistka. W Polsce Leokadia popularna w XIX i pierwszej połowie XX w. — zdrobnienie Leosia lub Lodzia. Dziś imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leosia, Lodzia, Lea</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leocadia (ang., wł., hiszp.), Léocadie (franc.), Леокадия (ros.)</p></div>',

  "Leokady": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Leokady to polska forma wywodząca się od łacińskiego <strong>Leocadius</strong>, związanego z greckim <em>leukos</em> (biały, jasny). Znaczenie: <strong>„jasny, biały, promienisty"</strong>. Odpowiada żeńskiemu imieniu Leokadia — to rzadka forma męska, niemal zapomniana we współczesnej Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Leokadia</strong> (zm. ok. 304) — chrześcijańska męczennica z Toledo, patronka Hiszpanii i Belgii. Kult świętej dotarł do Polski przez Czechy wraz z chrześcijaństwem. Imię Leokady w formie męskiej jest dziś niemal zapomniane — zachowane w historycznych dokumentach metrykalnych i w kalendarzu liturgicznym. Nadawano je w środowiskach szlacheckich i kościelnych XIX w., dziś wzbudza zainteresowanie jako imię wyjątkowe i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Leo, Leok, Leokadek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Leocadius (łac.), Leocadio (hiszp.), Leocade (franc.) — forma żeńska: Leokadia (pol.), Leocadia (hiszp., wł.)</p></div>',

  "Fortunata": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Fortunata pochodzi z języka <strong>łacińskiego</strong> — żeńska forma od <em>fortunatus</em> (szczęśliwy, obdarzony przez los), od <em>fortuna</em> (szczęście, los). Znaczenie: <strong>„szczęśliwa, błogosławiona przez los"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Fortunata</strong> — postać z powieści Pérez Galdósa <em>Fortunata y Jacinta</em> (1887) — klasyka literatury hiszpańskiej. <strong>Święta Fortunata</strong> — chrześcijańska męczennica. W Polsce imię Fortunata rzadkie, historyczne, o optymistycznym znaczeniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Forta, Tata, Fortunatka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Fortunata (ang., wł., hiszp.), Fortunée (franc.), Фортуната (ros.)</p></div>',

  "Fryderyka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Fryderyka to żeńska forma imienia Fryderyk, ze <strong>starowysokoniemieckiego</strong> — od <em>frid</em> (pokój) + <em>rich</em> (władca). Znaczenie: <strong>„władczyni pokoju"</strong>. Żeńska forma imienia Chopina.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma od imienia <strong>Fryderyka Chopina</strong> i <strong>Fryderyka Wielkiego</strong>. <strong>Fryderyka von Reden</strong> — księżniczka pruska. W Polsce Fryderyka to imię rzadkie, historyczne, o arystokratycznym rodowodzie. Elegancka forma dla miłośników kultury germańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Fryda, Freda, Ryka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Frederica (ang., wł.), Frédérique (franc.), Friederike (niem.), Federica (hiszp.), Фредерика (ros.)</p></div>',

  "Archibald": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Archibald pochodzi ze <strong>starowysokoniemieckiego lub germańskiego</strong> — od <em>Ercanwald</em>: <em>ercan</em> (prawdziwy, naturalny) + <em>bald</em> (odważny). Znaczenie: <strong>„prawdziwie odważny"</strong>. Imię szkockie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w Szkocji i wśród szkockich rodów — Campbellów i Douglasów. <strong>Archibald Campbell</strong> — 1. margrabia Argyll. <strong>Archibald Wavell</strong> — brytyjski feldmarszałek II wojny. <strong>Archie</strong> — bohater popularnych komiksów. W Polsce imię bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Archie, Archek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Archibald (ang., szkoc., niem.), Archibaldo (wł., hiszp.), Архибальд (ros.)</p></div>',

  "Armin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Armin pochodzi ze <strong>starowysokoniemieckiego lub perskiego</strong> — od germańskiego <em>Hari</em> (wojsko) + <em>man</em> (człowiek), lub od perskiego imienia. Znaczenie: <strong>„wojownik"</strong>. Imię historycznego wodza Germanów.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Arminius</strong> — wódz germańskiego plemienia Cherusków, który pokonał trzy legiony rzymskie w Lesie Teutoburskim (9 r. n.e.) — jedno z największych klęsk Rzymu. W Niemczech uważany za ojca narodu. <strong>Armin van Buuren</strong> — holenderski DJ i producent muzyczny.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arminek, Armi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Armin (niem., ang.), Armand (franc.), Armando (wł., hiszp.), Армин (ros.)</p></div>',

  "Baldwin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Baldwin pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Baldwini</em>: <em>bald</em> (odważny) + <em>wine</em> (przyjaciel). Znaczenie: <strong>„odważny przyjaciel"</strong>. Imię krzyżowców.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Baldwin I z Boulogne</strong> — pierwszy łaciński król Jerozolimy (1100). <strong>James Baldwin</strong> — afroamerykański pisarz (<em>Inny kraj</em>). <strong>Alec Baldwin</strong> — aktor. <strong>Baldwin IV</strong> — trędowaty król Jerozolimy, bohater filmu <em>Królestwo Niebieskie</em>. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Baldi, Baldwinek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Baldwin (ang., niem.), Baudouin (franc.), Baldovino (wł.), Балдуин (ros.)</p></div>',

  "Balladyna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Balladyna to imię literackie <strong>polskiego</strong> pochodzenia — od słowa <em>ballada</em> (utwór literacki/muzyczny), które pochodzi z łaciny/prowansalskiego. Znaczenie: <strong>„bohaterka ballady"</strong>. Imię stworzone przez Słowackiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Balladyna</strong> — dramat Juliusza Słowackiego (1839), polska „Lady Makbet". Córka wdowy, która zamordowała siostrę Alinę i wdrapała się na tron — zginęła od pioruna. Jedna z ikon polskiego romantyzmu. W Polsce imię rzadkie, używane przez miłośników literatury.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Balla, Dyna, Balladynka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Imię typowo polskie, stworzone przez Słowackiego</p></div>',

  "Astryda": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Astryda pochodzi ze <strong>staronordyjskiego</strong> — od <em>Ástríðr</em>: <em>áss</em> (bóg nordycki) + <em>fríðr</em> (piękna). Znaczenie: <strong>„bosko piękna"</strong>. Imię nordyckich królowych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Astrid</strong> — imię noszone przez wiele królowych skandynawskich. <strong>Astrid Lindgren</strong> — szwedzka pisarka, autorka <em>Pippi Langstrump</em> i <em>Dzieci z Bullerbyn</em>. <strong>Astrid</strong> — królowa Belgii, żona Leopolda III, zginęła w wypadku samochodowym (1935). W Polsce Astryda rzadka.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Astrid, Astra, Ast</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Astrid (skandynaw., ang., niem.), Астрид (ros.) — imię nordyckie</p></div>',

  "Asumpta": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Asumpta pochodzi z języka <strong>łacińskiego</strong> — od <em>assumpta</em> (wzięta, przyjęta w górę), od <em>assumere</em> (wziąć, unieść). Znaczenie: <strong>„wzięta do nieba"</strong>. Nawiązanie do Wniebowzięcia Maryi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię nawiązujące do dogmatu <strong>Wniebowzięcia Najświętszej Maryi Panny</strong> (Assumptio Mariae). Imię popularniejsze w krajach hiszpańskojęzycznych jako Asunción/Asunta — szczególnie w Ameryce Łacińskiej. W Polsce imię rzadkie, dewocyjne i kościelne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Asta, Asumptka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Assunta (wł.), Asunción (hiszp.), Assumpta (ang., łac.), Ассумпта (ros.)</p></div>',

  "Antonina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Antonina to żeńska forma imienia Antoni, z języka <strong>łacińskiego</strong> — od rodu Antoniuszów (<em>Antonius</em>). Znaczenie: <strong>„z rodu Antoniuszów"</strong>. Imię polskie o długiej tradycji.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Antonina</strong> — żona cesarza Justyniana I, Teodora. <strong>Antonina Żabińska</strong> — żona dyrektora zoo warszawskiego, razem z mężem ukrywała Żydów podczas II wojny (<em>Azyl. Opowieść żony dyrektora zoo</em>). W Polsce Antonina popularna historycznie, dziś wracająca do mody.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tosia, Nina, Tola, Antka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Antonina (ang., wł., hiszp.), Antonine (franc.), Антонина (ros.)</p></div>',

  "Arystarch": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Arystarch pochodzi z języka <strong>greckiego</strong> — od <em>aristarchos</em>: <em>aristos</em> (najlepszy) + <em>archon</em> (władca). Znaczenie: <strong>„najlepszy władca"</strong>. Imię greckiego astronoma.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Arystarch z Samos</strong> (310–230 p.n.e.) — grecki astronom, który jako pierwszy zaproponował, że Ziemia krąży wokół Słońca (heliocentryzm) — 1800 lat przed Kopernikiem. <strong>Arystarch z Samotraki</strong> — gramatyk aleksandryjski, wzór krytyka literackiego. W Polsce imię bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Arysto, Aryszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aristarchus (łac., ang.), Aristarte (franc.), Aristarco (wł., hiszp.), Аристарх (ros.)</p></div>',

  "Apolinaria": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Apolinaria to żeńska forma imienia Apolinary, z języka <strong>greckiego</strong> — od boga Apollona przez <em>Apollinaris</em>. Znaczenie: <strong>„poświęcona Apollinowi"</strong>. Imię kościelne i historyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma imienia nawiązująca do Apollona i świętego Apollinarego. <strong>Apollinaris</strong> — woda mineralna, czczona przez miłośników bąbelków. W Polsce Apolinaria to imię bardzo rzadkie, historyczne. Znana jest <strong>Apolinaria Suslova</strong> — kochanka Dostojewskiego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Apolka, Polina, Aposia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apollinaris (łac.), Apollinaire (franc., forma męska), Apollinaria (wł.), Аполлинария (ros.)</p></div>',

  "Awit": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Awit pochodzi z języka <strong>łacińskiego</strong> — od <em>avitus</em> (dziedziczny, po dziadku), od <em>avus</em> (dziadek). Znaczenie: <strong>„dziedziczny, potomek"</strong>. Imię łacińskie i cesarskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Awit</strong> — cesarz zachodniorzymski (455–456). <strong>Awit z Vienne</strong> — biskup, poeta łaciński z V–VI w. W Polsce imię Awit bardzo rzadkie, znane z kalendarza imienin. Imię o historycznym, łacińskim rodowodzie — niemal nieużywane we współczesnej Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Awinek, Awit</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Avitus (łac.), Avit (franc.), Avito (wł., hiszp.), Авит (ros.)</p></div>',

  "Barłaam": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Barłaam pochodzi z języka <strong>aramejskiego lub syryjskiego</strong> — od <em>bar Alam</em>: <em>bar</em> (syn) + <em>alam</em> (świat, lud). Znaczenie: <strong>„syn ludu"</strong>. Imię pustelnicy i świętych Wschodu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Barłaam i Jozafat</strong> — chrześcijański romans hagiograficzny, który okazał się przeróbką legendy o Buddzie (Jozafat = Budda!). Jeden z najszerzej tłumaczonych tekstów średniowiecza. <strong>Barłaam z Kalabrii</strong> — nauczyciel greki Petrarki i Boccaccia.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Barek, Barłamek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Barlaam (ang., łac.), Balaam (franc.), Barlaam (wł.), Варлаам (ros.)</p></div>',

  "Bazylisa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Bazylisa pochodzi z języka <strong>greckiego</strong> — od <em>basilissa</em> (królowa), żeńska forma od <em>basileus</em> (król). Znaczenie: <strong>„królowa"</strong>. Żeńska forma imienia Bazyli/Basil.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Bazylisa</strong> — chrześcijańska męczennica z III w. Imię ma ten sam rdzeń co <em>Bazylika</em> (budynek królewski, potem kościół). W Polsce Bazylisa to imię rzadkie, historyczne. Pokrewne z Bazylim i Bazyleą. Elegancka forma o antycznym rodowodzie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Basylka, Bazyla</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Basilissa (łac., ang.), Basilisse (franc.), Basilissa (wł.), Василиса (ros.)</p></div>',

  "Agaton": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Agaton pochodzi z języka <strong>greckiego</strong> — od <em>agathos</em> (dobry, szlachetny). Znaczenie: <strong>„dobry, szlachetny"</strong>. Imię filozofa i świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Agaton</strong> — ateński tragik, przyjaciel Platona; Uczta Platona odbywa się w jego domu. <strong>Papież Agaton</strong> (VII w.) — uznał prymat Konstantynopola nad Wschodem. <strong>Agaton Giller</strong> — polski działacz niepodległościowy XIX w. W Polsce imię rzadkie, filozoficzne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Agat, Agatonek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Agathon (ang., franc., niem.), Agatone (wł.), Agatón (hiszp.), Агафон (ros.)</p></div>',

  "Aloiza": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Aloiza to żeńska forma imienia Alojzy/Alojzy (Aloysius), z języka <strong>germańskiego lub prowansalskiego</strong> — od <em>Alois</em>, związanego z <em>Hludwig</em> (Ludwik). Znaczenie: <strong>„słynna wojowniczka"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma imienia <strong>Świętego Alojzego Gonzagi</strong> — patrona młodzieży i studentów. Imię popularne w XIX w. w Polsce, szczególnie na Śląsku i w Galicji. <strong>Aloiza Bednarz</strong> — działaczka. Forma Aloizja też używana.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alka, Alojzka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aloysia (łac.), Aloisia (niem.), Aloyse (franc.), Алоиза (ros.)</p></div>',

  "Alojza": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Alojza to wariant żeńskiej formy imienia Alojzy, z języka <strong>germańskiego</strong> — od <em>Alois</em>, związanego z Ludwikiem. Znaczenie: <strong>„słynna wojowniczka"</strong>. Forma polska imienia Aloysia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Forma związana z imieniem <strong>Świętego Alojzego Gonzagi</strong> (1568–1591) — jezuita, patron młodzieży akademickiej i chorych na AIDS. <strong>Alojzy Feliński</strong> — dramaturg, autor <em>Barbary Radziwiłłówny</em>. W Polsce Alojza to imię historyczne, regionalne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alka, Ojza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Aloysia (łac.), Aloisa (niem.), Aloyse (franc.) — żeńska forma Alojzego</p></div>',

  "Agrypina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Agrypina pochodzi z języka <strong>łacińskiego</strong> — od <em>Agrippina</em>, związanego z rodem Agryppów. Znaczenie: <strong>„z rodu Agryppów"</strong> lub „urodzona w ciężkim porodzie". Imię cesarskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Agrypina Młodsza</strong> — matka cesarza Nerona, jedna z najambitniejszych kobiet starożytnego Rzymu, zamordowana przez własnego syna. <strong>Agryppina Wanogenbach</strong> — rosyjska śpiewaczka. W Polsce imię rzadkie, historyczne, kojarzone z historią cesarskiego Rzymu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Aga, Agrypka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Agrippina (ang., łac.), Agrippine (franc.), Агриппина (ros.)</p></div>',

  "Adolfa": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Adolfa to żeńska forma imienia Adolf, ze <strong>starowysokoniemieckiego</strong> — od <em>adal</em> (szlachetny) + <em>wolf</em> (wilk). Znaczenie: <strong>„szlachetna wilczyca"</strong>. Dziś imię niemal nieużywane.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeńska forma imienia Adolf — zdyskredytowanego przez Adolfa Hitlera. <strong>Adolfa</strong> jako imię pojawiała się w XIX i wczesnym XX w. w Polsce. Dziś jest praktycznie nienadawane. Historycznie imię nosiły głównie osoby o germańskich korzeniach.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adka, Olfka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adolpha (ang.), Adolphe (franc., forma męska), Adolfa (niem., wł., hiszp.) — imię dziś rzadkie</p></div>',

  "Anastazja": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Anastazja pochodzi z języka <strong>greckiego</strong> — od <em>anastasis</em> (zmartwychwstanie, powstanie). Znaczenie: <strong>„ta, która zmartwychwstała"</strong>. Imię głęboko chrześcijańskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Anastazja</strong> — chrześcijańska męczennica, patronka tkaczy. <strong>Anastazja Romanow</strong> — najmłodsza córka cara Mikołaja II, zamordowana w 1918 r. — bohaterka wielu legend o rzekomym ocaleniu. Film animowany <em>Anastazja</em> (1997) opowiada jej historię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Nastka, Nastusia, Nastia, Ania</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anastasia (ang., wł., hiszp.), Anastasie (franc.), Анастасия (ros.)</p></div>',

  "Abelard": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Abelard pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Adalhard</em>: <em>adal</em> (szlachetny) + <em>hard</em> (silny). Znaczenie: <strong>„szlachetnie silny"</strong>. Imię słynnego filozofa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Piotr Abelard</strong> (1079–1142) — jeden z największych filozofów średniowiecza, kochanek <strong>Heloizy</strong>. Ich korespondencja to jeden z najpiękniejszych romansów w historii. Pionier scholastyki.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Abel, Abelardek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Abelard (ang., franc.), Abelardo (wł., hiszp.), Абеляр (ros.)</p></div>',











  "Josefina": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Josefina to hiszpańska i skandynawska forma imienia Józefina, wywodząca się z języka <strong>hebrajskiego</strong> — od imienia <em>Yosef</em>: „niech Bóg pomnoży, niech Bóg doda". Znaczenie: <strong>„ta, której Bóg pomnoży"</strong>. Żeńska forma imienia patriarchy Józefa.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Formę tę rozsławiła <strong>Joséphine de Beauharnais</strong> (1763–1814) — pierwsza żona Napoleona Bonaparte, cesarzowa Francuzów, urodzona na Martynice. <strong>Josephine Baker</strong> (1906–1975) — afroamerykańska artystka, gwiazda Paryża lat 20., działaczka praw obywatelskich, odznaczona Legią Honorową. W Polsce forma Josefina używana sporadycznie jako wariant artystyczny lub egzotyczny imienia Józefina; popularna w krajach romańskich i nordyckich.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Josi, Fina, Jose, Josefinka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Josephine (ang., franc.), Giuseppina (wł.), Josefina (hiszp., port., czes.), Josefine (niem., duń.), Жозефина (ros.)</p></div>',


  'Leontyna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Leontyna pochodzi z języka <strong>łacińskiego</strong> — od <em>leo, leonis</em> (<strong>„lew"</strong>). Jest rozbudowaną żeńską formą imienia Leon. Oznacza „lwia", „mężna jak lew". Imię pełne siły i dostojeństwa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Polsce w XIX i na początku XX w., szczególnie wśród szlachty i inteligencji. Leontyna — znana postać z polskiej literatury. Dziś rzadziej nadawane, lecz cenione za elegancję i historyczny charakter.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Leontynka, Leosia, Tyna</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Leontine (franc., niem.), Leontina (wł., hiszp.), Леонтина (ros.)</p></div>',


  'Paraskewa': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Paraskewa pochodzi z języka <strong>greckiego</strong> — od słowa <em>paraskeuē</em> (<em>παρασκευή</em>), oznaczającego <strong>„piątek"</strong> lub „przygotowanie". W tradycji chrześcijańskiej piątek to dzień przygotowania do szabatu i dzień ukrzyżowania Jezusa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię świętej Paraskiewy z Ikonium (II w.) — dziewicy i męczennicy, bardzo czczonej w Kościele prawosławnym i greckokatolickim. Patronka Rumunii i Mołdawii. W Polsce znana jako Paraskewa lub Paraskiewia, czczona szczególnie na Ukrainie i wśród Łemków.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Paraska, Parasza, Paraksia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Paraskeva (łac., ang.), Parascève (franc.), Параскева (ros., ukr.)</p></div>',

  'Stefania': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Stefania pochodzi z języka <strong>greckiego</strong> — jest żeńską formą imienia Stefan, wywodzącego się od <em>stephanos</em> (<strong>„wieniec"</strong>, korona). Oznacza „uwieńczona", „koronowana", „ozdobiona wieńcem chwały".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez wiele arystokratek i dam dworu w historii Europy. Stefania Belgijska (1864–1945) — księżniczka, żona następcy tronu Austro-Węgier arcyksięcia Rudolfa. W Polsce imię popularne w XIX i XX w. Stefania Woytowicz — wybitna polska śpiewaczka operowa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Stefa, Stefcia, Fania, Stefanka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Stephanie (ang., franc., niem.), Stefania (wł., hiszp.), Стефания (ros.)</p></div>',

  'Teodozja': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Teodozja pochodzi z języka <strong>greckiego</strong> — złożone z <em>theos</em> (Bóg) i <em>dosis</em> (dar, dawanie). Oznacza <strong>„dar Boga"</strong> lub „ta, która jest darem bożym". Bliskoznaczne z imieniem Teodora.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię kilku świętych kobiet wczesnochrześcijańskich. Święta Teodozja z Cezarei — dziewica i męczennica z IV w. W Polsce imię rzadkie, sporadycznie nadawane jako wyraz tradycji religijnej lub hołd dla imienia patronki.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Teodka, Tosia, Dosia, Teodozjuszka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Theodosia (ang.), Théodosie (franc.), Teodosia (wł., hiszp.), Феодосия (ros.)</p></div>',



  'Edwina': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Edwina pochodzi z języka <strong>staroangielskiego</strong> — jest żeńską formą imienia Edwin, złożonego z <em>ead</em> (bogactwo, szczęście) i <em>wine</em> (przyjaciel). Oznacza <strong>„bogaty przyjaciel"</strong> lub „szczęśliwa towarzyszka".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Anglii, w Polsce rzadko spotykane. Edwina Mountbatten (1901–1960) — angielska arystokratka, ostatnia wicekrólowa Indii, znana z pracy humanitarnej i przyjaźni z Jawaharlal Nehru. Edwina Currie — brytyjska polityk i pisarka.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Edwinka, Eda, Wina</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Edwina (ang.), Edvina (chorw., słow.), Эдвина (ros.)</p></div>',


  "Gerwazy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Gerwazy pochodzi ze <strong>starogermańskiego</strong> — od <em>ger</em> (włócznia, oszczep) i <em>was</em> (sługa). Znaczenie: <strong>„sługa włóczni"</strong>. Imię przybyło do Polski przez kościół łaciński jako <em>Gervasius</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święci Gerwazy i Protazy</strong> — chrześcijańscy bracia-bliźniacy, męczennicy z Mediolanu (I w.), których relikwie odkrył święty Ambroży w 386 r. Imię rozsławił Adam Mickiewicz w <em>Panu Tadeuszu</em> (1834) — <strong>Gerwazy Rębajło</strong>, klucznik zamkowy, wielki mówca, sercem i szablą oddany Horeszkom. Symbol starej szlacheckiej wierności. W Polsce imię dziś niemal wyłącznie historyczne, kojarzone właśnie z Mickiewiczem.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Gerwazek, Gerek, Gerwuś</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gervase / Jarvis (ang.), Gervais (franc.), Gervasio (wł., hiszp.), Гервасий (ros.)</p></div>',

  'Ignacja': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Ignacja pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Ignacy, wywodzącego się od <em>Ignatius</em>. Etymologia niepewna — część badaczy wiąże je z łacińskim <em>ignis</em> (<strong>„ogień"</strong>), inni z etruskim imieniem własnym.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Żeński odpowiednik imienia świętego Ignacego Loyoli (1491–1556) — hiszpańskiego rycerza, który po nawróceniu założył Towarzystwo Jezusowe (jezuitów). Ignacy Krasicki (1735–1801) — ksiądz i wybitny polski pisarz oświeceniowy. Imię Ignacja rzadkie w Polsce, noszone jako wyraz czci dla patrona.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Ignaczka, Ignaśka, Naśka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Ignacia (hiszp.), Ignazia (wł.), Ignace (franc.), Игнатия (ros.)</p></div>',


  "Korneliusz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Korneliusz pochodzi z języka <strong>łacińskiego</strong> — od rodu Korneliuszów (<em>Cornelius</em>), od <em>cornu</em> (róg). Znaczenie: <strong>„rogaty, silny"</strong>. Imię papieskie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Korneliusz</strong> — III-wieczny papież i męczennik. <strong>Korneliusz</strong> — setnik z Dziejów Apostolskich, pierwszy nawrócony poganin. <strong>Pierre Corneille</strong> — dramaturg francuski. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kornel, Korniusz</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cornelius (ang., niem.), Corneille (franc.), Cornelio (wł., hiszp.), Корнелий (ros.)</p></div>',


  "Makryna": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Makryna pochodzi z języka <strong>greckiego</strong> — od przymiotnika <em>makros</em>, oznaczającego „długi, wielki, rozległy". Znaczenie: <strong>„wielka, dostojna"</strong>. Imię rzadkie, o wczesnochrześcijańskim rodowodzie, znane w Polsce przede wszystkim przez postać błogosławionej zakonnicy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Makryna Młodsza</strong> (ok. 327–379) — starsza siostra Bazylego Wielkiego i Grzegorza z Nyssy, ascetka i filozofka, zwana przez brata „nauczycielką". <strong>Makryna Mieczysławska</strong> (1811–1883) — polska zakonnica bazylianki, beatyfikowana przez Jana Pawła II w 1994 roku. W Polsce imię niemal wyłącznie kościelne i historyczne, nadawane bardzo rzadko, lecz niosące bogatą tradycję duchową.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Makrynka, Maka, Makrusia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Macrina (ang., wł., hiszp.), Macrine (franc.), Makrina (niem.), Макрина (ros.)</p></div>',

  "Narcyz": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Narcyz pochodzi z języka <strong>greckiego</strong> — od <em>narkissos</em> (narcyz, kwiat), od <em>narke</em> (odurzenie). Znaczenie: <strong>„odurzający"</strong>. Imię mitologicznego pięknego młodzieńca.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Narcyz</strong> — w mitologii piękny młodzieniec, który zakochał się we własnym odbiciu w wodzie i umarł z tęsknoty — stąd słowo <em>narcyzm</em>. <strong>Święty Narcyz</strong> — biskup Jerozolimy II w. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Narcek, Narcy</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Narcissus (łac., ang.), Narcisse (franc.), Narciso (wł., hiszp.), Нарцисс (ros.)</p></div>',

  "Oktawian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Oktawian pochodzi z języka <strong>łacińskiego</strong> — od <em>octavus</em> (ósmy). Znaczenie: <strong>„ósmy"</strong>. Imię pierwszego cesarza Rzymu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Oktawian August</strong> — pierwszy cesarz Rzymu (27 p.n.e.–14 n.e.), od jego imienia pochodzi miesiąc <em>sierpień</em> (augustus). Wnuk Juliusza Cezara. Czas jego panowania to <em>Pax Augusta</em> — złoty wiek Rzymu. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Oktawek, Taweł</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Octavian (ang.), Octavien (franc.), Ottaviano (wł.), Octaviano (hiszp.), Октавиан (ros.)</p></div>',

  "Palmira": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Palmira pochodzi z języka <strong>łacińskiego lub arabskiego</strong> — od nazwy miasta Palmyra (miasto palm). Znaczenie: <strong>„z miasta palm"</strong>. Imię geograficzne.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Palmira</strong> (Palmyra) — starożytne miasto na Pustyni Syryjskiej, stolica królestwa Zenobii. Dziś słynne ruiny, wpisane na listę UNESCO. W Polsce Palmira kojarzy się z lasem pod Warszawą — miejscem egzekucji Polaków przez Niemców w 1940 r.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Palma, Palmirka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Palmira (ang., wł., hiszp.), Palmine (franc.), Пальмира (ros.)</p></div>',

  "Reginald": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Reginald pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Raginwald</em>: <em>ragin</em> (rada) + <em>wald</em> (władca). Znaczenie: <strong>„mądry władca"</strong>. Angielska forma Rajnolda.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Reginald Pole</strong> — ostatni katolicki arcybiskup Canterbury. <strong>Reginald</strong> — imię popularne w średniowiecznej Anglii wśród arystokracji. W Polsce imię bardzo rzadkie, znane z historii zachodniej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Reg, Reginek, Reggi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Reginald (ang.), Renaud (franc.), Rinaldo (wł.), Reinaldo (hiszp.), Реджинальд (ros.)</p></div>',

  "Scholastyka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Scholastyka pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>scholasticus</em> (uczony, szkolny). Znaczenie: <strong>„uczona"</strong>. Imię siostry Benedykta.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Scholastyka</strong> — siostra bliźniaczka świętego Benedykta z Nursji, założycielka żeńskiej gałęzi benedyktynek. Patron studentów. W Polsce imię rzadkie, kojarzone z zakonnicami i historią Kościoła.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Schola, Scholka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Scholastica (ang., łac.), Scholastique (franc.), Scholastica (wł., hiszp.), Схоластика (ros.)</p></div>',

  "Teofilakt": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Teofilakt pochodzi z języka <strong>greckiego</strong> — od <em>theos</em> (Bóg) + <em>phylax</em> (strażnik). Znaczenie: <strong>„strażnik Boga"</strong>. Imię arcybiskupa i świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Teofilakt z Ochrydy</strong> — arcybiskup Ochrydy XI/XII w., wybitny egzegeta biblijny. <strong>Teofilakt</strong> — imię kilku cesarzy bizantyjskich. W Polsce imię bardzo rzadkie, historyczne, znane z Kościoła wschodniego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Teofilek, Filakt</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theophylact (ang.), Théophylacte (franc.), Teofilatto (wł.), Феофилакт (ros.)</p></div>',

  "Walburga": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Walburga pochodzi ze <strong>staroangielskiego</strong> — od <em>wealdburg</em>: <em>weald</em> (władza) + <em>burg</em> (zamek, ochrona). Znaczenie: <strong>„potężna opiekunka"</strong>. Imię angielskiej misjonarki w Niemczech.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Walburga</strong> (710–779) — angielska misjonarka, chrystianizowała Niemcy. Jej wspomnienie (1 maja) dało nazwę <em>nocy Walpurgii</em> — dawnego germańskiego święta, dziś kojarzonego z czarownicami. W Polsce imię bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Walba, Burga</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Walburga (niem., ang.), Vauburge (franc.), Valburga (wł., hiszp.), Вальбурга (ros.)</p></div>',

  "Zefiryn": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Zefiryn pochodzi z języka <strong>greckiego lub łacińskiego</strong> — od <em>Zephyrinus</em>, od <em>zephyros</em> (zachodni wiatr). Znaczenie: <strong>„zachodni wiatr"</strong>. Imię papieża-męczennika.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Papież Zefiryn</strong> (zm. 217) — papież przez 18 lat, uznany za męczennika. <strong>Zefiryn Namuncurá</strong> — błogosławiony argentyński młodzieniec, syn wodza Mapuczów. W Polsce imię bardzo rzadkie, egzotyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zefir, Zefek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zephyrinus (łac.), Zéphirin (franc.), Zefirino (wł., hiszp.), Зефирин (ros.)</p></div>',
  'Gerwazja': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Gerwazja pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Gerwazy. Prawdopodobnie złożone z <em>ger</em> (włócznia) i <em>vas</em> (sługa). Oznacza <strong>„sługa z włócznią"</strong> lub „wojownicza służebnica". Imię o wyraźnych germańskich korzeniach.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię świętego Gerwazego — wczesnochrześcijańskiego męczennika z Mediolanu, czczonego razem ze świętym Protazym. Ich relikwie odkrył święty Ambroży w 386 r. W Polsce imię rzadkie, nadawane jako wyraz kultu obu świętych braci i nawiązania do tradycji łacińskiej.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Gerwazka, Gerwazjuszka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Gervaise (franc.), Gervagia (wł.), Гервазия (ros.)</p></div>',

  "Elzbietka": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Elżbietka to zdrobnienie imienia Elżbieta, z języka <strong>hebrajskiego</strong> — od <em>Elisheba</em> (Bóg jest moją przysięgą). Znaczenie: <strong>„mała Elżbieta"</strong>. Czułe zdrobnienie popularne w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Elżbietka to typowo polska, czuła forma imienia Elżbieta. Używana jako imię własne lub zdrobnienie. W Polsce zdrobnienia od Elżbiety — Elżbietka, Ela, Bietka — są bardzo popularne i ciepło odbierane.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Elka, Bietka, Ela</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Elizabetta (wł.), Elisabeta (hiszp.), Elisabeth (franc., niem.), Elizabeth (ang.)</p></div>',

  "Kryspin": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kryspin pochodzi z języka <strong>łacińskiego</strong> — od <em>crispus</em> (kędzierzawy). Znaczenie: <strong>„kędzierzawy"</strong>. Imię świętego szewca i patrona rzemiosła.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Kryspin</strong> — razem ze świętym Kryspinianem patronuje szewcom i garbarze. Bitwa pod Azincourt (1415) rozegrała się w dzień świętego Kryspina — uwiecznił to Szekspir w <em>Henryku V</em> (mowa świętego Kryspina). W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Kryspinek, Krys</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Crispin (ang.), Crépin (franc.), Crispino (wł.), Crispín (hiszp.), Криспин (ros.)</p></div>',

  "Maksymilian": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Maksymilian pochodzi z języka <strong>łacińskiego</strong> — imię złożone z Maksymus i Emilianus przez cesarza Fryderyka III. Znaczenie: <strong>„największy"</strong>. Imię cesarzy i świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święty Maksymilian Kolbe</strong> — franciszkanin, oddał życie za współwięźnia w Auschwitz, patron naszych czasów. <strong>Maksymilian I</strong> — cesarz Meksyku. <strong>Maksymilian Habsburg</strong> — cesarz. W Polsce Maksymilian popularny dzięki świętemu Kolbemu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maks, Maksio, Maki</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maximilian (ang., niem.), Maximilien (franc.), Massimiliano (wł.), Maximiliano (hiszp.), Максимилиан (ros.)</p></div>',

  "Otylia": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Otylia pochodzi ze <strong>starowysokoniemieckiego</strong> — od <em>Odilia</em>, od <em>odal</em> (majątek, dziedzictwo). Znaczenie: <strong>„dziedziczka"</strong>. Imię patronki Alzacji.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Otylia</strong> — patronka Alzacji i niewidomych. Wedle legendy urodziła się ślepa, a wzrok odzyskała przy chrzcie. Klasztor Odilienberg w Alzacji — jedno z najpopularniejszych miejsc pielgrzymkowych. <strong>Otylia Jędrzejczak</strong> — polska pływaczka, mistrzyni olimpijska.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ota, Otylka, Tila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Odilia, Ottilia (niem.), Odile (franc.), Odilia (ang., wł., hiszp.), Отилия (ros.)</p></div>',

  "Pankracy": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Pankracy pochodzi z języka <strong>greckiego</strong> — od <em>pankrates</em>: <em>pan</em> (wszystko) + <em>kratos</em> (władza). Znaczenie: <strong>„wszechpotężny"</strong>. Jeden z Trzech Ogrodnicy.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Pankracy, Serwacy i Bonifacy</strong> — „Trzej Ogrodnicy" lub „Zimni Ogrodnicy" (12–14 maja) — święci, których wspomnienia przypadają w czasie ostatnich przymrozków wiosny. W Polsce przysłowie: <em>Do Pankracego nie zdejmuj kożucha z ramienia</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Pankrac, Pankracek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Pancratius (łac.), Pancrace (franc.), Pancrazio (wł.), Pancracio (hiszp.), Панкратий (ros.)</p></div>',
  'Leokad': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Leokad pochodzi z języka <strong>greckiego</strong> — od <em>leukas</em> (<strong>„biały"</strong>, jasny, świetlisty). Nawiązuje do greckiej wyspy Lefkada (Leukas). Imię o poetyckiej jasności, kojarzone z bielą i czystością.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię świętego Leokadesa (Leokada) z Toledo — biskupa i męczennika z początku IV w., patrona Toledo w Hiszpanii. W Polsce imię rzadkie, spotykane jako wyraz kultu mało znanych świętych lub jako imię oryginalne i niebanalne. Cenione przez znawców historii imiennictwa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Leokadek, Leokadzio, Leoś</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Leocadio (hiszp.), Leocade (franc.), Леокад (ros.)</p></div>',

  "Kordula": '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Kordula pochodzi z języka <strong>łacińskiego</strong> — od <em>cor/cordis</em> (serce). Znaczenie: <strong>„serdeczna, z serca"</strong>. Imię towarzyszki świętej Urszuli.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p><strong>Święta Kordula</strong> — legendarnie jedna z 11 000 towarzyszek świętej Urszuli, męczennic z Kolonii. Wg legendy ze strachu ukryła się, lecz następnego dnia sama oddała się w ręce oprawców. Symbol odważnej skruchy. W Polsce imię rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Korka, Dula, Kordulka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cordula (ang., niem.), Cordule (franc.), Cordula (wł., hiszp.), Кордула (ros.)</p></div>',

  'Alfreda': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Alfreda pochodzi z języka <strong>staroangielskiego</strong> — jest żeńską formą imienia Alfred, złożonego z <em>aelf</em> (elf, duch) i <em>raed</em> (rada, mądrość). Oznacza <strong>„mądra jak elf"</strong> lub „obdarzona elfią radą". Imię wywodzące się z angielskiej tradycji.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Anglii, rzadziej spotykane na kontynencie. Alfred Wielki (849–899) — król Wesseksu, jeden z największych władców angielskich. Alfred Nobel (1833–1896) — szwedzki chemik i wynalazca dynamitu, fundator nagród Nobla. Imię Alfreda rzadkie w Polsce.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Alfreda, Freda, Fredzia, Alka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Alfreda (ang., niem.), Alfréda (węg.), Alfrede (franc.)</p></div>',
  'Alwina': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Alwina pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Alwin, złożonego z <em>adal</em> (szlachetny) i <em>win</em> (przyjaciel). Oznacza <strong>„szlachetna przyjaciółka"</strong> lub „przyjaciel szlachetnego rodu".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularniejsze w Niemczech i Skandynawii niż w Polsce. Alwine von Chezy (1778–1856) — niemiecka pisarka i poetka. W Polsce imię rzadkie, spotykane wśród rodzin o tradycjach germańskich lub jako wyraz artystycznej oryginalności rodziców.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Alwinka, Wina, Alka, Alwi</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Alwine (niem.), Alvina (ang., szwedz., norw.), Алвина (ros.)</p></div>',
  'Ambrozja': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Ambrozja pochodzi z języka <strong>greckiego</strong> — jest żeńską formą imienia Ambroży, od <em>ambrotos</em> (<strong>„nieśmiertelny"</strong>, boski). Wywodzi się z <em>a-</em> (nie) i <em>brotos</em> (śmiertelny). Ambrozja to w mitologii pokarm bogów dający wieczne życie.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię rzadkie w Polsce, lecz o pięknej symbolice. Nawiązuje do świętego Ambrożego z Mediolanu (ok. 340–397) — jednego z czterech wielkich Doktorów Kościoła. W kulturze antycznej ambrozja była synonimem czegoś wyjątkowo smacznego i boskiego.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Ambrozja, Brozia, Ambra</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Ambrosia (ang., hiszp., wł.), Ambrosie (franc.), Амброзия (ros.)</p></div>',
  'Arnolf': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Arnolf pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>arn</em> (orzeł) i <em>wulf</em> (wilk). Oznacza <strong>„orli wilk"</strong> lub „ten, który łączy siłę orła i wilka". Imię ewokuje drapieżność, swobodę i nieustraszenie.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię historyczne, dziś rzadko spotykane. Arnulf III (ok. 1055–1071) — hrabia Flandrii, zginął młodo w walce. Arnulf z Mediolanu — arcybiskup z XI w. Imię było popularne wśród frankijskiej i germańskiej szlachty w średniowieczu.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Arnolfek, Arnulf (starsza forma)</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Arnulf (niem., ang.), Arnolfo (wł.), Arnulphe (franc.), Арнольф (ros.)</p></div>',
  'Arseniusz': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Arseniusz pochodzi z języka <strong>greckiego</strong> — od słowa <em>arsenios</em> (<em>ἀρσένιος</em>), oznaczającego <strong>„mężny"</strong>, dzielny, silny jak mężczyzna. Wywodzi się z <em>arsen</em> — mężczyzna, samiec. Imię związane z siłą i męstwem.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Kościele wschodnim. Święty Arseniusz Wielki (354–445) — egipski pustelnik urodzony w Rzymie, wychowawca cesarskich synów, który wyrzekł się świeckiej kariery i zamieszkał na pustyni. Jeden z najbardziej cenionych Ojców Pustyni.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Arsenek, Arsenusio</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Arsenius (łac., ang., niem.), Arsène (franc.), Arsenio (hiszp., wł.), Арсений (ros.)</p></div>',
  'Astrid': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Astrid pochodzi z języka <strong>staronordyjskiego</strong> — złożone z <em>áss</em> (bóg, Aser — nordyccy bogowie) i <em>fríðr</em> (piękny, ukochany). Oznacza <strong>„boskie piękno"</strong> lub „ukochana przez bogów". Imię głęboko zakorzenione w skandynawskiej kulturze.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Skandynawii od ponad tysiąca lat. Astrid Lindgren (1907–2002) — szwedzka pisarka, autorka Pippi Langstrumpf, Emila ze Smalandii i Dzieci z Bullerbyn — jednych z najpiękniejszych książek dla dzieci w historii. Astrid — królowa Belgii (1905–1935), zginęła w wypadku samochodowym.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Astra, Assi, Astrydka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Astrid (szwedz., norw., duń., niem., ang.), Астрид (ros.)</p></div>',
  'Berta': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Berta pochodzi z języka <strong>starogermańskiego</strong> — od <em>beraht</em> (<strong>„jasny"</strong>, błyszczący, sławny). Jest skróconą formą imion złożonych z tym rdzeniem, jak Alberta czy Roberta. Imię symbolizuje jasność i sławę.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w średniowiecznej Europie. Berta von Suttner (1843–1914) — austriacka pisarka i działaczka pacyfistyczna, autorka <em>Precz z bronią!</em>, <strong>pierwsza kobieta laureatka Pokojowej Nagrody Nobla</strong> (1905). Berta z Burgundii — żona króla Franków Pepina Krótkiego.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bertka, Bertunia, Berta, Bertka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Bertha (ang., niem., franc.), Berta (hiszp., wł., pol.), Берта (ros.)</p></div>',
  'Bogusława': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bogusława pochodzi z języka <strong>słowiańskiego</strong>. Jest żeńską formą imienia Bogusław, złożoną z członów <em>Bóg</em> i <em>sław</em>. Oznacza <strong>„sławiąca Boga"</strong> lub „ta, która sławną jest przez Boga".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię staropolskie, noszone od wieków średnich. Żeńska odpowiedź na tradycję nadawania imion książęcych — Bogusław to imię m.in. ostatniego księcia Pomorza Bogusława XIV (1580–1637). Dziś rzadko nadawane.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bogusia, Sławka, Bogusławka, Bosia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Bogusława (pol.), Bogoslava (chorw., słow.), Богуслава (ros.)</p></div>',
  'Bolesław': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bolesław pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>bol</em> (wielki, potężny) i <em>sław</em> (sława). Oznacza <strong>„wielka sława"</strong> lub „ten, którego sława jest ogromna".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię trzech królów polskich: Bolesława I Chrobrego (967–1025) — pierwszego króla Polski, Bolesława II Śmiałego (1042–1081) i Bolesława III Krzywoustego (1086–1138). Bolesław Prus (1847–1912) — jeden z najwybitniejszych polskich pisarzy, autor <em>Lalki</em> i <em>Faraona</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bolek, Bolko, Bolesławek, Bolcio</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Boleslav (czes.), Boleslao (hiszp., wł.), Болеслав (ros., słow.)</p></div>',
  'Bolesława': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bolesława pochodzi z języka <strong>słowiańskiego</strong> — jest żeńską formą imienia Bolesław, złożonego z <em>bol</em> (wielki) i <em>sław</em> (sława). Oznacza <strong>„wielka sława"</strong>. Imię nawiązuje do tradycji pierwszych królów Polski.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię dawne, noszone przez szlachcianki i arystokratki w dawnej Polsce. Żeński odpowiednik imion trzech królów polskich z dynastii Piastów: Bolesława Chrobrego, Bolesława Śmiałego i Bolesława Krzywoustego. Dziś rzadko nadawane, lecz cenione jako wyraz przywiązania do historii.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bolka, Sławka, Bolesławka, Bola</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Boleslava (czes.), Boleslawa (niem.) — imię typowo słowiańskie</p></div>',
  'Bonifacy': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bonifacy pochodzi z języka <strong>łacińskiego</strong> — od <em>bonum facere</em> (<strong>„czynić dobro"</strong>) lub <em>bona fata</em> (dobry los). Łączy w sobie ideał moralny i pragnienie pomyślności. Imię o głęboko chrześcijańskim przesłaniu.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię wielu papieży. Święty Bonifacy (ok. 675–754) — angielski mnich benedyktyński, <strong>apostoł Niemiec</strong>, arcybiskup Moguncji, który schrystianizował znaczną część Germanii. Zamordowany przez pogan nad Jeziorem Ijssel. Patron Niemiec.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bonifacek, Bonisio</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Boniface (ang., franc.), Bonifatius (niem.), Bonifacio (hiszp., wł.), Бонифаций (ros.)</p></div>',
  'Borys': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Borys pochodzi prawdopodobnie z języka <strong>turskiego</strong> — od <em>bars</em> (lampart, tygrys). Inne teorie wywodzą je ze słowiańskiego <em>bor</em> (<strong>„walka"</strong>, bój). Imię bułgarsko-słowiańskie, szeroko znane w Europie Wschodniej.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Borys I (ok. 830–907) — car Bułgarii, który przyjął chrześcijaństwo w 864 r. i zaprowadził je w całym państwie, stając się apostołem Bułgarów. Borys Pasternak (1890–1960) — rosyjski pisarz, autor <em>Doktora Żywago</em>, laureat Nagrody Nobla 1958. Borys Jelcyn — pierwszy prezydent Rosji.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Borysek, Borko, Boreczek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Boris (ang., franc., niem., ros.), Борис (ros., bułg., serb.)</p></div>',
  'Czesława': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Czesława pochodzi z języka <strong>słowiańskiego</strong>. Jest żeńską formą imienia Czesław, złożoną z <em>cześć</em> (szacunek, chwała) i <em>sław</em> (sława). Oznacza <strong>„sławna czcią"</strong> lub „ta, którą sławi się za szacunek".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię słowiańskie, popularne w Polsce szczególnie w pierwszej połowie XX wieku — w pokoleniu urodzonym w latach 1910–1940. Czesław Miłosz (1911–2004) — noblista, jeden z największych polskich poetów, nosił męską formę tego imienia.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Czesia, Sławka, Czesławka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Česlava (czes.) — imię typowo słowiańskie, znane głównie w Polsce</p></div>',
  'Dezydery': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Dezydery pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>desiderium</em>, oznaczającego <strong>„pragnienie"</strong>, tęsknota, gorące życzenie. Wywodzi się z <em>desiderare</em> — pragnąć, tęsknić. Imię związane z głęboką duchową tęsknotą za dobrem i Bogiem.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez kilku papieży i świętych w średniowieczu. Święty Dezydery — biskup Vienne w Galii, zginął śmiercią męczeńską ok. 607 r. z rozkazu królowej Brunhildy. Dezyderiusz Erazm z Rotterdamu — znany jako Erazm — najwybitniejszy humanista północnej Europy (1466–1536).</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Dezyderek, Dezyderuszek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Didier (franc.), Desiderio (wł., hiszp.), Desiderius (łac., niem.), Дезидерий (ros.)</p></div>',
  'Dobromił': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Dobromił pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>dobro</em> i <em>miły</em>. Oznacza <strong>„dobry i miły"</strong> lub „ten, którego dobroć jest miła". Imię odzwierciedla ideał człowieka łączącego moralną doskonałość z ujmującą osobowością.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Historyczne imię słowiańskie, używane w Polsce i krajach słowiańskich od wczesnego średniowiecza. Należy do grupy imion dwuczłonowych, popularnych wśród Słowian zachodnia. Dziś rzadkie, lecz wybierane przez rodziców ceniących słowiańskie korzenie i tradycję.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Dobroś, Miłek, Dobromilec</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Dobromil (czes., chorw., słow.), Добромил (bułg.) — imię typowo słowiańskie</p></div>',
  'Dobromir': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Dobromir pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>dobro</em> (dobry, moralny) i <em>mir</em> (pokój, świat, wspólnota). Oznacza <strong>„dobry i pokojowy"</strong> lub „ten, który niesie dobro i pokój światu". Imię odzwierciedla słowiański ideał człowieka łączącego dobroć z harmonią.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Historyczne imię słowiańskie, używane w Polsce i krajach słowiańskich od wczesnego średniowiecza. Należy do grupy imion dwuczłonowych, popularnych wśród Słowian zachodnich. Dziś rzadkie, lecz wybierane przez rodziców ceniących słowiańskie korzenie i tradycję kulturową.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Dobroś, Mirek, Dobromireczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Dobromir (czes., chorw., bułg., serb.), Добромир (ros., bułg.) — imię typowo słowiańskie, bez odpowiedników w językach zachodnich</p></div>',
  'Dobrosław': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Dobrosław pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>dobro</em> i <em>sław</em> (sława). Oznacza <strong>„sławny dobrocią"</strong> lub „ten, którego sławią za dobroć".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Historyczne imię słowiańskie, używane w Polsce od wczesnego średniowiecza. Nawiązuje do tradycji słowiańskiej, w której imiona odzwierciedlały pożądane cnoty. Dziś rzadko nadawane, bywa wybierane przez rodziców ceniących słowiańskie korzenie.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Dobrek, Sławek, Dobrosławek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Dobroslav (czes., chorw., słow., bułg.) — imię typowo słowiańskie</p></div>',
  'Edwarda': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Edwarda pochodzi z języka <strong>staroangielskiego</strong> — jest żeńską formą imienia Edward, złożonego z <em>ead</em> (bogactwo, szczęście, dobrobyt) i <em>weard</em> (strażnik, opiekun). Oznacza <strong>„strażniczka bogactwa"</strong> lub „opiekunka dostatku".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeński odpowiednik imienia wielu królów angielskich — od Edwarda Wyznawcy (1003–1066), patrona Anglii, przez Edwardów I–VIII aż do współczesności. Edward VIII (1894–1972) — król, który abdykował z miłości do Wallis Simpson. W Polsce imię Edwarda rzadkie, noszone jako żeński hołd dla tradycji.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Edka, Eda, Edwardka, Edzia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Edwarda (ang., wł., hiszp.), Édouarde (franc.), Эдварда (ros.)</p></div>',
  'Eligiusz': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eligiusz pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>eligere</em>, oznaczającego <strong>„wybierać"</strong>, „wybrać". Dosłownie: „wybrany", „ten, który został wybrany". Imię o głęboko religijnym przesłaniu — każdy Eligiusz to człowiek wybrany przez Boga.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Eligiusza z Noyon (ok. 588–660) — frankijskiego złotnika i biskupa, <strong>patrona złotników, kowali, jubilerów i jeźdźców</strong>. Jeden z najważniejszych świętych Galii. Zasłynął ze swej sztuki złotniczej na dworze króla Chlotara II. W Polsce imię rzadkie, lecz znane dzięki kultowi świętego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Eligiuszek, Elżek, Elig</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Eligius (łac., niem.), Eloi (franc., hiszp.), Eligio (wł.), Элигий (ros.)</p></div>',
  'Emilian': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emilian pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu <em>Aemilius</em>, wywodzącego się prawdopodobnie z łacińskiego <em>aemulus</em> (<strong>„rywalizujący"</strong>, naśladujący, dążący do dorównania innym). Imię inspiruje do ambicji i ciągłego doskonalenia.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Emiliana z Kogolii (ok. 473–574) — hiszpańskiego pustelnika, patrona Kastylii i La Rioja. Emilian Orzeszkowa — skojarzenie z wielką polską pisarką Elizą Orzeszkową. Emiliano Zapata (1879–1919) — meksykański rewolucjonista, jeden z przywódców rewolucji meksykańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Emil, Emilek, Emilianek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emilian (rum.), Emiliano (hiszp., wł.), Émilien (franc.), Эмилиан (ros.)</p></div>',
  'Emiliana': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Emiliana pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Emilian, wywodzącego się od starożytnego rodu <em>Aemilius</em> i łacińskiego <em>aemulus</em> (<strong>„rywalizująca"</strong>, dążąca do doskonałości). Imię związane z ambicją i szlachetnością ducha.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Emiliany — ciotki świętego Grzegorza Wielkiego, papieża, żyjącej w VI w. w Rzymie. Znana z głębokiej pobożności i mistycznych wizji. W Polsce imię rzadkie, lecz cenione za eleganckie brzmienie i starochrześcijańskie korzenie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Emilka, Emia, Emilianeczka, Mila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Emiliana (hiszp., wł., ang.), Émiliane (franc.), Эмилиана (ros.)</p></div>',
  'Eufemia': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Eufemia pochodzi z języka <strong>greckiego</strong> — złożone z <em>eu</em> (dobry, piękny) i <em>phēmē</em> (głos, mowa, sława). Oznacza <strong>„piękna mowa"</strong> lub „ta, o której dobrze mówią". Wywodzi się z tradycji starożytnej Grecji, gdzie <em>euphemia</em> oznaczała zachowanie milczenia w czasie obrzędów religijnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Eufemii z Chalcedonu (ok. 289–307) — dziewicy i męczennicy, patronki Chalcedonu. Sobór Chalcedoński (451 r.) obradował w kościele pod jej wezwaniem. W Polsce imię rzadkie, lecz piękne i o doniosłej historii kościelnej. Ciotka Teodozjusza II nosiła to imię.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Efka, Eufemka, Femia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Euphemia (ang., łac.), Euphémie (franc.), Eufemia (wł., hiszp.), Евфимия (ros.)</p></div>',
  'Felicjan': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Felicjan pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>felix</em> (<strong>„szczęśliwy"</strong>, pomyślny) z sufiksem <em>-ianus</em>. Oznacza „szczęśliwy", „błogosławiony", „obdarzony pomyślnością". Bliskoznaczne z imieniem Feliks, lecz rzadsze i bardziej uroczyste.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Felicjana z Foligno (ok. 160–251) — biskupa, jednego z najstarszych męczenników Umbrii. Felicjan Faleński (1825–1910) — wybitny polski poeta, tłumacz Szekspira i Sofoklesa. Felicjan Sławoj Składkowski (1885–1962) — premier Polski w latach 1936–1939.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Felcio, Felicjanek, Felek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Felician (ang., franc.), Feliciano (wł., hiszp.), Фелициан (ros.)</p></div>',
  'Gizela': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Gizela pochodzi z języka <strong>starogermańskiego</strong> — od <em>gisal</em>, oznaczającego <strong>„zakładnik"</strong> lub „zastaw". W dawnej germańskiej tradycji zakładnicy wysyłani do sojuszników byli traktowani honorowo, więc imię nabrało znaczenia „dar" czy „rękojmia pokoju".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię błogosławionej Gizeli Węgierskiej (ok. 985–1060) — siostry świętego Stefana, króla Węgier, żony Henryka II Bawarskiego. Gizela von Habsburg (ur. 1856) — córka cesarza Franciszka Józefa i cesarzowej Sisi. W Polsce imię rzadkie, kojarzone z europejską arystokracją.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Giza, Gizelka, Gizia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Gisela (niem., hiszp.), Giselle (franc., ang.), Gisella (wł.), Гизела (ros.)</p></div>',
  'Herbert': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Herbert pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>heri</em> (wojsko, armia) i <em>beraht</em> (jasny, błyszczący, sławny). Oznacza <strong>„sławny wojownik"</strong> lub „ten, który jaśnieje w armii". Imię o rycerskim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Herbert Asquith (1852–1928) — premier Wielkiej Brytanii w latach 1908–1916. Zbigniew Herbert (1924–1998) — jeden z najwybitniejszych polskich poetów XX w., twórca cyklu wierszy o Panu Cogito, moralista i eseista. Herbert George Wells (1866–1946) — angielski pisarz science-fiction, autor <em>Wojny światów</em>.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Hertek, Herbusio, Heri</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Herbert (ang., niem., hiszp.), Herberto (wł.), Херберт (ros.)</p></div>',
  'Hugo': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Hugo pochodzi z języka <strong>starogermańskiego</strong> — od <em>hug</em> lub <em>hugo</em>, oznaczającego <strong>„umysł"</strong>, myśl, duch, inteligencja. Imię cenione przez germańską arystokrację jako wyraz mądrości i przenikliwości intelektualnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Hugo Kołłątaj (1750–1812) — polski polityk, pisarz i reformator, współtwórca Konstytucji 3 Maja. Victor Hugo (1802–1885) — geniusz francuskiego romantyzmu, autor <em>Nędzników</em> i <em>Katedry Marii Panny w Paryżu</em>. Hugo Steinhaus (1887–1972) — wybitny polski matematyk ze Lwowa, twórca szkoły matematycznej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Huguś, Hug, Hugon (forma pełna)</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Hugo (ang., hiszp., port., szwedz.), Hugues (franc.), Ugo (wł.), Хуго (ros.)</p></div>',
  'Ewald': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Ewald pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>ewa</em> (prawo, prawo zwyczajowe) i <em>wald</em> (władza). Oznacza <strong>„władca prawa"</strong> lub „ten, który rządzi przez prawo".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię dwóch świętych braci-misjonarzy z VII w.: Ewalda Czarnego i Ewalda Białego, którzy przybyli z Irlandii chrystianizować Westfalię i ponieśli śmierć męczeńską ok. 690 r. Ich relikwie spoczywają w Kolonii.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Ewalek, Ewal</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Ewald (ang., niem.), Ewaldo (wł.) — imię typowo germańskie</p></div>',

  'Jarosław': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Jarosław pochodzi z języka <strong>słowiańskiego</strong> i jest złożeniem dwóch członów: <em>jar</em> (żar, wiosenna energia, wigor) oraz <em>sław</em> (sława). Oznacza zatem <strong>„żarliwie sławny"</strong> lub „ten, którego sława płonie jak ogień".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez wielu władców słowiańskich. Najbardziej znany Jarosław Mądry (ok. 978–1054) — wielki książę kijowski, który rozkwitł kulturalnie i politycznie Ruś Kijowską. W Polsce imię popularne przez całe wieki, szczególnie w XX wieku.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Jarek, Jarosiek, Jaro, Jareczek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Jaroslav (czes., słow., ros.), Yaroslav (ukr., ang.), Jaroslav (chorw.), Ярослав (ros., ukr.)</p></div>',
  'Józef': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Józef pochodzi z języka <strong>hebrajskiego</strong> — od imienia <em>Yosef</em>, które wywodzi się od słowa <em>yasaf</em>, oznaczającego <strong>„dodać"</strong>, „pomnożyć". Pełne znaczenie to „niech Bóg doda" lub „Bóg pomnoży". Do Polski dotarło przez łacinę jako <em>Josephus</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię niezwykle ważne w tradycji chrześcijańskiej — noszone przez biblijnego syna Jakuba (bohater Księgi Rodzaju) oraz Józefa z Nazaretu, opiekuna Jezusa Chrystusa. W Polsce popularność imienia wiąże się z kultem świętego Józefa. Nosi je m.in. Józef Piłsudski (1867–1935) — marszałek i ojciec odrodzonej niepodległości.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Józio, Józek, Pepek, Pepa, Józefek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Joseph (ang., franc., niem.), José (hiszp.), Giuseppe (wł.), Jozef (niderl.), Иосиф (ros.), Yusuf (arab.)</p></div>',
  'Józefina': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Józefina pochodzi z języka <strong>hebrajskiego</strong> — jest żeńską formą imienia Józef (<em>Yosef</em>), oznaczającego <strong>„niech Bóg pomnoży"</strong>. Do Europy dotarło przez Francję jako <em>Joséphine</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię rozsławiła Joséphine de Beauharnais (1763–1814) — cesarzowa Francji, pierwsza żona Napoleona Bonapartego. Josephine Baker (1906–1975) — słynna amerykańsko-francuska piosenkarka i tancerka, działaczka praw człowieka.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Józia, Józefinka, Pepa, Josi</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Joséphine (franc.), Josephine (ang., niem.), Josefina (hiszp.), Giuseppina (wł.), Жозефина (ros.)</p></div>',
  'Lech': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Lech pochodzi z języka <strong>słowiańskiego</strong>. Wywodzone od legendarnego protoplasty Polaków — <strong>Lecha</strong>. Część badaczy wiąże je z prasłowiańskim <em>lech</em> — oznaczającym szlachcica, człowieka wolnego, możnego. Jedno z najstarszych i najbardziej polskich imion.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Związane z legendą o trzech braciach: Lechu, Czechu i Rusie, którzy dali początek Słowianom. Imię reaktywowane w XX w. jako wyraz patriotyzmu. Lech Wałęsa (ur. 1943) — przywódca „Solidarności", prezydent Polski 1990–1995, laureat Pokojowej Nagrody Nobla 1983.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Leszek, Lechosław (powiązane imię), Lechek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Lech (pol.) — imię unikatowo polskie, niemal bez odpowiedników w innych językach</p></div>',
  'Lilianna': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Lilianna jest połączeniem imion <em>Lilia</em> i <em>Anna</em>. Nawiązuje do kwiatu lilii — od łacińskiego <em>lilium</em>, które pochodzi z greckiego <em>leirion</em>. Lilia od starożytności symbolizuje <strong>czystość, niewinność i piękno</strong>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię współczesne, popularne w Polsce od drugiej połowy XX wieku. Łączy tradycję imion kwiatowych (Lilia, Liliana) z popularnym imieniem Anna. Forma Liliana jest znana w kulturze włoskiej i hiszpańskiej od wieków.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Lila, Lili, Liliana, Ania, Lilianka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Liliana (hiszp., wł.), Liliane (franc.), Lillian (ang.), Liliána (węg.)</p></div>',
  'Ludmiła': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ludmiła pochodzi z języka <strong>słowiańskiego</strong> — złożone z <em>lud</em> (lud, naród, ludzie) i <em>miły</em> (miły, kochany). Oznacza <strong>„miła ludowi"</strong> lub „ta, która jest ukochana przez naród". Imię głęboko zakorzenione w kulturze słowiańskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Ludmiły (ok. 860–921) — księżnej czeskiej, babki świętego Wacława, patronki Czech. Zamordowana przez własną synową. Ludmila Pagliero — włoska baletnica. Ludmiła Semeniaka — wybitna śpiewaczka operowa. W Polsce imię sporadyczne, kojarzone z kulturą czeską i rosyjską.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Luda, Ludka, Miła, Ludmiłka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Ludmila (czes., ang.), Ľudmila (słow.), Людмила (ros., ukr., bułg.)</p></div>',
  'Ludwika': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Ludwika pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Ludwik, złożonego z <em>hlud</em> (sława, głośny) i <em>wig</em> (walka, bitwa). Oznacza <strong>„sławna wojowniczka"</strong> lub „ta, której chwała pochodzi z walki".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię wielu europejskich królowych. Ludwika Maria Gonzaga (1611–1667) — żona dwóch królów polskich: Władysława IV i Jana II Kazimierza. Królowa Luiza (Ludwika) Pruska (1776–1810) — symbol pruskiego patriotyzmu. Ludwika van Beethoven — siostrzenica kompozytora. W Polsce imię arystokratyczne.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Lusia, Ludka, Luiza, Ludwisia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Louise (franc., ang.), Luisa (hiszp., wł.), Luise (niem.), Луиза (ros.)</p></div>',
  'Matylda': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Matylda pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>maht</em> (moc, siła) i <em>hild</em> (bitwa, walka). Oznacza <strong>„potężna wojowniczka"</strong> lub „ta, której siła objawia się w walce". Imię królewskie, pełne determinacji i odwagi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Matylda z Tusculum (ok. 1046–1115) — hrabina Toskanii, jedna z najpotężniejszych kobiet średniowiecza, sojuszniczka papieży w sporze o inwestyturę. Matylda z Anglii — córka Henryka I, pretendentka do tronu angielskiego. Waltzing Matilda — nieoficjalny hymn Australii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Matylcia, Tyldka, Tilda, Mati, Matyleczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Mathilde (franc., niem.), Matilda (ang., szwedz.), Matelda (wł.), Матильда (ros.)</p></div>',
  'Maurycy': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Maurycy pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>Maurus</em>, oznaczającego <strong>„Maur"</strong>, mieszkaniec Mauretanii (północna Afryka). Odnosiło się do ciemnej karnacji. Do Polski dotarło przez łacińskie <em>Mauritius</em> i związki z Kościołem.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Maurycego — żołnierza Legionu Tebańskiego, który poniósł śmierć męczeńską ok. 286 r. za odmowę składania ofiar bogom. Patron Szwajcarii, Sabaudii i armii. Maurycy Mochnacki (1803–1834) — wybitny polski krytyk literacki i polityk, działacz powstania listopadowego.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Maurek, Maurelio, Maurycek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Maurice (ang., franc.), Mauritius (łac., niem.), Maurizio (wł.), Mauricio (hiszp.), Маврикий (ros.)</p></div>',
  'Medard': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Medard pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>mad</em> lub <em>med</em> (łąka, moc) i <em>hard</em> (twardy, silny, dzielny). Oznacza <strong>„mocny jak łąka"</strong> lub „ten, który trwa niezłomnie". Imię kojarzone z pogodą — dzień świętego Medarda wyznacza kierunek pogody.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Medarda (ok. 456–545) — biskupa Noyon i Tournai, patrona pogody w tradycji ludowej. Według przysłowia: <em>„Na świętego Medarda deszcz — przez czterdzieści dni nie wyjdziesz bez"</em>. Dzień świętego Medarda (8 czerwca) to jeden z popularniejszych dni imienin w Polsce.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Medardek, Medek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Médard (franc.), Medardo (wł., hiszp.), Медард (ros.)</p></div>',
  'Przemysław': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Przemysław pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>przemysł</em> (zaradność, przebiegłość, przemyślność) oraz <em>sław</em> (sława). Oznacza <strong>„sławny zaradnością"</strong> lub „ten, którego sławią za przemyślność".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię historyczne, noszone przez Przemysła II (1257–1296) — króla Polski, który po ponad 200 latach rozbicia dzielnicowego zjednoczył kraj i koronował się w Gnieźnie w 1295 r. Zamordowany rok później. Imię rzadkie dziś, lecz cenione jako wyraz przywiązania do historii.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Przemek, Przemo, Przemko, Przemysiek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Přemysl (czes.) — imię typowo słowiańskie, znane głównie w Polsce i Czechach</p></div>',
  'Romana': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Romana pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Roman, wywodzącego się od <em>Romanus</em> (<strong>„Rzymianin"</strong>, obywatel Rzymu). Imię związane z jedną z najpotężniejszych cywilizacji starożytności — Imperium Romanum.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Romany z Reims — dziewicy i pustelniczki z IV/V w. Romana Próchnik — polska polityk okresu dwudziestolecia. Romana Bobrowska — postać z kart historii polskiego ruchu kobiecego. W Polsce imię popularne w XX w., noszone przez kobiety z tradycyjnych polskich rodzin.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Roma, Romka, Romaneczka, Romcia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Romana (wł., hiszp., czes.), Romaine (franc.), Романа (ros.)</p></div>',
  'Róża': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Róża pochodzi od nazwy kwiatu, wywodzącej się z języka <strong>łacińskiego</strong> — <em>rosa</em>. Słowo to przejęte zostało z greckiego <em>rhodon</em>. Kwiat róży od starożytności symbolizuje <strong>miłość, piękno i doskonałość</strong>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię rozsławiła święta Róża z Limy (1586–1617) — dominikańska tercjarka, pierwsza kanonizowana osoba z obu Ameryk, patronka Ameryki Łacińskiej. W Polsce imię noszone przez wiele szlachcianek. Róża Luksemburg (1871–1919) — wybitna polska i niemiecka działaczka polityczna.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Różyczka, Różka, Rosi, Różusia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Rose (ang.), Rosa (hiszp., niem., wł., port.), Rosalie (franc.), Rosaria (wł.), Роза (ros.)</p></div>',
  'Seweryna': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Seweryna pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Seweryn, wywodzącego się od <em>severus</em> (<strong>„surowy"</strong>, poważny, srogi). Imię związane z surowością i powagą, kojarzone z osobami o silnym charakterze i zasadami moralnymi.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię kilku świętych i biskupa. Seweryn z Kolonii (V w.) — patron Kolonii. Seweryna Duchińska (1816–1905) — polska poetka i działaczka emigracyjna. Seweryna Szmaglewska (1916–1992) — polska pisarka, autorka <em>Dymy nad Birkenau</em> — jednego z pierwszych świadectw o Auschwitz.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Sewcia, Sewerynka, Sewa</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Severina (ang., wł., hiszp.), Séverine (franc.), Северина (ros.)</p></div>',
  'Symforoza': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Symforoza pochodzi z języka <strong>greckiego</strong> — od słowa <em>sympherō</em> (<em>συμφέρω</em>), oznaczającego <strong>„przynosić razem"</strong>, „być pożytecznym", „służyć dobru". Imię o rzadkim i wyjątkowym brzmieniu, związane z pojęciem wspólnego dobra.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Symforozy z Tiburu — wdowy i męczennicy chrześcijańskiej z II w., która poniosła śmierć za wiarę wraz z siedmioma synami za panowania cesarza Hadriana. Czczona jako patronka matek i wdów. W Polsce imię niezwykle rzadkie, znane głównie z martyrologiów.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Symka, Symunia, Foroza</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Symphorosa (łac., ang.), Symphorose (franc.), Симфороза (ros.)</p></div>',
  'Teodora': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Teodora pochodzi z języka <strong>greckiego</strong> — złożone z <em>theos</em> (Bóg) i <em>doron</em> (dar). Oznacza <strong>„dar Boga"</strong> lub „ta, która jest bożym darem". Odwrócona wersja imienia Dorota (Dorothea = doron + theos). Oba imiona mają identyczne znaczenie, lecz odwrócone człony.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Teodora (ok. 500–548) — cesarzowa Bizancjum, żona Justyniana I Wielkiego, jedna z najpotężniejszych kobiet starożytności późnej. Córka treserza niedźwiedzi, wspięła się na szczyt władzy. Współrządziła imperium i wpłynęła na kodeks praw Justyniana. Mozaiki z jej podobizną w Rawennie zaliczone do UNESCO.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tedzia, Teodorka, Toda, Dosia</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theodora (ang., niem.), Théodora (franc.), Teodora (wł., hiszp., czes.), Феодора (ros.)</p></div>',
  'Teofil': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Teofil pochodzi z języka <strong>greckiego</strong> — złożone z <em>theos</em> (Bóg) i <em>philos</em> (miły, przyjaciel, kochający). Oznacza <strong>„miły Bogu"</strong> lub „ten, który miłuje Boga". Imię o głęboko duchowym przesłaniu, związane z pobożnością i miłością do sacrum.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Do Teofila zaadresowana jest Ewangelia według świętego Łukasza i Dzieje Apostolskie (Łk 1,3). Teofil Lenartowicz (1822–1893) — polski poeta romantyczny, „lirnik mazowiecki". Teofil Noniewicz — wybitny polsko-litewski szlachcic. W Polsce imię popularne w XIX w., dziś rzadsze.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Teofilek, Teoś, Filek, Teofek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theophilus (ang., łac.), Théophile (franc.), Teofilo (wł., hiszp.), Феофил (ros.)</p></div>',
  'Teofila': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Teofila pochodzi z języka <strong>greckiego</strong> — jest żeńską formą imienia Teofil, złożonego z <em>theos</em> (Bóg) i <em>philos</em> (miły, przyjaciel, kochający). Oznacza <strong>„miła Bogu"</strong> lub „ta, która miłuje Boga". Imię o głęboko duchowym przesłaniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeński odpowiednik imienia biblijnego adresata Ewangelii świętego Łukasza i Dziejów Apostolskich. Teofila Naimska — postać z polskiej hagiografii. W Polsce imię rzadkie, lecz cenione przez rodziców szukających imion o pięknym, religijnym znaczeniu i greckiej etymologii.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Teofilka, Filka, Teosia, Fila</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Theophila (ang., łac.), Théophile (franc.), Teofila (wł., hiszp.), Феофила (ros.)</p></div>',
  'Wilhelm': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Wilhelm pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>wil</em> (wola, pragnienie, życzenie) i <em>helm</em> (hełm, ochrona). Oznacza <strong>„ten, który ochrania swą wolą"</strong> lub „ochrona przez silną wolę". Jedno z najpopularniejszych imion germańskich w historii.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Wilhelm I Zdobywca (1028–1087) — książę Normandii, który podbił Anglię w 1066 r. Wilhelm II (1859–1941) — ostatni cesarz Niemiec. Wilhelm Tell — legendarny szwajcarski łucznik, symbol wolności. Wilhelm Szekspir (William Shakespeare, 1564–1616) — największy dramaturg w historii literatury angielskiej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Wilek, Wilhek, Wileczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>William (ang.), Guillaume (franc.), Guillermo (hiszp.), Guglielmo (wł.), Вильгельм (ros.)</p></div>',
  'Władysława': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Władysława pochodzi z języka <strong>słowiańskiego</strong> — jest żeńską formą imienia Władysław, złożonego z <em>włada</em> (władać, rządzić) i <em>sław</em> (sława). Oznacza <strong>„ta, której sławą jest władanie"</strong> lub „sławna władczyni".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeński odpowiednik imienia kilku królów polskich. Władysław I Łokietek (1261–1333) — król, który zjednoczył Polskę po rozbiciu dzielnicowym. Władysław II Jagiełło (1352–1434) — król zwycięski pod Grunwaldem. W Polsce imię Władysława było popularne w XIX i XX w., szczególnie na wsi.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Władka, Wladzia, Władzia, Ława</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Vladislava (czes., słow., chorw.), Władisława (ros.) — imię typowo słowiańskie</p></div>',
  'Zachariasz': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Zachariasz pochodzi z języka <strong>hebrajskiego</strong> — od <em>Zəḵaryāh</em>, złożonego z <em>zakar</em> (pamiętać) i <em>Yah</em> (skrót od Jahwe). Oznacza <strong>„Bóg pamięta"</strong> lub „ten, o którym Bóg nie zapomina". Imię o głęboko biblijnym charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię wielu postaci biblijnych — m.in. kapłana Zachariasza, ojca Jana Chrzciciela (Łk 1). Prorok Zachariasz — autor jednej z ksiąg Starego Testamentu. Papież Zachariasz (741–752) — wpłynął na ukształtowanie państwa Kościelnego. W Polsce imię rzadkie, noszone jako wyraz przywiązania do tradycji biblijnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Zacharek, Zachar, Zachasz</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Zachary, Zacharias (ang.), Zacharie (franc.), Zaccaria (wł.), Zacarías (hiszp.), Захария (ros.)</p></div>',
  'Zefiryn': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Zefiryn pochodzi z języka <strong>greckiego</strong> — od <em>Zephyros</em> (<em>Ζέφυρος</em>), boga <strong>zachodniego wiatru</strong> w mitologii greckiej. Zefir był łagodnym, wiosennym wiatrem przynoszącym deszcz i ciepło, zwiastunem wiosny i rozkwitu.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię kilku papieży wczesnochrześcijańskich, m.in. Zefiryna I — biskupa Rzymu w latach 199–217, który zginął śmiercią męczeńską. W Polsce imię rzadkie, lecz o pięknym brzmieniu i głębokiej symbolice związanej z wiatrem i wiosną.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Zefirek, Zefirynek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Zephyrin (franc.), Zefferino (wł.), Ceferino (hiszp.), Зефирин (ros.)</p></div>',
  'Zenobia': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Zenobia pochodzi z języka <strong>greckiego</strong> — złożone z <em>Zeus</em> (najwyższy bóg grecki) i <em>bios</em> (życie). Oznacza <strong>„życie Zeusa"</strong> lub „ta, której życie pochodzi od bogów". Imię pełne majestatu i boskości.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię sławnej Zenobii (ok. 240–275) — królowej Palmiry w Syrii, która po śmierci męża samodzielnie rządziła państwem i stawiła opór Imperium Rzymskiemu. Jedna z najwybitniejszych władczyń starożytności. Pokonana przez cesarza Aureliana w 272 r.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Zena, Zenobiuszka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Zenobia (ang., hiszp., wł.), Zénobie (franc.), Зенобия (ros.)</p></div>',
  'Zygmunt': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Zygmunt pochodzi z języka <strong>starogermańskiego</strong>. Złożone z członów <em>sieg</em> (zwycięstwo) i <em>mund</em> (ochrona, opieka) — oznacza <strong>„zwycięski obrońca"</strong>. Do Polski dotarło przez łacińskie <em>Sigismundus</em>.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię trzech królów polskich z dynastii Jagiellonów: Zygmunta I Starego (1467–1548), Zygmunta II Augusta (1520–1572) i Zygmunta III Wazy (1566–1632). Za ich panowania przypadł złoty wiek kultury polskiej. Zygmunt Freud (1856–1939) — austriacki neurolog, twórca psychoanalizy.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Zygmuś, Zygmuncik, Zyga, Zygmuntek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Sigismund (ang., niem.), Sigmund (niem.), Sigismondo (wł.), Zikmund (czes.), Сигизмунд (ros.), Zsigmond (węg.)</p></div>',
  'Chryzant': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Chryzant pochodzi z języka <strong>greckiego</strong> — złożone z <em>chrysos</em> (złoto) i <em>anthos</em> (kwiat). Oznacza <strong>„złoty kwiat"</strong>. Od tego imienia pochodzi też nazwa kwiatu chryzantemy (<em>chrysanthemum</em>). Imię niezwykłe — pełne blasku i urody.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Chryzanta — egipskiego szlachcica i chrześcijańskiego męczennika z III w., czczonego razem ze świętą Darią. Oboje zginęli za Numeriana ok. 283 r. w Rzymie. Ich święto przypada 25 października. W Polsce imię niezwykle rzadkie, znane głównie z kalendarzy kościelnych.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Chryś, Chryzanek, Antek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Chrysanthus (łac., ang.), Chrysanthe (franc.), Crisanto (wł., hiszp.), Хрисанф (ros.)</p></div>',
  'Cyriak': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Cyriak pochodzi z języka <strong>greckiego</strong> — od <em>kyriakos</em> (<em>κυριακός</em>), oznaczającego <strong>„należący do Pana"</strong> lub „pański, boski". Wywodzi się z <em>kyrios</em> — Pan, władca, Bóg. Imię o wyraźnie chrześcijańskim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Cyriaka — diakona i męczennika z Rzymu, który poniósł śmierć ok. 303 r. za panowania Dioklecjana. Patron jednej z czternastu świętych wspomożycieli (Nothelfer) — grupy świętych szczególnie czczonych w Kościele zachodnim. W Polsce imię rzadkie, znane z tradycji kościelnej.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Cyrianek, Kyrek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Cyriacus (łac.), Ciriaco (wł., hiszp.), Cyriaque (franc.), Кириак (ros.)</p></div>',
  'Ambroży': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Ambroży pochodzi z języka <strong>greckiego</strong> — od słowa <em>ambrotos</em>, oznaczającego <strong>„nieśmiertelny"</strong>, boski. Wywodzi się z połączenia <em>a-</em> (nie) i <em>brotos</em> (śmiertelny). Ambrozja to w mitologii greckiej pokarm bogów dający nieśmiertelność.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię rozsławił święty Ambroży z Mediolanu (ok. 340–397) — jeden z czterech Doktorów Kościoła, biskup Mediolanu, nauczyciel świętego Augustyna. Wyróżniał się elokwencją i był twórcą hymnów kościelnych. Patron Mediolanu i pszczelarzy.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Ambroś, Ambro, Ambrożek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Ambrose (ang.), Ambrosius (łac., niem.), Ambroise (franc.), Ambrosio (hiszp.), Ambrogio (wł.), Амвросий (ros.)</p></div>',
  'Alfons': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alfons pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>adal</em> (szlachetny, ród) i <em>funs</em> (gotowy, chętny). Oznacza <strong>„szlachetnie gotowy"</strong> lub „ten, kto jest chętny do służby szlachetnemu rodowi". Imię popularne wśród hispanoromańskiej arystokracji.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię trzynastu królów Kastylii i Leonu noszących imię Alfonso. Alfons X Mądry (1221–1284) — król Kastylii, mecenas nauki i kultury, twórca pierwszych praw spisanych po kastylijski. Alfons Ligori (1696–1787) — włoski teolog i założyciel redemptorystów, doktor Kościoła.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alfek, Fons, Alfonsik</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alfonso (hiszp., wł.), Alphonse (franc.), Alphons (niem.), Альфонс (ros.)</p></div>',
  'Adelaida': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adelaida pochodzi z języka <strong>starogermańskiego</strong> — złożone z <em>adal</em> (szlachetny, ród) i <em>heid</em> (rodzaj, natura, stan). Oznacza <strong>„szlachetnego rodu"</strong> lub „ta, która jest z wybitnej rodziny". Imię o arystokratycznym, europejskim charakterze.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Adelajdy (ok. 931–999) — cesarzowej, żony Ottona I Wielkiego, patronki wdów i cesarstwa. Adelaide — stolica Australii Południowej, nazwana na cześć królowej Adelajdy, żony Wilhelma IV. W Polsce imię rzadkie, kojarzone z europejską arystokracją i historią średniowieczną.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Ada, Adela, Adelka, Heida</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adelaide (ang., wł.), Adélaïde (franc.), Adelheid (niem.), Аделаида (ros.)</p></div>',
  'Alena': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Alena pochodzi z języka <strong>greckiego</strong> lub <strong>starogermańskiego</strong>. Jako forma imienia Helena — od <em>helene</em> (<strong>„jasna, błyszcząca"</strong>) lub od greckiej <em>Selene</em> (księżyc). Może też być słowiańską lub skandynawską wariantem imienia. Imię o jasnym, świetlistym znaczeniu.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Aleny z Forest (VII w.) — irlandzkiej dziewicy i męczennicy, patronki Belgii i regionu Forest koło Brukseli. Alena — forma używana w krajach słowiańskich (Czechy, Słowacja, Polska) jako wariant imienia Helena lub Alina. W Polsce sporadyczne, lecz eleganckie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Alenka, Alka, Lena, Aleneczka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Alena (czes., słow., chorw.), Alène (franc.), Алена (ros., ukr.)</p></div>',
  'Anastazja': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Anastazja pochodzi z języka <strong>greckiego</strong> — od słowa <em>anastasis</em>, oznaczającego <strong>„zmartwychwstanie"</strong>. Wywodzi się z <em>ana</em> (znów) i <em>stasis</em> (stanie). Imię związane z nadzieją odrodzenia.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Kościele wschodnim. Nosi je kilka świętych. Wielka księżna Anastazja Romanow (1901–1918) — córka ostatniego cara Rosji Mikołaja II, rozstrzelana przez bolszewików, stała się jedną z najbardziej znanych postaci historycznych XX w.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Nastia, Nastka, Stasia, Nastusia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Anastasia (ang., wł., ros., hiszp.), Anastasie (franc.), Anastazja (pol.)</p></div>',
  'Adolfina': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adolfina pochodzi z języka <strong>starogermańskiego</strong> — jest żeńską formą imienia Adolf, złożonego z <em>adal</em> (szlachetny) i <em>wulf</em> (wilk). Oznacza <strong>„szlachetna jak wilczyca"</strong>. Imię noszone przez europejskie arystokratki, dziś bardzo rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię popularne w XIX w. wśród rodzin arystokratycznych Niemiec i Austro-Węgier. Adolfina Zimajer — polska działaczka kobieca z XIX w. Ze względu na skojarzenia historyczne imię Adolf i pochodne przestały być nadawane po II wojnie światowej. Adolfina jako forma żeńska pozostaje historyczną ciekawostką.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adolka, Dolfina, Fina, Adolfinka</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adolphine (franc., niem.), Adolfina (wł., hiszp.), Адольфина (ros.)</p></div>',
  'Anatol': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Anatol pochodzi z języka <strong>greckiego</strong> — od słowa <em>anatole</em>, oznaczającego <strong>„wschód słońca"</strong>, wschód, strona wschodnia. Wywodzi się z <em>anatello</em> — wschodzić, rozbłyskać.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię popularne w Rosji i Polsce w XIX i XX w. Anatole France (1844–1924) — wybitny francuski pisarz i krytyk literacki, laureat Nagrody Nobla w dziedzinie literatury w 1921 r. Anatol Stern (1899–1968) — polski poeta i współtwórca futuryzmu.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Anatolek, Tolek, Antek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Anatole (franc.), Anatoly (ang.), Anatoliy (ukr.), Анатолий (ros.)</p></div>',
  'Apollinaris': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Apollinaris pochodzi z języka <strong>greckiego</strong> — od imienia boga <em>Apollon</em> (<em>Ἀπόλλων</em>), w mitologii greckiej boga słońca, muzyki, poezji i przepowiedni. Oznacza <strong>„należący do Apollina"</strong> lub „poświęcony Apollinowi".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Apollinarego z Rawenny — pierwszego biskupa Rawenny (I/II w.), ucznia apostoła Piotra, męczennika i patrona Rawenny. Bazylika Sant&#39;Apollinare in Classe — arcydzieło architektury wczesnochrześcijańskiej wpisane na listę UNESCO. W Polsce imię skrajnie rzadkie.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Apollek, Polinek, Apollinareuszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Apollinaris (łac., ang., niem.), Apollinaire (franc.), Apollinare (wł.), Аполлинарий (ros.)</p></div>',
  'Sylwester': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Sylwester pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>silvestris</em>, oznaczającego <strong>„leśny"</strong>, „dziki", „związany z lasem". Wywodzi się z <em>silva</em> — las.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię papieża Sylwestra I (314–335), który sprawował urząd w czasach przełomowych — za panowania cesarza Konstantyna Wielkiego, gdy chrześcijaństwo uzyskało wolność. Tradycja wiąże jego imię z zabawą sylwestrową (31 grudnia — wigilia jego wspomnienia). Św. Sylwester II (999–1003) to pierwszy papież z Francji.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Sylwek, Sylwuś, Syl, Sylweczek</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Sylvester (ang., niem.), Silvestre (franc., hiszp.), Silvestro (wł.), Сильвестр (ros.)</p></div>',
  'Serafin': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Serafin pochodzi z języka <strong>hebrajskiego</strong> — od słowa <em>serafim</em>, oznaczającego <strong>„płonące"</strong> lub „ogniste". Serafiny to w Biblii (Księga Izajasza 6) najwyższy chór aniołów, stojący najbliżej tronu Boga, otaczający Go ogniem miłości.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez świętego Serafina z Sarowa (1754–1833) — rosyjskiego mnicha, pustelnika i mistyka, jednego z najważniejszych świętych prawosławnych, słynącego z cudów i daru przepowiadania. Patron Rosyjskiej Cerkwi Prawosławnej.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Serafinek, Seraf</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Séraphin (franc.), Seraphim (ang., niem.), Serafino (wł.), Серафим (ros.)</p></div>',
  'Scholastyka': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Scholastyka pochodzi z języka <strong>łacińskiego</strong> — od słowa <em>scholasticus</em>, oznaczającego <strong>„uczony"</strong>, „szkolny". Wywodzi się z <em>schola</em> — szkoła. Imię wprost związane z wiedzą i nauką.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię siostry świętego Benedykta z Nursji (ok. 480–547), założyciela zakonu benedyktynów. Scholastyka zamieszkała niedaleko brata i poświęciła życie modlitwie. Patron uczniów, studentów i szkół. Jej dzień (10 lutego) poprzedza dzień św. Walentego.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Scholastyczka, Stasia, Schola</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Scholastica (ang., wł.), Scholastique (franc.), Scholastika (niem.), Схоластика (ros.)</p></div>',
  'Tekla': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Tekla pochodzi z języka <strong>greckiego</strong> — od imienia <em>Theokleia</em>, złożonego z <em>theos</em> (Bóg) i <em>kleos</em> (sława, chwała). Oznacza <strong>„chwała Boga"</strong> lub „ta, której chwałą jest Bóg".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię pierwszej chrześcijańskiej dziewicy-męczennicy wg tradycji — uczennicy świętego Pawła Apostoła z I w. Jej dzieje opisują apokryficzne <em>Dzieje Pawła i Tekli</em>. Bardzo czczona w Kościele wschodnim. W Polsce imię popularne do XIX w., dziś rzadsze.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Teklusia, Teklinka, Tela</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Thecla (łac., ang.), Thekla (niem.), Tèkla (katalon.), Фёкла (ros.)</p></div>',
  'Walburga': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Walburga pochodzi z języka <strong>starogermańskiego</strong>. Złożone z <em>wald</em> (władza, las) i <em>burg</em> (twierdza, gród). Oznacza <strong>„władczyni twierdzy"</strong> lub „ta, która strzeże grodu".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię angielskiej mniszki i misjonarki Walburgi (ok. 710–779), która przybyła do Niemiec na prośbę świętego Bonifacego. Była opatką w Heidenheim. Kanonizowana w 870 r. Z jej imieniem związana jest <strong>Noc Walpurgii</strong> (30 kwietnia) — tradycja obchodzona do dziś w Europie Środkowej.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Walburga, Wala, Walka</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Walburga (ang., niem.), Valpurga (wł.), Gauburge (franc.), Вальбурга (ros.)</p></div>',
  'Symeon': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Symeon pochodzi z języka <strong>hebrajskiego</strong> — od <em>Shim&#39;on</em>, wywodzącego się z <em>shama</em> (<strong>„słyszeć"</strong>). Oznacza „wysłuchany przez Boga". Jest starszą, hebrajską formą imienia Szymon.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię jednego z 12 patriarchów izraelskich. Symeon Słupnik (ok. 390–459) — syryjski asceta, który przez 37 lat mieszkał na platformie na szczycie kolumny, stając się symbolem skrajnego wyrzeczenia. Symeon I Wielki — car Bułgarii, twórca bułgarskiej państwowości.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Symek, Szymek (forma polska)</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Simon (ang., franc., niem.), Simón (hiszp.), Simone (wł.), Симеон (ros., bułg.)</p></div>',
  'Adriana': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Adriana pochodzi z języka <strong>łacińskiego</strong> — jest żeńską formą imienia Adrian, wywodzącego się od <em>Hadrianus</em> — „pochodzący z Hadrii", miasta w Italii nad Morzem Adriatyckim. Oznacza <strong>„mieszkanka wybrzeża Adriatyku"</strong>.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Żeński odpowiednik imienia cesarza Hadriana (76–138) — jednego z najlepszych władców Rzymu, budowniczego Wału Hadriana w Brytanii i Panteonu w Rzymie. Adriana Lima (ur. 1981) — brazylijska supermodelka. Adriana Lecouvreur — tytułowa bohaterka opery Francesco Cilei. W Polsce popularne od lat 80. XX w.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Adria, Adrianka, Adrianeczka, Aria</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Adriana (wł., hiszp., port., czes.), Adrienne (franc.), Адриана (ros.)</p></div>',
  'Albrecht': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Albrecht pochodzi z języka <strong>starogermańskiego</strong> — jest starszą formą imienia Albert, złożonego z <em>adal</em> (szlachetny) i <em>beraht</em> (jasny, błyszczący). Oznacza <strong>„szlachetnie jasny"</strong> lub „ten, który jaśnieje szlachetnością".</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Albrecht Dürer (1471–1528) — jeden z największych artystów renesansu północnego, malarz i grafik, autor słynnych akwarel i drzeworytów. Albrecht von Brandenburg — wielki mistrz Zakonu Krzyżackiego, który sekularyzował Prusy w 1525 r. W Polsce imię znane z historycznych kontaktów z Niemcami i Habsburgami.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Albek, Albrechteczek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Albert (ang., franc., hiszp., wł.), Adalbert (łac.), Альбрехт (ros.) — forma typowo germańska</p></div>',
  'Bogumił': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bogumił pochodzi z języka <strong>słowiańskiego</strong>. Złożone z członów <em>Bóg</em> i <em>miły</em>. Oznacza <strong>„miły Bogu"</strong> lub „ten, który jest miłością Bożą". Imię odzwierciedla głęboko chrześcijański charakter staropolskiego nazewnictwa.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię noszone przez błogosławionego Bogumiła (zm. ok. 1092) — arcybiskupa gnieźnieńskiego, który porzucił godność kościelną i resztę życia spędził jako pustelnik. Jego relikwie czczone są w Dobrowie. Patron archidiecezji gnieźnieńskiej.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bogumilec, Bogumisio, Bogumił</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Bogumil (czes., chorw.), Bogomil (bułg.), Богумил (ros., bułg.)</p></div>',
  'Bogumiła': '<div class=\"name-desc-section\"><div class=\"name-desc-label\">Znaczenie imienia</div><p>Imię Bogumiła pochodzi z języka <strong>słowiańskiego</strong>. Jest żeńską formą imienia Bogumił, złożoną z członów <em>Bóg</em> i <em>miła</em>. Oznacza <strong>„miła Bogu"</strong> lub „ta, która jest miła Bogu".</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Historia</div><p>Imię staropolskie, znane od wczesnego średniowiecza. Nawiązuje do słowiańskiej tradycji nadawania imion podkreślających pobożność i związek z Bogiem. Dziś rzadziej nadawane, lecz nadal obecne w polskich metrykach.</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Zdrobnienia</div><p>Bogusia, Miłka, Bogumiłka, Misia</p></div><div class=\"name-desc-section\"><div class=\"name-desc-label\">Odpowiedniki w innych językach</div><p>Bogumila (czes., słow.), Bogomila (chorw., bułg.), Bogumił/Bogumiła (pol.)</p></div>',
  'Anatola': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Anatola pochodzi z języka <strong>greckiego</strong> — od <em>anatolē</em> (<em>ἀνατολή</em>), oznaczającego <strong>„wschód"</strong>, wschód słońca, świt. Jest żeńską formą imienia Anatol. Imię związane ze wschodem i odrodzeniem — jak słońce wschodzące każdego ranka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętego Anatola z Konstantynopola — patriarchy z V w. Anatole France (1844–1924) — wybitny francuski pisarz, laureat Nagrody Nobla w 1921 r., autor <em>Wyspy Pingwinów</em> i <em>Bogów pragną krwi</em>. W Polsce forma Anatola jako żeńska imię rzadkie, forma Anatol (męska) częstsza.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Tosia, Anatolka, Natola</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anatolia (wł., hiszp.), Anatolie (franc.), Анатолия (ros.) — forma żeńska od Anatol</p></div>',
  'Antoniusz': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Antoniusz pochodzi z języka <strong>łacińskiego</strong> — od starożytnego rodu <em>Antonius</em>. Etymologia niepewna — prawdopodobnie z etruskiego. Część badaczy wywodzi je od greckiego <em>anthos</em> (kwiat) lub <em>anti</em> (przeciw). Jest starszą, łacińską formą imienia Antoni.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Marek Antoniusz (83–30 p.n.e.) — rzymski wódz i polityk, sojusznik Juliusza Cezara, kochanek Kleopatry VII. Jego tragiczna historia stała się tematem tragedii Szekspira <em>Antoniusz i Kleopatra</em>. Antoniusz Pustelnik (ok. 251–356) — ojciec chrześcijańskiego monastycyzmu, patron mnichów.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Antek, Tonek, Tońko, Antoniuszek</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Anthony (ang.), Antoine (franc.), Antonio (hiszp., wł.), Anton (niem., ros.), Антоний (ros.)</p></div>',
  'Agnes': '<div class="name-desc-section"><div class="name-desc-label">Znaczenie imienia</div><p>Imię Agnes pochodzi z języka <strong>greckiego</strong> — od <em>hagnos</em> (<em>ἁγνός</em>), oznaczającego <strong>„czysty"</strong>, święty, niewinny. Przez łacinę (<em>Agnes</em>) stało się popularne w całej chrześcijańskiej Europie. Jest starszą formą polskiego imienia Agnieszka.</p></div><div class="name-desc-section"><div class="name-desc-label">Historia</div><p>Imię świętej Agnieszki Rzymskiej (ok. 291–304) — dziewicy i męczennicy, jednej z najczcigodniejszych świętych Kościoła, patronki dziewcząt i czystości. Agnes von Kurowsky — pielęgniarka, pierwsza miłość Ernesta Hemingwaya, inspiracja dla <em>Pożegnania z bronią</em>. Matka Teresa z Kalkuty — Agnes Gonxha Bojaxhiu.</p></div><div class="name-desc-section"><div class="name-desc-label">Zdrobnienia</div><p>Agnesik, Nessa, Agni, Agi</p></div><div class="name-desc-section"><div class="name-desc-label">Odpowiedniki w innych językach</div><p>Agnes (ang., niem., szwedz.), Agnès (franc.), Agnese (wł.), Inés (hiszp.), Агнес (ros.)</p></div>',
};







